-- Poems batch 429
INSERT OR IGNORE INTO poems (id,title,author,dynasty,collection,collection_id,rhythmic,tags,excerpt,length,source_path,paragraphs) VALUES
('yuanqu-9637','尾・披衣强拈纸与笔，奈心绪烦多书万一。欲向芳卿行诉些憔悴，笔尖头','侯正卿','元','元曲','yuanqu','','[]','陶写哀情，纸面上敷陈怨气。',63,'元曲/yuanqu.json','["陶写哀情，纸面上敷陈怨气。", "待写个平安字样，都是俺虚脾拍塞。", "一封愁信息，向银台畔读不去也伤悲。", "蜡炬行明知人情意，也垂下数行红泪。"]'),
('yuanqu-9638','南吕・一枝花为玉叶儿作','亢文苑','元','元曲','yuanqu','','[]','名高唐国盘，色压陈亭榭。',59,'元曲/yuanqu.json','["名高唐国盘，色压陈亭榭。", "霞光侵赵璧，瑞霭赛隋珠。", "无半点儿尘俗，不比寻常物，世间总不如。", "莫夸谈天上飞琼，休卖弄人间美玉。"]'),
('yuanqu-9639','梁州・你为我堆宝髻羞盘凤翅，淡朱唇懒注胭脂。东君有意偷窥视。翠鸾','亢文苑','元','元曲','yuanqu','','[]','寻梦，彩扇题诗；花笺写恨，锦字传词。',109,'元曲/yuanqu.json','["寻梦，彩扇题诗；花笺写恨，锦字传词。", "包藏着无限相思，思量煞可意人儿。", "几时看靠纱窗偷转秋波，几时见整云髻轻舒玉指，几时看倚东风笑捻花枝。", "新婚，燕尔。", "到如今抛闪得人独自，你那点至诚心有谁似？休把那山海盟言不勾思，相会何时。"]'),
('yuanqu-9640','梁州・尽是些暄晓日茅檐燕雀，故意困盐车千里骅骝。英雄肯落儿曹彀？','亢文苑','元','元曲','yuanqu','','[]','乾坤倦客，江海扁舟，床头金尽，壮志难酬。',98,'元曲/yuanqu.json','["乾坤倦客，江海扁舟，床头金尽，壮志难酬。", "任飘零身寄南州，恨黄尘敝尽貂裘。", "看别人苫眼铺眉，笑自己缄舌闭口，但则索向寒窗袖手藏头。", "如今，更有，那屠龙计策干生受，慢劳攘慢奔走。", "顾我真成丧家狗，计拙如鸠。"]'),
('yuanqu-9641','尾・蛟龙须待春雷吼，雕鹗腾风万里游。大丈夫峥崂恁时候，扶汤佐周，','亢文苑','元','元曲','yuanqu','','[]','光前耀后，直教万古清名长不朽！。',16,'元曲/yuanqu.json','["光前耀后，直教万古清名长不朽！。"]'),
('yuanqu-9642','南吕・一枝花为玉梅作','亢文苑','元','元曲','yuanqu','','[]','人生萼绿生，天上轮茭降。',59,'元曲/yuanqu.json','["人生萼绿生，天上轮茭降。", "比南周琼解语，比西锦能香。", "淡沫玄霜，自有罗浮像，扫梁园红翠乡。", "千般儿玉骨玲珑，一段儿冰魂荡漾。"]'),
('yuanqu-9643','梁州・受用杀西湖处土，风流煞东阁何郎。芳湿一点何时忘。银钗半露，','亢文苑','元','元曲','yuanqu','','[]','粉颈微妆；想那调羹滋味，止渴思量。',99,'元曲/yuanqu.json','["粉颈微妆；想那调羹滋味，止渴思量。", "占一枝素魂芬芳，算百花总是寻常。", "则要挂新月点缀昏黄，合夜雪色藏暗香，却休趁东风泄漏春光。", "惜花人正想寻芳，驿使频来往，怎禁那寂莫苦情况。", "则怕羌管声中，零落了萦损柔肠。"]'),
('yuanqu-9644','尾・堪图石氏黄金帐，宜住芦花白玉堂，折莫便冰雪前村一千丈。沽一壶','亢文苑','元','元曲','yuanqu','','[]','酒浆，向蹇驴背上，教那快忍冻的书生尽自赏。',21,'元曲/yuanqu.json','["酒浆，向蹇驴背上，教那快忍冻的书生尽自赏。"]'),
('yuanqu-9645','吕蒙正风雪破窑记・仙吕/点绛唇','王实甫','元','元曲','yuanqu','','[]','则我这好胜爷娘，故意娇养，如花样。',30,'元曲/yuanqu.json','["则我这好胜爷娘，故意娇养，如花样。", "招配新郎，卷翠帘在妆楼上。"]'),
('yuanqu-9646','吕蒙正风雪破窑记・混江龙','王实甫','元','元曲','yuanqu','','[]','凭栏凝望，猛然间回首问梅香。',113,'元曲/yuanqu.json','["凭栏凝望，猛然间回首问梅香。", "(梅香云)姐姐，你问我些甚么？(正旦唱)见二人衣冠齐整，鞍马非常。", "能偿个守蓝桥饱醋生，料强如误桃源聪俊俏刘郎。", "挤眉弄眼，俐齿伶牙，攀高接贵，顺水推船，小则小偏和咱厮强。", "不尘俗模样，穿着些打眼目衣裳。"]'),
('yuanqu-9647','吕蒙正风雪破窑记・油葫芦','王实甫','元','元曲','yuanqu','','[]','学剑攻书折桂郎，有一日开选场，半间儿书舍换做都堂。',130,'元曲/yuanqu.json','["学剑攻书折桂郎，有一日开选场，半间儿书舍换做都堂。", "想韩信偷瓜手生扭做了元戎将，传说那筑墙板番做了头厅相。", "想当初王鼎臣，姜吕望，那鼎臣将柴担子横在肩头上，太公八十岁遇着文王。", "(梅香云)姐姐，等的到八十岁，可老了也。", "(正旦云)梅香，可不道君子人待时守分也。", "(唱)。"]'),
('yuanqu-9648','吕蒙正风雪破窑记・天下乐','王实甫','元','元曲','yuanqu','','[]','岂不闻有福之人不在忙，我这里参也波详，心自想。',52,'元曲/yuanqu.json','["岂不闻有福之人不在忙，我这里参也波详，心自想。", "平地一声雷振响，朝为田舍郎，暮登天子堂。", "可不道寒门生将相。"]'),
('yuanqu-9649','吕蒙正风雪破窑记・金盏儿','王实甫','元','元曲','yuanqu','','[]','绣球儿你寻一个心慈善性温良，有志气好文章，这一生事都在你这绣球儿上。',198,'元曲/yuanqu.json','["绣球儿你寻一个心慈善性温良，有志气好文章，这一生事都在你这绣球儿上。", "夫妻相待，贫和富有何妨？贫和富足我命福，好共歹在你斟量。", "休打着那无恩情轻薄子，你寻一个知敬重画眉郎。", "(正旦做抛绣球科)(吕蒙正云)哥哥，你看，那小姐，将绣球儿抛在我跟前了。", "(寇准云)兄弟，敢这绣球儿误落在你怀中。", "咱且走在一边伺候，看员外怎生处断。", "(净云)绣球儿也抛与了别人，我和你等些甚么？咱两个一人唱一句，去了罢。", "(大净唱)。"]'),
('yuanqu-9650','吕蒙正风雪破窑记・金字经','王实甫','元','元曲','yuanqu','','[]','绣球儿今日个打着一个穷秀才，(二净唱)气的区区泪满腮，泪满腮。',71,'元曲/yuanqu.json','["绣球儿今日个打着一个穷秀才，(二净唱)气的区区泪满腮，泪满腮。", "(大净唱)也是他缘分该，(二净唱)休相怪。", "(大净唱)咱拽着尾巴归去来。", "(同下)。"]'),
('yuanqu-9651','吕蒙正风雪破窑记・醉中天','王实甫','元','元曲','yuanqu','','[]','者莫他烧地权为炕，凿壁借偷光，一任教无底砂锅漏了饭汤。',79,'元曲/yuanqu.json','["者莫他烧地权为炕，凿壁借偷光，一任教无底砂锅漏了饭汤。", "者莫足站就蜘蛛网，土炕芦席草房，那里有绣帏罗帐？(刘员外云)你再思想咱。", "(正旦唱)您孩儿心顺处便是天堂。"]'),
('yuanqu-9652','吕蒙正风雪破窑记・尾声','王实甫','元','元曲','yuanqu','','[]','到晚来月射的破窑明，风刮的蒲帘响，便是俺花烛洞房。',92,'元曲/yuanqu.json','["到晚来月射的破窑明，风刮的蒲帘响，便是俺花烛洞房。", "实丕丕家私财物广，虚飘飘罗锦千箱。", "守着才郎，恭俭温良，憔悴了菱花镜里妆。", "我也不恋鸳衾象床，绣帏罗帐，则住那破窑风月射漏星堂。", "(同下)。"]'),
('yuanqu-9653','吕蒙正风雪破窑记・正宫/端正好','王实甫','元','元曲','yuanqu','','[]','夫妇取今生，缘分关前世。',38,'元曲/yuanqu.json','["夫妇取今生，缘分关前世。", "穷和富是我裙带头衣食。", "帘儿揭起柴门倚，专等俺投斋婿。"]'),
('yuanqu-9654','吕蒙正风雪破窑记・滚绣球','王实甫','元','元曲','yuanqu','','[]','听的钟声响报信息，这斋食有次第。',92,'元曲/yuanqu.json','["听的钟声响报信息，这斋食有次第。", "俺知他的情意，他待俺着甚回席。", "虽然是时下贫，有朝发愤日，那其间报答恩德。", "这其间不见回归，做下碗热羹汤等待贤太冷。", "揣着个冻酸馅，未填还拙妇的饥，有甚希奇。"]'),
('yuanqu-9655','吕蒙正风雪破窑记・倘秀才','王实甫','元','元曲','yuanqu','','[]','今日个灵鹃儿吖吖的报喜，甚风儿吹来到俺这里？淡饭黄齑吃甚的？(刘员外云)那穷厮那里去了？(正旦唱)旋酒处舀了一碗热水，抄纸处讨了把石灰，教学处寻了管旧笔。',77,'元曲/yuanqu.json','["今日个灵鹃儿吖吖的报喜，甚风儿吹来到俺这里？淡饭黄齑吃甚的？(刘员外云)那穷厮那里去了？(正旦唱)旋酒处舀了一碗热水，抄纸处讨了把石灰，教学处寻了管旧笔。"]'),
('yuanqu-9656','吕蒙正风雪破窑记・尾声','王实甫','元','元曲','yuanqu','','[]','则这瓦窑中将一应人皆回避，你金榜无名誓不归。',100,'元曲/yuanqu.json','["则这瓦窑中将一应人皆回避，你金榜无名誓不归。", "(云)若得官呵，你为义夫，妾身为节妇。", "(唱)立一通贤达德政碑，扶起攀蟾折桂枝，带将你那金银还家来报答你那妻。", "你若提着一个瓦罐还家来，我可也怨不的你。", "(下)。"]'),
('yuanqu-9657','吕蒙正风雪破窑记・中吕/粉蝶儿','王实甫','元','元曲','yuanqu','','[]','瓮牖桑枢，世间穷尽都在此处，有一千个不识消疏。',63,'元曲/yuanqu.json','["瓮牖桑枢，世间穷尽都在此处，有一千个不识消疏。", "范丹也索移，原宪也索躲，便有那颜回也难住。", "虽然是人不堪居，我觑的肚兰堂绿窗朱户。"]'),
('yuanqu-9658','吕蒙正风雪破窑记・醉春风','王实甫','元','元曲','yuanqu','','[]','恨只恨买臣妻，学不学卓氏女，破窑中熬了我数年，多受了些个苦，苦。',50,'元曲/yuanqu.json','["恨只恨买臣妻，学不学卓氏女，破窑中熬了我数年，多受了些个苦，苦。", "一饮一啄，事皆前定，也是我一生衣禄。"]'),
('yuanqu-9659','吕蒙正风雪破窑记・上小楼','王实甫','元','元曲','yuanqu','','[]','你如今知咱受苦，将咱小觑。',54,'元曲/yuanqu.json','["你如今知咱受苦，将咱小觑。", "怎肯道是连累街坊，带累亲邻，败坏风俗。", "冻杀我，甘心死去，则这个泼家私觑也那是不觑。"]'),
('yuanqu-9660','吕蒙正风雪破窑记・普天乐','王实甫','元','元曲','yuanqu','','[]','我这里猛然观，抬头觑，我道是谁家个奸汉，却原来是应举的儿夫。',144,'元曲/yuanqu.json','["我这里猛然观，抬头觑，我道是谁家个奸汉，却原来是应举的儿夫。", "咱须足旧有姻，关连着亲肠肚。", "(吕蒙正云)小姐，我如今落薄了，不曾得官。", "(正旦云)便落薄何如？(唱)但得个身安乐还家重完聚，问其么官不官便待怎的！(云)遇与不遇，有个比喻。", "(唱)有一个张良也曾弃印，有一个陶潜罢职，有一个范蠡归湖。"]'),
('yuanqu-9661','吕蒙正风雪破窑记・十二月','王实甫','元','元曲','yuanqu','','[]','走将来朝云暮雨，似水也那如鱼。',52,'元曲/yuanqu.json','["走将来朝云暮雨，似水也那如鱼。", "又无那暖烘烘的被卧，都是些薄湿湿的衣服。", "叫晃晃腰间甚物？怎想你那身上埋伏。"]'),
('yuanqu-9662','吕蒙正风雪破窑记・尧民歌','王实甫','元','元曲','yuanqu','','[]','呀，两三层麻布里裹珍珠，万万丈波心里钓鳌鱼。',164,'元曲/yuanqu.json','["呀，两三层麻布里裹珍珠，万万丈波心里钓鳌鱼。", "怕你得官酬志汉相如，倒做了好色荒淫鲁秋胡。", "儿也波夫，冤家问一句，说罢也重完了聚。", "(吕蒙正云)小姐，我不瞒你说，我故意的试探你，那媒婆也是我使他来，谁想小姐一片贞节之心。", "我得了本处县令，着我衣锦还乡。", "我到来日，夸官三日，我和你同享富贵。", "(正旦云)兀的不欢喜杀我也，谁想有今日也。", "(唱)。"]'),
('yuanqu-9663','吕蒙正风雪破窑记・尾声','王实甫','元','元曲','yuanqu','','[]','到来日慌张杀那秃院上，没乱杀俺那一双老父母。',54,'元曲/yuanqu.json','["到来日慌张杀那秃院上，没乱杀俺那一双老父母。", "今日个显耀你那里夺来的富，折准我那从前受过的苦。", "(同吕蒙正下)。"]'),
('yuanqu-9664','吕蒙正风雪破窑记・双调/新水令','王实甫','元','元曲','yuanqu','','[]','破窑中节妇轿儿抬，满城人大惊小怪。',49,'元曲/yuanqu.json','["破窑中节妇轿儿抬，满城人大惊小怪。", "驾车当酒垆，包土筑坟台。", "俺男儿日转千阶，我和他妆些模样做些娇态。"]'),
('yuanqu-9665','吕蒙正风雪破窑记・川拨棹','王实甫','元','元曲','yuanqu','','[]','我叹这个老员外，积趱下些不义财。',53,'元曲/yuanqu.json','["我叹这个老员外，积趱下些不义财。", "俺男儿的受了宣牌，媳妇儿的有些人才，百姓每恭心管待，那其间谁赍发吕秀才？。"]'),
('yuanqu-9666','吕蒙正风雪破窑记・七兄弟','王实甫','元','元曲','yuanqu','','[]','你那时上街，百刂划。',41,'元曲/yuanqu.json','["你那时上街，百刂划。", "送枯柴。", "严寒天雪冷实难捱，贫家米贱冻难捱，则今日趁了方何碍？。"]'),
('yuanqu-9667','吕蒙正风雪破窑记・收江南','王实甫','元','元曲','yuanqu','','[]','牙，你记的满头风雪却回来，今日个一天好事奔人来。',78,'元曲/yuanqu.json','["牙，你记的满头风雪却回来，今日个一天好事奔人来。", "(长老云)行者，开佛殿，朝中大人降香来也。", "(正旦唱)听的道朝中宰相降香来，百姓海等待。", "却正是月明千里故人来。"]'),
('yuanqu-9668','吕蒙正风雪破窑记・水仙子','王实甫','元','元曲','yuanqu','','[]','状元郎仇恨汇在心怀，忤逆女将爷娘不认睬。',72,'元曲/yuanqu.json','["状元郎仇恨汇在心怀，忤逆女将爷娘不认睬。", "我这里悔过也展脚舒腰拜，望慈亲免罪责，被尘埃险将我沉埋。", "女受了金花官诰，女婿便绯袍玉带，也是我苦尽甘来。"]'),
('yuanqu-9669','荆楚臣重对玉梳记・仙吕/点绛唇','贾仲明','元','元曲','yuanqu','','[]','风月家门，又无资本，别营运。',29,'元曲/yuanqu.json','["风月家门，又无资本，别营运。", "止不过送旧迎新，凭卖笑衣食稳。"]'),
('yuanqu-9670','荆楚臣重对玉梳记・混江龙','贾仲明','元','元曲','yuanqu','','[]','倚仗着高谈阔论，全用些野狐涎扑子弟打郎君。',144,'元曲/yuanqu.json','["倚仗着高谈阔论，全用些野狐涎扑子弟打郎君。", "散春情柳眉星眼，取和气皓齿朱唇。", "和他笑一笑敢忽的软了四肢，将他靠一靠管烘的走了三魂。", "为俺呵搬的那读书的慵观经史，作商的懒去辛勤，为吏的焉遵法度，做官的岂惜簪绅。", "生着那义和的兄弟厮寻爷，孝顺的儿子学生分。", "都是俺个败人家油鬏髻太岁，送人命粉脸脑凶神。"]'),
('yuanqu-9671','荆楚臣重对玉梳记・元和令','贾仲明','元','元曲','yuanqu','','[]','常言道母慈悲儿孝顺，则为你娘狠毒儿生分。',82,'元曲/yuanqu.json','["常言道母慈悲儿孝顺，则为你娘狠毒儿生分。", "每日家三餐饱饭要腥荤，四季衣换套儿新。", "(卜儿云)须不是荆秀才的钱物。", "(正旦唱)送的他离乡背井，进退无门，恰便似汤浇雪风卷云。"]'),
('yuanqu-9672','荆楚臣重对玉梳记・上马娇','贾仲明','元','元曲','yuanqu','','[]','你那眼又亲，手又准，似饿鹞扑鹌鹑。',41,'元曲/yuanqu.json','["你那眼又亲，手又准，似饿鹞扑鹌鹑。", "将一座花柳营，生扭做迷魂阵，真是个女吊客母丧门。"]'),
('yuanqu-9673','荆楚臣重对玉梳记・游四门','贾仲明','元','元曲','yuanqu','','[]','再休想不应亲者强来亲，则理会的说响钞共精银。',48,'元曲/yuanqu.json','["再休想不应亲者强来亲，则理会的说响钞共精银。", "恁那之乎者也都休沦，使不着调子曰弄诗云，待做惜花人。"]'),
('yuanqu-9674','荆楚臣重对玉梳记・胜葫芦','贾仲明','元','元曲','yuanqu','','[]','眼前面便是西出阳关无故人，(卜儿云)走的快着。',68,'元曲/yuanqu.json','["眼前面便是西出阳关无故人，(卜儿云)走的快着。", "(正旦唱)个带伤也着昏，生逼人千里关山劳梦魂。", "若早知你这般圈缋，那般局段，急抽身不囫囵！。"]'),
('yuanqu-9675','荆楚臣重对玉梳记・幺篇','贾仲明','元','元曲','yuanqu','','[]','都是你个爱钱的虔婆送了人，(荆楚臣云)可不着人唾骂奶奶也！(正旦唱)那里怕千人骂万人嗔？则愿的臭死尸骸蛆乱虫分，遮莫便狼拖狗拽，鸦口嵌鹊啄，休想我系一条麻布孝腰',83,'元曲/yuanqu.json','["都是你个爱钱的虔婆送了人，(荆楚臣云)可不着人唾骂奶奶也！(正旦唱)那里怕千人骂万人嗔？则愿的臭死尸骸蛆乱虫分，遮莫便狼拖狗拽，鸦口嵌鹊啄，休想我系一条麻布孝腰裙！。"]'),
('yuanqu-9676','荆楚臣重对玉梳记・后庭花','贾仲明','元','元曲','yuanqu','','[]','他虽然身贫志不贫，(荆楚臣云)姐姐，有钱的来了，小生告回。',259,'元曲/yuanqu.json','["他虽然身贫志不贫，(荆楚臣云)姐姐，有钱的来了，小生告回。", "(正旦唱)我怎肯钱亲人不亲？(荆楚臣云)常言道后浪催前浪，(正旦唱)尽教他后浪催前浪，(带云)楚臣放心，(唱)休想我新人换旧人。", "(净云)二十载绵花都送大姐哩！(正旦唱)卖花人卖花唇，(带云)我劝你咱，(唱)休入俺这花营锦阵。", "(带云)我说几般儿你受用的茶饭。", "(唱)三停刀砍脚跟，百炼锤打脑门。", "生铁钩搭脊筋，钅俞镔杓剜眼轮。", "连珠箭雨点频，九稍炮风势紧。", "漫天纲措备的真，陷入坑埋没的准。", "钉人钉勾二百斤，钻人钻有十数根，秤人秤安顿的稳。", "急收拾没了半文，刚刚的剩纸路引。"]'),
('yuanqu-9677','荆楚臣重对玉梳记・赚煞尾','贾仲明','元','元曲','yuanqu','','[]','从今后都一般病染梦魂劳，两下里人远天涯近。',216,'元曲/yuanqu.json','["从今后都一般病染梦魂劳，两下里人远天涯近。", "好苦痛也荆郎楚臣，(荆楚臣云)姐姐。", "你肯守志么？(正旦唱)我敢一上青山便化身。", "从今后枕冷衾寒，索自温存。", "(净云)有小人陪侍大姐，二十载绵花不剩一分回去！(正旦唱)这嘶待逞精神卖弄家门，(净云)二十载绵花。", "则和大姐歇一夜罢。", "(正旦云)呆汉！(唱)休想和你一夜夫妻百夜恩！(净云)柳茂英买了顾玉香也！(正旦唱)你待要抟香弄粉，妆孤学俊。", "(带云)呆汉！(唱)便准备着那一年春尽一年春。", "(同荆下)。"]'),
('yuanqu-9678','荆楚臣重对玉梳记・仙吕/赏花时','贾仲明','元','元曲','yuanqu','','[]','君既取功名妾不留，妾谨守香闺君莫忧。',54,'元曲/yuanqu.json','["君既取功名妾不留，妾谨守香闺君莫忧。", "(带云)我将这玉梳呵，(唱)分两下有因由，则怕你撇咱脑后，似破镜合妆楼。"]'),
('yuanqu-9679','荆楚臣重对玉梳记・幺篇','贾仲明','元','元曲','yuanqu','','[]','无瑕玷的情怀图个永久，有温润的姻缘博个到头。',58,'元曲/yuanqu.json','["无瑕玷的情怀图个永久，有温润的姻缘博个到头。", "(做拜别科)(唱)若赴京阙到皇州，有一日功名成就，做夫妇可风流。", "(下)。"]'),
('yuanqu-9680','荆楚臣重对玉梳记・正宫/端正好','贾仲明','元','元曲','yuanqu','','[]','人乍别受姜凉，病易感添寂寞，记相别，可早半月期过。',43,'元曲/yuanqu.json','["人乍别受姜凉，病易感添寂寞，记相别，可早半月期过。", "俺悉人病里如何过？又被这秋景相回和。"]'),
('yuanqu-9681','荆楚臣重对玉梳记・倘秀才','贾仲明','元','元曲','yuanqu','','[]','无奈何浅妆淡抹，有甚有梳艳裹，每日懒出门木呈绣房里坐。',47,'元曲/yuanqu.json','["无奈何浅妆淡抹，有甚有梳艳裹，每日懒出门木呈绣房里坐。", "朝忘餐食无味，夜废寝眼难合，不索你问我。"]'),
('yuanqu-9682','荆楚臣重对玉梳记・滚绣球','贾仲明','元','元曲','yuanqu','','[]','我与你觅下的金寻下的银，买下的锦攒下的罗，珠和翠整箱儿盛垛，娘呵，你那哭穷口恰似翻河。',229,'元曲/yuanqu.json','["我与你觅下的金寻下的银，买下的锦攒下的罗，珠和翠整箱儿盛垛，娘呵，你那哭穷口恰似翻河。", "(带云)金钱不使呵，(唱)莫不阴司下要用他？(带云)珠翠不戴呵，(唱)莫不灵堂前要显豁？(带云)绞锦不穿呵，(唱)莫不留着棺函中装裹？(卜儿云)忤逆弟子，你待着我死哩！(正旦云)你死呵，(唱)也不索做水陆动钟鼓铙钹。", "(卜儿云)可是为甚么？(正旦唱)你终朝看的昧心经管取消了灾障，每日念的养家咒多应免些罪过。", "(卜儿云)你咒的我好！好儿女！好儿女！(正旦唱)咱可甚儿女情多！。"]'),
('yuanqu-9683','荆楚臣重对玉梳记・倘秀才','贾仲明','元','元曲','yuanqu','','[]','休假温存絮叨叨取撮，佯问候热刺刺念合，更怕我不趱你那冷气虚心厮拾掇。',89,'元曲/yuanqu.json','["休假温存絮叨叨取撮，佯问候热刺刺念合，更怕我不趱你那冷气虚心厮拾掇。", "哑谜儿有甚难猜破？甜句儿将我紧兜罗，口如蜜钵。", "(卜儿云)我如今老了，抬举的你成人，你也可怜我些儿。", "(正旦唱)。"]'),
('yuanqu-9684','荆楚臣重对玉梳记・滚绣球','贾仲明','元','元曲','yuanqu','','[]','做娘的肯哀怜肯付合，做女的有疼热有瓜葛，指头上单养的我一个，须不是过房的买到前窝。',115,'元曲/yuanqu.json','["做娘的肯哀怜肯付合，做女的有疼热有瓜葛，指头上单养的我一个，须不是过房的买到前窝。", "熬煎的点秋霜两鬓皤，抬举我正青春二九过。", "衣食勾家私得过，因甚的闹炒炒做不的个存活？每日间八阳经便少呵也有三千卷，五代史至轻呵也有二百合，又不是风魔。"]'),
('yuanqu-9685','荆楚臣重对玉梳记・脱布衫','贾仲明','元','元曲','yuanqu','','[]','一心待趁浪逐波，恣情的妙舞清歌。',32,'元曲/yuanqu.json','["一心待趁浪逐波，恣情的妙舞清歌。", "呆子弟迎风把火，强风情指山卖磨。"]'),
('yuanqu-9686','荆楚臣重对玉梳记・滚绣球','贾仲明','元','元曲','yuanqu','','[]','俺这暖烘烘锦被窝，似翻滚滚油舶镬。',114,'元曲/yuanqu.json','["俺这暖烘烘锦被窝，似翻滚滚油舶镬。", "这效鸾凰翠屏绣幕，是陷平人虎窟狼窝。", "红莲舌是斩郎君古定刀，青丝发是缚子弟降魔索。", "鸩人药是美甘甘舌尖上几口甜唾，招人命是香喷喷袖门内半幅轻罗。", "泼人汤三转身揩些眼泪，催人命百忙里着句褪科，平地风波。"]'),
('yuanqu-9687','荆楚臣重对玉梳记・赛鸿秋','贾仲明','元','元曲','yuanqu','','[]','则俺那双解元普天下声名播。',78,'元曲/yuanqu.json','["则俺那双解元普天下声名播。", "哎，你个冯员外舍性命推没磨。", "则这个苏小卿怎肯伏低？将料着这苏婆休想轻饶过。", "呆厮你收拾买花钱，休习闲牙磕。", "常言道：井口上瓦罐终须破。"]'),
('yuanqu-9688','荆楚臣重对玉梳记・二煞','贾仲明','元','元曲','yuanqu','','[]','若是娶的我去家中过，便是引得狼来屋里窝。',120,'元曲/yuanqu.json','["若是娶的我去家中过，便是引得狼来屋里窝。", "俺这粉面油头，便是非灾横祸；画阁兰堂，便是地纲天罗。", "敢着你有家难奔，有口难言，有气难呵。", "弄的个七上八落，只待睁着眼跳黄河。", "(净云)大姐，我恰才不道来？二十载绵花都不打紧，则娶大姐做个老婆。", "(正旦唱)。"]'),
('yuanqu-9689','荆楚臣重对玉梳记・中吕/粉蝶儿','贾仲明','元','元曲','yuanqu','','[]','秋况消疏，远村迷淡烟深处，断桥边野水平芜。',50,'元曲/yuanqu.json','["秋况消疏，远村迷淡烟深处，断桥边野水平芜。", "盼邮亭巴堠子，一步捱一步。", "早则是途径崎岖，恼行人痛伤情绪。"]'),
('yuanqu-9690','荆楚臣重对玉梳记・醉春风','贾仲明','元','元曲','yuanqu','','[]','则为俺那不心软的狠毒娘，更合着这忒忤逆的逃窜女。',70,'元曲/yuanqu.json','["则为俺那不心软的狠毒娘，更合着这忒忤逆的逃窜女。", "恰便似孟姜女送寒衣，谁曾受这般苦！苦！那里问养育情怀，则为俺夫妻恩爱，早难道割不断子母肠肚。"]'),
('yuanqu-9691','荆楚臣重对玉梳记・红绣鞋','贾仲明','元','元曲','yuanqu','','[]','按天际落霞孤鹜，映残阳老树啼乌，古道傍飘衰叶折枯蒲。',45,'元曲/yuanqu.json','["按天际落霞孤鹜，映残阳老树啼乌，古道傍飘衰叶折枯蒲。", "蒹葭排雁字，云水捕鱼图，洒西风弹泪雨。"]'),
('yuanqu-9692','荆楚臣重对玉梳记・迎仙客','贾仲明','元','元曲','yuanqu','','[]','转过这山额角生惨凄，见一簇恶林郎黑模糊，不由我心儿里猛然添怕惧。',93,'元曲/yuanqu.json','["转过这山额角生惨凄，见一簇恶林郎黑模糊，不由我心儿里猛然添怕惧。", "两耳火云烧，浑身冷汗出，似钩住我皮肤，把不定头梢儿竖。", "(梅香云)姐姐，早寻个灯火店安下也好。", "(净上喝，旦慌科)(正旦唱)。"]'),
('yuanqu-9693','荆楚臣重对玉梳记・石榴花','贾仲明','元','元曲','yuanqu','','[]','唬的我意慌张心乔怯战都速，无了魂魄，软了身躯，则见他恶哏哏嗔忿忿气扑扑。',152,'元曲/yuanqu.json','["唬的我意慌张心乔怯战都速，无了魂魄，软了身躯，则见他恶哏哏嗔忿忿气扑扑。", "(净扭旦认科)(正旦云)放手！(净云)走的好！今日见你也。", "(正旦唱)猛见了他面目，事在当初。", "不合将他千般数落十分怒，料应来命在须臾。", "(净云)既然见了你，好歹要成合，不肯便杀了你！(正旦唱)这厮待强风情打家截道拚着做，那里讨护身符？。"]'),
('yuanqu-9694','荆楚臣重对玉梳记・上小楼','贾仲明','元','元曲','yuanqu','','[]','你道是如何发付，我索避着不做。',70,'元曲/yuanqu.json','["你道是如何发付，我索避着不做。", "我这里敛袂回身，褪后趋前，眼笑眉舒。", "(做拜科)(唱)施礼数，道万福，殷勤观觑，施呈着我尊前席上那些假虚脾和睦。"]'),
('yuanqu-9695','荆楚臣重对玉梳记・幺篇','贾仲明','元','元曲','yuanqu','','[]','待将咱所图，我宁死不辱！这厮笑里藏刀，节外生枝，暗地埋伏。',180,'元曲/yuanqu.json','["待将咱所图，我宁死不辱！这厮笑里藏刀，节外生枝，暗地埋伏。", "这里是大道官塘，怎没个行人，南来北去？天那，眼见的死的来不着坟墓。", "(净扯住，云)大姐，成合了罢？(正旦叫科，云)有杀人贼也！(荆楚臣引祗候上，云)甚么人叫杀人贼？左右每拿住！(做拿净，与旦认科)(荆楚臣云)玉香姐姐，你认的我么？(正旦云)救我的是谁那？(荆楚臣云)小生荆楚臣也。", "(正旦云)惭愧。", "(唱)。"]'),
('yuanqu-9696','荆楚臣重对玉梳记・满庭芳','贾仲明','元','元曲','yuanqu','','[]','也是天然对付，险些儿身归地府，命掩泉途。',228,'元曲/yuanqu.json','["也是天然对付，险些儿身归地府，命掩泉途。", "(荆楚臣云)为甚这厮做出这等事来？(正旦唱)这厮只因饱暖生淫欲。", "(荆楚臣云)这是关系性命，暂时随顺，省致如此狼狈。", "(正旦唱)便休想似水如鱼。", "(荆楚臣云)权时之事，何故认真？(正旦唱)与这嘶待一时间莺俦燕侣，我情愿尽世儿凤只鸾孤。", "(荆楚巨云)且免一时危难，也不为过。", "(正旦唱)楚臣也，你深思虑，因何难共处？岂不闻冰炭不同炉？(荆楚臣云)左右，拿过那逆贼来！(祗从拿净跪，旦骂介)(净云)二十载绵花都送大姐。", "(正旦唱)。"]'),
('yuanqu-9697','荆楚臣重对玉梳记・普天乐','贾仲明','元','元曲','yuanqu','','[]','这厮起荒淫，生嫉妒，抵多少守株待免，缘木求龟。',153,'元曲/yuanqu.json','["这厮起荒淫，生嫉妒，抵多少守株待免，缘木求龟。", "(净做慌介)(正旦唱)贼汉意下慌，楚臣心头怒。", "(荆楚臣云)据这贼情理难容，该问死罪哩！(正旦唱)据此贼情理难容伤时务，坏人伦罪不容诛。", "一心待偎红倚翠，论黄数黑，恶紫夺朱。", "(云)楚臣，你好生施行此贼咱。", "(荆楚臣云)左右，将此贼押赴县里去者！(押净下)(正旦唱)。"]'),
('yuanqu-9698','荆楚臣重对玉梳记・快活三','贾仲明','元','元曲','yuanqu','','[]','楚臣索自窨付，君子断其初。',33,'元曲/yuanqu.json','["楚臣索自窨付，君子断其初。", "说山盟言海誓做妻夫，怎忘的咱剪发燃香处。"]'),
('yuanqu-9699','荆楚臣重对玉梳记・朝天子','贾仲明','元','元曲','yuanqu','','[]','自楚臣应举，听妾身拜覆，俺娘将我待嫁做商人妇。',158,'元曲/yuanqu.json','["自楚臣应举，听妾身拜覆，俺娘将我待嫁做商人妇。", "贤愚从来不并居，因此上不避红尘路。", "谁想来至中途，逢着贼徒，几乎问遭问阻。", "猛可里得遇，将妾身救取，方信道天自有安排处。", "(荆楚臣云)元来如此。", "你可来做甚么？我自有人来取你。", "(正旦云)楚臣，你如今那里为官？(荆楚臣云)今授句容县令，你也受用五花官诰，做夫人县君也。", "(正旦唱)。"]'),
('yuanqu-9700','荆楚臣重对玉梳记・十二月','贾仲明','元','元曲','yuanqu','','[]','拜辞丁清歌妙舞，打迭起傅粉施朱。',51,'元曲/yuanqu.json','["拜辞丁清歌妙舞，打迭起傅粉施朱。", "受了些了辛万苦，熬了些短叹长吁。", "早则有准成地朝云暮雨，依然的复旧如初。"]'),
('yuanqu-9701','荆楚臣重对玉梳记・尧民歌','贾仲明','元','元曲','yuanqu','','[]','等着也五花官诰七香车，尽受用满身花影倩人扶。',94,'元曲/yuanqu.json','["等着也五花官诰七香车，尽受用满身花影倩人扶。", "今日个花生满路得荣除，早则不碧桃花下凤鸾孤。", "欢娱欢娱乐有余，轻怜惜偎香五。", "(荆楚臣云)左右，鞴马！一壁抬过轿儿来，共夫人同回县里去！(正旦唱)。"]'),
('yuanqu-9702','荆楚臣重对玉梳记・耍孩儿','贾仲明','元','元曲','yuanqu','','[]','原来这夫人也许俺娼人做，我则道尽肚儿常为妓女。',83,'元曲/yuanqu.json','["原来这夫人也许俺娼人做，我则道尽肚儿常为妓女。", "不想粪堆上蓦然氏灵芝，鹊巢中生出鸾雏。", "显耀杀妾本云间住，光辉了君家淮甸居。", "恰才但有半点儿风声污，可不羞归西浙，耻向东吴。"]'),
('yuanqu-9703','荆楚臣重对玉梳记・一煞','贾仲明','元','元曲','yuanqu','','[]','肩厮并比翼鸟，腮厮贴比目鱼，手厮把合欢带，同心结连枝树。',76,'元曲/yuanqu.json','["肩厮并比翼鸟，腮厮贴比目鱼，手厮把合欢带，同心结连枝树。", "头厮磕低凋儿歌金缕，腿厮压高擎着倒玉壶。", "臂厮搂似并头莲在鸳帏宿，尽情儿颠鸾倒凤，尽兴儿弄粉抟酥。"]'),
('yuanqu-9704','荆楚臣重对玉梳记・煞尾','贾仲明','元','元曲','yuanqu','','[]','做男儿的除县宰称了心，为妻儿的号县君享受福。',53,'元曲/yuanqu.json','["做男儿的除县宰称了心，为妻儿的号县君享受福。", "则我这香名儿贯满松江府，我与那普天下猱儿每可都做的主。", "(下)。"]'),
('yuanqu-9705','荆楚臣重对玉梳记・双调/新水令','贾仲明','元','元曲','yuanqu','','[]','风尘中埋没了二十年，平空的唤县君有何颜面！告辞了春风歌宛转，夜月舞蹁跹。',98,'元曲/yuanqu.json','["风尘中埋没了二十年，平空的唤县君有何颜面！告辞了春风歌宛转，夜月舞蹁跹。", "俺如今福禄双全，稳拍拍的绿窗下做针线。", "(见科)(荆楚臣云)夫人，我想当初若非你赠我盘缠，进取功名，焉得有今日也？(正旦唱)。"]'),
('yuanqu-9706','荆楚臣重对玉梳记・驻马听','贾仲明','元','元曲','yuanqu','','[]','你如今位得荣迁，两行朱衣列马前。',78,'元曲/yuanqu.json','["你如今位得荣迁，两行朱衣列马前。", "当初你身虽贫贱，也曾一春常费买花钱。", "则我这节妇牌旌表在丽春园，更和你紫泥宣颁降到临川县。", "这的是心坚石也穿，喜鸳鸯双锁黄金殴。"]'),
('yuanqu-9707','荆楚臣重对玉梳记・落梅风','贾仲明','元','元曲','yuanqu','','[]','寻夫主真减志，盼京师不甚远。',66,'元曲/yuanqu.json','["寻夫主真减志，盼京师不甚远。", "飕飕把风霜亲践，脚竹踵是脚心世踏破的茧，(荆楚臣云)生受夫人。", "(正旦云)休道生受。", "(唱)便死呵死而无怨。"]'),
('yuanqu-9708','荆楚臣重对玉梳记・水仙子','贾仲明','元','元曲','yuanqu','','[]','你道我顾玉香是娇滴滴玉天仙，偏撞他柳盗跖恶哏哏做死冤。',103,'元曲/yuanqu.json','["你道我顾玉香是娇滴滴玉天仙，偏撞他柳盗跖恶哏哏做死冤。", "手持着明晃晃利刃如秋练，唬得我战钦钦魂灵儿飞半天。", "若不是你荆楚臣急忙忙剩到根前，将一个赤力力活擒拿，将一个喜孜孜生放免，怎能勾大和妇，美甘甘再得缠绵？。"]'),
('yuanqu-9709','荆楚臣重对玉梳记・甜水令','贾仲明','元','元曲','yuanqu','','[]','想着咱锦片前程，十分恩爱，百年姻眷，非今世是前缘。',52,'元曲/yuanqu.json','["想着咱锦片前程，十分恩爱，百年姻眷，非今世是前缘。", "问甚么首饰房奁，金珠镯钏，钗环头面。", "玉梳儿对勘的依然。"]'),
('yuanqu-9710','荆楚臣重对玉梳记・锦上花','贾仲明','元','元曲','yuanqu','','[]','当日在娟楼百般留恋，今日在琴堂受用无边。',40,'元曲/yuanqu.json','["当日在娟楼百般留恋，今日在琴堂受用无边。", "一个青春，一个少年；一个荣华，一个贵显。"]'),
('yuanqu-9711','荆楚臣重对玉梳记・幺篇','贾仲明','元','元曲','yuanqu','','[]','相公不负心，贱妾能酬愿，比目鸳鸯天生可羡。',41,'元曲/yuanqu.json','["相公不负心，贱妾能酬愿，比目鸳鸯天生可羡。", "百岁欢娱，两情缱绻；玉漏休残，金杯莫浅。"]'),
('yuanqu-9712','荆楚臣重对玉梳记・清江引','贾仲明','元','元曲','yuanqu','','[]','老鸨儿那个不爱钱？谁似你坐钱眼中间转。',46,'元曲/yuanqu.json','["老鸨儿那个不爱钱？谁似你坐钱眼中间转。", "只争他少共多，再不问良和贱，也还比他二十载绵花好过遣。"]'),
('yuanqu-9713','荆楚臣重对玉梳记・离亭宴煞','贾仲明','元','元曲','yuanqu','','[]','这里是阳春德泽桃花县，他怎肯将小民脂血做黄金辇，除了些月支的俸钱，无过是酒一尊琴三弄诗千卷。',100,'元曲/yuanqu.json','["这里是阳春德泽桃花县，他怎肯将小民脂血做黄金辇，除了些月支的俸钱，无过是酒一尊琴三弄诗千卷。", "说甚三媒六证财，再受你百计千方骗。", "俺如今也得个夫人位转，若早上了你歹王魁贩茶船，可不干赚了我俏苏卿一世里蹇。"]'),
('yuanqu-9714','张君瑞闹道场(第一本)・仙吕/赏花时','王实甫','元','元曲','yuanqu','','[]','夫主京师禄命终，子母孤孀途路穷；因此上旅榇在梵王宫。',41,'元曲/yuanqu.json','["夫主京师禄命终，子母孤孀途路穷；因此上旅榇在梵王宫。", "盼不到博陵旧冢，血泪洒杜鹃红。"]'),
('yuanqu-9715','张君瑞闹道场(第一本)・么篇','王实甫','元','元曲','yuanqu','','[]','可正是人值残春蒲郡东，门掩重关萧寺中；花落水流红，闲愁万种，无语怨东风。',41,'元曲/yuanqu.json','["可正是人值残春蒲郡东，门掩重关萧寺中；花落水流红，闲愁万种，无语怨东风。", "(并下)。"]'),
('yuanqu-9716','张君瑞闹道场(第一本)・仙吕/点绛唇','王实甫','元','元曲','yuanqu','','[]','游艺中原，脚根无线、如蓬转。',25,'元曲/yuanqu.json','["游艺中原，脚根无线、如蓬转。", "望眼连天，日近长安远。"]'),
('yuanqu-9717','张君瑞闹道场(第一本)・混江龙','王实甫','元','元曲','yuanqu','','[]','向诗书经传，蠹鱼似不出费钻研。',77,'元曲/yuanqu.json','["向诗书经传，蠹鱼似不出费钻研。", "将棘围守暖，把铁砚磨穿。", "投至得云路鹏程九万里，先受了雪窗萤火二十年。", "才高难入俗人机，时乖不遂男儿愿。", "空雕虫篆刻，缀断简残编。"]'),
('yuanqu-9718','张君瑞闹道场(第一本)・油葫芦','王实甫','元','元曲','yuanqu','','[]','九曲风涛何处显，则除是此地偏。',83,'元曲/yuanqu.json','["九曲风涛何处显，则除是此地偏。", "这河带齐梁，分秦晋，隘幽燕；雪浪拍长空，天际秋云卷；竹索缆浮桥，水上苍龙偃；东西溃九州，南北串百川。", "归舟紧不紧如何见？却便似弩箭乍离弦。"]'),
('yuanqu-9719','张君瑞闹道场(第一本)・天下乐','王实甫','元','元曲','yuanqu','','[]','只疑是银河落九天；渊泉、云外悬，入东洋不离此径穿。',49,'元曲/yuanqu.json','["只疑是银河落九天；渊泉、云外悬，入东洋不离此径穿。", "滋洛阳千种花，润梁园万顷田，也曾泛浮槎到日月边。"]'),
('yuanqu-9720','张君瑞闹道场(第一本)・村里迓鼓','王实甫','元','元曲','yuanqu','','[]','随喜了上方佛殿，早来到下方僧院。',108,'元曲/yuanqu.json','["随喜了上方佛殿，早来到下方僧院。", "行过厨房近西，法堂北，钟楼前面。", "游了洞房，登了宝塔，将回廊绕遍。", "数了罗汉，参了菩萨，拜了圣贤。", "(莺莺引红娘捻花枝上，云)红娘，俺去佛殿上耍去来。", "(末做见科)呀！正撞着五百年前风流业冤。"]'),
('yuanqu-9721','张君瑞闹道场(第一本)・上马娇','王实甫','元','元曲','yuanqu','','[]','这的是兜率宫，休猜做了离恨天。',45,'元曲/yuanqu.json','["这的是兜率宫，休猜做了离恨天。", "呀，谁想着寺里遇神仙！我见他宜嗔宜喜春风面，偏、宜贴翠花钿。"]'),
('yuanqu-9722','张君瑞闹道场(第一本)・胜葫芦','王实甫','元','元曲','yuanqu','','[]','则见他宫样眉儿新月偃，斜侵入鬓云边。',76,'元曲/yuanqu.json','["则见他宫样眉儿新月偃，斜侵入鬓云边。", "(旦云)红娘，你觑：寂寂僧房人不到，满阶苔衬落花红。", "(末云)我死也！未语人前先腼腆，樱桃红绽，玉粳白露，半响恰方言。"]'),
('yuanqu-9723','张君瑞闹道场(第一本)・幺篇','王实甫','元','元曲','yuanqu','','[]','恰便似呖呖莺声花外啭，行一步可人怜。',43,'元曲/yuanqu.json','["恰便似呖呖莺声花外啭，行一步可人怜。", "解舞腰肢娇又软，千般袅娜，万般旖旎，似垂柳晚风前。"]'),
('yuanqu-9724','张君瑞闹道场(第一本)・后庭花','王实甫','元','元曲','yuanqu','','[]','若不是衬残红，芳径软，怎显得步香尘底样儿浅。',98,'元曲/yuanqu.json','["若不是衬残红，芳径软，怎显得步香尘底样儿浅。", "且休题眼角儿留情处，则这脚踪儿将心事传。", "慢俄延，投至到栊门儿前面，刚挪了一步远。", "刚刚的打个照面，风魔了张解元。", "似神仙归洞天，空余下杨柳烟，只闻得鸟雀喧。"]'),
('yuanqu-9725','张君瑞闹道场(第一本)・柳叶儿','王实甫','元','元曲','yuanqu','','[]','呀，门掩着梨花深院，粉墙儿高似青天。',86,'元曲/yuanqu.json','["呀，门掩着梨花深院，粉墙儿高似青天。", "恨天，天不与人行方便，好着我难消遣，端的是怎留连。", "小姐呵，则被你兀的不引了人意马心猿？(聪云)休惹事，河中开府的小姐去远了也。", "(末唱)。"]'),
('yuanqu-9726','张君瑞闹道场(第一本)・赚煞','王实甫','元','元曲','yuanqu','','[]','饿眼望将穿，馋口涎空咽，空着我透骨髓相思病染，怎当他临去秋波那一转！休道是小生，便是铁石人也意惹情牵。',98,'元曲/yuanqu.json','["饿眼望将穿，馋口涎空咽，空着我透骨髓相思病染，怎当他临去秋波那一转！休道是小生，便是铁石人也意惹情牵。", "近庭轩，花柳争妍，日午当庭塔影圆。", "春光在眼前，争奈玉人不见，将一座梵王宫疑是武陵源。", "(并下)。"]'),
('yuanqu-9727','张君瑞闹道场(第一本)・中吕/粉蝶儿','王实甫','元','元曲','yuanqu','','[]','不做周方，埋怨杀你个法聪和尚！借与我半间儿客舍僧房，与我那可憎才居止处门儿相向。',61,'元曲/yuanqu.json','["不做周方，埋怨杀你个法聪和尚！借与我半间儿客舍僧房，与我那可憎才居止处门儿相向。", "虽不能够窃玉偷香，且将这盼行云眼睛儿打当。"]'),
('yuanqu-9728','张君瑞闹道场(第一本)・醉春风','王实甫','元','元曲','yuanqu','','[]','往常时见傅粉的委实羞，画眉的敢是谎;今日多情人一见了有情娘，着小生心儿里早痒、痒。',109,'元曲/yuanqu.json','["往常时见傅粉的委实羞，画眉的敢是谎;今日多情人一见了有情娘，着小生心儿里早痒、痒。", "迤逗得肠慌，断送得眼乱，引惹得心忙。", "(末见聪科)(聪云)师父正望先生来哩，只此少待，小僧通报去。", "(洁出见末科)(末云)是好一个和尚呵！。"]'),
('yuanqu-9729','张君瑞闹道场(第一本)・迎仙客','王实甫','元','元曲','yuanqu','','[]','我则见他头似雪，鬓如霜，面如童，少年得内养；貌堂堂，声朗朗，头直上只少个圆光。',50,'元曲/yuanqu.json','["我则见他头似雪，鬓如霜，面如童，少年得内养；貌堂堂，声朗朗，头直上只少个圆光。", "恰便似捏塑来的僧伽像。"]'),
('yuanqu-9730','张君瑞闹道场(第一本)・石榴花','王实甫','元','元曲','yuanqu','','[]','大师一一问行藏，小生仔细诉衷肠，自来西洛是吾乡，宦游在四方，寄居咸阳。',90,'元曲/yuanqu.json','["大师一一问行藏，小生仔细诉衷肠，自来西洛是吾乡，宦游在四方，寄居咸阳。", "先人拜礼部尚书多名望，五旬上因病身亡。", "(洁云)老相公弃世，必有所遗。", "(末唱)平生正直无偏向，止留下四海一空囊。"]'),
('yuanqu-9731','张君瑞闹道场(第一本)・上小楼','王实甫','元','元曲','yuanqu','','[]','小生特来见访，大师何须谦让。',167,'元曲/yuanqu.json','["小生特来见访，大师何须谦让。", "(洁云)老僧决不敢受，(末唱)这钱也难买柴薪，不够斋粮，且备茶汤。", "(觑聪云)这一两银末为厚礼。", "你若有主张，对艳妆，将言词说上，我将你众和尚死生难忘。", "(洁云)先生必有所请。", "(末云)小生不揣有恳，因恶旅邸冗杂，早晚难以温习经史；欲假一室，晨昏听讲。", "房金按月任意多少。", "(洁云)敝寺颇有数问，任先生拣选。", "(末唱)。"]'),
('yuanqu-9732','张君瑞闹道场(第一本)・幺篇','王实甫','元','元曲','yuanqu','','[]','也不要香积厨，枯木堂。',77,'元曲/yuanqu.json','["也不要香积厨，枯木堂。", "远着南轩，离着东墙，靠着西厢。", "近主廊，过耳房，都皆停当。", "(洁云)便不呵，就与老僧同处何如？(末笑云)要恁怎么。", "你是必休提着长老方丈。"]'),
('yuanqu-9733','张君瑞闹道场(第一本)・脱布衫','王实甫','元','元曲','yuanqu','','[]','大人家举止端详，全没那半点儿轻狂。',33,'元曲/yuanqu.json','["大人家举止端详，全没那半点儿轻狂。", "大师行深深拜了，启朱唇语言得当。"]'),
('yuanqu-9734','张君瑞闹道场(第一本)・小梁州','王实甫','元','元曲','yuanqu','','[]','可喜娘的庞儿浅淡妆，穿一套缟素衣裳；胡伶渌老不寻常，偷睛望，眼挫里抹张郎。',37,'元曲/yuanqu.json','["可喜娘的庞儿浅淡妆，穿一套缟素衣裳；胡伶渌老不寻常，偷睛望，眼挫里抹张郎。"]'),
('yuanqu-9735','张君瑞闹道场(第一本)・幺篇','王实甫','元','元曲','yuanqu','','[]','若共他多情的小姐同鸳帐。',45,'元曲/yuanqu.json','["若共他多情的小姐同鸳帐。", "怎舍得他叠被铺床。", "我将小姐央，夫人央，他不令许放，我亲门写与从良。"]'),
('yuanqu-9736','张君瑞闹道场(第一本)・快活三','王实甫','元','元曲','yuanqu','','[]','崔家女艳汝，莫不是演撒你个老洁郎？(洁云)俺出家人那有此事？(末唱)既不沙，却怎睃趁着你头上放毫光，打扮的特来晃。',57,'元曲/yuanqu.json','["崔家女艳汝，莫不是演撒你个老洁郎？(洁云)俺出家人那有此事？(末唱)既不沙，却怎睃趁着你头上放毫光，打扮的特来晃。"]'),
('yuanqu-9737','张君瑞闹道场(第一本)・四边静','王实甫','元','元曲','yuanqu','','[]','人间天上，看莺莺强如做道场。',41,'元曲/yuanqu.json','["人间天上，看莺莺强如做道场。", "软玉温香，休道是相亲傍；若能够荡他一荡，倒与人消灾障。"]'),
('yuanqu-9738','张君瑞闹道场(第一本)・耍孩儿','王实甫','元','元曲','yuanqu','','[]','当初那巫山远隔如天样，听说罢又在巫山那厢。',85,'元曲/yuanqu.json','["当初那巫山远隔如天样，听说罢又在巫山那厢。", "业身躯虽是立在回廊，魂灵儿巴在他行。", "本待要安排心事传幽客，我只怕漏泄春光与乃堂。", "夫人怕女孩儿春心荡，怪黄莺儿作对，怨粉蝶儿成双。"]'),
('yuanqu-9739','张君瑞闹道场(第一本)・五煞','王实甫','元','元曲','yuanqu','','[]','小姐年纪小，性气刚。',63,'元曲/yuanqu.json','["小姐年纪小，性气刚。", "张郎倘得相亲榜，乍相逢厌见何郎粉，看邂逅偷将韩寿香。", "才到得风流况，成就了会温存的娇婿，怕甚么能拘束的亲娘。"]'),
('yuanqu-9740','张君瑞闹道场(第一本)・四煞','王实甫','元','元曲','yuanqu','','[]','夫人忒虑过，小生空妄想，郎才女貌合相仿。',61,'元曲/yuanqu.json','["夫人忒虑过，小生空妄想，郎才女貌合相仿。", "休直待眉儿浅淡思张敞，春色飘零忆阮郎，非是咱自夸奖：他有德言工貌，小生有恭俭温良。"]'),
('yuanqu-9741','张君瑞闹道场(第一本)・三煞','王实甫','元','元曲','yuanqu','','[]','想着他眉儿浅浅描，脸儿淡淡妆，粉香腻玉搓咽项。',224,'元曲/yuanqu.json','["想着他眉儿浅浅描，脸儿淡淡妆，粉香腻玉搓咽项。", "翠裙鸳绣金莲小，红袖鸾销玉笋长。", "不想呵其实强：你撇下半天风韵，我拾得万种思量。", "却忘了辞长老。", "(见洁科)小生敢问长老，房舍如何？(洁云)塔院侧过西厢一间房，甚是潇洒，正可先生安下。", "现收拾下了，随先生早晚来。", "(末云)小生便回店中搬去。", "(洁云)吃斋了去。", "(末云)老僧收拾下斋，小生取行李便来。", "(洁云)既然如此，老僧准备下斋，先生是必便来。", "(下)(末云)若在店中人闹，倒好消遣；搬在寺中静处，怎么捱这凄凉也呵。"]'),
('yuanqu-9742','张君瑞闹道场(第一本)・二煞','王实甫','元','元曲','yuanqu','','[]','院宇深，枕簟凉，一灯孤影摇书幌。',58,'元曲/yuanqu.json','["院宇深，枕簟凉，一灯孤影摇书幌。", "纵然酬得今生志，着甚支吾此夜长。", "睡不着如翻掌，少可有一万声长吁短叹，五千遍捣枕槌床。"]'),
('yuanqu-9743','张君瑞闹道场(第一本)・尾','王实甫','元','元曲','yuanqu','','[]','娇羞花解语，温柔玉有香，我和他乍相逢记不真娇模样，我则索手低着牙儿慢慢的想。',42,'元曲/yuanqu.json','["娇羞花解语，温柔玉有香，我和他乍相逢记不真娇模样，我则索手低着牙儿慢慢的想。", "(下)。"]'),
('yuanqu-9744','张君瑞闹道场(第一本)・越调/斗鹌鹑','王实甫','元','元曲','yuanqu','','[]','玉宇无尘，银河泻影；月色横空，花阴满庭；罗袂生寒，芳心自警。',54,'元曲/yuanqu.json','["玉宇无尘，银河泻影；月色横空，花阴满庭；罗袂生寒，芳心自警。", "侧着耳朵儿听，蹑着脚步儿行，悄悄冥冥，潜潜等等。"]'),
('yuanqu-9745','张君瑞闹道场(第一本)・紫花儿序','王实甫','元','元曲','yuanqu','','[]','等待那齐齐整整，袅袅婷婷，姐姐莺莺。',69,'元曲/yuanqu.json','["等待那齐齐整整，袅袅婷婷，姐姐莺莺。", "一更之后，万籁无声，直至莺庭。", "若是回廊下没揣的见俺可憎，将他来紧紧的搂定；只问你那会少离多，有影无形。"]'),
('yuanqu-9746','张君瑞闹道场(第一本)・金蕉叶','王实甫','元','元曲','yuanqu','','[]','猛听得角门呀的一声，风过处花香细生。',141,'元曲/yuanqu.json','["猛听得角门呀的一声，风过处花香细生。", "踮着脚儿仔细定睛，比我那初见时庞儿越整。", "(旦云)红娘，移香桌儿近太湖石畔放者！(末做看科，云)料想着娇厌拘束，等闲飞出广寒宫。", "看他容分一捻，体露半襟，辨香袖以无言，垂罗裙而不语。", "似湘陵妃子，斜倚舜庙朱扉；如玉殿嫦娥，微观蟾宫素影。", "是好女子也呵！。"]'),
('yuanqu-9747','张君瑞闹道场(第一本)・调笑令','王实甫','元','元曲','yuanqu','','[]','我这里甫能，见娉婷，比着那月殿嫦娥也不恁般撑。',210,'元曲/yuanqu.json','["我这里甫能，见娉婷，比着那月殿嫦娥也不恁般撑。", "遮遮掩掩穿芳径，料应来小脚儿难行。", "可喜娘的脸儿百媚生，兀的不引子人魂灵。", "(旦云)取香来！(末云)听小姐祝告甚么？(旦云)此一炷香，愿化去先人，早生天界！此一柱香，愿中堂老母，身安无事！此一炷香，……(做不语科)(红云)姐姐不祝这一炷香，我替姐姐祝告：愿俺姐姐早寻一个姐夫，拖带红娘咱！(旦再拜云)心中无限伤心事，尽在深深两拜中。", "(长吁科)(末云)小姐倚栏长叹，似有动情之意。"]'),
('yuanqu-9748','张君瑞闹道场(第一本)・秃厮儿','王实甫','元','元曲','yuanqu','','[]','早是那脸儿上扑堆着可憎，那堪那心儿里埋没着聪明。',46,'元曲/yuanqu.json','["早是那脸儿上扑堆着可憎，那堪那心儿里埋没着聪明。", "他把那新诗和得忒应声，一字字，诉衷情，堪听。"]'),
('yuanqu-9749','张君瑞闹道场(第一本)・圣药王','王实甫','元','元曲','yuanqu','','[]','那语句清，抒律轻，小名儿不枉了唤做莺莺。',53,'元曲/yuanqu.json','["那语句清，抒律轻，小名儿不枉了唤做莺莺。", "他若是共小生、厮觑定，隔墙儿酬和到天明。", "方信道\"惺惺的自古惜惺惺。"]'),
('yuanqu-9750','张君瑞闹道场(第一本)・麻郎儿','王实甫','元','元曲','yuanqu','','[]','我拽起罗衫欲行，(旦做见科)他陪着笑脸儿相迎。',74,'元曲/yuanqu.json','["我拽起罗衫欲行，(旦做见科)他陪着笑脸儿相迎。", "(红云)姐姐，有人，咱家去来，怕夫人嗔着。", "(莺回顾下)(末唱)不做美的红娘太浅情，便做道\"谨依来命\"。"]'),
('yuanqu-9751','张君瑞闹道场(第一本)・幺篇','王实甫','元','元曲','yuanqu','','[]','我忽听、一声、猛惊。',53,'元曲/yuanqu.json','["我忽听、一声、猛惊。", "原来是扑剌刺宿鸟飞腾，颤巍巍花梢弄影，乱纷纷落红满径。", "小姐，你去了呵，那里发付小生！。"]'),
('yuanqu-9752','张君瑞闹道场(第一本)・络丝娘','王实甫','元','元曲','yuanqu','','[]','空撇下碧澄澄苍苔露冷，明皎皎花筛月影。',35,'元曲/yuanqu.json','["空撇下碧澄澄苍苔露冷，明皎皎花筛月影。", "白日凄凉枉耽病，今夜把相思再整。"]'),
('yuanqu-9753','张君瑞闹道场(第一本)・绵搭絮','王实甫','元','元曲','yuanqu','','[]','恰寻归路，伫立空庭，竹梢风摆，斗柄云横。',57,'元曲/yuanqu.json','["恰寻归路，伫立空庭，竹梢风摆，斗柄云横。", "呀！今夜凄凉有四星，他不瞅人待怎生！虽然是眼角儿传情，咱两个口不言心自省。"]'),
('yuanqu-9754','张君瑞闹道场(第一本)・拙鲁速','王实甫','元','元曲','yuanqu','','[]','对着盏碧萤萤短檠灯，倚着扇冷清清旧帏屏。',82,'元曲/yuanqu.json','["对着盏碧萤萤短檠灯，倚着扇冷清清旧帏屏。", "灯儿又不明，梦儿又不成；窗儿外淅零零的风儿透疏棂，忒楞楞的纸条儿鸣；枕头儿上孤另，被窝儿坐寂静。", "你便是铁石人，铁石人也动情。"]'),
('yuanqu-9755','张君瑞闹道场(第一本)・幺篇','王实甫','元','元曲','yuanqu','','[]','怨不能，恨不成，坐不安，睡不宁。',68,'元曲/yuanqu.json','["怨不能，恨不成，坐不安，睡不宁。", "有一日柳遮花映，雾帐云屏，夜阑人静，海誓山盟。", "恁时节风流嘉庆，锦片也似前程，美满恩情，咱两个画堂春自生。"]'),
('yuanqu-9756','张君瑞闹道场(第一本)・尾','王实甫','元','元曲','yuanqu','','[]','一天好事从今定，一首诗分明照证；再不向青琐闼梦儿中寻，则去那碧桃花树儿下等。',42,'元曲/yuanqu.json','["一天好事从今定，一首诗分明照证；再不向青琐闼梦儿中寻，则去那碧桃花树儿下等。", "(下)。"]'),
('yuanqu-9757','张君瑞闹道场(第一本)・双调/新水令','王实甫','元','元曲','yuanqu','','[]','梵王宫殿月轮高，碧琉璃瑞烟笼罩。',40,'元曲/yuanqu.json','["梵王宫殿月轮高，碧琉璃瑞烟笼罩。", "香烟云盖结，讽咒海波潮。", "幡影飘遥，诸檀越尽来到。"]'),
('yuanqu-9758','张君瑞闹道场(第一本)・驻马听','王实甫','元','元曲','yuanqu','','[]','法鼓金铎，二月春雷响殿角；钟声佛号，半天风雨洒松梢。',98,'元曲/yuanqu.json','["法鼓金铎，二月春雷响殿角；钟声佛号，半天风雨洒松梢。", "侯门不许老僧敲，纱窗外定有红娘报。", "害相思的馋眼脑，见他时须看个十分饱。", "(末见洁科)(洁云)先生先拈香，恐夫人问呵，则说是老僧的亲，(末拈香科)。"]'),
('yuanqu-9759','张君瑞闹道场(第一本)・雁儿落','王实甫','元','元曲','yuanqu','','[]','我则道这玉天仙离了碧霄，原来是可意种来清醮。',39,'元曲/yuanqu.json','["我则道这玉天仙离了碧霄，原来是可意种来清醮。", "小子多愁多病身，怎当他倾国倾城貌。"]'),
('yuanqu-9760','张君瑞闹道场(第一本)・得胜令','王实甫','元','元曲','yuanqu','','[]','恰便似檀口点樱桃，粉鼻儿倚琼瑶，淡白梨花面，轻盈杨柳腰。',48,'元曲/yuanqu.json','["恰便似檀口点樱桃，粉鼻儿倚琼瑶，淡白梨花面，轻盈杨柳腰。", "妖娆，满面儿扑堆着俏；苗条，一团儿是娇。"]'),
('yuanqu-9761','张君瑞闹道场(第一本)・甜水令','王实甫','元','元曲','yuanqu','','[]','老的小的，村的俏的，没颠没倒，胜似闹元宵。',44,'元曲/yuanqu.json','["老的小的，村的俏的，没颠没倒，胜似闹元宵。", "稔色人儿，可意冤家，怕人知道，看时节泪眼偷瞧。"]'),
('yuanqu-9762','张君瑞闹道场(第一本)・折桂令','王实甫','元','元曲','yuanqu','','[]','着小生迷留没乱，心痒难挠。',86,'元曲/yuanqu.json','["着小生迷留没乱，心痒难挠。", "哭声儿似莺啭乔林，泪珠儿似露滴花梢。", "大师也难学，把一个发慈悲的脸儿来朦着，击磬的头陀懊恼，添香的行者心焦。", "烛影风摇，香霭云飘；贪着莺莺，烛灭香消。"]'),
('yuanqu-9763','张君瑞闹道场(第一本)・锦上花','王实甫','元','元曲','yuanqu','','[]','外像儿风流，青春年少；内性儿聪明，冠世才学。',43,'元曲/yuanqu.json','["外像儿风流，青春年少；内性儿聪明，冠世才学。", "扭捏着身子儿百般做作，米往向人前卖弄俊俏。"]'),
('yuanqu-9764','张君瑞闹道场(第一本)・幺篇','王实甫','元','元曲','yuanqu','','[]','黄昏这一回，白日那一觉，窗儿外那会镬铎。',42,'元曲/yuanqu.json','["黄昏这一回，白日那一觉，窗儿外那会镬铎。", "到晚来向书帏里比及睡着，千万声长吁怎捱到晓。"]'),
('yuanqu-9765','张君瑞闹道场(第一本)・碧玉箫','王实甫','元','元曲','yuanqu','','[]','情引眉梢，心绪你知道；愁种心苗，情思我猜着。',51,'元曲/yuanqu.json','["情引眉梢，心绪你知道；愁种心苗，情思我猜着。", "畅懊恼！响铛铛云板敲。", "行者又嚎，沙弥又哨，您须不夺人之好。"]'),
('yuanqu-9766','张君瑞闹道场(第一本)・鸳鸯煞','王实甫','元','元曲','yuanqu','','[]','有心争似无心好，多情却被无情恼。',78,'元曲/yuanqu.json','["有心争似无心好，多情却被无情恼。", "劳攘了一宵，月儿沈，钟儿响，鸡儿叫。", "畅道是玉人归去得疾，好事收拾得早，道场毕诸人散了。", "酩子里各归家，葫芦提闹到晓。", "(并下)。"]'),
('yuanqu-9767','张君瑞闹道场(第一本)・络丝娘煞尾','王实甫','元','元曲','yuanqu','','[]','则为你闭月羞花相貌，少不得剪草除根大小。',20,'元曲/yuanqu.json','["则为你闭月羞花相貌，少不得剪草除根大小。"]'),
('yuanqu-9768','正宫・塞鸿秋浔阳即景','周德清','元','元曲','yuanqu','','[]','长江万里白如练，淮山数点青如淀。',104,'元曲/yuanqu.json','["长江万里白如练，淮山数点青如淀。", "江帆几片疾如箭，山泉千尺飞如电。", "晚云都变露，新月初学扇，塞鸿一字来如线。", "灞桥雪拥驴难跨，剡溪水冻船难驾；秦楼美酝添高价，陶家风味都闲话。", "羊羔饮兴佳，金帐歌声罢，醉魂不到蓝关下。"]'),
('yuanqu-9769','中吕・朝天子秋夜客怀','周德清','元','元曲','yuanqu','','[]','月光，桂香，趁着风飘荡。',112,'元曲/yuanqu.json','["月光，桂香，趁着风飘荡。", "砧声催动一天霜，过雁声嘹亮；叫起离情，敲残愁况，梦家山身异乡。", "夜凉，枕凉，不许愁人强。", "书所见鬓鸦，脸霞，屈杀将陪嫁；规模全是大人家，不在红娘下。", "笑眼偷瞧，文谈回话，真如解语花。", "若咱，得他，倒了葡萄架。"]'),
('yuanqu-9770','中吕・满庭芳看岳王传','周德清','元','元曲','yuanqu','','[]','披文握武，建中兴庙宇，载青史图书。',278,'元曲/yuanqu.json','["披文握武，建中兴庙宇，载青史图书。", "功成却被权臣妒，正落奸谋。", "闪杀人望旌节中原士夫，误杀人弃丘陵南渡銮舆！钱塘路，愁风怨雨，长是洒西湖！韩世忠安危属君，立勤王志节，比翊汉功勋。", "临机料敌存威信，际会风云。", "似恁地尽忠勇匡君报本，也消得坐都堂秉笏垂绅。", "闲评论，中兴宰臣，万古揖清芬！误国贼秦桧官居极品，欺天误主，贱土轻民。", "把一场和议为公论，妒害功臣。", "通贼虏怀奸诳君，那些儿立朝堂仗义依仁？英雄恨，使飞云幸存，那里有南北二朝分？张俊谋渊略广，论兵用武，立国安邦。", "佐中兴一代贤明将，怎生来险幸如狼？蓄祸心奸私放党，附权臣构陷忠良。", "朝堂上，把一个精忠岳王，屈死葬钱塘！。"]'),
('yuanqu-9771','越调・天净沙嘲歌者茶茶','周德清','元','元曲','yuanqu','','[]','根窠生长灵芽，旗枪搠立烟花，不许冯魁串瓦。',71,'元曲/yuanqu.json','["根窠生长灵芽，旗枪搠立烟花，不许冯魁串瓦。", "休抬高价，小舟来贩茶茶。", "舟阻女儿港庐山面已难寻，孤山鞋不曾沉，掩面留鞋意深。", "不知因甚，女儿港到如今。"]'),
('yuanqu-9772','越调・柳营曲冬夜怀友','周德清','元','元曲','yuanqu','','[]','暮云收，冷风飕，到中宵月来清更幽。',216,'元曲/yuanqu.json','["暮云收，冷风飕，到中宵月来清更幽。", "倚遍江楼，望断汀洲，雪月照人愁。", "舍梅花谁是交游？饮松醪自想期俦。", "王子猷干罢手，戴安道且蒙头。", "休，谁驾剡溪舟？别友一叶身，二毛人，功名壮怀犹未伸。", "夜雨论文，明月伤神，秋色淡离樽。", "离东君桃李侯门，过西风杨柳渔村。", "酒船同棹月，诗担自挑云。", "君，孤雁不堪听！有所思燕子来，海棠开，西厢尚愁音信乖。", "问柳章台，采药天台，归去却伤怀，恰嗔人踏破苍苔，不知他行出瑶阶。", "见刚刚三寸迹，想窄窄一双鞋。", "猜，多早晚到书斋？。"]'),
('yuanqu-9773','双调・蟾宫曲送客之武昌','周德清','元','元曲','yuanqu','','[]','折垂杨都是残枝，诗满银笺，酒劝金卮。',277,'元曲/yuanqu.json','["折垂杨都是残枝，诗满银笺，酒劝金卮。", "自在庐山，君游鄂渚，两地相思。", "白鹿洞谁谈旧史？黄鹤楼又有新诗。", "拈断吟髭，笑把霜毫，满写乌丝。", "别友唾珠玑点破湖光，千变云霞，一字文章。", "吴楚东南，江山雄壮，诗酒疏狂。", "正鸡黍樽前月朗，又鲈莼江上风凉！记取他乡，落日观山，夜雨连床。", "宰金头黑脚天鹅，客有钟期，座有韩娥。", "吟既能吟，听还能听，歌也能歌。", "和《白雪》新来较可，放行云飞去如何？醉睹银河，灿灿蟾孤，点点星多。", "倚蓬窗无语嗟呀，七件儿全无，做甚么人家？柴似灵芝，油如甘露，米若丹砂。", "酱瓮儿恰才梦撒，盐瓶儿又告消乏。", "茶也无多。", "醋也无多，七件事尚且艰难，怎生教我折柳攀花？套数。"]'),
('yuanqu-9774','南吕・一枝花遗张伯元','周德清','元','元曲','yuanqu','','[]','正伯牙志未谐，遇钟子心能解。',59,'元曲/yuanqu.json','["正伯牙志未谐，遇钟子心能解。", "使高山群虎啸，要流水老龙哀。", "洒落襟怀，一笑乾坤大，高谈云雾开。", "几行北雁吞声，一片西山失色。"]'),
('yuanqu-9775','梁州・无人我惊心句险，有江山空日烟埋。相逢尽是他乡客。我淹吴楚，','周德清','元','元曲','yuanqu','','[]','君显江淮。',87,'元曲/yuanqu.json','["君显江淮。", "雄游海宇，挺出人材。", "箕裘事业合该，簪缨苗裔传来。", "大胸襟进履圯桥壮游。", "玩乘槎大海，老风波走马章台。", "千载，后代，子孙更风流煞！万一见此豪迈。", "玉有润难明借月色，出落吾侪。"]'),
('yuanqu-9776','隔尾・向管中窥豹那知外？坐井底观天又出来。运斧般门志何大！出削个','周德清','元','元曲','yuanqu','','[]','好歹，但成个架格，未敢望将如栋梁采。',18,'元曲/yuanqu.json','["好歹，但成个架格，未敢望将如栋梁采。"]'),
('yuanqu-9777','越调・斗鹌鹑双陆','周德清','元','元曲','yuanqu','','[]','四角盘中，三十骑里，多少机关？包藏见识。',48,'元曲/yuanqu.json','["四角盘中，三十骑里，多少机关？包藏见识。", "席上风前，花间树底。", "起斗刚，各论智。", "盘样新奇，声清韵美。"]'),
('yuanqu-9778','紫花儿・月儿对浑如水照，夕儿花有若云生，点儿疏恰似星稀。马儿齐摆','周德清','元','元曲','yuanqu','','[]','下，色儿大休掷。',42,'元曲/yuanqu.json','["下，色儿大休掷。", "会拈色的便宜，更递马双行休倒提。", "虽凭色难同使力，递有高低，要识迟疾。"]'),
('yuanqu-9779','天净沙・盘中排营寨城池，眼前无弓箭旌旗，心内有刀枪剑戟。局面儿几','周德清','元','元曲','yuanqu','','[]','般形势，似英雄征战相持。',12,'元曲/yuanqu.json','["般形势，似英雄征战相持。"]'),
('yuanqu-9780','小桃红・散二似萧何追韩言待回归，众军士傍观立。散三似敬德赶秦王不','周德清','元','元曲','yuanqu','','[]','相离，有叔宝后跟随。',50,'元曲/yuanqu.json','["相离，有叔宝后跟随。", "百一局似关云长独赴单刀会，败到这其间有几？赢了的百中无一，输了的似楚霸王刎江湄。"]'),
('yuanqu-9781','三台印・两家局安营地，施谋智，似挑军对垒。等破绽用心机，色儿似飞','周德清','元','元曲','yuanqu','','[]','沙走石。',38,'元曲/yuanqu.json','["沙走石。", "汉高皇对敌楚项籍，诸葛亮要擒司马懿。", "那两个地割鸿沟，这两个兵屯渭水。"]'),
('yuanqu-9782','金蕉叶・撤底似孙膑伏兵未起，外划似孙武挑兵教习。五梁似吕望兵临孟','周德清','元','元曲','yuanqu','','[]','水，六梁似吕布遭围下邳。',12,'元曲/yuanqu.json','["水，六梁似吕布遭围下邳。"]'),
('yuanqu-9783','含笑花・暗疾，函谷孟尝归，不下鸿门樊哙急。失家如误了吴元济，点颏','周德清','元','元曲','yuanqu','','[]','如跳溪刘备。',23,'元曲/yuanqu.json','["如跳溪刘备。", "无梁如火烧曹孟德，撞门如拒水张飞。"]'),
('yuanqu-9784','小拜门・把门似临潼会里，{坫瓦}颏如细柳军围，看诸葛纵擒蜀孟获。两','周德清','元','元曲','yuanqu','','[]','下里，马来回，堪题。',10,'元曲/yuanqu.json','["下里，马来回，堪题。"]'),
('yuanqu-9785','圣药王・等一掷，心暗喜，并合梁恨不的马都回。恰四六十，又三四七，','周德清','元','元曲','yuanqu','','[]','更幺三一二紧相随，心急马行迟。',15,'元曲/yuanqu.json','["更幺三一二紧相随，心急马行迟。"]'),
('yuanqu-9786','幺・贩了迟，却变疾，头颏卷尽可伤悲。色不随，梁不齐；不甫能打的个','周德清','元','元曲','yuanqu','','[]','马儿回，他一马走如飞。',11,'元曲/yuanqu.json','["马儿回，他一马走如飞。"]'),
('yuanqu-9787','幺・若论迟，有甚奇，破着呵不打枉驱驰！怕两帖子救一，道两马可当十，','周德清','元','元曲','yuanqu','','[]','巴到家不得马休题，更有截七带去的。',17,'元曲/yuanqu.json','["巴到家不得马休题，更有截七带去的。"]'),
('yuanqu-9788','麻郎儿・到此际人难强嘴，空打的马不停蹄。色不顺那堪性急，焦起来更','周德清','元','元曲','yuanqu','','[]','加错递。',4,'元曲/yuanqu.json','["加错递。"]'),
('yuanqu-9790','络丝娘・怕的是盖着门{坫瓦}着颏又起，村的是把着马揭着头盖底。采到','周德清','元','元曲','yuanqu','','[]','后喝着的都应的，也随邪顺着人意。',16,'元曲/yuanqu.json','["后喝着的都应的，也随邪顺着人意。"]'),
('yuanqu-9791','紫花儿・却是红如鹤顶，赤若鸡冠，白似羊脂。是望月犀牛独自，是穿花','周德清','元','元曲','yuanqu','','[]','鸾凤雄雌。',46,'元曲/yuanqu.json','["鸾凤雄雌。", "是兔儿灵芝，是螭虎是翎毛是鹭鸶。", "是海青拿天鹅不是？我则是想像因而，你敢那就里知之。"]'),
('yuanqu-9792','小沙门・别是个玲珑样子，另生成剔透心儿，为风流尽教拈断髭。不负我，','周德清','元','元曲','yuanqu','','[]','赠新诗、新词。',7,'元曲/yuanqu.json','["赠新诗、新词。"]'),
('yuanqu-9793','圣药王・重玩视，巧意思，羽毛枝干细如丝。温润资，雕琢时，那其间应','周德清','元','元曲','yuanqu','','[]','是辨妍媸，必定是明师！。',12,'元曲/yuanqu.json','["是辨妍媸，必定是明师！。"]'),
('yuanqu-9795','虎牢关三战吕布・仙吕/点绛唇','郑光祖','元','元曲','yuanqu','','[]','每日家赤闲门闲，虎躯慵懒。',94,'元曲/yuanqu.json','["每日家赤闲门闲，虎躯慵懒。", "(关末云)兄弟，俺颇攻遁甲之书，久后必有大用也。", "(正末唱)攻书晚，厮琅琅顿剑摇环。", "(关末云)兄弟，便好道奋发有时，休得心困也(正末唱)哥也，兀的不屈沉杀俺英雄汉。"]'),
('yuanqu-9796','虎牢关三战吕布・油葫芦','郑光祖','元','元曲','yuanqu','','[]','少不的一事无成两鬓斑，恁时节后悔晚。',192,'元曲/yuanqu.json','["少不的一事无成两鬓斑，恁时节后悔晚。", "(关末云)我想这为官的，不如闲居倒好也。", "(正末唱)做甚早算来名利不如闲？(刘末云)兄弟，俺如何去的也？(正末唱)大哥哥你不肯将男子功名干，(关末云)俺又不会兵书战策，断然不敢去也。", "(正末唱)二哥哥你枉将《左传春秋》看。", "(关末云)依着兄弟主意如何？(正末唱)我则待恶战在杀场军阵中，您则待高卧在竹篱茅舍间。", "似恁的几年间梦见周公旦？您则待要睡彻日三竿。"]'),
('yuanqu-9797','虎牢关三战吕布・那吒令','郑光祖','元','元曲','yuanqu','','[]','不是这个张冀德，我觑吕温侯似等闲;(关末云)他使一枝方天画杆戟，好生利害也。',146,'元曲/yuanqu.json','["不是这个张冀德，我觑吕温侯似等闲;(关末云)他使一枝方天画杆戟，好生利害也。", "(正末唱)则我这条丈八矛，将方天戟来小看。", "(关末云)骑一匹卷毛赤兔马，好生奔劣也。", "(正末唱)跨下这匹豹月乌，不剌刺把赤兔马来当翻。", "(刘末云)破吕布凭着你些甚么那？(正末唱)凭着我这捉将手、挟人惯，两条臂有似的这栏关。"]'),
('yuanqu-9798','虎牢关三战吕布・鹊踏枝','郑光祖','元','元曲','yuanqu','','[]','上阵处磕搭的攥住狮蛮，交马处滴溜扑摔下雕鞍。',115,'元曲/yuanqu.json','["上阵处磕搭的攥住狮蛮，交马处滴溜扑摔下雕鞍。", "直杀的他败将投降战马空还，败残军将追也那后赶，他每可都撇漾了些金鼓旗幡。", "(曹操云)玄德公，您这里有多少人马？报个总数来。", "(刘末云)量刘备官小职微，那里得那人马来？并然去不的也(正末唱)。"]'),
('yuanqu-9799','虎牢关三战吕布・寄生草','郑光祖','元','元曲','yuanqu','','[]','俺这里衙门静，活计艰，每月家俸钱刚把他这家私办。',91,'元曲/yuanqu.json','["俺这里衙门静，活计艰，每月家俸钱刚把他这家私办。", "除公田又无甚别积趱，都是些个擎鞭执帽关西汉。", "(曹操云)破吕布可用多少人马？(正末唱)战吕布轻弓短箭俺三人，哥也何消的锦衣绣袄军十万！。"]'),
('yuanqu-9800','虎牢关三战吕布・河西后庭花','郑光祖','元','元曲','yuanqu','','[]','哥也我题起那斯杀呵也不打悭，天生的忒奈烦。',70,'元曲/yuanqu.json','["哥也我题起那斯杀呵也不打悭，天生的忒奈烦。", "我则待渴饮刀头血，困来在这马上眠。", "要活的呵将那厮臂牢拴，要死的呵将那厮天灵来打烂，两庄儿由元帅拣。"]'),
('yuanqu-9801','虎牢关三战吕布・尾声','郑光祖','元','元曲','yuanqu','','[]','十载武夫闲，九得兵书看。',159,'元曲/yuanqu.json','["十载武夫闲，九得兵书看。", "八卦阵如同等闲，七禁令将军我小看。", "六丁神不许将我遮拦，者么是五云间，四壁银山，三姓家奴恁意儿反。", "(关末云)兄弟，想吕布十分英勇，又有八健将，则怕你难敌么？(正末唱)二哥哥你休将我小看，凭着我这一生得村汉。", "(关末云)兄弟也，两阵之间，你可怎生交马也？(正末唱)我可敢半空中滴溜扑番过那一座虎牢关。"]'),
('yuanqu-9802','虎牢关三战吕布・驻马听','郑光祖','元','元曲','yuanqu','','[]','我可甚么高枕无忧？空抄定拽硬弓搠长枪阿呸我这对捉将手。',120,'元曲/yuanqu.json','["我可甚么高枕无忧？空抄定拽硬弓搠长枪阿呸我这对捉将手。", "我可是么低头来切肉？怒睁开我这辨风云别气色这一对杀人眸。", "大哥哥羞惭替他羞，二哥哥受苦甘心受。", "我则怕掉下一个树叶儿来呵我则怕倒打破您那头，(云)长沙太守孙坚！(唱)怎么来早是非只为多开口。"]'),
('yuanqu-9803','虎牢关三战吕布・雁儿落','郑光祖','元','元曲','yuanqu','','[]','往常我观云间乌兔走，今日个看地下蚍蜉斗。',45,'元曲/yuanqu.json','["往常我观云间乌兔走，今日个看地下蚍蜉斗。", "姜太公渭水河边执着钓钩，今日个轮到俺辕门外打鼻钮。"]'),
('yuanqu-9804','虎牢关三战吕布・得胜令','郑光祖','元','元曲','yuanqu','','[]','哥也更兀则这里怎敢不低头？似恁的几时得到摘星楼？别人去省部里标了名姓，哥也赤紧的俺县衙甲无甚解忧。',289,'元曲/yuanqu.json','["哥也更兀则这里怎敢不低头？似恁的几时得到摘星楼？别人去省部里标了名姓，哥也赤紧的俺县衙甲无甚解忧。", "(刘末云)但得个大小官职也罢。", "(正末唱)但得个知州，也是我不待屈不能勾。", "(刘末云)哎约！哎约！(正末唱)哎约屈的我冷汗便似浇流。", "(云)刘、关、张弟兄三人，破一百万黄巾贼，临了在辕门外与别人打躬。", "(唱)我可甚么男儿得志秋！(卒子云)平身。", "可不早说。", "喏！报的元帅得知，吕布索战。", "(孙坚云)我肚里疼了。", "(正末云)哥也，走了马也。", "(刘末云)在那里？(正末见孙坚科，云)喏，我医元帅肚里疼也！(孙坚云)你要医我的病，好个丑太医！你有甚么名方妙药，治我的病？你试说一遍，我试听咱。", "(正末唱)。"]'),
('yuanqu-9805','虎牢关三战吕布・仙吕/赏花时','郑光祖','元','元曲','yuanqu','','[]','你那厮丁建阳身亡可也不驾车，去你那董卓跟前深唱喏。',122,'元曲/yuanqu.json','["你那厮丁建阳身亡可也不驾车，去你那董卓跟前深唱喏。", "(杨奉云)老叔，你去便去，通名显姓咱。", "(正末唱)我是您吕布的第三个爷爷。", "(杨奉云)可知道吕布利害哩，他还有这么一个老子哩！你姓甚名谁？(正末唱)张飞可便是也。", "到来日儿出马可兀的搦您爹爹。", "(下)。"]'),
('yuanqu-9806','虎牢关三战吕布・中吕/粉蝶儿','郑光祖','元','元曲','yuanqu','','[]','又不敢东转西移，守着那甲杖库也不似这般费心劳力，将元帅那护身符在意收者。',67,'元曲/yuanqu.json','["又不敢东转西移，守着那甲杖库也不似这般费心劳力，将元帅那护身符在意收者。", "猛然间，才听罢，三通鼓擂，猛可里观窥，我看那孙太守气也那不气。"]'),
('yuanqu-9807','虎牢关三战吕布・醉春风','郑光祖','元','元曲','yuanqu','','[]','恼的我恶向胆边生，不由我怒从心上起。',77,'元曲/yuanqu.json','["恼的我恶向胆边生，不由我怒从心上起。", "(云)我不恼他别，(唱)自从那早晨间打躬到日平西。", "孙坚那里取这个礼，礼！道不的个千战千赢、百发百中，他则落的一人一骑。"]'),
('yuanqu-9808','虎牢关三战吕布・石榴花','郑光祖','元','元曲','yuanqu','','[]','则听的数声寒角一似老龙悲，扑冬冬的征鼙鼓响似震天雷。',195,'元曲/yuanqu.json','["则听的数声寒角一似老龙悲，扑冬冬的征鼙鼓响似震天雷。", "(孙坚云)你可瞧见我那一会儿传令，怎么支拨人马来？(正末唱)马军步军鞭梢一点雁行齐，各排着阵势，呐喊摇旗。", "(孙坚云)吕布出马，教我就敌住他了。", "(正末唱)则见吕温侯勒马垓心内，来、来、来不怕死的与吾两个相持。", "见元帅你不剌刺纵马到垓心内，您两个不答话便相持。", "(孙坚云)那一会恼哩，答甚么话！恨不的一刀抓了他首级哩。", "看来那厢也慌了。", "(正末唱)。"]'),
('yuanqu-9809','虎牢关三战吕布・斗鹌鹑','郑光祖','元','元曲','yuanqu','','[]','元帅闪霍霍刀晃动银盖朱缨，吕温侯赤力力戟摆动那金钱豹尾。',295,'元曲/yuanqu.json','["元帅闪霍霍刀晃动银盖朱缨，吕温侯赤力力戟摆动那金钱豹尾。", "(孙坚云)早则还是我的刀哩，才敌住他的戟，第二个也输在他手里了。", "(正末唱)元帅将刀刃斜钐。", "(云)那吕布见刀来，出的躲来。", "(唱)他将那戟尖戟尖来便刺。", "(孙坚云)俺两个揪住袍，攥住带，就交成一团，打做一块。", "怎么肯放了他，饶了他？饶蝎子的娘哩！(正末唱)你两个一来一往一上一下有似飞。", "见元帅打闹哩。", "(云)一个道：\"休来赶，休来赶！\"(唱)你可暗暗的私奔。", "(云)那吕布道：\"住者！\"(唱)脑背后高声可便叫起。", "(孙坚云)参谋使，你可不曾见那厮杀，两匹马滚在一处，我要下马出恭，百忙里拴了个关门镫绊住脚，急的我要不的。", "他叫我做甚么来？(正末唱)。"]'),
('yuanqu-9810','虎牢关三战吕布・幺篇','郑光祖','元','元曲','yuanqu','','[]','恰离了军阵中，早来到林琅里。',168,'元曲/yuanqu.json','["恰离了军阵中，早来到林琅里。", "可又早解开擐带，松开戎装，脱下征衣。", "吕温侯他纵玉勒，再赶到，十里田地。", "(孙坚云)这个是我使的计来。", "(正末云)你那计，(唱)厮杀不到两三合脱的赤条条的。", "(孙坚云)这厮好无礼也，着言语讥讽我。", "你是一个掠阵使，别人都报了功也，你这早晚才来，你有什么功劳？(正末云)张飞有功劳来。", "(孙坚云)有什么功劳来？(正末唱)。"]'),
('yuanqu-9811','虎牢关三战吕布・满庭芳','郑光祖','元','元曲','yuanqu','','[]','昨宵晚夕，长空淡淡，凉月辉辉，张屯来往巡绰拿住个奸细，手中将着几件东西。',226,'元曲/yuanqu.json','["昨宵晚夕，长空淡淡，凉月辉辉，张屯来往巡绰拿住个奸细，手中将着几件东西。", "(孙坚云)莫不是两事家使的枪刀剑戟么？(正末唱)也不是两事家使的枪刀剑戟。", "(孙坚云)可是甚么那？(正末云)左右将来！(做将衣甲丢在当面科，唱)那一个诸侯王的这衣甲头盔。", "(孙坚云)哎哟，嗨！一个好先生，买命算卦，说我不合破财，果然今日还送将来了。", "(正末唱)唬的他一个呆痴的。", "(云)元帅你不道来，(唱)快将你那儿郎准备。", "(云)这衣袍铠甲，被别人夺将去了。", "(唱)这的是你那人和着凯歌回。"]'),
('yuanqu-9812','虎牢关三战吕布・耍孩儿','郑光祖','元','元曲','yuanqu','','[]','我道来我道来。',78,'元曲/yuanqu.json','["我道来我道来。", "不是我说强嘴说强嘴，则我这点钢枪分付在那厮鼻凹里。", "遮截架解难投奔，则我这刺搠签创枪法疾。", "我是个好厮杀的天魔祟，从虎者应无善兽，好斗者必遇强敌。"]'),
('yuanqu-9813','虎牢关三战吕布・尾声','郑光祖','元','元曲','yuanqu','','[]','说与那交辽王吕奉先。',69,'元曲/yuanqu.json','["说与那交辽王吕奉先。", "正撞见英雄张翼德。", "跨下这匹豹月乌，不剌刺便荡番赤兔追风骑。", "则我这丈八矛，咭叮生扛折那厮方天画杆戟。", "(同刘末、关末下)。"]'),
('yuanqu-9814','虎牢关三战吕布・正宫/端正好','郑光祖','元','元曲','yuanqu','','[]','今日个奉圣敕战温侯，驱士马擒贼将，俺弟兄每尽忠尽志气昂昂。',97,'元曲/yuanqu.json','["今日个奉圣敕战温侯，驱士马擒贼将，俺弟兄每尽忠尽志气昂昂。", "(刘末云)三兄弟今日战退吕布，肃靖边关，俺保社稷之坚固，立家邦之永昌，方显大将之能也。", "(正末唱)俺将这汉朝社稷重开创，显耀处八面威风像。"]'),
('yuanqu-9815','虎牢关三战吕布・滚绣球','郑光祖','元','元曲','yuanqu','','[]','则这个张翼德性气刚，(刘末云)俺二兄弟云长，勇烈刚强也。',533,'元曲/yuanqu.json','["则这个张翼德性气刚，(刘末云)俺二兄弟云长，勇烈刚强也。", "(正末唱)更和这关云长武艺强。", "(刘末云)这一场征战，皆托二兄弟之威也。", "(正末唱)若不是刘玄德一冲一撞，俺端的逞英雄恶战在杀场。", "(刘末云)那吕布恃强独霸，搅扰中原，威镇于虎牢关下，仗八健将之勇猛，谁想今日大败亏输，力不能敌也。", "(正末唱)逼的个吕温侯逃命荒，八健将已中伤，杀的那败残军尽皆失丧。", "(刘末云)俺杀的那吕温侯倒戈卸甲，血染黄沙。", "这场大战，非同小可也。", "(正末唱)恰便似卧麻般撇漾了些剑戟刀枪。", "杀的他冠斜獬豸将军败，血染征袍马带伤。", "四海名扬。", "(云)可早来到辕门首也。", "左右接了马者。", "小校报复去，道有刘、关、张弟兄三人，得胜而回也。", "(卒子云)报的元帅得知，有刘关张弟兄三人，得胜而回也。", "(袁绍云)道有请。", "(卒子云)理会的。", "有请。", "(见科)(刘末云)元帅，想刘备才德俱薄，兵微将寡，托赖圣人洪福、元帅之威，方得战退吕布也。", "(袁绍云)据玄德公声播寰区，名传海字，得胜英杰，才超俊士，况其二弟相扶，譬如猛虎，加之羽翼。", "因贼子反乱中原，四海之民，受其残暴，杀败十八路诸侯，拱手而伏，无能拒御。", "谁想三位将军，到于牢关，汗马之劳，战退了吕布，以解圣主之忧，救苍生涂炭之苦。", "今主上大喜，命某在此帅府，封官赐赏。", "这一场非同小可也。"]'),
('yuanqu-9816','虎牢关三战吕布・倘秀才','郑光祖','元','元曲','yuanqu','','[]','托赖着圣明工宽洪大量，二来是十八路诸侯伎俩。',159,'元曲/yuanqu.json','["托赖着圣明工宽洪大量，二来是十八路诸侯伎俩。", "因此上耀武扬威托上苍。", "(袁绍云)此一场上答天心，下合人意，以此上剿除贼众也。", "(正末唱)这的是天心顺，国荣吕，平除了寇党。", "(袁绍云)您弟兄三人，在那虎牢关，怎生角声助战，画鼓添威，排兵布阵，调遣三军，战退温侯，剿除贼党，有劳三将略说一遍咱。", "(正)末云试听张飞说一遍咱。", "(唱)。"]'),
('yuanqu-9817','虎牢关三战吕布・脱布衫','郑光祖','元','元曲','yuanqu','','[]','虎牢关排军校杀气飘扬，鸣金鼓声震穹苍。',89,'元曲/yuanqu.json','["虎牢关排军校杀气飘扬，鸣金鼓声震穹苍。", "(袁绍云)门旗开处，玄德公使的是那一般兵器？(正末唱)大哥哥双股剑实难措手，(袁绍云)云长公用那一般器械来？(正末唱)二哥哥三停刀怎生遮当。"]'),
('yuanqu-9818','虎牢关三战吕布・小梁州','郑光祖','元','元曲','yuanqu','','[]','张飞我跃马横担丈八枪，舞梨花搅海翻江。',65,'元曲/yuanqu.json','["张飞我跃马横担丈八枪，舞梨花搅海翻江。", "(袁绍云)吕布可怎生对敌来？(正末唱)吕温侯方天画戟怎提防，杀的他无归向。", "今日个一阵定兴亡。"]'),
('yuanqu-9819','虎牢关三战吕布・幺篇','郑光祖','元','元曲','yuanqu','','[]','今日个中原清静升平像，保山河臣宰贤良。',98,'元曲/yuanqu.json','["今日个中原清静升平像，保山河臣宰贤良。", "(袁绍云)您弟兄三人，有如此大功，正当食君之禄也。", "(正末唱)怎消的禄位迁，加俺为边庭将。", "(袁绍云)今日共享太平之福也。", "(正末唱)端的是太平之世，愿圣寿水无疆。"]'),
('yuanqu-9820','闺怨佳人拜月亭・仙吕/赏花时','关汉卿','元','元曲','yuanqu','','[]','卷地狂风吹塞沙，映日疏林啼暮鸦。',35,'元曲/yuanqu.json','["卷地狂风吹塞沙，映日疏林啼暮鸦。", "满满的捧流霞，相留得半霎，咫尺隔天涯。"]'),
('yuanqu-9821','闺怨佳人拜月亭・幺篇','关汉卿','元','元曲','yuanqu','','[]','行色一鞭催瘦马。',59,'元曲/yuanqu.json','["行色一鞭催瘦马。", "（孤云了）（正旦唱）你直待白骨中原如卧麻。", "虽是这战伐，负着个天摧地塌，是必想着俺子母每早来家。", "（下）。"]'),
('yuanqu-9822','闺怨佳人拜月亭・仙吕/点烽唇','关汉卿','元','元曲','yuanqu','','[]','锦绣华夷，忽从西北天兵起。',27,'元曲/yuanqu.json','["锦绣华夷，忽从西北天兵起。", "觑那关口城池，马到处成平地。"]'),
('yuanqu-9823','闺怨佳人拜月亭・混江龙','关汉卿','元','元曲','yuanqu','','[]','许来大中都城内，各家烦恼各家知。',96,'元曲/yuanqu.json','["许来大中都城内，各家烦恼各家知。", "且说君臣分散，想俺父子别离。", "遥想着尊父东行何日还？又随着车驾、车驾南迁甚日回？（夫人云了）（正旦做嗟叹科）这青湛湛碧悠悠天也知人意，早是秋风飒飒，可更暮雨凄凄。"]'),
('yuanqu-9824','闺怨佳人拜月亭・天下乐','关汉卿','元','元曲','yuanqu','','[]','阿者，你这般没乱慌张到得那里？（夫人云了）（做意了）兀的般云低、天欲黑，至近的道店十数里。',71,'元曲/yuanqu.json','["阿者，你这般没乱慌张到得那里？（夫人云了）（做意了）兀的般云低、天欲黑，至近的道店十数里。", "上面风雨，下面泥水，阿者，慢慢的枉步，显的你没气力。"]'),
('yuanqu-9825','闺怨佳人拜月亭・金盏儿','关汉卿','元','元曲','yuanqu','','[]','您昆仲各东西，俺子母两分离。',94,'元曲/yuanqu.json','["您昆仲各东西，俺子母两分离。", "怕哥哥不嫌相辱呵，权为个妹；（末云了）（寻思了）哥哥道做：军中男女若相随，有儿夫的不掳掠，无家长的落便宜。", "（做意了）这般者波，怕不问时权做弟兄，问着后道做夫妻。"]'),
('yuanqu-9826','闺怨佳人拜月亭・醉扶归','关汉卿','元','元曲','yuanqu','','[]','你道您"祖上亲文墨，昆仲晓书集，从上流传直到你，辈辈儿都及第"。',88,'元曲/yuanqu.json','["你道您\"祖上亲文墨，昆仲晓书集，从上流传直到你，辈辈儿都及第\"。", "您端的是姑舅也那叔伯也那两姨，偏怎生养下这个贼兄弟？（外末云了）（末云了）哥哥你有此心，莫不错寻思了么？（唱）。"]'),
('yuanqu-9827','闺怨佳人拜月亭・金盏儿','关汉卿','元','元曲','yuanqu','','[]','你心里把褐衲袄脊梁上披，强似着紫朝衣，论盆家饮酒压着诗词会。',73,'元曲/yuanqu.json','["你心里把褐衲袄脊梁上披，强似着紫朝衣，论盆家饮酒压着诗词会。", "嫌这攀蟾折桂做官迟，为那笔尖上发禄晚，见这刀刃上变钱疾。", "你也待风高学放火，月黑做强贼。"]'),
('yuanqu-9828','闺怨佳人拜月亭・赚尾','关汉卿','元','元曲','yuanqu','','[]','然是弟兄心，殷勤意。',112,'元曲/yuanqu.json','["然是弟兄心，殷勤意。", "本酒量窄推辞少吃，乐意开怀虽恁地，也省可里不记东西。", "（做扶着末科）（做寻思科）呵！我自思忆，想我那从你的行为，被这地乱天翻教我做不的伶俐。", "假妆些厮收厮拾，佯做个一家一计，且着这脱身术瞒过这打家贼。", "（下）。"]'),
('yuanqu-9829','闺怨佳人拜月亭・南吕/一枝花','关汉卿','元','元曲','yuanqu','','[]','干戈动地来，横祸事从天降：爷娘三不归，家国一时亡。',60,'元曲/yuanqu.json','["干戈动地来，横祸事从天降：爷娘三不归，家国一时亡。", "龙斗来鱼伤，情愿受消疏况。", "怎生般不应当，脱着衣裳，感得这些天行好缠仗。"]'),
('yuanqu-9830','闺怨佳人拜月亭・梁州','关汉卿','元','元曲','yuanqu','','[]','恰似悒悒的锥挑太阳，忽忽的火燎胸膛。',159,'元曲/yuanqu.json','["恰似悒悒的锥挑太阳，忽忽的火燎胸膛。", "身沉体重难回项，口干舌涩，声重言狂。", "可又别无使数，难请街坊，则我独自一个婆娘，与他无明夜过药煎汤。", "呵！早是俺两口儿背井离乡！口应！则怏他一路上荡风打浪，嗨！谁想他百忙里卧枕着床。", "内伤、外伤，怕不待倾心吐胆尽筋竭力把个牙推请；则怕小处尽是打当。", "只愿的依本分伤家没变症，慢慢的传受阴阳。"]'),
('yuanqu-9831','闺怨佳人拜月亭・牧羊关','关汉卿','元','元曲','yuanqu','','[]','这大夫好调理，的是诊候的强，这的十中九敢药病相当。',72,'元曲/yuanqu.json','["这大夫好调理，的是诊候的强，这的十中九敢药病相当。", "阿的是五夜其高，六日向上，解利呵过了时晌，下过呵正是时光。", "不用那百解通神散，教吃这三一承气汤。"]'),
('yuanqu-9832','闺怨佳人拜月亭・贺新郎','关汉卿','元','元曲','yuanqu','','[]','自从都下对尊堂，走马离朝，阿马间别无恙？（孤认了）则恁的犹自常思想，可更随车驾南迁汴梁；教俺去住无门、徊徨，家缘都撇漾，人口尽逃亡，闪的俺一双子母每无归向。',100,'元曲/yuanqu.json','["自从都下对尊堂，走马离朝，阿马间别无恙？（孤认了）则恁的犹自常思想，可更随车驾南迁汴梁；教俺去住无门、徊徨，家缘都撇漾，人口尽逃亡，闪的俺一双子母每无归向。", "自从身体上一朝出帝辇，俺这梦魂无夜不辽阳！。"]'),
('yuanqu-9833','闺怨佳人拜月亭・牧羊关','关汉卿','元','元曲','yuanqu','','[]','您孩儿无挨靠，没倚仗，深得他本人将傍。',76,'元曲/yuanqu.json','["您孩儿无挨靠，没倚仗，深得他本人将傍。", "（孤云了）（做意了）当日目下有身亡，眼前是杀场。", "刀剑明晃晃，士马闹荒荒；那其间这锦绣红妆女，那里觅个银鞍白面郎？。"]'),
('yuanqu-9834','闺怨佳人拜月亭・哭皇天','关汉卿','元','元曲','yuanqu','','[]','教了数个贼汉把我相侵傍，阿马想波，这恩临怎地忘？闪的他活支沙三不归，强教俺生各扎两分张。',161,'元曲/yuanqu.json','["教了数个贼汉把我相侵傍，阿马想波，这恩临怎地忘？闪的他活支沙三不归，强教俺生各扎两分张。", "觑着兀的般着床卧枕，叫唤声疼，撇在他个没人的店房！常言道：相逐百步，尚有徘徊。", "你怎生便教我眼睁睁的不问当？（做分付末了）男儿呵！如今俺父亲将我去也，你好生的觑当你身起！（末云了）（做艰难科）男儿，兀的是俺亲爷的恶党，休把您这妻儿怨畅。"]'),
('yuanqu-9835','闺怨佳人拜月亭・乌夜啼','关汉卿','元','元曲','yuanqu','','[]','天那！一霎儿把这世间愁都撮在我眉尖上，这场愁不许堤防。',100,'元曲/yuanqu.json','["天那！一霎儿把这世间愁都撮在我眉尖上，这场愁不许堤防。", "（末云了）既相别此语伊休忘：怕你那换脉交阳，是必省可里掀扬。", "俺这风雹乱下的紫袍郎。", "不识你个云雷未至的白衣相。", "咱这片霎中如天祥，一时哽咽，两处凄凉。"]'),
('yuanqu-9836','闺怨佳人拜月亭・收尾','关汉卿','元','元曲','yuanqu','','[]','休想我为翠屏红烛流苏帐，撇了你这黄卷青灯映雪窗。',103,'元曲/yuanqu.json','["休想我为翠屏红烛流苏帐，撇了你这黄卷青灯映雪窗。", "（孤云了）（末云了）（打别了）（嘱咐末科）你心间莫昏忘，你心间索记当：我言词更无妄，不须伊再审详。", "咱兀的做夫妻三个月时光，你莫不曾见您这歹浑家说个谎？（下）。"]'),
('yuanqu-9837','闺怨佳人拜月亭・正宫/端正好','关汉卿','元','元曲','yuanqu','','[]','我想那受官厅，读书舍，谁不曾虎困龙蛰？（带云）信着我父亲呵，世间人把丹桂都休折，留着手把雕弓拽。',48,'元曲/yuanqu.json','["我想那受官厅，读书舍，谁不曾虎困龙蛰？（带云）信着我父亲呵，世间人把丹桂都休折，留着手把雕弓拽。"]'),
('yuanqu-9838','闺怨佳人拜月亭・滚绣球','关汉卿','元','元曲','yuanqu','','[]','俺这个背晦爷，听的把古书说，他便恶忿忿的脑裂，粗豪的今古皆绝。',88,'元曲/yuanqu.json','["俺这个背晦爷，听的把古书说，他便恶忿忿的脑裂，粗豪的今古皆绝。", "您这些富产业，更怕我顾恋情惹，俺向那笔尖上自挣扎得些豪奢。", "搠起柄夫荣妇贵三檐伞，抵多少爷饭娘羹驷马车！两件儿浑别。"]'),
('yuanqu-9839','闺怨佳人拜月亭・倘秀才','关汉卿','元','元曲','yuanqu','','[]','休着个滥名儿将咱来引惹。',92,'元曲/yuanqu.json','["休着个滥名儿将咱来引惹。", "口应！待不你个小鬼头春心儿动也！（小旦云了）放心，放心。", "我与你宽打周遭向父亲行说。", "（小旦云了）你不要呵，我要则么那？（小旦云了）我又不风欠，不痴呆，要则甚迭！。"]'),
('yuanqu-9840','闺怨佳人拜月亭・笑和尚','关汉卿','元','元曲','yuanqu','','[]','韵悠悠比及把角品绝，碧荧荧投至那灯儿灭，薄设设衾共枕空舒设；冷清清不恁迭，闲遥遥生枝节，闷恹恹怎捱他如年夜！。',55,'元曲/yuanqu.json','["韵悠悠比及把角品绝，碧荧荧投至那灯儿灭，薄设设衾共枕空舒设；冷清清不恁迭，闲遥遥生枝节，闷恹恹怎捱他如年夜！。"]'),
('yuanqu-9841','闺怨佳人拜月亭・倘秀才','关汉卿','元','元曲','yuanqu','','[]','来波？我怨感、我合哽咽，不刺！你啼哭你为甚迭？（小旦云了）你莫不元是俺男儿的旧妻妾？阿是，阿是，当时只争个字儿别，我错呵了应者！。',65,'元曲/yuanqu.json','["来波？我怨感、我合哽咽，不刺！你啼哭你为甚迭？（小旦云了）你莫不元是俺男儿的旧妻妾？阿是，阿是，当时只争个字儿别，我错呵了应者！。"]'),
('yuanqu-9842','闺怨佳人拜月亭・呆骨朵','关汉卿','元','元曲','yuanqu','','[]','似恁的呵！咱从今后越索着疼热，休想似在先时节。',90,'元曲/yuanqu.json','["似恁的呵！咱从今后越索着疼热，休想似在先时节。", "你又是我妹妹、姑姑，我又是你嫂嫂、姐姐。", "（小旦云了）这般者，俺父母多宗派，您昆仲无枝叶；从今后休从俺爷娘家根脚排，只做俺儿夫家亲眷者。"]'),
('yuanqu-9843','闺怨佳人拜月亭・二煞','关汉卿','元','元曲','yuanqu','','[]','则就那里先肝肠眉黛千干结，烟水云山万万叠。',83,'元曲/yuanqu.json','["则就那里先肝肠眉黛千干结，烟水云山万万叠。", "他便似烈焰飘风，劣心卒性，怎禁那后拥前推、乱棒胡枷！呵，谁无个老父？谁无个尊君？谁无个亲爷？从头儿看来，都不似俺那狠爹爹！。"]'),
('yuanqu-9844','闺怨佳人拜月亭・尾','关汉卿','元','元曲','yuanqu','','[]','他把世间毒害收拾彻，我将天下忧愁结缆绝。',121,'元曲/yuanqu.json','["他把世间毒害收拾彻，我将天下忧愁结缆绝。", "（小旦云了）没盘缠，在店舍，有谁人，厮抬贴？那消疏，那凄切，生分离，厮抛撇。", "从相别，恁时节，音书无，信息绝。", "我这些时眼跳腮红耳轮热，眠梦交杂不宁贴。", "您哥哥暑湿风寒纵较些，多被那烦恼忧愁上送了也！（下）。"]'),
('yuanqu-9845','闺怨佳人拜月亭・双调/新水令','关汉卿','元','元曲','yuanqu','','[]','我眼悬悬整盼了一周年，你也枉把您这不自由的姐姐来埋怨。',59,'元曲/yuanqu.json','["我眼悬悬整盼了一周年，你也枉把您这不自由的姐姐来埋怨。", "恰才投至我贴上这缕金钿，一霎儿向镜台旁边，媒人每催逼了我两三遍。"]'),
('yuanqu-9846','闺怨佳人拜月亭・驻马听','关汉卿','元','元曲','yuanqu','','[]','你贪着个断简残编，恭俭温良好缱绻；我贪着个轻弓短箭。',90,'元曲/yuanqu.json','["你贪着个断简残编，恭俭温良好缱绻；我贪着个轻弓短箭。", "粗豪勇猛恶因缘。", "（小旦云了）可知煞是也。", "您的管梦回酒醒诵诗篇，俺的敢灯昏人静夸征战；少不的向我绣帏边，说的些碜可可落得的冤魂现。"]'),
('yuanqu-9847','闺怨佳人拜月亭・庆东原','关汉卿','元','元曲','yuanqu','','[]','他则图今生贵，岂问咱夙世缘？违着孩儿心，只要遂他家愿。',64,'元曲/yuanqu.json','["他则图今生贵，岂问咱夙世缘？违着孩儿心，只要遂他家愿。", "则怕他夫妻百年，招了这文武两员，他家里要将相双权。", "不顾自家嫌，则要旁人羡。"]'),
('yuanqu-9848','闺怨佳人拜月亭・镇江回','关汉卿','元','元曲','yuanqu','','[]','俺兀那姊妹儿的新郎又忒腼腆；俺这新女婿那嘲掀，瞅的我两三番斜避了新妆面，查查胡胡的向玳筵前，知他俺那主婚人是见也那不见？（孤云了）（外末把盏科）（正旦唱）。',78,'元曲/yuanqu.json','["俺兀那姊妹儿的新郎又忒腼腆；俺这新女婿那嘲掀，瞅的我两三番斜避了新妆面，查查胡胡的向玳筵前，知他俺那主婚人是见也那不见？（孤云了）（外末把盏科）（正旦唱）。"]'),
('yuanqu-9849','闺怨佳人拜月亭・步步娇','关汉卿','元','元曲','yuanqu','','[]','见他那鸭子绿衣服上圈金线，这打扮早难坐琼林宴。',68,'元曲/yuanqu.json','["见他那鸭子绿衣服上圈金线，这打扮早难坐琼林宴。", "俺这新状元，早难道花压得乌纱帽檐偏。", "把这盏许亲酒又不敢慢俄延，则索扭回头半口儿家刚刚的咽。"]'),
('yuanqu-9850','闺怨佳人拜月亭・雁儿落','关汉卿','元','元曲','yuanqu','','[]','你而今病疾儿都较痊？你而今身体儿全康健？当初咱那埚儿各间别，怎承望这搭儿里重相见！。',42,'元曲/yuanqu.json','["你而今病疾儿都较痊？你而今身体儿全康健？当初咱那埚儿各间别，怎承望这搭儿里重相见！。"]'),
('yuanqu-9851','闺怨佳人拜月亭・水仙子','关汉卿','元','元曲','yuanqu','','[]','今日这半边鸾镜得团圆，早则那一纸鱼封不更传。',98,'元曲/yuanqu.json','["今日这半边鸾镜得团圆，早则那一纸鱼封不更传。", "（末云了）你说这话！（做意了）须是俺狠毒爷强匹配我成婚眷。", "不刺，可是谁央及你个蒋状元，一投得官也接了丝鞭！我常把伊思念，你不将人挂恋，亏心的上有青天！。"]'),
('yuanqu-9852','闺怨佳人拜月亭・胡十八','关汉卿','元','元曲','yuanqu','','[]','我便浑身上都是口，待教我怎分辨？枉了我情脉脉、恨绵绵！我昼忘饮馔夜无眠，则兀那瑞莲便是证见；怕你不信后，没人处问一遍。',191,'元曲/yuanqu.json','["我便浑身上都是口，待教我怎分辨？枉了我情脉脉、恨绵绵！我昼忘饮馔夜无眠，则兀那瑞莲便是证见；怕你不信后，没人处问一遍。", "（末云了）兀的不是您妹子瑞莲那！（末共小旦打认了）（告孤科）（末云了）（老夫人云了）（老孤云了）你试问您那兄弟去；我劝和您姊妹去。", "（正末云了）（小旦云了）妹子，我和您哥哥厮认得了也！你却招取兀那武举状元呵，如何？（小旦云了）你便信我则么那！（小旦云了）（正旦唱）。"]'),
('yuanqu-9853','闺怨佳人拜月亭・挂玉钩','关汉卿','元','元曲','yuanqu','','[]','二百口家属语笑喧，如此般深宅院；休信我一时间狂口言，便那里有冤魂现！（小旦云了）我特故里说的别，包弹遍；不嫌些蹬弯开弓，怎说他袒臂挥拳。',68,'元曲/yuanqu.json','["二百口家属语笑喧，如此般深宅院；休信我一时间狂口言，便那里有冤魂现！（小旦云了）我特故里说的别，包弹遍；不嫌些蹬弯开弓，怎说他袒臂挥拳。"]'),
('yuanqu-9854','闺怨佳人拜月亭・乔牌儿','关汉卿','元','元曲','yuanqu','','[]','兀的须显出我那不乐愿，量这的有甚难见？每日我绿窗前不整闲针线，不曾将眉黛展。',38,'元曲/yuanqu.json','["兀的须显出我那不乐愿，量这的有甚难见？每日我绿窗前不整闲针线，不曾将眉黛展。"]'),
('yuanqu-9855','闺怨佳人拜月亭・夜行船','关汉卿','元','元曲','yuanqu','','[]','须是我心上斜横着这美少年，你可别无甚闷缕愁牵。',45,'元曲/yuanqu.json','["须是我心上斜横着这美少年，你可别无甚闷缕愁牵。", "便坐驷马高车，管着满门良贱，但出入唾盂掌扇。"]'),
('yuanqu-9856','闺怨佳人拜月亭・幺篇','关汉卿','元','元曲','yuanqu','','[]','但行处两行朱衣列马前，等个文章士发禄是何年？你想那陋巷颜渊，箪瓢原宪，你又不是不曾受秀才的贫贱！。',49,'元曲/yuanqu.json','["但行处两行朱衣列马前，等个文章士发禄是何年？你想那陋巷颜渊，箪瓢原宪，你又不是不曾受秀才的贫贱！。"]'),
('yuanqu-9857','闺怨佳人拜月亭・沽美酒','关汉卿','元','元曲','yuanqu','','[]','骤将他职位迁，中京内作行院，把虎头金牌腰内悬；见那金花诰帝宣，没因由得要团圆。',39,'元曲/yuanqu.json','["骤将他职位迁，中京内作行院，把虎头金牌腰内悬；见那金花诰帝宣，没因由得要团圆。"]'),
('yuanqu-9858','闺怨佳人拜月亭・太平令','关汉卿','元','元曲','yuanqu','','[]','咱却且尽教佯呆着休劝，请夫人更等三年。',56,'元曲/yuanqu.json','["咱却且尽教佯呆着休劝，请夫人更等三年。", "你既爱青灯黄卷，却不要随机而变，把你这眼前、厌倦、物件，分付与他别人请佃。"]'),
('yuanqu-9859','中吕・喜春来过普天乐','赵岩','元','元曲','yuanqu','','[]','琉璃殿暖香浮细，翡翠帘深卷燕迟，夕阳芳草小亭西。',122,'元曲/yuanqu.json','["琉璃殿暖香浮细，翡翠帘深卷燕迟，夕阳芳草小亭西。", "间纳履，见十二个粉蝶儿飞。", "一个恋花心，一个搀春意。", "一个翩翻粉翅，一个乱点罗衣。", "一个掠草飞，一个穿帘戏。", "一个赶过杨花西园里睡，一个与游人步步相随。", "一个拍散晚烟，一个贪欢嫩蕊，那一个与祝英台梦里为期。"]'),
('yuanqu-9860','幺・世事谙博看，人情冷暧谁经惯？风帽与尘寰，遍朱门白眼相看。腹内','董君瑞','元','元曲','yuanqu','','[]','闲，五车经典，七步文章。',67,'元曲/yuanqu.json','["闲，五车经典，七步文章。", "到处难兴贩，半纸虚名薄官。", "飘零吴越，梦觉邯郸。", "碧天凤翼未曾附，苍海龙鳞几时攀。", "困此穷途，进退无门，似羝羊触藩。"]'),
('yuanqu-9861','耍孩儿・待向人前开口实羞赧，折腰处拳拳意懒。这回不免向君前，曲弓','董君瑞','元','元曲','yuanqu','','[]','弓冒突台颜。',41,'元曲/yuanqu.json','["弓冒突台颜。", "故来海上垂钩线，特向津头执钓竿，有意相侵犯。", "将你个高门谄媚，小子相干。"]'),
('yuanqu-9862','六煞・知君廉俭犹清干，据头角轩昂见罕。即非面谕厮过从，将明公焉敢','董君瑞','元','元曲','yuanqu','','[]','相残？岂不知甜言与我三冬暧，恶语伤人六月寒？你是多少人称赞，道你量如江海，器若丘山。',42,'元曲/yuanqu.json','["相残？岂不知甜言与我三冬暧，恶语伤人六月寒？你是多少人称赞，道你量如江海，器若丘山。"]'),
('yuanqu-9863','五・也不索闲言赞，冷句儿攒，快疾做取英雄汉。扫除乞俭分开吝，倚阁','董君瑞','元','元曲','yuanqu','','[]','酸寒打破悭。',22,'元曲/yuanqu.json','["酸寒打破悭。", "忙迭办，俺巷来近远，怎地回还？。"]'),
('yuanqu-9864','四・你是明白与，俺索子细拣，怕有挑剜接补并糜烂。至元折脑通行少，','董君瑞','元','元曲','yuanqu','','[]','中统糖心倒换难。',26,'元曲/yuanqu.json','["中统糖心倒换难。", "翻复从头看，则要完全贯伯，分晓边阑。"]'),
('yuanqu-9865','三・你要寻走衮，觅转关，上天掇看梯儿赶。襟厮封头发牢结定，额厮拶','董君瑞','元','元曲','yuanqu','','[]','眉毛紧厮拴。',29,'元曲/yuanqu.json','["眉毛紧厮拴。", "厮蘸定权休散，坐时同坐，<走山>后齐<走山>。"]'),
('yuanqu-9866','二・你又奔，俺又顽，则要紧无格迸松无慢。皮锅里炒爆铜豌豆，火炕上','董君瑞','元','元曲','yuanqu','','[]','叠翻铁卧单。',20,'元曲/yuanqu.json','["叠翻铁卧单。", "无辞惮，天生性耐，不喜心烦。"]'),
('yuanqu-9867','一・谩把猾，枉占奸，布衫领安上难寻绽。头巾顶攒就宜新裹，钅敖子饼','董君瑞','元','元曲','yuanqu','','[]','热时赶热翻。',25,'元曲/yuanqu.json','["热时赶热翻。", "消息汤着犯，你便辘轳井口，直打的泉干。"]'),
('yuanqu-9869','双调・锦上花春游','张碧山','元','元曲','yuanqu','','[]','燕语莺啼，和风迟日。',87,'元曲/yuanqu.json','["燕语莺啼，和风迟日。", "郊外踏青，禁烟寒食。", "拜扫人家，这壁共那壁。", "悲喜交杂，哭的共笑的。", "坟前列子孙，冢上卧狐狸。", "几处荒坟，半全共半毁。", "几陌银钱，半灰共半泥。", "几个相知，半人共半鬼。"]'),
('yuanqu-9870','清江引・见了也泪淹衫袖湿，这的是傍州例。黄金少甚藏，白酒须当醉，','张碧山','元','元曲','yuanqu','','[]','浇奠杀九泉无半米。',9,'元曲/yuanqu.json','["浇奠杀九泉无半米。"]'),
('yuanqu-9871','碧玉箫・寒暑相催，日月率风疾。名利驱驰，车辄涌潮退。省可里着气力，','张碧山','元','元曲','yuanqu','','[]','休则管里耽是非。',35,'元曲/yuanqu.json','["休则管里耽是非。", "饱暖肚皮，留取元阳真气。", "将一伙儿鼓笛，选一答儿清闲地。"]'),
('yuanqu-9872','尾声・摆一个齐整欢筵会，做一段笑乐新杂剧。杂剧要旦末双全，筵席要','张碧山','元','元曲','yuanqu','','[]','水陆俱备。',42,'元曲/yuanqu.json','["水陆俱备。", "唱道趁着这美景良辰，请几个达时务英雄辈。", "劝你这知已的相识，知知不知在于你。"]'),
('yuanqu-9873','黄钟・人月圆伤心莫问前朝事，重上越王台。鹧鸪啼处，东风草绿，残照','倪瓒','元','元曲','yuanqu','','[]','花开。',92,'元曲/yuanqu.json','["花开。", "怅然孤啸，青山故国，乔木苍苔。", "当时明月，依依素影，何处飞来？惊回一枕当年梦，渔唱起南津。", "画屏云嶂，池塘春草，无限销魂。", "旧家应在，梧桐覆井，杨柳藏门。", "闲身空老，孤篷听雨，灯火江村。"]'),
('yuanqu-9874','双调・折桂令拟张鸣善','倪瓒','元','元曲','yuanqu','','[]','草茫茫秦汉陵阙，世代兴亡，却便似月影圆缺。',148,'元曲/yuanqu.json','["草茫茫秦汉陵阙，世代兴亡，却便似月影圆缺。", "山人家堆案图书，当窗松桂，满地薇蕨。", "侯门深何须刺谒，白云自可怡悦。", "到如今世事难说，天地间不见一个英雄，不见一个豪杰。", "辛亥过陆庄片帆轻水远山长，鸿雁将来，菊蕊初黄。", "碧海鲸鲵，兰苕翡翠，风露鸳鸯。", "问音信何人谛当，想情怀旧日风光。", "杨柳池塘，随处凋零，无限思量。"]'),
('yuanqu-9875','锦云堂暗定连环计・仙吕/点绛唇','无名氏','元','元曲','yuanqu','','[]','俺可也虚度春秋，强捱昏昼。',29,'元曲/yuanqu.json','["俺可也虚度春秋，强捱昏昼。", "空生受，肥马轻裘，为甚事担消瘦。"]'),
('yuanqu-9876','锦云堂暗定连环计・混江龙','无名氏','元','元曲','yuanqu','','[]','则为这汉家宇宙，好着俺两条眉锁庙廊愁。',98,'元曲/yuanqu.json','["则为这汉家宇宙，好着俺两条眉锁庙廊愁。", "恰便似花开值雨，怎的个叶落归秋。", "俺只问鸳鹭班中怎容的诸盗贼，麒麟阁上是画的甚公侯。", "做官时都气勃勃待超前，立功处早退怯怯甘居后。", "若得他一人定国，也不枉万代名留。"]'),
('yuanqu-9877','锦云堂暗定连环计・油葫芦','无名氏','元','元曲','yuanqu','','[]','想当日楚汉兴兵争战秋。',193,'元曲/yuanqu.json','["想当日楚汉兴兵争战秋。", "君与臣犹未剖，他也曾中分天下指鸿沟。", "(杨彪云)既然中分天下，怎独是我汉朝成其工业，流传四百余年，这都谁人之力也？(正末唱)这其间多亏了张子房说地谈天口，韩元帅握雾拿云手。", "那一个能战敌，那一个善计谋。", "他把千年基业扶持就，端的是分破帝王忧。", "(杨彪云)如今董卓专权，威振中外。", "想起当日各处诸侯，勒兵百万，在于虎牢关下，不曾得他一根折箭。", "似此强横，如何剿除也。", "(正末唱)。"]'),
('yuanqu-9878','锦云堂暗定连环计・天下乐','无名氏','元','元曲','yuanqu','','[]','我则怕烦恼皆因强出头，想十八路诸也波侯，题起来满面羞。',102,'元曲/yuanqu.json','["我则怕烦恼皆因强出头，想十八路诸也波侯，题起来满面羞。", "(杨彪云)若不是刘关张三人破吕布一阵，天下诸侯可不羞死也。", "(正末唱)想当日虎牢关一时难措手，到如今文官每尽拜降，武将每皆遁走，惯的那厮呵千自在百自由。"]'),
('yuanqu-9879','锦云堂暗定连环计・后庭花','无名氏','元','元曲','yuanqu','','[]','没阿只你个董太师掌大权，(董卓做笑科，云)我这权元也不小。',288,'元曲/yuanqu.json','["没阿只你个董太师掌大权，(董卓做笑科，云)我这权元也不小。", "(正末唱)吕温侯为帅首。", "俺可也同商议，待择个好日头。", "(董卓云)元来你们要择个好日头，敢是商量请我吃酒么？(正末云)非也，待请太师早登大位耳。", "(董卓笑云)只怕孤家到不得这地位。", "(正末唱)见说的话相投，(董卓云)若果有此日呵，你等但说的，我便依卿所奏也。", "(正末唱)便道是依卿所奏，(做背科，唱)只怕你这狠心肠无了休。", "(董卓云)杨太尉，俺问你，从古以来，也有将平天冠让人戴的么？(杨彪云)古语有云：有道伐无道，汤放桀，武王杀纣是也。", "无德让有德，尧禅舜，舜禅禹是也。", "(董卓云)王司徒，这等看来，今日之事，亦可知矣。", "(正末唱)。"]'),
('yuanqu-9880','锦云堂暗定连环计・那吒令','无名氏','元','元曲','yuanqu','','[]','打一个虞舜帝，他承唐祚温恭自守。',116,'元曲/yuanqu.json','["打一个虞舜帝，他承唐祚温恭自守。", "有一个秦始早．他并周家强梁不久。", "有一个新臣君，他篡汉室狂乖出丑。", "(董卓云)孤家为这一事，用了多少机谋，一时不得成就，以此心中好生着恼。", "(正末唱)你如今怕甚么计不成，怕甚么谋难就？便待要一勇性乱举戈矛。"]'),
('yuanqu-9881','锦云堂暗定连环计・鹊踏枝','无名氏','元','元曲','yuanqu','','[]','你可也强承头，大睁眸，岂不见天象璇玑，气运周流。',103,'元曲/yuanqu.json','["你可也强承头，大睁眸，岂不见天象璇玑，气运周流。", "(董卓做笑科，云)既然天象如此，只怕孤家没这福分。", "(正末云)元来太师不知，近日银台门内筑一高台，此非为禅授而何？(唱)早筑下高台禅授，休忘了俺两个王允、杨彪。"]'),
('yuanqu-9882','锦云堂暗定连环计・寄生草','无名氏','元','元曲','yuanqu','','[]','这本是服德非关力，你休便将恩认做仇。',94,'元曲/yuanqu.json','["这本是服德非关力，你休便将恩认做仇。", "则愿你仗龙泉扫荡风尘垢，按龙韬补尽乾坤漏，坐龙庭稳占江山秀。", "(董卓云)此事只宜疾，不宜迟也。", "(正末唱)则愿你顺人和有麝自然香，休得要逆天心无祸谁能勾？。"]'),
('yuanqu-9883','锦云堂暗定连环计・金盏儿','无名氏','元','元曲','yuanqu','','[]','我本是一重愁，翻做了两重愁，方信道是非只为多开口。',145,'元曲/yuanqu.json','["我本是一重愁，翻做了两重愁，方信道是非只为多开口。", "(杨彪云)司徒怎生定计擒拿此贼，方可保安汉室江山。", "(正末唱)待教我神机妙策苦搜求，怎做的姜子牙能伐纣，张子房会兴刘？(杨彪云)小官觑司徒也不弱于先贤，只要先算计了吕布一人，那董卓便易擒矣。", "(正末唱)你待要剿除了董太师，甚法儿所算了吕温侯？。"]'),
('yuanqu-9884','锦云堂暗定连环计・南吕/一枝花','无名氏','元','元曲','yuanqu','','[]','急切里称不的王允心，酬不了吾皇愿，擒不到董太师，立不起汉山川。',75,'元曲/yuanqu.json','["急切里称不的王允心，酬不了吾皇愿，擒不到董太师，立不起汉山川。", "则着我算后思前，将百计搜寻遍，奈一时难布展，忧的我神思竭默默无言，愁的我魂胆丧兢兢打战。"]'),
('yuanqu-9885','锦云堂暗定连环计・四块玉','无名氏','元','元曲','yuanqu','','[]','我则道他瘦恹恹苦病缠，却元来悄促促耽闺怨，方信道色胆从来大似天。',162,'元曲/yuanqu.json','["我则道他瘦恹恹苦病缠，却元来悄促促耽闺怨，方信道色胆从来大似天。", "(旦儿做泣科)(正末唱)则见他泪痕儿界破残妆面。", "我可甚治家如治国，他也不能守礼似守身，都做的顾后不顾前。", "(云)貂蝉，你在这里做甚么？敢如此大胆也。", "(梅香云)决撒了，老爷都听见了也。", "(旦儿云)你孩儿在此不曾说甚么，则为身子不快，特来烧香。", "(正末云)噤声。", "(唱)。"]'),
('yuanqu-9886','锦云堂暗定连环计・骂玉郎','无名氏','元','元曲','yuanqu','','[]','还待要花言巧语将咱骗，你恰才个焚香拜旨青天，深深顶礼亲发愿。',51,'元曲/yuanqu.json','["还待要花言巧语将咱骗，你恰才个焚香拜旨青天，深深顶礼亲发愿。", "似这等心又虔、意又坚，可则是保你身无倦？。"]'),
('yuanqu-9887','锦云堂暗定连环计・感皇恩','无名氏','元','元曲','yuanqu','','[]','呀，你说甚么再递丝鞭，重整良缘，是谁人打散了你这锦纹鸯，分开了双飞燕，斫断了并头莲？害的你一生恨惹，则为这两下情牵。',101,'元曲/yuanqu.json','["呀，你说甚么再递丝鞭，重整良缘，是谁人打散了你这锦纹鸯，分开了双飞燕，斫断了并头莲？害的你一生恨惹，则为这两下情牵。", "(旦儿云)你孩儿并无此言。", "(正末云)你还赖哩。", "(唱)我则问你遭间阻，经离别，是何年？。"]'),
('yuanqu-9888','锦云堂暗定连环计・牧羊关','无名氏','元','元曲','yuanqu','','[]','想王允官衔小，才艺浅，怎当的公子登筵。',114,'元曲/yuanqu.json','["想王允官衔小，才艺浅，怎当的公子登筵。", "(吕布云)老宰辅，你请我有何主意？(正末云)我王允也别无他意，只重奉先的威名耳。", "(唱)愿温侯家给千兵，愿温侯户封八县。", "愿温侯早掌元戎印，愿温侯早受帝王宣。", "愿温侯皂盖飞头上，愿温侯朱衣列马前。"]'),
('yuanqu-9889','锦云堂暗定连环计・隔尾','无名氏','元','元曲','yuanqu','','[]','一个眼传情羞掩芙蓉面，一个坐不稳难登玳瑁筵。',274,'元曲/yuanqu.json','["一个眼传情羞掩芙蓉面，一个坐不稳难登玳瑁筵。", "则见他佯带酒推更衣且宽转。", "(吕布云)老宰辅，乞恕吕布疏狂之罪。", "(正末唱)请温侯稳便，(吕布做呕科，云)吕布酒醉了，混践华堂，岂不得罪？(正末唱)有甚么混践。", "(云)奉先请坐，老夫前后执料去咱。", "(唱)我口儿里说话，将身躯倒退的远。", "(虚下)(吕布低云)老宰辅去了也。", "貂蝉！(旦儿应科)(吕布云)妻也，你怎生却在这里？(旦儿云)自从俺临洮失散，流落在司徒府中，不想今日才得相见。", "奉先，则被你痛杀我也。", "(旦儿做哭、吕布掩泣科，云)貂蝉，兀的不想杀我也。", "(正末冲上，云)你两个说甚么哩？(吕布同旦儿跪科)(正末唱)。"]'),
('yuanqu-9890','锦云堂暗定连环计・乌夜啼','无名氏','元','元曲','yuanqu','','[]','俺只道侯门一入如天远，(云)这个不是老夫的私宅。',127,'元曲/yuanqu.json','["俺只道侯门一入如天远，(云)这个不是老夫的私宅。", "(吕布云)不是老宰辅私宅，可是那里？(正末唱)谁承望汉刘晨误入桃源。", "枉着你佳人受尽相思怨，早两个携手挨肩，共枕同眠。", "则待要宝骅骝再接紫丝鞭，怎肯教锦鸳鸯深锁黄金殿。", "美前程，新姻眷，一任的春风院宇，夜月庭轩。"]'),
('yuanqu-9891','锦云堂暗定连环计・黄钟尾','无名氏','元','元曲','yuanqu','','[]','到明朝安排下鸿门摆设重瞳宴，准备着打凤机关吕后筵。',147,'元曲/yuanqu.json','["到明朝安排下鸿门摆设重瞳宴，准备着打凤机关吕后筵。", "用心肠，使机见。", "这权术，要巧便。", "奏笙歌，列管弦。", "花如锦，酒似川。", "我更谦下，做软善。", "董太师，酒性颠。", "见红颜，决顾恋。", "那其间我把这美貌貂蝉伪托献。", "暗暗的对天说咒愿。", "(带云)你道我愿甚的来？(唱)则愿的早灭了贼臣，将俺那圣明来显。", "(同季旅、祗候下)。"]'),
('yuanqu-9892','锦云堂暗定连环计・正宫/端正好','无名氏','元','元曲','yuanqu','','[]','仗才能，凭谋量，不须动阔剑长枪，无非是偎红倚翠如屏障，早摆设的都停当。',35,'元曲/yuanqu.json','["仗才能，凭谋量，不须动阔剑长枪，无非是偎红倚翠如屏障，早摆设的都停当。"]'),
('yuanqu-9893','锦云堂暗定连环计・滚绣球','无名氏','元','元曲','yuanqu','','[]','炉焚着宝篆香，酒斟着玉液浆，奏笙歌乐声嘹亮，今日个画堂中别是风光。',87,'元曲/yuanqu.json','["炉焚着宝篆香，酒斟着玉液浆，奏笙歌乐声嘹亮，今日个画堂中别是风光。", "虽然是锦绣乡，暗藏着战斗场，则争无虎贲郎将，玳筵前拥出红妆。", "我只待窝弓药箭擒狼虎，布网张罗打凤凰，不比寻常。"]'),
('yuanqu-9894','锦云堂暗定连环计・伴读书','无名氏','元','元曲','yuanqu','','[]','见太师言分朗。',52,'元曲/yuanqu.json','["见太师言分朗。", "教王允听明降。", "说道是指日当朝多兴旺，百司文武皆升赏。", "那其间新情旧意休偏向，愿太师福寿无疆。"]'),
('yuanqu-9895','锦云堂暗定连环计・笑和尚','无名氏','元','元曲','yuanqu','','[]','愿太师暮登天子堂，(董卓云)若果有这日，李肃加为甚么官？(正末唱)李肃做先锋将。',165,'元曲/yuanqu.json','["愿太师暮登天子堂，(董卓云)若果有这日，李肃加为甚么官？(正末唱)李肃做先锋将。", "(董卓云)是了。", "吾儿吕布，可加为甚么官？(正末唱)吕布坐金顶莲花帐。", "(董卓云)这个正当。", "(做笑科，云)司徒，你可要做甚么官？(正末唱)臣则是掌图书佐庙廊，又不曾擐甲胄战沙场，(董卓云)虽然如此，你可端的要做甚么官？(正末唱)望太师着王允做一个头厅相。"]'),
('yuanqu-9896','锦云堂暗定连环计・滚绣球','无名氏','元','元曲','yuanqu','','[]','油掠的髟。',5,'元曲/yuanqu.json','["油掠的髟。"]'),
('yuanqu-9897','锦云堂暗定连环计・叨叨令','无名氏','元','元曲','yuanqu','','[]','见董卓厮琅琅将酒盏躬身放，(董卓云)好美貌的女子。',199,'元曲/yuanqu.json','["见董卓厮琅琅将酒盏躬身放，(董卓云)好美貌的女子。", "我府里虽有千数丫鬟，并无一个能及之者。", "怎么这老头儿有那等好的？(正末唱)他把那娇滴滴艳质从头相。", "(董卓做扯旦儿科，云)你便近着我些，有何妨碍？(正末唱)见貂蝉羞答答身子儿难亲傍，(董卓做看旦儿科，云)好女子也！(正末唱)那老贼涎邓邓的眼脑儿偷睛望。", "(董卓云)好女子也，你靠前些。", "(正末唱)这厮早则中计也波哥，早则中计也波哥，我推个支分厨下离了筵上。"]'),
('yuanqu-9898','锦云堂暗定连环计・耍孩儿','无名氏','元','元曲','yuanqu','','[]','觑你个吕温侯本是英雄将，则这条方天戟有谁人抵当。',90,'元曲/yuanqu.json','["觑你个吕温侯本是英雄将，则这条方天戟有谁人抵当。", "也曾虎牢关外把姓名扬，吓的众诸侯胆落魂亡。", "你本是扶持社稷擎天柱，平定乾坤架海粱。", "你有仁义他无辞让，怎将那连云相府，生扭做行雨高唐？。"]'),
('yuanqu-9899','锦云堂暗定连环计・二煞','无名氏','元','元曲','yuanqu','','[]','他敛黄金尽四方，怕没红颜满洞房？怎么禽兽般做的能淫荡。',74,'元曲/yuanqu.json','["他敛黄金尽四方，怕没红颜满洞房？怎么禽兽般做的能淫荡。", "你当初把离愁泣诉华筵畔，到今日将密爱轻分半壁厢。", "还顾甚多恩养，便不想臣能报国，也索要夫与妻纲。"]'),
('yuanqu-9900','锦云堂暗定连环计・煞尾','无名氏','元','元曲','yuanqu','','[]','虽然是女娘家不气长，从来个做男儿当自强。',50,'元曲/yuanqu.json','["虽然是女娘家不气长，从来个做男儿当自强。", "若要你勃腾腾怒发三千丈，则除今夜里亲见貂蝉细细的访。", "(下)。"]'),
('yuanqu-9901','锦云堂暗定连环计・双调/新水令','无名氏','元','元曲','yuanqu','','[]','空着我两头三面用心机，则为这汉江山有人希觊。',49,'元曲/yuanqu.json','["空着我两头三面用心机，则为这汉江山有人希觊。", "偏生的铜壶传漏永，皓月上窗迟。", "彻夜徘徊，睡不到眼儿内。"]'),
('yuanqu-9902','锦云堂暗定连环计・驻马听','无名氏','元','元曲','yuanqu','','[]','董太师燕约莺期，欢喜杀肉重千斤新女婿。',195,'元曲/yuanqu.json','["董太师燕约莺期，欢喜杀肉重千斤新女婿。", "吕温侯鸾孤凤只，烦恼杀情分两处旧矫妻。", "貂蝉女泪珠儿滴满了凤凰杯，吕温侯怒风儿吹散了鸳鸯会。", "因此上自惊疑，则怕那一枝泄漏春消息。", "(吕布上，云)俺吕布一拳打倒那老贼，他必然差人来拿我。", "俺且躲在王司徒府中，与他商议，务要杀了那老贼，夺回貂蝉，才称我平生之愿。", "这是司徒府门首，待我唤咱。", "开门来！开门来！(正末云))这唤门的好似吕布的声音，这厮敢中计也。", "(唱)。"]'),
('yuanqu-9903','锦云堂暗定连环计・步步娇','无名氏','元','元曲','yuanqu','','[]','猛听的门外人声自惭愧，若不是中了咱家计，怎这等厮琅琅连扣击？(再做听科，唱)现如今夜静更阑是阿谁？忙出去问真实。',105,'元曲/yuanqu.json','["猛听的门外人声自惭愧，若不是中了咱家计，怎这等厮琅琅连扣击？(再做听科，唱)现如今夜静更阑是阿谁？忙出去问真实。", "(云)我开开这门，看是谁咱。", "(吕布云)老宰辅，是您孩儿吕布。", "(正末唱)则见他气丕丕的斜倚着门儿立。"]'),
('yuanqu-9904','锦云堂暗定连环计・胡十八','无名氏','元','元曲','yuanqu','','[]','据着我王允的心，怎不替你个奉先气，枉了你厮帮助，厮扶持，普天下不似那个老无知。',65,'元曲/yuanqu.json','["据着我王允的心，怎不替你个奉先气，枉了你厮帮助，厮扶持，普天下不似那个老无知。", "行这般所为，驴马的见识，这便是出气力、出气力落来的。"]'),
('yuanqu-9905','锦云堂暗定连环计・雁儿落','无名氏','元','元曲','yuanqu','','[]','他下的你下的，你有义他无义。',26,'元曲/yuanqu.json','["他下的你下的，你有义他无义。", "人无害虎心，虎有伤人意。"]'),
('yuanqu-9906','锦云堂暗定连环计・得胜令','无名氏','元','元曲','yuanqu','','[]','方信道天网自恢恢，业重祸相随。',65,'元曲/yuanqu.json','["方信道天网自恢恢，业重祸相随。", "他认做威福长堪假，怎知道江山不可移？今日个燃脐，也是他自做下舀天罪。", "我和你扬眉，不枉了舍残生救主危。"]'),
('yuanqu-9907','锦云堂暗定连环计・挂玉钩','无名氏','元','元曲','yuanqu','','[]','这都是天地神灵暗护持，因此上感动的英雄辈。',230,'元曲/yuanqu.json','["这都是天地神灵暗护持，因此上感动的英雄辈。", "(杨彪云)我想董卓倚恃吕布，结为养子，怎么就肯归顺朝廷，共讨此贼，却是为何？(正末唱)谁承望义女貂蝉正是吕布妻，他不合相调戏。", "(杨彪云)这事我已尽知了。", "但吕布一个便要报仇，那李肃也是董卓的养子，为何都肯顺俺？(正末云)那董卓为貂蝉之故，差李肃擒拿吕布，到我府中，被我把几句忠义的说话激发他，连李肃也不忿其事。", "因此拔刀相助，得成大功，皆二人之力也。", "(唱)吕布有盖世威，李肃有冲天气。", "若非他归顺厂皇朝，谁与咱剿灭这奸贼？。"]'),
('yuanqu-9908','锦云堂暗定连环计・水仙子','无名氏','元','元曲','yuanqu','','[]','元来那风道人掷布本仙机，蔡学士你为谋早预知。',354,'元曲/yuanqu.json','["元来那风道人掷布本仙机，蔡学士你为谋早预知。", "董太师果断送在连环计，吕温侯有胆力，如今个杨太尉奏上丹墀。", "(杨彪上，云)你众官望阙跪者，听圣人的命。", "(正末同众跪科)(杨彪云)卓本关西一武骑，自恃雄豪足盖世。", "亲提健卒入朝来，眼底全无汉皇帝。", "揽权擅威行不道，纳用子妻如狗彘。", "腹心牙爪尽崩离，已知此虏为天弃。", "即今斩首银台门，焚尸长安正厥罪。", "蔡邕学士多智谋，往来其间用游说。", "特加礼部侍郎衔，兼掌中书知诰制。", "吕布订贼建首功，封王出镇幽燕地。", "其妻貂蝉亦国君，随夫之爵身荣贵。", "李肃曾是卓家奴，晚能自拔来归义。", "可以骠骑大将军，仍领羽林作环卫。", "老臣王允怀主忧，当筵巧使连环计。", "是用报卿左丞相，与国同休永无替。", "(众谢恩科)(王允云)臣允老矣，恐不能久在朝端，扶助主上。", "(唱)愿圣主千年寿，保皇家万代基，容王允可便拂袖而归。", "(众下)。"]'),
('yuanqu-9909','越调・斗鹌鹑寄别','李邦基','元','元曲','yuanqu','','[]','百岁光阴，寄身宇宙。',48,'元曲/yuanqu.json','["百岁光阴，寄身宇宙。", "半世蹉跎，忘怀诗酒。", "窃玉偷香，寻花问柳。", "放浪行，不自羞。", "十载江淮，胸蟠星斗。"]'),
('yuanqu-9910','紫花儿・鬓丝禅榻，眉黛吟窗，扇影歌楼。献书北阙，挟策南州。迟留，','李邦基','元','元曲','yuanqu','','[]','社燕秋鸿几回首。',23,'元曲/yuanqu.json','["社燕秋鸿几回首。", "壮怀感旧，妩媚精神，罗绮风流。"]'),
('yuanqu-9911','调笑令・渐久，过清秋，今古盟山惜未休。琴樽相对消闲昼，尽乌丝醉围','李邦基','元','元曲','yuanqu','','[]','红袖。',19,'元曲/yuanqu.json','["红袖。", "阳关一声人去后，消疏了月枕双讴。"]'),
('yuanqu-9912','秃厮儿・浩浩寒波野鸥，消消夜雨兰舟，津亭送别风外柳。甚不解？系离','李邦基','元','元曲','yuanqu','','[]','愁，悠悠。',5,'元曲/yuanqu.json','["愁，悠悠。"]'),
('yuanqu-9913','圣药王・夜气收，人语幽，西楼梦断月沉钩。惜胜游，忆唱酬，追思往事','李邦基','元','元曲','yuanqu','','[]','到心头，肠欲断泪先流。',11,'元曲/yuanqu.json','["到心头，肠欲断泪先流。"]'),
('yuanqu-9915','双调・清江引','刘婆惜','元','元曲','yuanqu','','[]','青青子儿枝上结，引惹人攀折。',37,'元曲/yuanqu.json','["青青子儿枝上结，引惹人攀折。", "其中全子仁，就里滋味别，只为你酸留意儿难弃舍。"]'),
('yuanqu-9916','中吕・粉蝶儿寄情人','王氏','元','元曲','yuanqu','','[]','江景萧疏，那堪楚天秋暮，战西风柳败荷枯。',46,'元曲/yuanqu.json','["江景萧疏，那堪楚天秋暮，战西风柳败荷枯。", "立夕阳，空凝伫，江乡古渡，水接天隅，眼弥漫晚山烟树。"]'),
('yuanqu-9917','醉春风・寂寞日偏长，别离人最苦。把一封正家书改做诈休书，冯魁不睹','王氏','元','元曲','yuanqu','','[]','是将我来娶，娶。',29,'元曲/yuanqu.json','["是将我来娶，娶。", "知他是身跳龙门，首登虎榜，想这故人何处？。"]'),
('yuanqu-9918','红绣鞋・往常时冬里卧芙蓉ブ褥，夏里铺藤席纱忄厨，但出门换套儿好衣','王氏','元','元曲','yuanqu','','[]','不应冯魁茶员外，茶员外钞姨夫，我则想俏双生为伴侣。',25,'元曲/yuanqu.json','["不应冯魁茶员外，茶员外钞姨夫，我则想俏双生为伴侣。"]'),
('yuanqu-9919','石榴花・看了那可人江景壁间图，妆点费工夫。比及江天暮雪见寒，盼平','王氏','元','元曲','yuanqu','','[]','沙趁宿，落雁无书。',42,'元曲/yuanqu.json','["沙趁宿，落雁无书。", "空随得远浦帆归去，渔村落照船归住。", "烟寺晚钟夕阳暮，洞庭秋月照人孤。"]'),
('yuanqu-9920','斗鹌鹑・愁多似山市晴岚，泣多似潇湘夜雨。少一个心上才郎，多一个脚','王氏','元','元曲','yuanqu','','[]','头丈夫。',41,'元曲/yuanqu.json','["头丈夫。", "每日价茶不茶饭不饭百无是处，教我那里告诉。", "最高的离恨天堂，最低的相思地狱。"]'),
('yuanqu-9921','上小楼・怕不待开些肺腑？都向诗中分付。我这里行想行思，行写行读，','王氏','元','元曲','yuanqu','','[]','雨泪如珠。',28,'元曲/yuanqu.json','["雨泪如珠。", "都是些道不出，写不出，忧愁思虑，了不罢声啼哭。"]'),
('yuanqu-9922','幺・他争知我嫁人，我知他应过举。翻做了鱼沉雁杳，瓶坠簪折，信断音','王氏','元','元曲','yuanqu','','[]','咫尺地半载余，一字无。',26,'元曲/yuanqu.json','["咫尺地半载余，一字无。", "双郎何处？我则索随他泛茶船去。"]'),
('yuanqu-9923','十二月・无福效同俦并侣，有分受枕剩衾余。想起来相思最苦，空教人好','王氏','元','元曲','yuanqu','','[]','梦全无。',20,'元曲/yuanqu.json','["梦全无。", "擗飞了清歌妙舞，受了些寂寞消疏。"]'),
('yuanqu-9924','尧民歌・闪得人凤凰台上月儿孤，趁帆风势下东吴。我这里安桅举棹泛江','王氏','元','元曲','yuanqu','','[]','湖，到不如沉醉罗帏倩人扶。',31,'元曲/yuanqu.json','["湖，到不如沉醉罗帏倩人扶。", "踌躇，踌躇，天边雁儿遥，枉把佳期误。"]'),
('yuanqu-9925','耍孩儿・这厮不通今古通商贾，是贩卖俺愁人的客旅。守着这厮愁闷怎消','王氏','元','元曲','yuanqu','','[]','除，真乃是牛马而襟裾。',47,'元曲/yuanqu.json','["除，真乃是牛马而襟裾。", "斗筲之器成何用，粪土之墙不可圬。", "想俺爱钱娘乔为做，不分些好弱，不辨贤愚。"]'),
('yuanqu-9926','三煞・娘呵你好下得好下得！忒狠毒忒狠毒！全没些子母情肠肚。则好教','王氏','元','元曲','yuanqu','','[]','三千场失火遭天震，一万处疔疮生背疽。',42,'元曲/yuanqu.json','["三千场失火遭天震，一万处疔疮生背疽。", "怎不教我心中怒？你在钱堆受用，撇我在水面上遭徒。"]'),
('yuanqu-9927','二・我上船时如上木驴，下舱时如下地府，靠桅杆似靠着将军柱。一个随','王氏','元','元曲','yuanqu','','[]','风倒柁船牢狱，趁浪逐波乘槛车。',37,'元曲/yuanqu.json','["风倒柁船牢狱，趁浪逐波乘槛车。", "伴着这扌若人物，便似冤魂般相缠，日影般相逐。"]'),
('yuanqu-9928','一・他正是冯魁酒正浓，苏卿愁起初，下船来行到无人处。我比娥皇女哭','王氏','元','元曲','yuanqu','','[]','舜添斑竹，比曹娥女泣江少一套孝服。',43,'元曲/yuanqu.json','["舜添斑竹，比曹娥女泣江少一套孝服。", "则怕他瞧破俺情绪，推眼疾偷掩痛泪，佯呵欠带几声长吁。"]'),
('yuanqu-9929','尾・比我这泪珠儿何日干？愁眉甚日舒？将普天下烦恼收拾聚，也似不得','王氏','元','元曲','yuanqu','','[]','苏卿半日苦。',6,'元曲/yuanqu.json','["苏卿半日苦。"]'),
('yuanqu-9930','正宫・醉太平寒食','王元鼎','元','元曲','yuanqu','','[]','珠帘外燕飞，乔木上莺啼，莺莺燕燕正寒食，想人生有几。',230,'元曲/yuanqu.json','["珠帘外燕飞，乔木上莺啼，莺莺燕燕正寒食，想人生有几。", "有花无酒难成配，无花有酒难成对。", "今日有花有酒有相识，不吃呵图甚的？声声啼乳鸦，生叫破韶华。", "夜深微雨润堤沙，香风万家。", "画楼洗净鸳鸯瓦，彩绳半湿秋千架。", "觉来红日上窗纱，听街头卖杏花。", "辜负了禁烟，冷落了秋千。", "春光去也怎留恋？听莺啼燕喧。", "红馥馥落尽桃花片，青丝丝舞困垂杨线，扑簌簌满地堕榆钱，芳心闷倦。", "花飞时雨残，帘卷处春寒。", "夕阳楼上望长安，洒西风泪眼。", "几时睚彻凄惶限？几时盼得南来雁？几番和月凭阑干？多情人未还！。"]'),
('yuanqu-9931','越调・凭栏人闺怨','王元鼎','元','元曲','yuanqu','','[]','垂柳依依惹暮烟，素魄娟娟当绣轩。',57,'元曲/yuanqu.json','["垂柳依依惹暮烟，素魄娟娟当绣轩。", "妾身独自眠，月圆人未圆。", "啼得花残声更悲，叫得春归郎未知。", "杜鹃奴倩伊，问郎休日归？。"]'),
('yuanqu-9932','双调・折桂令桃花马','王元鼎','元','元曲','yuanqu','','[]','问刘郎骥控亭槐，觉红雨潇潇，乱落苍苔。',68,'元曲/yuanqu.json','["问刘郎骥控亭槐，觉红雨潇潇，乱落苍苔。", "溪上笼归，桥边洗罢，洞口牵来。", "摇玉辔春风满街，摘金鞍流水天台。", "锦绣毛胎，嘶过玄都，千树齐开。", "套数。"]'),
('yuanqu-9933','柳叶儿・走将来乜斜头撒吣，不熨贴性儿希林，软处捏硬处掐甜处渗。休','王元鼎','元','元曲','yuanqu','','[]','忒恁，莫沉吟，休辜负了柳影花阴。',16,'元曲/yuanqu.json','["忒恁，莫沉吟，休辜负了柳影花阴。"]'),
('yuanqu-9934','大石调・雁传书','王元鼎','元','元曲','yuanqu','','[]','春归后，柳丝难挽别离情。',64,'元曲/yuanqu.json','["春归后，柳丝难挽别离情。", "一片花飞减却春，对东风无语销魂。", "伤情，花飞泪落堕红雨，苍苔上海棠堆径。", "愁无尽，怕的是梨花庭院，风雨黄昏。"]'),
('yuanqu-9935','明妃曲・愁闻，是谁家风前笛韵？梅花吹落江城。难禁，吹出了断肠声，','王元鼎','元','元曲','yuanqu','','[]','到惹得月愁人病。',39,'元曲/yuanqu.json','["到惹得月愁人病。", "鹃啼春思月中魂，花迷蝶梦窗前影。", "恹恹病，这相思能终得几个黄昏。"]'),
('yuanqu-9936','秋海棠・谁似你辜恩？谁似我痴心？负心的上有神明，到如今参不透薄情','王元鼎','元','元曲','yuanqu','','[]','心性。',34,'元曲/yuanqu.json','["心性。", "好姻缘甚日重盟，恶姻缘番成画饼。", "多愁闷，消磨了白昼，顿送黄昏。"]'),
('yuanqu-9937','比目鱼・数归期，掏得指头疼；盼归期，望断楚山云。泪珠，泪珠滴尽湘','王元鼎','元','元曲','yuanqu','','[]','江满，只落得暗里自沉吟。',64,'元曲/yuanqu.json','["江满，只落得暗里自沉吟。", "从今，再不去梦里搜寻，再不去愁中加病，再不去挂肚牵心。", "泪痕销夜烛，翠被拥鸡声。", "捱过了几番寂寞，几度黄昏。"]'),
('yuanqu-9939','双调・夜行船秋怀','萧德润','元','元曲','yuanqu','','[]','一夜秋声入井梧，碧纱厨枕剩珊瑚。',34,'元曲/yuanqu.json','["一夜秋声入井梧，碧纱厨枕剩珊瑚。", "秦凤东归，楚云西去，旧欢娱等闲辜负。"]'),
('yuanqu-9940','风入松・翠屏灯影照人孤，花外响啼蛄。丁宁似把闲愁诉，凄凉待怎支吾。','萧德润','元','元曲','yuanqu','','[]','泪珠伴檐化簌簌，梦魂惊城角呜呜。',16,'元曲/yuanqu.json','["泪珠伴檐化簌簌，梦魂惊城角呜呜。"]'),
('yuanqu-9942','乔牌儿・相思病忒狠毒，风流债久担误。波涛隔断蓝桥路，枉子把鹊声占','萧德润','元','元曲','yuanqu','','[]','龟卦卜。',4,'元曲/yuanqu.json','["龟卦卜。"]'),
('yuanqu-9943','甜水令・到如今镜破青铜，钗分金凤，箫闲碧玉，无语自踌躇。果若命分','萧德润','元','元曲','yuanqu','','[]','合该，于飞终效，姻缘当遇，甘心儿为你嗟吁。',21,'元曲/yuanqu.json','["合该，于飞终效，姻缘当遇，甘心儿为你嗟吁。"]'),
('yuanqu-9944','鸳鸯煞・锦回文织就别离谱，碧云笺写遍伤心句。旧物空存，薄情何处？','萧德润','元','元曲','yuanqu','','[]','畅道往事千端，柔肠九曲，软玉温香，作念着何曾住？人问我秋到也较何如？怕的是战碎芭蕉画阑雨。',45,'元曲/yuanqu.json','["畅道往事千端，柔肠九曲，软玉温香，作念着何曾住？人问我秋到也较何如？怕的是战碎芭蕉画阑雨。"]'),
('yuanqu-9945','黄钟・人月圆甘露怀古','徐再思','元','元曲','yuanqu','','[]','江皋楼观前朝寺，秋色入秦淮。',120,'元曲/yuanqu.json','["江皋楼观前朝寺，秋色入秦淮。", "败垣芳草，空廊落叶，深砌苍苔。", "远人南去，夕阳西下，江水东来。", "木兰花在，山僧试问，知为谁开？兰亭茂林修竹风流地，重到古山阴。", "壮怀感慨，醉眸俯仰，世事浮沉。", "惠风归燕，团沙宿鹭，芳树幽禽。", "山山水水，诗诗酒酒，古古今今。"]'),
('yuanqu-9946','黄钟・红锦袍','徐再思','元','元曲','yuanqu','','[]','那老子爱清闲主意别，钓桐江江上雪，泛桐江江上月。',233,'元曲/yuanqu.json','["那老子爱清闲主意别，钓桐江江上雪，泛桐江江上月。", "君王想念者；宣到凤凰阙。", "想著七里渔滩，将著一钩香饵，望著富春山归去也。", "那老子陷身在虎狼穴，将夫差仇恨雪，进西施谋计拙。", "若不早去些，乌喙意儿别。", "驾著一叶扁舟，披著一蓑烟雨，望他五湖中归去也。", "那老子见高皇斩了蛇，助萧何立大节，荐韩侯劳汗血。", "渔樵做话说，千古汉三杰。", "想著云外青山，纳了腰间金印，伴赤松子归去也。", "那老子觑功名如梦蝶，五斗米腰懒折，百里侯心便舍。", "十年事可嗟，九日酒须赊，种著三径黄花，栽著五株杨柳，望东篱归去也。"]'),
('yuanqu-9947','仙吕・一半儿病酒','徐再思','元','元曲','yuanqu','','[]','昨宵中酒懒扶头，今日看花惟袖手，害酒愁花人问羞。',118,'元曲/yuanqu.json','["昨宵中酒懒扶头，今日看花惟袖手，害酒愁花人问羞。", "病根由，一半儿因花一半儿酒。", "落花河阳香散唤提壶，金谷魂消啼鹧鸪，隋苑春归闻杜宇。", "片红无，一半儿狂风一半儿雨。", "春情眉传雨恨母先疑，眼送云情人早知，口散风声谁唤起。", "这别离，一半儿因咱一半儿你。"]'),
('yuanqu-9948','中吕・朝天子西湖','徐再思','元','元曲','yuanqu','','[]','里湖，外湖，无处是无春处。',237,'元曲/yuanqu.json','["里湖，外湖，无处是无春处。", "真山真水真画图，一片玲珑玉。", "宜酒宜诗，宜晴宜雨。", "销金锅锦绣窟，老苏，老逋，杨柳堤梅花墓。", "手帕酒痕，泪痕，半带着胭脂润。", "鲛渊一片玉霄云，缕缕东风恨。", "待写回文，敷陈方寸，怕莺花说与春。", "使人，赠君，寄风月平安信。", "常山江行远山，近山，一片青无间。", "逆流流流诉上乱石滩，险似连云栈。", "落日昏鸦，西风归雁，叹崎岖途路难。", "得闲，且闲，何处无鱼羹饭？杨姬艳冶，唱彻，〔金缕〕歌全阕。", "秋娘声价有谁轶？曾奉黄金阙。", "歌扇生春，舞裙回雪，不风流不醉也。", "舞者，唱者，一曲秦楼月。"]'),
('yuanqu-9949','中吕・满庭芳赠歌者','徐再思','元','元曲','yuanqu','','[]','犀梳玉簪，歌裙翠浅，舞袖红深。',59,'元曲/yuanqu.json','["犀梳玉簪，歌裙翠浅，舞袖红深。", "风流消得缠头锦，一笑千金。", "痛饮时花前痛饮，知音人席上知音。", "春无禁，蜂蝶快寻，先到海棠心。"]'),
('yuanqu-9950','中吕・红绣鞋雪','徐再思','元','元曲','yuanqu','','[]','白鹭交飞溪脚，玉龙横卧山腰，满乾坤无处不琼瑶。',130,'元曲/yuanqu.json','["白鹭交飞溪脚，玉龙横卧山腰，满乾坤无处不琼瑶。", "因风吹柳絮，和月点梅梢，想孤山鹤睡了。", "半月泉凿透林间山溜，平分天上中秋，菱花分破印寒流。", "沁梅疏影缺，攀桂片云愁，待团圆掬在手。", "道院一榻白云竹径，半窗明月松声，红尘无处是篷瀛。", "青猿藏火枣，黑虎听《黄庭》，山人参内景。"]'),
('yuanqu-9951','中吕・阳春曲皇亭晚泊','徐再思','元','元曲','yuanqu','','[]','水深水浅东西涧，云去云来远近山。',215,'元曲/yuanqu.json','["水深水浅东西涧，云去云来远近山。", "秋风征棹钓鱼滩，烟树晚，茅舍两三间。", "双渐苏卿倦织回文锦，双渐空怀买笑金。", "风流一点海棠心，不听琴，只是不知音。", "春情桃花月淡胭脂冷，杨柳风微翡翠轻。", "玉人欹枕倚云屏，酒未醒，肠断紫箫声。", "闺怨妾身悔作商人妇，妾命当逢薄幸夫。", "别时只说到东吴，三载余，却得广州书。", "赠海棠玉环梦断风流事，银烛歌成富贵词。", "东风一树玉胭脂，双燕子，曾见正开时。", "春思酒醒眉记青鸾恨，春去香消紫燕尘。", "阑干掐遍月儿痕，深闭门，花落又黄昏。"]'),
('yuanqu-9952','越调・小桃红花篮区髻','徐再思','元','元曲','yuanqu','','[]','东风攒簇一筐春，吹在秋蝉鬓，玉露凝香宝钗润。',50,'元曲/yuanqu.json','["东风攒簇一筐春，吹在秋蝉鬓，玉露凝香宝钗润。", "绿无尘，同心双挽蜂蝶阵。", "群芳顶上，连环枝下，分断楚山云。"]'),
('yuanqu-9953','越调・天净沙探梅','徐再思','元','元曲','yuanqu','','[]','昨朝深雪前村，今宵淡月黄昏，春到南枝几分？水香冰晕，唤回逋老诗魂。',249,'元曲/yuanqu.json','["昨朝深雪前村，今宵淡月黄昏，春到南枝几分？水香冰晕，唤回逋老诗魂。", "吕侯席上素波笑浅流花，轻衫舞争飘霞，席上司空鬓华。", "酒阑歌罢，不知春在谁家？别高宰青山远远天台，白云隐隐萧台，回首江南倦客。", "西湖诗债，梅花等我归来。", "春情双双翠舞珠歌，卿卿酒病花魔，为问风流玉娥。", "海棠开过，牡丹消息如何？渔父忘形雨笠烟蓑，知心牧唱樵歌，明月清风共我。", "闲人三个，从他今古消磨。", "秋江夜泊斜阳万点昏鸦，西风两岸芦花，船系浔阳酒家。", "多情司马，青衫梦里琵琶。", "题情多才惹得多愁，多情便有多忧，不重不轻证候。", "甘心消受，谁教你会风流？。"]'),
('yuanqu-9954','双调・沉醉东风息斋画竹','徐再思','元','元曲','yuanqu','','[]','葛陂里神龙蜕形，丹山中彩凤栖庭。',156,'元曲/yuanqu.json','["葛陂里神龙蜕形，丹山中彩凤栖庭。", "风吹粉箨香，雨洗苍苔冷，老仙翁笔底春生。", "明月阑干酒半醒，对一片儿潇湘翠影。", "春情一自多才间阔，几时盼得成合。", "今日个猛见他门前过，待唤着怕人瞧科。", "我这里高唱当时《水调歌》，要识得声音是我。", "红灼灼花明翠牖。", "翠丝丝柳拂青楼。", "锦谷春，银瓶酒，玉天仙燕体莺喉。", "不向樽前醉后休，枉笑煞花间四友。"]'),
('yuanqu-9955','双调・蟾宫曲西湖','徐再思','元','元曲','yuanqu','','[]','十年不到湖山，齐楚秦燕，皓首苍颜。',429,'元曲/yuanqu.json','["十年不到湖山，齐楚秦燕，皓首苍颜。", "今日重来，莺嫌花老，燕怪春悭。", "听越女鸾箫象板，恼司空雾鬓云环。", "道院弹关，酒会诗坛，万古西湖，天上人间。", "钱子云赴都赋河梁渺渺予怀，今日阳关，明日秦淮。", "鹏翼风云，龙门波浪，马足尘埃。", "宽洗汕胸中四海，便蜚腾天上三台。", "休等书斋，梅子花开，人在江南，先寄诗来。", "江淹寺紫霜毫是是非非，万古虚名，一梦初回。", "失又何愁？得之何喜？闷也何为？落日外萧山翠微，小桥边古寺残碑。", "文藻珠玑，醉墨淋淳，何似班超，投却毛锥。", "登太和楼白云中涌出蓬莱，俯视西湖，图画天开。", "暮雨珠帘，朝云画栋，夜月瑶台。", "书籍会三千剑客，管弦声十二金钗。", "对酒兴杯，拊髀怜才，寄语玲珑，王粲曾来。", "竹夫人湘妃应是前身，不记何年，封虢封秦。", "万古虚心，百年贞节，一世故人。", "剖苍壁寒凝泪痕，挽潜蛟巧结香纹。", "侍枕知恩，入梦无春，两腋清风，满枕行云。", "姑苏台荒台谁唤姑苏？兵渡西兴，祸起东吴。", "切齿仇冤，捧心钓饵，尝胆权谋。", "三千尺侵云粪土，十万家泣血膏腴。", "日月居诸，台殿丘墟。", "何似灵岩，山色如初。"]'),
('yuanqu-9956','双调・清江引苕溪','徐再思','元','元曲','yuanqu','','[]','驼风两桥分燕尾，人物风流地。',224,'元曲/yuanqu.json','["驼风两桥分燕尾，人物风流地。", "白云四面山，明月双溪水，身在董元图画里。", "盘龙寺山僧定回月半吐，叱咤神龙处。", "空廊旧爪痕，古殿新盘路，卷起讲华台下雨。", "春夜云间玉箫三四声，人倚阑干听。", "风生翡翠棂，露滴梧桐井，明月半帘花弄影。", "私欢梧酮画阑明月斜，酒散笙歌歇。", "梅香走将来，耳畔低低说：后堂中正夫人沉醉也。", "笑靥儿东风不知何处来？吹动胭脂色。", "旋成一点春，添上十分态，有千金俏人儿谁共买。", "相思相思有如少债的，每日相催逼。", "常挑着一担愁，准不了三分利，这本钱见他时才算得。"]'),
('yuanqu-9957','双调・寿阳曲梅影','徐再思','元','元曲','yuanqu','','[]','枝横水，花未雪，镜中春玉痕明灭。',240,'元曲/yuanqu.json','["枝横水，花未雪，镜中春玉痕明灭。", "梨云梦残人瘦也，弄黄昏半窗明月。", "手帕香多处，情万缕，织春愁一方柔玉。", "寄多才怕不知心内苦，带胭脂泪痕将去。", "春情心疼事，肠断词，背秋千泪痕红渍。", "剔春纤碎榴花瓣儿，就窗纱砌成愁字。", "昨宵是，你自说，许是咱这般时节。", "到西厢等的人静也，又不成再推明夜。", "闲情绪，深院宇，正东风满帘飞絮。", "怕梨花不禁三月雨，是谁教燕衔春去？醉姬绯霞佩，金缕衣，枕东风美人深醉。", "便休将玉箫花下吹，怕惊回海棠春睡。", "柳腰连环玉，一搦酥，舞春风柳丝相妒。", "沈东阳带红香双抱住，怕随着彩云飞去。"]'),
('yuanqu-9958','双调・水仙子夜雨','徐再思','元','元曲','yuanqu','','[]','一声梧叶一声秋，一点芭蕉一点愁，三更归梦三更后。',527,'元曲/yuanqu.json','["一声梧叶一声秋，一点芭蕉一点愁，三更归梦三更后。", "落灯花棋未收，叹新丰孤馆人留。", "枕上十年事，江南二老忧，都到心头。", "弹唱佳人玉纤流恨出冰丝，瓠齿和春吐怨辞，秋波送巧传心事。", "似邻船初听时，问江州司马何之。", "青衫泪，锦字诗，总是相思。", "红指甲落花飞上笋牙尖，宫叶犹将冰箸粘，抵牙关越显得樱唇艳。", "怕伤春不卷帘，捧菱花香印妆奁。", "雪藕丝霞十缕，镂枣班血半点，掐刘郎春在纤纤。", "佳人钉履金莲脱瓣载云轻，红叶浮香带雨行，渍春泥印在苍苔径。", "三寸中数点星，玉玲珑环佩交鸣。", "溅越女红裙湿，沁湘妃罗袜冷，点寒波小小蜻蜓。", "春情九分恩爱九分忧，两处相思两处愁，十年迤逗十年受。", "几遍成几遍休，半点事半点惭羞。", "三秋恨三秋感旧，三春怨三春病酒，一世害一世风流。", "青玉花筒蜂房分蜜入乌云，莺嘴流金拂翠颦，鸾钗嵌玉浮红晕。", "似蕊珠宫内人，虚心腹管束东君。", "两朵儿瑶花弄色，半缕儿香绵沁粉，一泓儿碧露涵春。", "重九东篱重赋紫萸诗，北海深倾白玉卮，西风了却黄花事。", "是渊明酒醉时，笑人间名利孜孜。", "钻醯瓮，检故纸，再谁题归去来兮？马嵬坡翠华香冷梦初醒，黄壤春深草自青，羽林兵拱听将军令。", "拥鸾舆蜀道行，妾虽亡天子还京。", "昭阳殿梨花月色，建章宫梧桐雨声，马嵬坡尘土虚名。", "惠山泉自天飞下九龙涎，走地流为一股泉，带风吹作千寻练。"]'),
('yuanqu-9959','双调・殿前欢钓台','徐再思','元','元曲','yuanqu','','[]','钓鱼台，便齐云安稳似云台。',172,'元曲/yuanqu.json','["钓鱼台，便齐云安稳似云台。", "故人同榻成何碍，太史瘦哉。", "三台宰相阶，百两黄金带，万丈风波海。", "争如休去，胜似归来。", "杨总管玉堂臣，经纶大展致其身。", "腰间斗大黄金印，志在新民。", "文章汉子云，韬略吴公瑾，勋业商伊尹。", "一番桃李，两字麒麟。", "观音山眠松老苍龙，避乖高卧此山中。", "岁寒心不肯为梁栋，翠蜿蜒俯仰相从。", "秦皇旧日封，靖节何年种？丁固当时梦，半溪明月，一枕清风。"]'),
('yuanqu-9960','双调・卖花声','徐再思','元','元曲','yuanqu','','[]','雪儿娇小歌《金缕》，老子婆娑倒玉壶，满身花影倩人扶。',171,'元曲/yuanqu.json','["雪儿娇小歌《金缕》，老子婆娑倒玉壶，满身花影倩人扶。", "昨宵不记，雕鞍归去，问今朝酒醒何处？碧桃红杏桃源路，绿水青山水墨图，杖头挑着酒胡芦。", "行行觑着，山童分付，问前村酒家何处？红罗佩吐狮头玉，碧珥香衔凤口珠，风流相遇恨须臾。", "梨花淡月，楼台如故，教吹箫玉人何处？云深不见南来羽，水远难寻北去鱼，两年不寄半行书。", "危楼目断，云山无数，望天涯故人何处？。"]'),
('yuanqu-9961','吕洞宾三醉岳阳楼・仙吕/点绛唇','马致远','元','元曲','yuanqu','','[]','这墨光照文房，取烟在太华顶上仙人掌。',32,'元曲/yuanqu.json','["这墨光照文房，取烟在太华顶上仙人掌。", "更压着五李三张，入砚松风响。"]'),
('yuanqu-9962','吕洞宾三醉岳阳楼・混江龙','马致远','元','元曲','yuanqu','','[]','梭头琴样，助吟毫清彻看书窗。',120,'元曲/yuanqu.json','["梭头琴样，助吟毫清彻看书窗。", "恰行过一区道院，几处斋堂。", "竹几暗添龙尾润，布袍常带麝脐香。", "早来到洞庭湖畔，百尺楼旁。", "(做上楼科，云)是好一座高楼也。", "(唱)端的是凭凌云汉，映带潇湘。", "俺这里蹑飞梯，凝望眼，离人间似有三千丈。", "则好高欢避暑，王粲思乡。"]'),
('yuanqu-9963','吕洞宾三醉岳阳楼・油葫芦','马致远','元','元曲','yuanqu','','[]','俺只见十二栏干接上苍。',317,'元曲/yuanqu.json','["俺只见十二栏干接上苍。", "(酒保云)招过客，招过客！(正末云)休叫，休叫。", "(酒保云)你怎生着我休叫？(正末唱)我则怕惊着玉皇，谁着你直侵北斗建糟坊。", "(酒保云)你看我这楼上有牌，牌上有字，上写着世间无此酒，天下有名楼。", "(正末唱)写道是岳阳楼形胜偏雄壮，更压着你洞庭春好酒新炊荡。", "(酒保云)老师父，你看这边景致。", "(正末唱)翠巍巍当着楚山。", "(酒保云)休道是楚山，连太山、华山都看见了。", "师父，你看这边景致。", "(正末唱)浪淘浪临着汉江。", "(酒保云)不要说汉江，连洞庭湖、鄱阳湖、青草湖都看见了。", "(正末云)正是鸡肥蟹壮之时。", "(唱)正菊花秋不醉倒陶元亮？(酒保云)师父，你来迟了，我这酒已卖尽，无了酒也。", "(正末云)你道是无酒呵，(唱)怎发付团脐蟹一包黄？。"]'),
('yuanqu-9964','吕洞宾三醉岳阳楼・天下乐','马致远','元','元曲','yuanqu','','[]','我则待当了一环绦醉一场。',216,'元曲/yuanqu.json','["我则待当了一环绦醉一场。", "(酒保云)说便这等说，实是无了酒也。", "(正末云)你道无酒，你闻波。", "(唱)那里这般清甘滑辣香？(酒保云)酒有，只你醉了不好下楼去。", "(正末唱)但将老先生醉死不要你偿。", "(酒保云)师父，这楼上好凉快哩。", "(正末唱)我特来趁晚凉，趁晚凉入醉乡。", "(酒保云)老师父，天色将晚了。", "(正末云)还早哩。", "(唱)争知俺仙家日月长。", "(云)小二哥，你供养的是一尊甚么神道？(酒保云）这是初造酒的杜康。", "我供养着他，这酒客日日常满。", "(正末唱)。"]'),
('yuanqu-9965','吕洞宾三醉岳阳楼・那吒令','马致远','元','元曲','yuanqu','','[]','我待和你唤上、那登真的伯阳，你觑当、更悬壶的长房，不强似你供养、那招财的杜康。',80,'元曲/yuanqu.json','["我待和你唤上、那登真的伯阳，你觑当、更悬壶的长房，不强似你供养、那招财的杜康。", "(酒保云)师父，我买活鱼来做按酒。", "(正末唱)休更说钓锦鳞刍新酿，待邀留他过往经商。"]'),
('yuanqu-9966','吕洞宾三醉岳阳楼・鹊踏枝','马致远','元','元曲','yuanqu','','[]','自隋唐，数兴亡，料着这一片青旗，能有的几日秋光。',44,'元曲/yuanqu.json','["自隋唐，数兴亡，料着这一片青旗，能有的几日秋光。", "对四面江山浩荡，怎消得我几行儿醉墨淋浪。"]'),
('yuanqu-9967','吕洞宾三醉岳阳楼・寄生草','马致远','元','元曲','yuanqu','','[]','说甚么琼花露，问甚么玉液浆。',105,'元曲/yuanqu.json','["说甚么琼花露，问甚么玉液浆。", "想鸾鹤只在秋江上，似鲸鲵吸尽银河浪，饮羊糕醉杀销金帐。", "这的是烧猪佛印待东坡，抵多少骑驴魏野逢潘阆。", "(酒保云)小人听得说，王弘送酒，刘伶荷锸，李白摸月，也不似先生这等贪杯。", "(正末唱)。"]'),
('yuanqu-9968','吕洞宾三醉岳阳楼・幺篇','马致远','元','元曲','yuanqu','','[]','想那等尘俗辈，恰便似粪土墙。',178,'元曲/yuanqu.json','["想那等尘俗辈，恰便似粪土墙。", "王弘探客在篱边望，李白扪月在江心丧，刘伶荷锸在坟头葬。", "我则待朗吟飞过洞庭湖，须不曾摇鞭误入平康巷。", "(云)小二哥，打二百长钱酒来。", "(酒保云)先交了钱，然后吃酒。", "(正末云)你也说的是，与你这一锭墨，便当二百文钱的酒。", "(酒保云)笑杀我也。", "量这一锭墨有甚么好处，那里便值二百文钱？(正末云)我这墨非同小可，便当二百文钱也不多哩。", "(唱)。"]'),
('yuanqu-9969','吕洞宾三醉岳阳楼・后庭花','马致远','元','元曲','yuanqu','','[]','这墨瘦身躯无四两，你可便消磨他有几场。',101,'元曲/yuanqu.json','["这墨瘦身躯无四两，你可便消磨他有几场。", "万事皆如此，(带云)酒保也，(唱)则你那浮生空自忙。", "他一片黑心肠，在这功名之上。", "(酒保云)我不要这墨，你则与我钱。", "(正末云)墨换酒，你也不要？(唱)敢糊涂了纸半张。"]'),
('yuanqu-9970','吕洞宾三醉岳阳楼・金盏儿','马致远','元','元曲','yuanqu','','[]','我这里据胡床，望三湘，有黄鹤对舞仙童唱。',79,'元曲/yuanqu.json','["我这里据胡床，望三湘，有黄鹤对舞仙童唱。", "主人家宽洪海量，醉何妨。", "直吃的卷帘邀皓月，再谁想开宴出红妆。", "但得一尊留墨客，(带云)我困了也，(唱)我可是两处梦黄粱。"]'),
('yuanqu-9971','吕洞宾三醉岳阳楼・醉中天','马致远','元','元曲','yuanqu','','[]','我见他拄着条过头杖，恰便似老龙王。',196,'元曲/yuanqu.json','["我见他拄着条过头杖，恰便似老龙王。", "(柳云)早知上仙在此，合当参拜。", "(正末唱)你这般曲脊驼腰，来我跟前有甚勾当？(带云)我看你本相(唱)我这里斜倚定栏干望。", "(柳云)师父，望甚么？(正末云)你道我望甚么？(唱)原来是挂望子门前老杨。", "(柳云)小圣在此千百余年也。", "(正末云)噤声！(唱)你道是埋根千丈，你如今絮沾泥，则怕泄漏春光。", "(云)柳也，你有几般儿歹处哩。", "(柳云)师父，我有甚么歹处？(正末唱)。"]'),
('yuanqu-9972','吕洞宾三醉岳阳楼・忆王孙','马致远','元','元曲','yuanqu','','[]','亚夫营里晚天凉，炀帝宫中春昼长。',59,'元曲/yuanqu.json','["亚夫营里晚天凉，炀帝宫中春昼长。", "按舞罢楚台人断肠，你只为春忙。", "(柳云)再有甚么歹处？(正末唱)饿得那楚宫女腰肢一捻香。"]'),
('yuanqu-9973','吕洞宾三醉岳阳楼・金盏儿','马致远','元','元曲','yuanqu','','[]','我是个吕纯阳，度你个绿垂杨。',74,'元曲/yuanqu.json','["我是个吕纯阳，度你个绿垂杨。", "你则管伴烟伴雨在溪桥上，舞东风飘荡弄轻狂。", "如今人早晨栽下树，到晚来要阴凉。", "则怕你滋生下些小业种，久已后干撇下你个老孤桩。"]'),
('yuanqu-9974','吕洞宾三醉岳阳楼・赚煞','马致远','元','元曲','yuanqu','','[]','似我这般抱定墨篮儿。',336,'元曲/yuanqu.json','["似我这般抱定墨篮儿。", "(柳抱篮科，云)师父，这般将着可好么？(正末唱)兀的不才似一个人模样。", "(柳云)师父，你怎生识的小圣来。", "(正末唱)我底根儿把你来看生见长。", "(柳云)师父仙乡何处？(正末唱)我家住在白云缥缈乡。", "(柳云)那里幽静么？(正末唱)俺那里无乱蝉鸣聒噪斜阳。", "(柳云)徒弟去则去，则是舍不的这一派水也。", "(正末唱)量湖光，不大似半亩芳塘。", "(柳云)徒弟省了也。", "(正末唱)你险做了长亭系马桩。", "(柳云)敢问师父两句言语，合道不合道是怎么说？(正末云)你一句句问将来。", "(柳云)师父，合道是怎生？(正末唱)合道在章台路旁。", "(柳云)不合道可是怎生？(正末唱)不合道你则在灞陵桥上。", "(云)你若肯跟我出家，教你学取一个。", "(柳云)学取那一个？(正末唱)我着你学那吕岩前松柏耐风霜。", "(同下)。"]'),
('yuanqu-9975','吕洞宾三醉岳阳楼・南吕/一枝花','马致远','元','元曲','yuanqu','','[]','犹兀自骑着个大肚驴，吃几顿黄粱饭。',120,'元曲/yuanqu.json','["犹兀自骑着个大肚驴，吃几顿黄粱饭。", "则今日有缘游阆苑，可正是无梦到邯郸。", "(云)有人说道，你这等醉生梦死的，那神仙大道却怎生得来？(唱)休笑我行步艰难，无症候装些残患。", "如今便岳阳楼来了两番，空听的骇浪惊涛，(带云)呆汉子，(唱)洗不净愚眉肉眼。"]'),
('yuanqu-9976','吕洞宾三醉岳阳楼・贺新郎','马致远','元','元曲','yuanqu','','[]','你看那龙争虎斗旧江山。',213,'元曲/yuanqu.json','["你看那龙争虎斗旧江山。", "(郭云)你笑甚么？(正末唱)我笑那曹操奸雄。", "(郭云)你哭甚么？(正末唱)我哭呵，哀哉霸王好汉。", "(郭云)老师父，你怎么哭了又笑，笑了又哭？(正末唱)为兴亡笑罢还悲叹，不觉的斜阳又晚。", "咱想这百年人则在这捻指中间。", "(郭云)不争老师父在楼上玩赏，可不搅了我茶客。", "(正末唱)空听得楼前茶客闹，争似江上野鸥闲。", "百年人光景皆虚幻。", "(正末看科)(郭云)我也学你看一看。", "(正末唱)我觑你一株金线柳，犹兀自闲凭着十二玉栏干。"]'),
('yuanqu-9977','吕洞宾三醉岳阳楼・梧桐树','马致远','元','元曲','yuanqu','','[]','你道是两碗通轻汗，独不闻一粒度三关。',42,'元曲/yuanqu.json','["你道是两碗通轻汗，独不闻一粒度三关。", "管甚么锟饨皮馒头馅和和剩饭，总是个有酒食先生馔。"]'),
('yuanqu-9978','吕洞宾三醉岳阳楼・隔尾','马致远','元','元曲','yuanqu','','[]','你休道这乞儿披定羊皮懒，你会首休猜做大卧单。',182,'元曲/yuanqu.json','["你休道这乞儿披定羊皮懒，你会首休猜做大卧单。", "(云)马儿，你吃了三盏茶，无一盏真的。", "(郭云)怎生无有一盏真的？(正末唱)我吐与你木瓜里枣、酥佥里脂、杏汤里瓣。", "(云)马儿，你吃了者。", "(郭云)吃不得。", "只恁般左难、右难。", "(云)马儿，吃了者。", "(郭云)其实吃不得。", "(正末云)你不吃，接了盏者。", "(正末哄科，云)打碎了盏儿也。", "(郭云)倒吓我一惊。", "(正末唱)我看你怎发付松风兔毛盏。"]'),
('yuanqu-9979','吕洞宾三醉岳阳楼・牧羊关','马致远','元','元曲','yuanqu','','[]','这吐也无那竹叶云涛泛，也无那石铛雪浪翻。',98,'元曲/yuanqu.json','["这吐也无那竹叶云涛泛，也无那石铛雪浪翻。", "这吐呵但开口满帘香散，更压着仙酒延年，更压着蟠桃般驻颜。", "也不索采蒙顶山头雪，也不索茶点鹧鸪斑。", "比尔你吸引扬子江心水，(带云)马儿也，(唱)可强似汤生螃蟹眼。"]'),
('yuanqu-9980','吕洞宾三醉岳阳楼・红芍药','马致远','元','元曲','yuanqu','','[]','把一片岁寒心烧做了火炎山，哎，你弟子好是凶顽。',149,'元曲/yuanqu.json','["把一片岁寒心烧做了火炎山，哎，你弟子好是凶顽。", "(郭扯袍科)(正末唱)把一领布袍襟扯住不容还，碎纷纷直似灵幡。", "(郭打科)(正末唱)打的我比春牛少片板，总是我不合劝修行吐尽心肝。", "(云)郭马儿，你休恼了我也。", "(郭云)恼了你，可怎么的我？(正末唱)把岳阳楼翻做鬼门关，休只管卖弄拳儇。", "(郭打科)(正末唱)。"]'),
('yuanqu-9981','吕洞宾三醉岳阳楼・哭皇天','马致远','元','元曲','yuanqu','','[]','我着你早寻个香火新公案，煞强似久堕风尘大道间。',132,'元曲/yuanqu.json','["我着你早寻个香火新公案，煞强似久堕风尘大道间。", "只为你瘦伶仃无人盼，才长大便争攀。", "若不是我把长条自挽，则你在洞庭湖上，扬子江边，受了些风吹日炙，雪压霜欺，险些儿做了这岳阳楼、岳阳楼酒望竿。", "(郭云)我就跟你出家去，有甚么好处？(正末唱)我着你逍遥散诞，你自待偎慵惰懒。"]'),
('yuanqu-9982','吕洞宾三醉岳阳楼・乌夜啼','马致远','元','元曲','yuanqu','','[]','愁甚么楚王宫陶令宅隋堤岸，我已安排下玉砌雕阑。',94,'元曲/yuanqu.json','["愁甚么楚王宫陶令宅隋堤岸，我已安排下玉砌雕阑。", "则要你早回头静坐把功程办，参透玄关，勘破尘环。", "待学他严子陵隐在钓鱼滩，管甚么张子房烧了连云栈。", "竞利名，为官宦；都只为半张字纸，却做了一枕槐安。"]'),
('yuanqu-9983','吕洞宾三醉岳阳楼・三煞','马致远','元','元曲','yuanqu','','[]','想人能克己身无患，事不欺心睡自安，便百年能得几时闲？去向那石火光中，急措手如何迭办？你何不早回看，直到落日桑榆暮景残，方才道倦鸟知还。',67,'元曲/yuanqu.json','["想人能克己身无患，事不欺心睡自安，便百年能得几时闲？去向那石火光中，急措手如何迭办？你何不早回看，直到落日桑榆暮景残，方才道倦鸟知还。"]'),
('yuanqu-9984','吕洞宾三醉岳阳楼・二煞','马致远','元','元曲','yuanqu','','[]','争如我盖间茅屋临幽涧，披片麻衣坐法坛。',103,'元曲/yuanqu.json','["争如我盖间茅屋临幽涧，披片麻衣坐法坛。", "倒也躲是非忘宠辱无牵绊，不强似你在人我场中，把个茶博士终朝淘渲。", "(做笑科，云)郭马儿，你及早省悟，也是迟了。", "(唱)我笑你忒愚顽，枉了我度你亲身三两番，还不省也天上人间。"]'),
('yuanqu-9985','吕洞宾三醉岳阳楼・黄钟尾','马致远','元','元曲','yuanqu','','[]','我着你看蓝采和舞春风六扇云阳板。',228,'元曲/yuanqu.json','["我着你看蓝采和舞春风六扇云阳板。", "(郭云)那一个呢？(正末唱)我着你看韩湘子开冬雪双茎锦牡丹。", "疾回头莫怠慢。", "(郭云)师父，我送你下楼去。", "(正末唱)下江楼近水湾。", "(云)呀，徐神翁等不的我，先去了也。", "(郭云)在那里？(正末唱)你与我撑开船，挂起帆。", "(云)郭马儿，上船来。", "(郭云)你先上船。", "(正末云)我先上船。", "(郭推正末科，云)推他娘在这水里。", "(正末云)呀，这厮险些儿不闪我在水里！(唱)行至蓬莱宫方丈山，俺那伙送行人世不曾西出阳关，早则不凝望渭城和泪眼。", "(下)。"]'),
('yuanqu-9986','吕洞宾三醉岳阳楼・仙吕/赏花时','马致远','元','元曲','yuanqu','','[]','这剑曾伴我三十年来海上游，夜夜光芒射斗牛。',122,'元曲/yuanqu.json','["这剑曾伴我三十年来海上游，夜夜光芒射斗牛。", "(云)郭马儿，我与你这一口剑，要些回答的礼物。", "(郭云)可要甚么回奉的礼物？(正末唱)要一颗血沥沥妇人头。", "(郭云)好容易也。", "(正末唱)为你这墙花路柳，(带云)若不是恁两个呵，(唱)谁肯三醉岳阳楼。", "(下)。"]'),
('yuanqu-9987','吕洞宾三醉岳阳楼・正宫/端正好','马致远','元','元曲','yuanqu','','[]','我劝你世间人，休争气，及早的归去来兮。',36,'元曲/yuanqu.json','["我劝你世间人，休争气，及早的归去来兮。", "可乾坤做一床黄绸被，单搦着陈抟睡。"]'),
('yuanqu-9988','吕洞宾三醉岳阳楼・滚绣球','马致远','元','元曲','yuanqu','','[]','我穿着领布懒衣，不吃烟火食。',88,'元曲/yuanqu.json','["我穿着领布懒衣，不吃烟火食。", "淡则淡淡中有味，又不是坐崖头打当牙椎。", "人问我姓甚的，住那里，要寻我煞是容易：酒排沙紧对着钟离。", "怕你虎狼丛吃闪呆獐般看，是非海淹着死马儿医。", "树倒风吹。"]'),
('yuanqu-9989','吕洞宾三醉岳阳楼・倘秀才','马致远','元','元曲','yuanqu','','[]','你在当街上把师父扯曳，这是我劝弟子修行的气力。',76,'元曲/yuanqu.json','["你在当街上把师父扯曳，这是我劝弟子修行的气力。", "(郭打科，云)我打你个弟子孩儿！(正末云)你打不的。", "(唱)打、打、打今世饶人不是痴，天生下、这顽皮，壮吃。"]'),
('yuanqu-9990','吕洞宾三醉岳阳楼・倘秀才','马致远','元','元曲','yuanqu','','[]','我不信那官人敢断谁，则为你愚不省将勾头来吊你，正是俺自有心猿百字碑。',51,'元曲/yuanqu.json','["我不信那官人敢断谁，则为你愚不省将勾头来吊你，正是俺自有心猿百字碑。", "哎，村物事，泼东西，怎到得那里？。"]'),
('yuanqu-9991','吕洞宾三醉岳阳楼・滚绣球','马致远','元','元曲','yuanqu','','[]','俺那里白云自在飞，仙鹤出入随。',220,'元曲/yuanqu.json','["俺那里白云自在飞，仙鹤出入随。", "俺那里洞门不闭。", "(郭云)师父，则怕那里有俺媳妇么？(正末唱)你可也再休题家有贤妻。", "(郭云)师父，这里是那里？(正末云)马儿，你看波。", "(唱)这壁银河织女机，那壁洞中玉女扉，怎发付你那酒色财气。", "则你那送行人何曾道展眼舒眉，你是个红尘道上千年柳，你觑波白玉堂前一树梅。", "(旦儿上)(郭见科，云)兀的不是我浑家贺腊梅哩！(正末云)疾！(旦下)(郭云)师父，俺媳妇那里去了？才在这里，怎生不见了！(正末唱)怎知这就里玄机。"]'),
('yuanqu-9992','吕洞宾三醉岳阳楼・伴读书','马致远','元','元曲','yuanqu','','[]','你道是花枝儿媳妇天然美，又道是笋条儿一对青年纪；端的谁遣来两个成匹配，到今日又谁拆散你这芳连理？可怎生不解其中意，还认作儿女夫妻！。',66,'元曲/yuanqu.json','["你道是花枝儿媳妇天然美，又道是笋条儿一对青年纪；端的谁遣来两个成匹配，到今日又谁拆散你这芳连理？可怎生不解其中意，还认作儿女夫妻！。"]'),
('yuanqu-9993','吕洞宾三醉岳阳楼・笑和尚','马致远','元','元曲','yuanqu','','[]','我、我、我要你媳妇儿做甚的，你、你、你扭住我欲何为？敢、敢、敢挟着这一纸文书的势，看、看、看你媳妇儿在那里；有、有、有谁是个杀人贼，来、来、来咱和你去当官对。',79,'元曲/yuanqu.json','["我、我、我要你媳妇儿做甚的，你、你、你扭住我欲何为？敢、敢、敢挟着这一纸文书的势，看、看、看你媳妇儿在那里；有、有、有谁是个杀人贼，来、来、来咱和你去当官对。"]'),
('yuanqu-9994','吕洞宾三醉岳阳楼・双调/新水令','马致远','元','元曲','yuanqu','','[]','则这杀人贼须是你护身符，教你做神仙悟也不悟。',97,'元曲/yuanqu.json','["则这杀人贼须是你护身符，教你做神仙悟也不悟。", "你看承我做酒布袋，请看这药葫芦；不是村夫，还有三卷天书。", "(郭云)甚么天书，敢是化缘的疏头。", "(正末唱)你休猜做化缘疏。", "(郭扯末云)告官去来。", "(正末唱)。"]'),
('yuanqu-9995','吕洞宾三醉岳阳楼・沉醉东风','马致远','元','元曲','yuanqu','','[]','是我绾角儿缩缘伴侣，垂髫时儿女妻夫。',90,'元曲/yuanqu.json','["是我绾角儿缩缘伴侣，垂髫时儿女妻夫。", "是我的媳妇儿？泼男女，尚古自参不透野花村务。", "(郭云)你是个出家人，如何要老婆？(正末唱)道士须当配道姑。", "(带云)呆汉！(唱)则俺两口儿先生姓吕。"]'),
('yuanqu-9996','吕洞宾三醉岳阳楼・梅花酒','马致远','元','元曲','yuanqu','','[]','想您个匹夫，不识贤愚。',77,'元曲/yuanqu.json','["想您个匹夫，不识贤愚。", "蠢蠢之物，落落之徒，休猜俺做左道术。", "俺自拿着捩鼻木，您拽着我布道服；俺急切里要回去，您当街里缠师父。", "俺为甚的不言语，您心下儿自踌躇。"]'),
('yuanqu-9997','吕洞宾三醉岳阳楼・收江南','马致远','元','元曲','yuanqu','','[]','俺则待朗吟飞过洞庭湖，您在茶坊中说甚蜜和酥。',76,'元曲/yuanqu.json','["俺则待朗吟飞过洞庭湖，您在茶坊中说甚蜜和酥。", "(外扮孤一行上，云)甚么人乱嚷，与我拿过来者！(正末唱)扇圈般一部落腮胡，更狠似道录，马头前不慌杀了贺仙姑。"]'),
('yuanqu-9998','吕洞宾三醉岳阳楼・收尾','马致远','元','元曲','yuanqu','','[]','则我向岳阳楼来往经三度，指引你双归紫府。',40,'元曲/yuanqu.json','["则我向岳阳楼来往经三度，指引你双归紫府。", "方才识仙家的日月长，再不受人间的斧斤苦。"]'),
('yuanqu-9999','双调・蟾宫曲昭君','武林隐','元','元曲','yuanqu','','[]','天风瑞雪剪玉蕊冰花，驾单车明妃无情无绪，气结愁云，泪湿腮霞。',113,'元曲/yuanqu.json','["天风瑞雪剪玉蕊冰花，驾单车明妃无情无绪，气结愁云，泪湿腮霞。", "只见十程五程，峻岭嵯峨，停骖一顾，断人肠际碧离天漠漠寒沙。", "只见三对两对搠旌旗古道西风瘦马，千点万点噪疏林老树昏鸦。", "哀哀怨怨，一曲琵琶，没撩没乱离愁悲悲切切，恨满天涯。"]'),
('yuanqu-10000','双调・蟾宫曲题《录鬼簿》','周浩','元','元曲','yuanqu','','[]','想贞元朝士无多，满目江山，日月如梭。',69,'元曲/yuanqu.json','["想贞元朝士无多，满目江山，日月如梭。", "上苑繁华，西湖富贵，总付高歌。", "麒麟冢衣冠坎坷，凤凰城人物蹉跎。", "生待如何？死待如何？纸上清名，万古难靡。"]'),
('yuanqu-10001','宜秋山赵礼让肥・仙吕/点绛唇','秦简夫','元','元曲','yuanqu','','[]','这些时囊箧消乏，又值着米粮增价，忧愁杀。',123,'元曲/yuanqu.json','["这些时囊箧消乏，又值着米粮增价，忧愁杀。", "一日三衙，几度添白发。", "(赵孝云)母亲，想俺弟兄两个，空学成满腹文章。", "俺只在这山中负薪，兄弟采些野菜药苗，似此充饥，几时是俺弟兄们发达的时节也？(正末云)哥哥，母亲年纪高大，俺正是家贫亲老，如之奈何？(唱)。"]'),
('yuanqu-10002','宜秋山赵礼让肥・混江龙','秦简夫','元','元曲','yuanqu','','[]','待着峰粗粝，眼睁睁俺子母各天涯。',119,'元曲/yuanqu.json','["待着峰粗粝，眼睁睁俺子母各天涯。", "想起来我心如刀割，题起来我泪似悬麻。", "饿杀人也无米无柴腹内饥，痛杀人也好儿好女眼前花。", "恢恢天网，漫漫黄沙，我一身饿死，四海无家。", "眼看得青云兄长事无成，可怜我白头老母年高大。", "压的我这双肩苦痛，走的我这两腿酸麻。"]'),
('yuanqu-10003','宜秋山赵礼让肥・油葫芦','秦简夫','元','元曲','yuanqu','','[]','子母哀哉苦痛杀，恨转加，我这里举头一望好嗟呀！伤心老母难安插，空对着赏心山色堪图画。',74,'元曲/yuanqu.json','["子母哀哉苦痛杀，恨转加，我这里举头一望好嗟呀！伤心老母难安插，空对着赏心山色堪图画。", "故园风落花，荒村水褪沙。", "俺只见斜阳一带林梢挂，掩映着茅舍两三家。"]'),
('yuanqu-10004','宜秋山赵礼让肥・天下乐','秦简夫','元','元曲','yuanqu','','[]','我则见落日平林噪晚鸦，火涯，何处家？则俺那弟兄每日月好是难过咱。',57,'元曲/yuanqu.json','["我则见落日平林噪晚鸦，火涯，何处家？则俺那弟兄每日月好是难过咱。", "母亲也年纪高，穴臣刂力乏，被这些穷家活把他没乱煞。"]'),
('yuanqu-10005','宜秋山赵礼让肥・鹊踏枝','秦简夫','元','元曲','yuanqu','','[]','他可也忒矜夸、忒豪华，争知俺少米无柴，怎地存札？子母每看看的饿杀，天那！则亏着俺这百姓人家。',46,'元曲/yuanqu.json','["他可也忒矜夸、忒豪华，争知俺少米无柴，怎地存札？子母每看看的饿杀，天那！则亏着俺这百姓人家。"]'),
('yuanqu-10006','宜秋山赵礼让肥・寄生草','秦简夫','元','元曲','yuanqu','','[]','饿的这民饥色，看看的如蜡渣。',451,'元曲/yuanqu.json','["饿的这民饥色，看看的如蜡渣。", "他每都家家上树把这槐芽掐，他每都村村沿道将偷皮剐，人每都人人绕户将粮食化。", "(赵孝云)兄弟，俺如今衣不遮身。", "食不充口。", "兀的不穷杀俺也！(正末唱)现如今弟兄衣袂不遮身，可着纶贫寒子母无安下。", "(云)我安排些饭食，与母亲食用咱。", "(赵孝云)兄弟，你则在这里守着母亲，我安排去。", "(正末云)哥哥陪侍母亲说话，你兄弟去。", "(卜儿云)你两个孩儿休去！老身安排去。", "(正末云)母亲坐的。", "您孩儿去这轿儿后面，还有一把儿米，就着这涧泉水，我淘了这米，拾的一把儿柴，兀的那一家儿人家！我去讨一把儿火。", "庄院里有人么？(丑扮都子开门科，云)是谁唤门哩？(正末云)我来讨一把儿火来。", "(都子云)兀的是火。", "等你做罢饭时，剩的刷锅水儿留些与我。", "(正末云)你要做甚么？(都子云)我要充饥哩。", "(下)(正末云)俺穷则穷，更有穷似俺的。", "我吹着这火，可早粥熟了也。", "哥哥，请母亲食用。", "这一碗与哥哥食用。", "(赵孝递粥科)(卜儿云)赵礼孩儿有么？(正末云)母亲，您孩儿有。", "(赵孝云)兄弟，你有么？(正末云)哥哥，您兄弟有了也。", "(唱)。"]'),
('yuanqu-10007','宜秋山赵礼让肥・醉扶归','秦简夫','元','元曲','yuanqu','','[]','我吃的这茶饭有难消化，母亲那肌肤瘦力衰乏。',163,'元曲/yuanqu.json','["我吃的这茶饭有难消化，母亲那肌肤瘦力衰乏。", "(卜儿云)可怎生孩儿碗里无粥汤。", "(正末云)母亲，你孩儿吃了也。", "(赵孝云)母亲，你看兄弟拿着个空碗儿哩。", "(正末云)哥哥，您兄弟有。", "(唱)量这半杓儿粥都添了有甚那？转着这空碗儿我着这匙尖儿刮，我陪着个笑脸儿百般的喜洽。", "(背云)母亲今日吃了这些粥汤，明日吃甚么那？(唱)不由我泪不住行儿下。"]'),
('yuanqu-10008','宜秋山赵礼让肥・青哥儿','秦简夫','元','元曲','yuanqu','','[]','他一声声向咱向咱抄化，我羞答答将甚些甚些赍发？可怜我也万苦千辛度命咱。',97,'元曲/yuanqu.json','["他一声声向咱向咱抄化，我羞答答将甚些甚些赍发？可怜我也万苦千辛度命咱。", "现如今心似油炸，肉似钩搭，死是七八，那个提拔？(带云)母亲！哥哥！(唱)似这般凄凄凉凉，波波渌渌，今夜宿谁家？多管在茅檐下。"]'),
('yuanqu-10009','宜秋山赵礼让肥・赚煞尾','秦简夫','元','元曲','yuanqu','','[]','我口不觉开合，脚不知高下，我则见天转山摇地塌。',155,'元曲/yuanqu.json','["我口不觉开合，脚不知高下，我则见天转山摇地塌。", "(跌科)(卜儿云)孩儿，你敢无食力么？(正末云)母亲，您孩儿没用，倒吓着母亲也。", "(唱)不是我无食力身躯闪这一滑，多管是少人行山路凹凸。", "(带云)母亲。", "(唱)你莫叫吖吖，你孩儿水米不曾粘牙，看来日饥时俺吃甚么？不冻杀多应饿杀。", "眼见的山间林下，可怜身死野人家。", "(同下)。"]'),
('yuanqu-10010','宜秋山赵礼让肥・正宫/端正好','秦简夫','元','元曲','yuanqu','','[]','则我这身似病中鹤，心若云间鹗，我本待要驾清风万里扶摇。',44,'元曲/yuanqu.json','["则我这身似病中鹤，心若云间鹗，我本待要驾清风万里扶摇。", "半生四海无着落，空着我穷似投林鸟。"]'),
('yuanqu-10011','宜秋山赵礼让肥・倘秀才','秦简夫','元','元曲','yuanqu','','[]','我绕着这浅水深山寻些个中吃无毒的药苗，我行过这高岭长堤采些个叶嫩枝新的野蒿。',70,'元曲/yuanqu.json','["我绕着这浅水深山寻些个中吃无毒的药苗，我行过这高岭长堤采些个叶嫩枝新的野蒿。", "吃了呵则愿的年老的尊堂得安乐，挨日月，度昏朝，我猛转过山林隘角。"]'),
('yuanqu-10012','宜秋山赵礼让肥・呆骨朵','秦简夫','元','元曲','yuanqu','','[]','我辞一辞呵着俺那年高老母知一个消耗。',151,'元曲/yuanqu.json','["我辞一辞呵着俺那年高老母知一个消耗。", "(带云)太仆！(唱)岂不闻道是哀哀父母劬劳？(马武云)你辞那母亲怎的？(正末唱)争奈俺老母年高，家兄软弱。", "(马武云)对你哥哥说些甚么？(正末唱)我着俺哥哥行仁孝，将俺那老母恩临报。", "(马武云)某不放你去！(正末唱)你做的个损别人安自己；母亲也，你可甚么养小来防备老！。"]'),
('yuanqu-10013','宜秋山赵礼让肥・倘秀才','秦简夫','元','元曲','yuanqu','','[]','走的我这口枯渴热烘烘面皮上浑如火燎，走的我遍体汗湿渌渌浑如水浇。',175,'元曲/yuanqu.json','["走的我这口枯渴热烘烘面皮上浑如火燎，走的我遍体汗湿渌渌浑如水浇。", "(云)到家中，母亲道：孩儿你来了也。", "(唱)我可甚么买卖归米汗未消？(云)母亲，开门来！开门来！你孩儿来了也。", "(见科，卜儿云)孩儿，你这般慌做甚么？(正末唱)我入门来他问个端的，我欲待要说根苗。", "(云)您孩儿恰才山中撞……(卜儿云)孩儿，你撞着甚么来？(正末唱)一句话到我这舌尖上我便咽了。"]'),
('yuanqu-10014','宜秋山赵礼让肥・滚绣球','秦简夫','元','元曲','yuanqu','','[]','您儿恰才山中觅吃食，不想疏林外遇着贼盗。',113,'元曲/yuanqu.json','["您儿恰才山中觅吃食，不想疏林外遇着贼盗。", "他那片杀人心可敢替天行道，他便待下山来将您儿紧紧的相邀。", "他那里茶饭忒整齐，筵席忒宽绰，这恩临可端的杀身难报，他行那管夷吾德行才学。", "在先结下知心友，我可敢道今日番为刎颈交，也是我命运州招。"]'),
('yuanqu-10015','宜秋山赵礼让肥・二煞','秦简夫','元','元曲','yuanqu','','[]','你道是办着一个耐心儿三口亲身告，恼犯那贼人瞪眼把俺来杀坏了。',107,'元曲/yuanqu.json','["你道是办着一个耐心儿三口亲身告，恼犯那贼人瞪眼把俺来杀坏了。", "我宁可身做自当，自遭自受；我怎肯愁死愁生，向他行求免求饶！(带云)母亲。", "(唱)你省可里啼啼哭哭。", "怨怨哀哀，忄敞忄敞焦焦。", "我奈家贫也那亲老，穷火院怎生熬？。"]'),
('yuanqu-10016','宜秋山赵礼让肥・一煞','秦简夫','元','元曲','yuanqu','','[]','我共埯哥哥半生情分干休了。',158,'元曲/yuanqu.json','["我共埯哥哥半生情分干休了。", "(带云)母亲！(唱)这的是你养儿女一世前程无下梢。", "我不能勾进取功名，干撇下母亲兄长，割舍我七尺身躯，和这满腹文学。", "(云)母亲请坐！受您孩儿几拜。", "(唱)我这里拜辞在阶下，知咱每相见在何年？不想我死在今朝。", "(卜儿云)孩儿也！等哥哥见一面去也好。", "(正末唱)我也等不的哥哥来到，怎肯失口信与儿曹！。"]'),
('yuanqu-10017','宜秋山赵礼让肥・随煞尾','秦简夫','元','元曲','yuanqu','','[]','我猛然拜罢那双脚。',127,'元曲/yuanqu.json','["我猛然拜罢那双脚。", "(卜儿哭云)儿也！则被你痛杀我也！(正末唱)哎呀！不阻防脑背后番身吃一交。", "(带云)母亲！(唱)那残病的身躯省懊恼，鼻痛心酸两泪抛，腹热肠慌乱刀绞。", "我想他毒害的强贼，我今日死不可逃。", "母亲也，则您这生分的孩儿，我其实送不的你那老！(哭下)。"]'),
('yuanqu-10018','宜秋山赵礼让肥・凭阑人','秦简夫','元','元曲','yuanqu','','[]','由你将我身躯七事子开，由你将我心肝一件件摘。',109,'元曲/yuanqu.json','["由你将我身躯七事子开，由你将我心肝一件件摘。", "我道来、我道来，除死呵无大灾。", "(赵孝慌上，云)那里不寻我那兄弟？兀那里不是我兄弟！(赵孝见正末哭科，云)兄弟，痛杀我也！(马武云)好、好、好，又走将一头牛来了也。", "(正末唱)。"]'),
('yuanqu-10019','宜秋山赵礼让肥・秃厮儿','秦简夫','元','元曲','yuanqu','','[]','至死也休将口开，谁着你杀人处钻出头来？这搭儿里问甚好共歹。',41,'元曲/yuanqu.json','["至死也休将口开，谁着你杀人处钻出头来？这搭儿里问甚好共歹。", "也是我年月日时衰，应该。"]'),
('yuanqu-10020','宜秋山赵礼让肥・络丝娘','秦简夫','元','元曲','yuanqu','','[]','我只道你杀人刀十分的利害，元来这活人心依然尚在。',50,'元曲/yuanqu.json','["我只道你杀人刀十分的利害，元来这活人心依然尚在。", "便做道俺两个该死的游魂甚耽待，也则是可怜见白头奶奶。"]'),
('yuanqu-10021','宜秋山赵礼让肥・东原乐','秦简夫','元','元曲','yuanqu','','[]','敢道是凶年岁，瘦骨骸，便剐将来也填不满一餐债。',57,'元曲/yuanqu.json','["敢道是凶年岁，瘦骨骸，便剐将来也填不满一餐债。", "因此在饿虎喉中乞得这免死牌，蒙恩贷。", "从今后遥望着你的营门常常礼拜！。"]'),
('yuanqu-10022','宜秋山赵礼让肥・收尾','秦简夫','元','元曲','yuanqu','','[]','稳情取马步禁军都元帅。',111,'元曲/yuanqu.json','["稳情取马步禁军都元帅。", "骨剌刺两面门旗展开。", "(带云)写着道是：风高放火，月黑杀人；图财致命，你死我活。", "(唱)我将你九江四海是非心，(带云)倒换做腰悬金印，身挂虎符，名标青史，图像麒麟。", "(唱)兀的万古千年那姓名来改。", "(并下)。"]'),
('yuanqu-10023','宜秋山赵礼让肥・双调/新水令','秦简夫','元','元曲','yuanqu','','[]','贤臣良将保銮舆，正遇着得收成太平时序。',46,'元曲/yuanqu.json','["贤臣良将保銮舆，正遇着得收成太平时序。", "一人元有庆，四海永无虞。", "顿首山呼，显见的圣大子百灵助。"]'),
('yuanqu-10024','宜秋山赵礼让肥・沉醉东风','秦简夫','元','元曲','yuanqu','','[]','想当时受尽了千辛万苦，谁承望有今日驷马安车。',67,'元曲/yuanqu.json','["想当时受尽了千辛万苦，谁承望有今日驷马安车。", "随着这同胞共乳兄，将着俺皓首苍颜母，稳请受皇家俸禄。", "煞强似一片荒山掘野蔬，才得个平生愿足。"]'),
('yuanqu-10025','宜秋山赵礼让肥・挂玉钩','秦简夫','元','元曲','yuanqu','','[]','吓的我手儿脚儿滴羞蹀躞战笃速。',118,'元曲/yuanqu.json','["吓的我手儿脚儿滴羞蹀躞战笃速。", "(马武云)贤士，你怕甚么？(正末唱)想着你那摘胆剜心处。", "(马武云)宜秋山下不成一个管待，至今犹自惭愧。", "(正末唱)当日个管待杀我也峨冠士大夫，谁想道这搭儿重相遇。", "多谢你个架海梁、擎大柱！生死难忘，今古谁如？。"]'),
('yuanqu-10026','宜秋山赵礼让肥・雁儿落','秦简夫','元','元曲','yuanqu','','[]','休道是莽将军不重儒，肯放我泼书生还奉母。',41,'元曲/yuanqu.json','["休道是莽将军不重儒，肯放我泼书生还奉母。", "既当日你金银曾受来，我如今这酬答何推拒？。"]'),
('yuanqu-10027','宜秋山赵礼让肥・得胜令','秦简夫','元','元曲','yuanqu','','[]','我可也须识报恩珠，怎敢便不饮盗泉余！若非你肯发慈悲念，准替咱存留冻饿躯？(马武云)贤士，你两个那孝顺不必说了；久闻你学问过人，文章盖世，直到今日，举荐入朝，也是',114,'元曲/yuanqu.json','["我可也须识报恩珠，怎敢便不饮盗泉余！若非你肯发慈悲念，准替咱存留冻饿躯？(马武云)贤士，你两个那孝顺不必说了；久闻你学问过人，文章盖世，直到今日，举荐入朝，也是迟哩！(正末唱)嗟吁！还说甚有学问千金赋，踌躇，干着了荐贤良一纸书。"]'),
('yuanqu-10028','宜秋山赵礼让肥・沽美酒','秦简夫','元','元曲','yuanqu','','[]','离家乡万里途，要囊箧一文无，本是桑间一饿夫。',70,'元曲/yuanqu.json','["离家乡万里途，要囊箧一文无，本是桑间一饿夫。", "今日做朝中宰辅，享荣华改门户。", "(邓禹云)贤士，这就是马武元帅举荐你来，老夫何功之有？(正末唱)。"]'),
('yuanqu-10029','宜秋山赵礼让肥・太平令','秦简夫','元','元曲','yuanqu','','[]','我只道保奏的是当朝邓禹，却原来是马武一力吹嘘。',69,'元曲/yuanqu.json','["我只道保奏的是当朝邓禹，却原来是马武一力吹嘘。", "但平生我和他有何知遇？多则是大也有安排我处。", "自语，甚福？托赖着帝主，则愿的万万岁民安国富！。"]'),
('yuanqu-10030','阀阅舞射柳蕤丸记・仙吕/点绛唇','无名氏','元','元曲','yuanqu','','[]','宰臣每燮则阴阳，圣朝卿相，一个个忠君上，立国安邦，扶持万载山河壮。',84,'元曲/yuanqu.json','["宰臣每燮则阴阳，圣朝卿相，一个个忠君上，立国安邦，扶持万载山河壮。", "(陈尧佐云)当今圣人治世，德化千邦，万国进贡，内外文臣武职，端的是赤心扶圣主，坚意保皇朝。", "(正末唱)。"]'),
('yuanqu-10031','阀阅舞射柳蕤丸记・混江龙','无名氏','元','元曲','yuanqu','','[]','文臣武将，申明教化振纲常，文臣每扶持社稷，武将每肃静边疆。',415,'元曲/yuanqu.json','["文臣武将，申明教化振纲常，文臣每扶持社稷，武将每肃静边疆。", "常则要守法奉公理庶民，屏邪除佞进忠良。", "见如今明君治世乾坤旺。", "(陈尧佐云)当今圣人，孝治天下，臣宰良贤，坚刚节操，秉性忠直，端的是秋毫无所犯，直正坐都堂也。", "(正末唱)俺若是一心行正，落一个万古名扬。", "(陈尧佐云)说话中间，可早来到也。", "左右人报复去，道有唐介，陈尧佐在于门首。", "(祗从云)理会的。", "(做报科，云)报的大人得知，有唐介，陈尧佐在于门首。", "(范仲淹云)道有请。", "(祗从云)理会的。", "有请。", "(正末陈尧佐同见科)(正末云)老相公，众官人勿罪也。", "(陈尧佐云)老相公会俺八府众官，有何事商议也？(范仲淹云)您众官人每都来了也。", "老夫非为私事，奉圣人的命，为因直北雁门关外，有一人乃是耶律万户，见今手下有数十万雄兵，此人虎视群雄，侵扰边境，他不从俺调，今要统兵征伐，争柰此人英雄难敌，十分利害，奉圣人的命，着老夫会您众官商议，可保举那一员上将，收捕虏寇去，您众官人可以深思也。", "(正末唱)。"]'),
('yuanqu-10032','阀阅舞射柳蕤丸记・油葫芦','无名氏','元','元曲','yuanqu','','[]','则说那虏寇军兵似虎狼，端的是难堵当。',152,'元曲/yuanqu.json','["则说那虏寇军兵似虎狼，端的是难堵当。", "(范仲淹云)说此人英雄赳赳，状貌堂堂，十分骁勇也。", "(正末唱)你道他雄威赳赳气昂昂，见如今无名草寇侵边上，他正是撩蜂剔蝎将残生丧。", "(范仲淹云)今日会您众官，可保那一员名将，收捕草寇去也。", "(正末唱)今日个会众官，这件事要主张。", "如今这英雄中选一个元戎将，则要他擒贼首伏戎羌。"]'),
('yuanqu-10033','阀阅舞射柳蕤丸记・哪吒令','无名氏','元','元曲','yuanqu','','[]','想当日指鸿沟，沛公和那霸正，运筹策，有范增共子房，驱铁骑，有周勃项庄。',152,'元曲/yuanqu.json','["想当日指鸿沟，沛公和那霸正，运筹策，有范增共子房，驱铁骑，有周勃项庄。", "(云)想韩信在项羽手下，不得意时，(唱)则做的个执戟郎，他难施展江湖量，他因此上背暗可便归降。", "(葛监军云)昔日韩信三荐登坛，不是我夸口，那个若荐我一荐，我连缸都蹬起来。", "(正末云)想韩信在沛公手下，沛公不识韩信，韩信夤夜私奔也。", "(唱)。"]'),
('yuanqu-10034','阀阅舞射柳蕤丸记・鹊踏枝','无名氏','元','元曲','yuanqu','','[]','若不是汉萧相，举贤良，不是他三荐登坛，怎能勾建节封王？(云)到后来韩信成了功呵。',436,'元曲/yuanqu.json','["若不是汉萧相，举贤良，不是他三荐登坛，怎能勾建节封王？(云)到后来韩信成了功呵。", "(唱)逼的一个楚重瞳至阴陵路上，他掣龙录自刎乌江。", "(范仲淹云)葛监军，便好道欲解倒悬之厄，须仗希世之才。", "今虏寇侵扰边境，须凭良将征之。", "您众官务要保举得力之人，攻拒草寇，平定寰区也。", "(葛监军云)老大人最是个聪明尚斯文的人，且休说我的人材貌相，若论我腹中的兵书，委的有神鬼不测之机，有捉鼠拿猫之法。", "我曾一箭射杀一个癞虾蟆，一枪扎死一个屎蜣螂。", "凭着我这么手段，量那虏寇，打甚么不紧。", "(范仲淹云)唐相公，圣人着您八府宰相，各人保举破虏之人，您众官在此，可端的保举何人去也？(正末云)相公，小官举一人，乃是娄宿太尉之子，完颜女直人氏，小字延寿马。", "此人骁勇，胆略过人，善能骑射，先帝手中，待罪在云中歇马，他手下有十万精兵。", "若得延寿马来，觑草寇一鼓而下，有何难哉。", "(范仲淹云)唐相公，你说延寿马骁勇过人，未知此人那刀马武艺、相持对垒如何？你说一遍，我试听者。", "(正末云)此人寸铁在手，有万夫不当之勇。", "(唱)。"]'),
('yuanqu-10035','阀阅舞射柳蕤丸记・寄生草','无名氏','元','元曲','yuanqu','','[]','他端的能征战，有胆量，他觑那三层鹿角如平荡，你看那七重围子直冲撞，他去那千军队里寻贼将。',485,'元曲/yuanqu.json','["他端的能征战，有胆量，他觑那三层鹿角如平荡，你看那七重围子直冲撞，他去那千军队里寻贼将。", "(净云)虽然他会武艺，他是个待罪歇马的人，又无甚么官职，他怎生掌的兵权？(正末唱)你道闲身怎敢掌兵权？可不道皇家选用忠良将。", "(净云)你无分晓，我为监军，你倒不保我，倒保延寿马，他怎生破的草寇？对着八府在此，那延寿马破不的耶律万户，他去不的。", "(吕夷简云)住，住，住，唐侍御，葛监军道延寿马去不的，他是监军，他当去。", "如今怎生着侍御保延寿马为先锋，葛监军为合后，恁的如何？(正末云)既然这般，葛监军你为合后，延寿马为先锋，你两个都到雁门关取齐，则要你得胜而回。", "(范仲淹云)既是这般呵，等取回延寿马来时，老夫自有主意，陈大人，(陈尧佐云)小官有。", "(范仲淹云)你今为使命，休避驱驰，直至云州，宣命延寿马去。", "将他在前罪犯，尽皆饶免，复还他旧职，就领他手下十万雄兵，与参谋使李信便赴京师，破虏之后，再有赐赏加官。", "则今日便索长行，老夫目今便去奏知圣人也。", "(陈尧佐云)小官理会的。", "(正末云)陈相公，国家用人之际，你不避驱驰，便索登程也。", "(陈尧佐云)相公，小官既为人臣，当以尽力，岂辞劳倦。", "(正末唱)。"]'),
('yuanqu-10036','阀阅舞射柳蕤丸记・尾声','无名氏','元','元曲','yuanqu','','[]','则今日赍圣敕出皇都，驰驿马须行上，直至那云州地方，说与那延寿马将军疾便往。',168,'元曲/yuanqu.json','["则今日赍圣敕出皇都，驰驿马须行上，直至那云州地方，说与那延寿马将军疾便往。", "(范仲淹云)着延寿马与参谋使李信，便赴京师。", "(正末唱)命参谋转运军粮，他若是领儿郎，摆列着阔剑长枪，恁时节得胜也鞭敲金镫响。", "(范仲淹云)他若破虏之后，自有重赏加封官。", "(正末唱)稳情取封官重赏，不枉了我举贤才的当，(云)若得了胜呵，(唱)那其间衣锦却还乡，(下)。"]'),
('yuanqu-10037','阀阅舞射柳蕤丸记・南吕/一枝花','无名氏','元','元曲','yuanqu','','[]','则要他黄公三略习，将吕望六韬记。',65,'元曲/yuanqu.json','["则要他黄公三略习，将吕望六韬记。", "摆顺天八卦盖，列五运转光旗。", "赳赳雄威，齐臻臻东西队，密匝匝前后围。", "锦衣郎枪挂珠璎，绣袄将幡悬画戟。"]'),
('yuanqu-10038','阀阅舞射柳蕤丸记・四块玉','无名氏','元','元曲','yuanqu','','[]','则说他有见识，则说他多智谋。',218,'元曲/yuanqu.json','["则说他有见识，则说他多智谋。", "(陈尧佐云)将军有伊吕之才，管乐之术，凭着你手下将勇兵强，无人可及。", "(正末唱)你道我将勇兵强有谁及，争奈待罪犯歇马在这云州地。", "(陈尧佐云)据将军文武高强，智勇并行，手下军校，人人敢勇，个个当先，谁人可敌？(正末唱)小官可也武艺低，手下可也军校微，(陈尧佐云)将军挂了元戎印者，若是迟误，便抗违宣敕也。", "(正末唱)我怎敢道违宣敕。", "(陈尧佐云)将军与参谋使李信，领你手下十万雄兵，休避驱驰，便索长行也。", "(正末唱)。"]'),
('yuanqu-10039','阀阅舞射柳蕤丸记・哭皇天','无名氏','元','元曲','yuanqu','','[]','既宣诏谁敢相回避，今日个便登程须索把军校齐。',111,'元曲/yuanqu.json','["既宣诏谁敢相回避，今日个便登程须索把军校齐。", "元帅印挂上，传号令您听者，指日把胡巢净洗。", "说与那参军副帅，合后先锋。", "支拨队伍，凋遣军卒。", "对阵处喧天呐喊，锣鼓声催，显的俺这大将军、人将军有八面威。", "摆列着戈矛斧钺，更和这枪刀剑戟。"]'),
('yuanqu-10040','阀阅舞射柳蕤丸记・乌夜啼','无名氏','元','元曲','yuanqu','','[]','俺这里人强马壮英雄队，摆列着杂彩征旗。',193,'元曲/yuanqu.json','["俺这里人强马壮英雄队，摆列着杂彩征旗。", "阵云高尘土遮天日，头戴军盔，身挂唐猊。", "剿除了残胡小丑逆大贼，托赖着圣明君洪福同天地。", "直赶到沙陀地，把那厮生擒斩首，稳情取得胜而回。", "(陈尧佐云)将军，你若到于京师，见了圣人，领兵拒敌，则要你赤心报国，竭力尽忠。", "若破了虏寇，得胜而回，那其间凌烟阁上标名，丹凤楼前画影，书入青史，万代流传，古今不朽也。", "(正末云)大人，想俺为臣者，当以尽忠报国也。", "(唱)。"]'),
('yuanqu-10041','阀阅舞射柳蕤丸记・尾声','无名氏','元','元曲','yuanqu','','[]','谁敢望麒麟阁上标名讳，我则待狼虎丛中决胜敌，平定了沙陀将大功立。',138,'元曲/yuanqu.json','["谁敢望麒麟阁上标名讳，我则待狼虎丛中决胜敌，平定了沙陀将大功立。", "托当今圣德，把匈奴每净洗，博一个万代名扬恁时节喜。", "(同李信下)(陈尧佐云)延寿马去了也。", "此人但若领兵，必然破了虏寇。", "小官回圣人话，走一遭去。", "全凭三略运机谋，为大帅统领戈矛。", "剿除了匈奴贼寇，受皇恩拜相封侯。", "(下)。"]'),
('yuanqu-10042','阀阅舞射柳蕤丸记・赏花时','无名氏','元','元曲','yuanqu','','[]','我这里深谢皇恩擢用臣，量这个愚鲁村夫有甚能。',115,'元曲/yuanqu.json','["我这里深谢皇恩擢用臣，量这个愚鲁村夫有甚能。", "(范仲淹云)将军有管仲之才，穰苴之略。", "(正末唱)将我似田穰苴的量看承，谢你个举贤才的晏婴，(范仲淹云)将军，则要你马到成功也。", "(正末云)大人放心。", "(唱)将丑虏生擒住献入这帝都城。", "(下)。"]'),
('yuanqu-10043','阀阅舞射柳蕤丸记・越调/斗鹌鹑','无名氏','元','元曲','yuanqu','','[]','战鼓声催，三军布摆。',96,'元曲/yuanqu.json','["战鼓声催，三军布摆。", "发喊连天，遮笼日色，凭着俺将勇兵强，威风气概。", "施战韬，显妙策。", "急风召风召杂彩旗摇，明晃晃枪刀器械。", "(李信云)将军，俺这一场征伐丑虏。", "不弱如古之名将，排兵布阵也。", "(正末唱)。"]'),
('yuanqu-10044','阀阅舞射柳蕤丸记・紫花儿序','无名氏','元','元曲','yuanqu','','[]','不弱如秦白起坑卒破赵，不弱如燕乐毅奋勇收齐，不弱如唐李朔。',29,'元曲/yuanqu.json','["不弱如秦白起坑卒破赵，不弱如燕乐毅奋勇收齐，不弱如唐李朔。"]'),
('yuanqu-10045','阀阅舞射柳蕤丸记・调笑令','无名氏','元','元曲','yuanqu','','[]','喝一声阵开。',117,'元曲/yuanqu.json','["喝一声阵开。", "好着我怒盈腮，好着我怒盟腮。", "呀，不刺刺一骑征马宛走到来，则见他横枪骤马将咱搦，你更怕我力尽筋衰。", "(万户云)兀那延寿马，量你那武艺，到的那里，及早下马受降，免你一死。", "(正末唱)我将这合扇刀举起劈他脑盖，我教你目前见横祸非灾。"]'),
('yuanqu-10046','阀阅舞射柳蕤丸记・圣药王','无名氏','元','元曲','yuanqu','','[]','我将这猿臂举，骤征马宛撞满怀。',147,'元曲/yuanqu.json','["我将这猿臂举，骤征马宛撞满怀。", "把钢刀举起觑个明白，他可便难措手，忙架解。", "四下厢军兵满野暗伏埋，着去则一箭生射下那厮战鞍来。", "(做射死耶律万户科)(李信云)将军是好武艺也，一箭射死耶律万户，一来托赖圣人洪福，二来是将军之功能也。", "(正末云)射死了耶律万户也，众军校跟随着某，追杀那败残军去来。", "(唱)。"]'),
('yuanqu-10047','阀阅舞射柳蕤丸记・尾声','无名氏','元','元曲','yuanqu','','[]','今日个感吾皇恩福齐天大，杀的他遍野尸山血海。',50,'元曲/yuanqu.json','["今日个感吾皇恩福齐天大，杀的他遍野尸山血海。", "今日个破草寇得功回，圣明主永掌山河万万载。", "(同李信下)。"]'),
('yuanqu-10048','阀阅舞射柳蕤丸记・双调/新水令','无名氏','元','元曲','yuanqu','','[]','忻逢佳节满皇都，贺端阳乐年欢助。',48,'元曲/yuanqu.json','["忻逢佳节满皇都，贺端阳乐年欢助。", "则见那锦衣悬彩仗，绣袄间公服。", "摆列着玉叶金簇，端的便屯满御园路。"]'),
('yuanqu-10049','阀阅舞射柳蕤丸记・乔牌儿','无名氏','元','元曲','yuanqu','','[]','我则见榴花恰喷吐，翠柳映微露。',30,'元曲/yuanqu.json','["我则见榴花恰喷吐，翠柳映微露。", "茸茸芳草生香浦，胜丹青如画图。"]'),
('yuanqu-10050','阀阅舞射柳蕤丸记・雁儿落','无名氏','元','元曲','yuanqu','','[]','锦标就地铺，翠柳阶傍竖。',30,'元曲/yuanqu.json','["锦标就地铺，翠柳阶傍竖。", "则听的箫韶彩仗摆，更和那鼓吹声喧助。"]'),
('yuanqu-10051','阀阅舞射柳蕤丸记・得胜令','无名氏','元','元曲','yuanqu','','[]','呀，我在这鞍上整彪躯，手内月弯弧。',251,'元曲/yuanqu.json','["呀，我在这鞍上整彪躯，手内月弯弧。", "远步马通先路，则他那双蹄口内吐。", "俺则辨个赢输，取胜如神助。", "(做射柳中科，云)射中了也。", "(唱)柳中这金镞，(云)监军，(唱)我和你敢再赌。", "(范仲淹云)延寿马射中了柳也。", "葛监军，你众官可打球门去。", "(葛监军云)这个可也不大紧，头里不干我事，是我这马眼叉把来走过去了。", "这打球门，我从小里可弄的熟。", "等我先打。", "(众做打球门科)(葛监军做打科，云)过去。", "(做打不中科)(范仲淹云)葛监军又打不中也。", "延寿马将军，你打球门去。", "(正末云)理会的。", "左右收了弓箭者。", "(正末做打球门科)(唱)。"]'),
('yuanqu-10052','阀阅舞射柳蕤丸记・川拨棹','无名氏','元','元曲','yuanqu','','[]','见花柳似锦模糊。',40,'元曲/yuanqu.json','["见花柳似锦模糊。", "贺蕤宾如画图。", "彩索灵符，酒泛菖蒲。", "丹漆盘包金角黍，巧结成香艾虎。"]'),
('yuanqu-10053','阀阅舞射柳蕤丸记・七弟兄','无名氏','元','元曲','yuanqu','','[]','明晃晃摆着利物，齐臻臻列着这士卒。',56,'元曲/yuanqu.json','["明晃晃摆着利物，齐臻臻列着这士卒。", "武将每一个个有机谋，施逞那武艺高强处。", "我恰才穿杨射柳定赢输，上雕鞍骤马当先去。"]'),
('yuanqu-10054','阀阅舞射柳蕤丸记・梅花酒','无名氏','元','元曲','yuanqu','','[]','呀，你可便看我结束头巾砌珍珠，绣袄子绒铺，闹妆带兔鹘。',75,'元曲/yuanqu.json','["呀，你可便看我结束头巾砌珍珠，绣袄子绒铺，闹妆带兔鹘。", "扑冬冬鼍鼓凯，骨刺刺锦旗舒。", "您可也众称许，款款的骤龙驹，轻轻的探身躯杓棒起月轮孤，彩球落晓星疏。"]'),
('yuanqu-10055','阀阅舞射柳蕤丸记・喜江南','无名氏','元','元曲','yuanqu','','[]','呀，我则见过球门一点透明珠，见文武将尽欢娱。',47,'元曲/yuanqu.json','["呀，我则见过球门一点透明珠，见文武将尽欢娱。", "金银玉带共香醑，圣人便赐与，则愿的万年千载永皇图。"]'),
('yuanqu-10056','阀阅舞射柳蕤丸记・折桂令','无名氏','元','元曲','yuanqu','','[]','今日个贺丰年锦绣皇都，(正末做拜科)(韩琦云)当今圣主，豁达大度，宽仁厚德，万民安乐，端的是千邦纳贡朝仁主，一统乾坤永圣明。',263,'元曲/yuanqu.json','["今日个贺丰年锦绣皇都，(正末做拜科)(韩琦云)当今圣主，豁达大度，宽仁厚德，万民安乐，端的是千邦纳贡朝仁主，一统乾坤永圣明。", "(正末唱)托赖着圣主宽仁，德胜唐虞。", "(韩琦云)大将威严，平定丑虏。", "(正末唱)见如今四海安宁，于邦纳土，一统车书。", "(正末做拜科)(韩琦云)为将者眠霜卧雪，多与皇家戮力。", "虽受了那百般苦楚，今日个坐享千钟。", "(正末唱)俺则待尽良忠开疆展土，辅助着万万年巩固皇图。", "(正末做拜科)(韩琦云)将军孝当竭力，于国尽忠，落一个青史标名。", "(正末唱)我如今秉笏披服，拜舞三呼。", "三舞蹈顿首减惶，赞明君慑伏的万国降服。", "(同下)。"]'),
('yuanqu-10057','商调・凉亭乐叹世','阿里西瑛','元','元曲','yuanqu','','[]','金乌玉兔走如梭，看看的老了人呵。',75,'元曲/yuanqu.json','["金乌玉兔走如梭，看看的老了人呵。", "有那等不识事的痴呆待怎么？急回头迟了些儿个。", "你试看凌烟阁上，功名不在我。", "则不如对酒当歌对酒当歌且快活，无忧愁，安乐窝。"]'),
('yuanqu-10058','双调・殿前欢懒云窝','阿里西瑛','元','元曲','yuanqu','','[]','懒云窝，醒时诗酒醉时歌。',166,'元曲/yuanqu.json','["懒云窝，醒时诗酒醉时歌。", "瑶琴不理抛书卧，无梦南柯。", "得清闲尽快活，日月似撺梭过，富贵比花开落。", "青春去也，不乐如何？懒云窝，醒时诗酒醉时歌。", "瑶琴不理抛书卧，尽自磨陀。", "想人生待则么？富贵比花开落，日月似撺梭过。", "呵呵笑我，我笑呵呵。", "懒云窝，客至待如何？懒云窝里和衣卧，尽自婆娑。", "想人生待则么？贵比我高些个，富比我松些个，呵呵笑我，我笑呵呵。"]'),
('yuanqu-10059','中吕・朝天子归隐','汪元亨','元','元曲','yuanqu','','[]','新诗吟兴浓，香醪量洪，好花插乌纱重。',416,'元曲/yuanqu.json','["新诗吟兴浓，香醪量洪，好花插乌纱重。", "百年世事苦匆匆，莫把眉头纵。", "鸥鹭新盟，云山清兴，远红尘俗事冗。", "假石崇运能，能范丹命穷，总一枕南柯梦。", "长歌咏楚词，细赓和杜诗，闲临写羲之字。", "乱云堆里结茅茨，无意居朝市。", "珠履三千，金钗十二，朝承恩暮赐死。", "来商山紫芝，理桐江钓丝，毕罢了功名事。", "住茅舍竹篱，穿芒鞋布衣，啖霍食藜羹味。", "两轮日月走东西，搬今古兴和废。", "蕙帐低垂，柴门深闭，大斋时犹未起。", "叹苏卿牧羝，笑刘琨听鸡，睡不足三竿日。", "任薰莸不分，尽玉石共焚，由人海鱼龙混。", "长歌楚些吊湘魂，谁待看匡时论。", "身重千金，舌缄三寸，坐时安行处稳。", "醉看山倒樽，醒读书闭门，无半点尘俗闷。", "荣华梦一场，功名纸半张，是非海波千丈。", "马啼踏碎禁街霜，听几度头鸡唱。", "尘土衣冠，江湖心量，出皇家麟凤网。", "慕夷齐首阳，叹韩彭未央，早纳纸风魔状。", "功名辞凤阙，浮生寄蚁穴，醉入黄鸡社。", "取之无禁用无竭，江上风山间月。", "基业隋唐，干戈吴越，付渔樵闲话说。", "酒杯中影蛇，枕头上梦蝶，二十载花开谢。"]'),
('yuanqu-10060','梁州・取崖畔枯藤作杖，伐江皋曲木为庐，主人素得林泉趣。烹茶扫叶，','汪元亨','元','元曲','yuanqu','','[]','引水通渠。',103,'元曲/yuanqu.json','["引水通渠。", "钩帘待月，俯槛观鱼。", "耻于求自抱憨愚，厌追陪懒混尘俗。", "傲慢似去彭泽弃职陶潜，疏散如困夔俯豪吟杜甫，清高似老孤山不仕林逋。", "岂浊，不鲁。", "处酸寒紧闭乾坤目，躲风雷看乌兔。", "静掩柴扉春日哺，便休题黑漆似程途。"]'),
('yuanqu-10061','尾・学不的睡不安苍荒拔剑鸡窗下舞，赶不上时未遇抖搜弹冠仕途上趋，','汪元亨','元','元曲','yuanqu','','[]','秉一段铁石心肠愈坚固。',43,'元曲/yuanqu.json','["秉一段铁石心肠愈坚固。", "折莫你赵平原诱英雄计谋，齐孟尝待贤良肚腹，赚不去狗盗鸡鸣类儿数。"]'),
('yuanqu-10062','仙吕・醉中天妓歪口','杜遵礼','元','元曲','yuanqu','','[]','一点樱桃挫，半壁杏腮多。',100,'元曲/yuanqu.json','["一点樱桃挫，半壁杏腮多。", "每日长吁暖耳朵，正觑着傍边唾。", "小唱单吹海螺，侧跷儿把戏做，口儿恰迎着。", "佳人脸上黑痣好似杨妃在，逃脱马嵬灾。", "曾向宫中捧砚台，堪伴诗书客，叵耐无情的李白，醉拈斑管，洒松烟点破桃腮。"]'),
('yuanqu-10063','出队子・伤心无奈，遣离人愁闷多。见银台绛蜡尽消磨，玉鼎无烟香烬火，','陈子厚','元','元曲','yuanqu','','[]','烛灭香消怎奈何？。',9,'元曲/yuanqu.json','["烛灭香消怎奈何？。"]'),
('yuanqu-10064','幺・情郎去后添寂寞，盼佳期无始末。这一双业眼敛秋波，两叶愁眉蹙翠','陈子厚','元','元曲','yuanqu','','[]','蛾，泪滴胭脂添玉颗。',10,'元曲/yuanqu.json','["蛾，泪滴胭脂添玉颗。"]'),
('yuanqu-10065','尾・着我倒枕捶床怎生卧？到二三更暖不温和，连这没人情的被窝儿也奚','陈子厚','元','元曲','yuanqu','','[]','落我！。',4,'元曲/yuanqu.json','["落我！。"]'),
('yuanqu-10066','海门张仲村乐堂・仙吕/点绛唇','无名氏','元','元曲','yuanqu','','[]','我如今乐矣忘忧，暮年衰朽，甘生受。',32,'元曲/yuanqu.json','["我如今乐矣忘忧，暮年衰朽，甘生受。", "虚度了春秋，每日家诗酒消白昼。"]'),
('yuanqu-10067','海门张仲村乐堂・混江龙','无名氏','元','元曲','yuanqu','','[]','遣家童耕耨，老夫则待爱庄农种植乐田畴。',87,'元曲/yuanqu.json','["遣家童耕耨，老夫则待爱庄农种植乐田畴。", "我无福穿轻罗衣锦，有分着坌绢粗绸。", "我则索睡彻三竿红日晓，觉来时一壶浊酒再扶头。", "我将世事都参透，幻身躯似风中秉烛，可怜见便似兀那水上浮沤。"]'),
('yuanqu-10068','海门张仲村乐堂・油葫芦','无名氏','元','元曲','yuanqu','','[]','每日家遥指南庄景物幽，指望待住的久，这的是祖宗基业子孙收。',88,'元曲/yuanqu.json','["每日家遥指南庄景物幽，指望待住的久，这的是祖宗基业子孙收。", "我和这等愚眉肉眼难相瞅，凡胎浊骨难相守。", "世间有三件事，我如今都一笔勾。", "到如今世财、红粉、高楼酒，休争气看看白了少年头。"]'),
('yuanqu-10069','海门张仲村乐堂・天下乐','无名氏','元','元曲','yuanqu','','[]','休、休、休。',70,'元曲/yuanqu.json','["休、休、休。", "人到中年万事休，我如今孤也波身，孤身可便得自由，端的是飘飘一叶不缆轻舟。", "假若我便得些自由，没揣的两鬓秋，争如我便且修身闲袖手？。"]'),
('yuanqu-10070','海门张仲村乐堂・村里迓鼓','无名氏','元','元曲','yuanqu','','[]','正值着那丽人天气，恰正是那太平的时候。',78,'元曲/yuanqu.json','["正值着那丽人天气，恰正是那太平的时候。", "趁着他这花红和柳绿，绕着这社南社北。", "他每则在兀那庄前庄后，他每都携着美酝，穿红杏，拖翠柳。", "我直吃的笑吟吟，醺醺的带酒。"]'),
('yuanqu-10071','海门张仲村乐堂・元和令','无名氏','元','元曲','yuanqu','','[]','锦模糊江景幽，翠峻峭远山岫。',90,'元曲/yuanqu.json','["锦模糊江景幽，翠峻峭远山岫。", "正是稻分畦，蚕齐簇，麦初熟。", "我是个老人家闲袖手，就着这古堤沙岸那答儿绿阴稠，缆船儿执着钓钩。", "(防御云)老相公收纶罢钓，新酒活鱼，是好幽乐也。", "(正末唱)。"]'),
('yuanqu-10072','海门张仲村乐堂・上马娇','无名氏','元','元曲','yuanqu','','[]','我将这锦鲤兜，网索收。',43,'元曲/yuanqu.json','["我将这锦鲤兜，网索收。", "就着这村务酒初熟，恰归来半醉黄昏后。", "暮雨儿收，看牧童归去倒骑牛。"]'),
('yuanqu-10073','海门张仲村乐堂・游四门','无名氏','元','元曲','yuanqu','','[]','秋间恰正是败荷萍里正方秋，呀呀的寒雁过南楼。',46,'元曲/yuanqu.json','["秋间恰正是败荷萍里正方秋，呀呀的寒雁过南楼。", "恰正是荷枯柳败芙蓉瘦，风力冷飕飕，看霜降水痕收。"]'),
('yuanqu-10074','海门张仲村乐堂・胜葫芦','无名氏','元','元曲','yuanqu','','[]','我则见浅碧粼粼露远洲，滴溜溜红叶一林秋，怕的是明日黄花蝶也愁。',53,'元曲/yuanqu.json','["我则见浅碧粼粼露远洲，滴溜溜红叶一林秋，怕的是明日黄花蝶也愁。", "仿孟嘉庄上，就渊明篱畔，老夫酒醒时节再扶头。"]'),
('yuanqu-10075','海门张仲村乐堂・后庭花','无名氏','元','元曲','yuanqu','','[]','冬间老夫待寻梅访故友，踏雪里沽艳酒。',92,'元曲/yuanqu.json','["冬间老夫待寻梅访故友，踏雪里沽艳酒。", "宝篆焚金鼎，浊醪饮巨瓯。", "我和你意相投，酒筵中不够，者莫再约住林下叟，就村务将琴剑留。", "(防御云)酒够了，老夫告回也。", "(正末云)早哩，且坐的也。", "(唱)。"]'),
('yuanqu-10076','海门张仲村乐堂・柳叶儿','无名氏','元','元曲','yuanqu','','[]','直吃到二更时候，笑喧哗交错觥筹，直待吃的月移梅影黄昏后。',43,'元曲/yuanqu.json','["直吃到二更时候，笑喧哗交错觥筹，直待吃的月移梅影黄昏后。", "心相爱意相投，醉时节衲被蒙头。"]'),
('yuanqu-10077','海门张仲村乐堂・单雁儿','无名氏','元','元曲','yuanqu','','[]','我向来打了个稽首，你身上的是非只为我恰才多开口。',49,'元曲/yuanqu.json','["我向来打了个稽首，你身上的是非只为我恰才多开口。", "这的是我做下事可着你承了头，可你敢休和老夫记冤仇。"]'),
('yuanqu-10078','海门张仲村乐堂・尾声','无名氏','元','元曲','yuanqu','','[]','我见他呵羞，我则推个逃席走，(防御云)老相公，再饮几杯。',174,'元曲/yuanqu.json','["我见他呵羞，我则推个逃席走，(防御云)老相公，再饮几杯。", "(拖下坐科)(正末唱)请你一个府尹官人放手。", "(云)同知！(唱)你可怎全不提防你那脑后忧，这的是你恋着金枷玉锁遭囚。", "我则怕你久已后，枉丁将你闲忧，我正是莫与儿孙作马牛。", "你如今贪杯恋酒，(云)你到的卧房中，将的镜子来，照你那面皮去波。", "(唱)则被这酒灌的你来黄干黑瘦，你正是养家活计下场头。", "(下)。"]'),
('yuanqu-10079','海门张仲村乐堂・南吕/一枝花','无名氏','元','元曲','yuanqu','','[]','同知着我不将差罚当，专把征驼喂，喂的似按板肥，好马也，我与你刷刨的恰便似泼油光。',90,'元曲/yuanqu.json','["同知着我不将差罚当，专把征驼喂，喂的似按板肥，好马也，我与你刷刨的恰便似泼油光。", "索与你收拾了铺床，把骏骑牵在槽上，草料也拌上一筐。", "我与你拖着那半片席头，美也，我与你急转过前厅后堂。"]'),
('yuanqu-10080','海门张仲村乐堂・梁州','无名氏','元','元曲','yuanqu','','[]','眷的是侧忄敝忄敝厨房中暄热，爱的是宽绰绰过道里风凉。',382,'元曲/yuanqu.json','["眷的是侧忄敝忄敝厨房中暄热，爱的是宽绰绰过道里风凉。", "夜深也无一个人来往。", "半片席斜铺在地下，两块砖掇在头行。", "正天炎似火，地热如炉。", "过道里不索开窗，洒家道来则这的便似天堂。", "我与你直挺挺忙拨倒身躯，就着这凉渗渗席垫着我这脊梁，美也，就着那风飕飕扇着我那胸膛。", "愁的是后晌，晌晌。", "我恰才煮料切草都停当，安排下搅草棒。", "喂的他槽上的征马宛有些肚囊，料煮到上半磁缸。", "(云)洒家与你睡一觉者。", "(做睡科)(王六斤同搽旦上，云)慢慢的走，赤、赤、赤。", "(搽旦、六斤做跳正末身上过)(打科)(正末云)哎哟，哎哟，甚么人劈劈泼泼，则管里打？(六斤云)是我都管。", "(正末云)都管，都管，你忒休都管了。", "(六斤云)夫人也在这里。", "(正末云)夫人，夫人，这早晚在这里。", "有甚么匀当？我别处睡去便了也。", "(下)(搽旦云)六斤也，我为你耽惊受怕，你休负了我心也。", "(六斤云)我若负心，我就该死也。", "(正末上)(唱)。"]'),
('yuanqu-10081','海门张仲村乐堂・贺新郎','无名氏','元','元曲','yuanqu','','[]','是谁人这早晚不寻常？俺的把曲槛斜穿，呀的将角门儿开放。',129,'元曲/yuanqu.json','["是谁人这早晚不寻常？俺的把曲槛斜穿，呀的将角门儿开放。", "是谁人这早晚往花园里撞？这嘶引定谁家一个艳妆？莫不是求食卖笑的红妆？(云)好也罗。", "(唱)荒淫怎坐夫人位。", "除了名字有何妨？着这个浪包搂一迷里胡厮谎。", "若拿贼做个证见，我着他望穿堂打会关防。", "(拿六斤科)(唱)。"]'),
('yuanqu-10082','海门张仲村乐堂・梧桐树','无名氏','元','元曲','yuanqu','','[]','你可便休想我把伊轻放，这公事决声扬。',43,'元曲/yuanqu.json','["你可便休想我把伊轻放，这公事决声扬。", "往往同知将他向，好也罗，将一个腌盆儿掇在他头直上。"]'),
('yuanqu-10083','海门张仲村乐堂・四块玉','无名氏','元','元曲','yuanqu','','[]','不索你厮掩藏，休倔强，(同知云)好是奇怪也，你回去罢。',99,'元曲/yuanqu.json','["不索你厮掩藏，休倔强，(同知云)好是奇怪也，你回去罢。", "(正末云)洒家知道。", "(唱)我急走的去那厨房中我点着灯光，若是实呵小人请功赏。", "早来个可便黑洞洞的，如今照耀的来便刚朗朗，请同知觑见这二人的气象！。"]'),
('yuanqu-10084','海门张仲村乐堂・乌夜啼','无名氏','元','元曲','yuanqu','','[]','请同知自向跟前望，夫人为甚么汗塌湿残妆？(搽旦云)是露水珠儿滴在我脸上来！(正末唱)都管为甚粉贴在鼻梁？(六斤云)我有些怕后，打了个白鼻儿。',289,'元曲/yuanqu.json','["请同知自向跟前望，夫人为甚么汗塌湿残妆？(搽旦云)是露水珠儿滴在我脸上来！(正末唱)都管为甚粉贴在鼻梁？(六斤云)我有些怕后，打了个白鼻儿。", "(正末云)夫人说波，都管说波，可怎生不言语？(唱)不似那昨来个爪驴、爪贼、爪马，叫吖吖的眼睛荒。", "(云)好也。", "(唱)不信你那扑扑的小鹿儿心头撞，打叠起无颜色，无情况，花言巧语，数黑论黄。", "(同知云)你说，他两人有甚么显证？(搽旦云)有甚么显证？你拿出来！(正末云)要见显证，金钗儿便是显证！(同知云)小夫人，这金钗儿不是你的？(搽旦云)我恰才着花枝儿抓在地下，这爪子拾了我的，他不还我。", "(同知云)夫人也，你这金钗儿吊了好几遭了也。", "(正末唱)。"]'),
('yuanqu-10085','海门张仲村乐堂・尾声','无名氏','元','元曲','yuanqu','','[]','则这金钗儿是二人口内的招伏状，更压着那十字街头犯由榜。',95,'元曲/yuanqu.json','["则这金钗儿是二人口内的招伏状，更压着那十字街头犯由榜。", "这公事不虚诳，道得来捏住喉嗓，请你个、请你个水晶塔的官人都莫偏向。", "做贼来见赃，杀人来见伤。", "这的是都管的奸情唆狗，不是这后槽的谎！(下)。"]'),
('yuanqu-10086','海门张仲村乐堂・双调/新水令','无名氏','元','元曲','yuanqu','','[]','同知着洒家下班去不唤再休来，便有那包龙图把他也难赛。',67,'元曲/yuanqu.json','["同知着洒家下班去不唤再休来，便有那包龙图把他也难赛。", "我则怕那王伯当，泼乔才，久后生心，(云)干我甚的事来？(唱)知他是和尚在钵盂在？。"]'),
('yuanqu-10087','海门张仲村乐堂・商调/集贤宾','无名氏','元','元曲','yuanqu','','[]','我从那幼年间将吏道文字把，我去那儒吏上少书滑。',99,'元曲/yuanqu.json','["我从那幼年间将吏道文字把，我去那儒吏上少书滑。", "笔尖上斟量一个轻重，案款内除减了增加。", "我则待惜黎民户减了差徭，须是我爱庄农一犁两耙。", "则俺那同知好将拦状插，前厅上审问撒达。", "这厮每其中必暗昧，就里决争差。"]'),
('yuanqu-10088','海门张仲村乐堂・逍遥乐','无名氏','元','元曲','yuanqu','','[]','我与你亲身临牢下，自审个虚实，辩个真假。',20,'元曲/yuanqu.json','["我与你亲身临牢下，自审个虚实，辩个真假。"]'),
('yuanqu-10089','海门张仲村乐堂・幺篇','无名氏','元','元曲','yuanqu','','[]','则被这金晃的我这眼睛儿花腊搽，吓的我这手脚儿软剌答，可若是官司知道怎割杀？(云)后兴。',91,'元曲/yuanqu.json','["则被这金晃的我这眼睛儿花腊搽，吓的我这手脚儿软剌答，可若是官司知道怎割杀？(云)后兴。", "(唱)你可是那里每将来，你与我疾道者，常好是心粗胆大。", "天也、天也，则被些小冤家送了这个忄敝知法。"]'),
('yuanqu-10090','海门张仲村乐堂・后庭花','无名氏','元','元曲','yuanqu','','[]','颇奈这个打关节的姜子牙，你待搭救这犯奸情的女浣纱。',134,'元曲/yuanqu.json','["颇奈这个打关节的姜子牙，你待搭救这犯奸情的女浣纱。", "你则怕萧相国差行了事，好、好、好，哎！你个包龙图能治家。", "(云)三画王！(牢子云)有。", "(正末唱)你与我换上沉枷，(牢子云)理会的。", "上枷。", "(正末唱)你可休将人来者剌。", "来日个坐早衙，大人行把状插。", "小夫人必事发，王都管必定杀。"]'),
('yuanqu-10091','海门张仲村乐堂・柳叶儿','无名氏','元','元曲','yuanqu','','[]','呀，请你个大夫人休怕，浪包搂项带沉枷，说着教他丧胆亡魂怕。',275,'元曲/yuanqu.json','["呀，请你个大夫人休怕，浪包搂项带沉枷，说着教他丧胆亡魂怕。", "休那里括剌刺，叫吖吖，合毒药则是你个蛆扒。", "(云)三画王，打着者。", "(搽旦云)并不干我事，都是大夫人来。", "(正末云)打着者！(牢子打六斤科，云)理会的。", "招了者！招了者！(六斤云)我吃不过这打。", "罢、罢、罢，是我来。", "(搽旦云)是我来，是我来。", "不要打，我招了便了。", "(正末云)他可道招了也。", "点了纸，画了字。", "三画王，将纸来，封了这罐儿者。", "(牢子云)将纸来，封了这罐儿。", "(正末云)三画王，开了牢门。", "(牢子开门科)(云)理会的，开了门也。", "(正末见同知科)(同知云)张本，你问的事如何？(正末做扯住同知科)(唱)。"]'),
('yuanqu-10092','海门张仲村乐堂・尾声','无名氏','元','元曲','yuanqu','','[]','向前来扯住他，这公事怎干罢？把你上梁不正相公拿，原告人一步一棍子打。',54,'元曲/yuanqu.json','["向前来扯住他，这公事怎干罢？把你上梁不正相公拿，原告人一步一棍子打。", "把他干连人监下，折证在蓟州府尹相公衙！。"]'),
('yuanqu-10093','海门张仲村乐堂・双调/新水令','无名氏','元','元曲','yuanqu','','[]','我则见几行新雁写秋云，画堂中一天风韵。',52,'元曲/yuanqu.json','["我则见几行新雁写秋云，画堂中一天风韵。", "看梅山清隐隐，拖素杖那观门外水粼粼。", "野馆山村，便着那丹青手画不尽。"]'),
('yuanqu-10094','海门张仲村乐堂・殿前欢','无名氏','元','元曲','yuanqu','','[]','怕不待叙寒温，(云)同知。',139,'元曲/yuanqu.json','["怕不待叙寒温，(云)同知。", "你不知道。", "(同知云)父亲道甚么来？(正末唱)又着你道不应江亲者强来亲。", "只因咱多话着你心怀恨，休怪咱波女婿郎君。", "(同知云)我一径的来告父亲来。", "(正末云)你告我怎么？(唱)放着你那筑坟台女赵贞，索甚么闲评论！两个人相般弄，一个叠尸的伯当，一个是贤德夫人！。"]'),
('yuanqu-10095','海门张仲村乐堂・喜江南','无名氏','元','元曲','yuanqu','','[]','过来波包龙图门中面糊盆，(做推防御出门科)(防御云)好无礼也。',381,'元曲/yuanqu.json','["过来波包龙图门中面糊盆，(做推防御出门科)(防御云)好无礼也。", "不认便罢，怎么推出我来？更待干罢？拿过那大夫人来，与我打着者。", "(做打大旦科)(大旦云)父亲救我者。", "(正末云)是我恶说了他来。", "(唱)常言道口是祸之门。", "打关节府尹怒生嗔，我这议论，便有那杀人的公事我招承。", "(防御云)既然如此，俺同见官去来。", "(众虚下)(府尹、张千上，云)聆音能鉴貌，奸伪自昭彰。", "小官府尹是也。", "昨日蓟州申到王六斤等一干人犯。", "张千，你与我律上厅来！(张千云)理会的。", "(做拿王六斤、搽旦、大旦、同知、张仲上)(见科)当面！(众跪科)(府尹云)合毒药是谁来？(王六斤云)是我来。", "(府尹云)送金是谁来？(张仲云)是老夫来。", "(府尹云)这桩事老夫尽知也。", "一行人听我老夫下断：二夫人败坏人伦，王六斤谋害情真。", "张孝友施仁重义，认送金回护姻亲。", "王同知复还旧职，大夫人无事拱明。", "今日个不能隐讳，将二人明正典刑！。"]'),
('yuanqu-10096','黄钟・人月圆马嵬效吴彦高','李齐贤','元','元曲','yuanqu','','[]','五云绣岭明珠殿，飞燕倚新妆。',29,'元曲/yuanqu.json','["五云绣岭明珠殿，飞燕倚新妆。", "小颦中有，渔阳胡马，惊破霓裳。"]'),
('yuanqu-10098','仙吕/点绛唇','杨景贤','元','元曲','yuanqu','','[]','梅绽南枝，已经春事，三之二。',25,'元曲/yuanqu.json','["梅绽南枝，已经春事，三之二。", "桃杏参差，拂嗅香风至。"]'),
('yuanqu-10099','混江龙','杨景贤','元','元曲','yuanqu','','[]','今日个早朝班次，公侯宰相会同时。',71,'元曲/yuanqu.json','["今日个早朝班次，公侯宰相会同时。", "亲传圣旨，总命诸司。", "赤羽诏传青彩凤，御炉香喷紫金狮。", "亲王驸马，国戚皇族，更和那商贾农工士。", "马停玉勒，酒泛金卮。"]'),
('yuanqu-10100','油葫芦','杨景贤','元','元曲','yuanqu','','[]','想俺那兴唐出战时，一日知他几个死，如今老来也憔悴鬓如丝，都将定国安邦志，改为养性修身事。',78,'元曲/yuanqu.json','["想俺那兴唐出战时，一日知他几个死，如今老来也憔悴鬓如丝，都将定国安邦志，改为养性修身事。", "往常时领大军，今日个拜国师。", "英雄将生扭得称居士，怎禁那天子自相辞？。"]'),
('yuanqu-10101','天下乐','杨景贤','元','元曲','yuanqu','','[]','这和尚伏虎降龙信有之，京师，诸弟子，焚香点烛齐叩齿。',52,'元曲/yuanqu.json','["这和尚伏虎降龙信有之，京师，诸弟子，焚香点烛齐叩齿。", "社火每鬼间着神，乐器中竹间着丝，闹起一座霸陵桥上市。"]'),
('yuanqu-10102','醉中天','杨景贤','元','元曲','yuanqu','','[]','幢幡上泥金字，写着道三藏是大唐师。',63,'元曲/yuanqu.json','["幢幡上泥金字，写着道三藏是大唐师。", "钟鼓饶钹夹道施，求法语的挨着咨次。", "都是骏马雕鞍的健儿，读那孔夫子文字，着他们拜如来节外生枝。"]'),
('yuanqu-10103','金盏儿','杨景贤','元','元曲','yuanqu','','[]','才吟罢送行诗，似歌彻断肠词，生离别便与死相似。',64,'元曲/yuanqu.json','["才吟罢送行诗，似歌彻断肠词，生离别便与死相似。", "死呵，三十气断更无思，生呵，一心怀远恨，千丈系游丝。", "死呵，如梦幻泡影，那有再来时。"]'),
('yuanqu-10104','赏花时','杨景贤','元','元曲','yuanqu','','[]','只是俺立国安邦志广施，杀将驱兵心不慈。',61,'元曲/yuanqu.json','["只是俺立国安邦志广施，杀将驱兵心不慈。", "若两阵对圆时，提着尉迟恭的名字，他每早魂不附其尸。", "(云)门旗开处，两阵对圆。", "(唱)。"]'),
('yuanqu-10105','幺','杨景贤','元','元曲','yuanqu','','[]','不刺刺却是战马拖缰敌将死，今日似困虎藏牙守洞时。',48,'元曲/yuanqu.json','["不刺刺却是战马拖缰敌将死，今日似困虎藏牙守洞时。", "因老病不能辞，奉圣旨勉强行之，问师父求取法名儿。"]'),
('yuanqu-10106','尾声','杨景贤','元','元曲','yuanqu','','[]','从今后演佛法领三宗，掌戒律兴诸寺，但依着吾师教旨。',235,'元曲/yuanqu.json','["从今后演佛法领三宗，掌戒律兴诸寺，但依着吾师教旨。", "此去西行十万里，急回来两鬓如丝。", "本是一个五陵儿，他道我有佛子容姿。", "(唐僧云)从今后灭火性消豪气，发善心脱名利。", "(尉迟唱)师父着我将豪气消磨，将善心来使。", "(唐僧云)众官军民人等听着：小僧折一枝松，插在此道傍要他活。", "我去后，此松朝西，如朝东，小僧回也。", "(虞云)师父，无根如何得活？(唐僧云)小僧无根要有根，有相若无相。", "我若取经回，松枝往东向。", "朝西呵是去时，朝东呵回至。", "(尉迟云)师父沿路保重了，俺众人年年来此看松枝。", "(下)。"]'),
('yuanqu-10107','双调/豆叶黄','杨景贤','元','元曲','yuanqu','','[]','胖哥王留，走得来偏疾。',51,'元曲/yuanqu.json','["胖哥王留，走得来偏疾。", "王大、张三，去得便宜。", "胖姑儿天生得我忒认得，中表相随。", "壮王二离了官厅，直到家里。"]'),
('yuanqu-10108','乔牌儿','杨景贤','元','元曲','yuanqu','','[]','一个个子执白木植，身穿着紫搭背。',52,'元曲/yuanqu.json','["一个个子执白木植，身穿着紫搭背。", "白石头黄铜片去腰间系，一对脚似踏在黑瓮里。", "(张云)那是个皂靴。", "(姑唱)。"]'),
('yuanqu-10109','新水令','杨景贤','元','元曲','yuanqu','','[]','官人每腰屈共头低，吃得醉醺醺脑门着地。',60,'元曲/yuanqu.json','["官人每腰屈共头低，吃得醉醺醺脑门着地。", "(张云)拜他哩。", "(姑唱)咿咿呜呜吹竹管，扑扑通通打牛皮。", "见几个无知，叫一会闹一会。"]'),
('yuanqu-10110','川拨棹','杨景贤','元','元曲','yuanqu','','[]','更好笑哩，好着我笑微微，一个汉木雕成两个腿。',57,'元曲/yuanqu.json','["更好笑哩，好着我笑微微，一个汉木雕成两个腿。", "见几个回回，舞着面旌旗，阿剌剌口里不知道甚的，妆着鬼，人多我看不仔细。"]'),
('yuanqu-10111','七弟兄','杨景贤','元','元曲','yuanqu','','[]','我钻在这壁，那壁，没安我这死身己。',44,'元曲/yuanqu.json','["我钻在这壁，那壁，没安我这死身己。", "滚将一个碌碡在根底，脚踏着才得见真实，百般打扮千般戏。"]'),
('yuanqu-10112','梅花酒','杨景贤','元','元曲','yuanqu','','[]','那的他唤做甚傀儡，黑墨线儿提着红白粉儿，妆着人样的东西。',76,'元曲/yuanqu.json','["那的他唤做甚傀儡，黑墨线儿提着红白粉儿，妆着人样的东西。", "飕飕胡哨起，咚咚地鼓声催，一个摩着大旗。", "他坐着吃堂食，我立着看筵席。", "两只腿板僵直，肚皮里似春雷。"]'),
('yuanqu-10113','随煞','杨景贤','元','元曲','yuanqu','','[]','雨余匀罢芝麻地，咱去那沤麻池里澡洗。',37,'元曲/yuanqu.json','["雨余匀罢芝麻地，咱去那沤麻池里澡洗。", "唐三藏此日起身，他胖姑儿从头告诉了你。"]'),
('yuanqu-10114','南吕/一枝花','杨景贤','元','元曲','yuanqu','','[]','大宛国天产才，渥洼水龙媒种。',64,'元曲/yuanqu.json','["大宛国天产才，渥洼水龙媒种。", "带轻云一块雪，走落日四蹄风。", "长尾银鬃，驮双将无嫌重，出群驽立大功。", "胜普贤白象身高，赛师利青狮性勇！。"]'),
('yuanqu-10115','牧羊关','杨景贤','元','元曲','yuanqu','','[]','这马你看一丈长头至尾，八尺高蹄至鬃，但一嘶凡马皆空。',76,'元曲/yuanqu.json','["这马你看一丈长头至尾，八尺高蹄至鬃，但一嘶凡马皆空。", "比豹月乌别样精神，比忽雷驳争些徒勇。", "又不是五色毛斑点，浑则是一片玉玲珑。", "影见在白云底，声传在明月中。"]'),
('yuanqu-10116','牧羊关','杨景贤','元','元曲','yuanqu','','[]','他曾到三足金乌窟，四蹄玉兔宫，他有吃天河水草神通。',122,'元曲/yuanqu.json','["他曾到三足金乌窟，四蹄玉兔宫，他有吃天河水草神通。", "晋支遁性命也似看承，周姬满心肝一般敬重。", "(唐僧云)请个价钱，要几多？(木叉唱)联城壁休言买，千金价岂相容？(唐僧云)恁的小僧买不成，那得许多钱来？(木叉云)我赊与你如何？载你权离此，驮经却向东。"]'),
('yuanqu-10117','尾','杨景贤','元','元曲','yuanqu','','[]','你西行似入游仙梦，我南往重归沧海中。',74,'元曲/yuanqu.json','["你西行似入游仙梦，我南往重归沧海中。", "到前途，莫惊恐。", "有山精，有大虫，有猿猴，有马熊。", "见放着龙君将老师奉，到花果山乱峰，相遇着悟空，取经卷回来受恩宠。"]'),
('yuanqu-10118','正宫/端正好','杨景贤','元','元曲','yuanqu','','[]','差十大保官来，同九曜星君降，把唐僧于路堤防。',39,'元曲/yuanqu.json','["差十大保官来，同九曜星君降，把唐僧于路堤防。", "天佛牒玉帝敕都交往，西天路收魔障。"]'),
('yuanqu-10119','滚绣球','杨景贤','元','元曲','yuanqu','','[]','宣灵王将火部驱，胡总管将火律掌，火鸦鸣振惊天上，火瓢倾卒律律四远光茫。',84,'元曲/yuanqu.json','["宣灵王将火部驱，胡总管将火律掌，火鸦鸣振惊天上，火瓢倾卒律律四远光茫。", "火丹袖五百，火轮踏一双，火葫芦紧缚师旷，使离娄拖定金枪。", "神中号作华光藏，佛会称为妙吉祥，正受天王。"]'),
('yuanqu-10120','倘秀才','杨景贤','元','元曲','yuanqu','','[]','玉皇殿金砖是我藏，后土祠琼花是我赏，炒闹起天宫这一场。',48,'元曲/yuanqu.json','["玉皇殿金砖是我藏，后土祠琼花是我赏，炒闹起天宫这一场。", "枪撞番四揭帝，砖打倒八金刚，众神祗索纳降。"]'),
('yuanqu-10121','滚绣球','杨景贤','元','元曲','yuanqu','','[]','上天宫闹玉皇，下人间保帝王，保得他国无灾庶民无恙，因此上感威灵岁岁烧香。',92,'元曲/yuanqu.json','["上天宫闹玉皇，下人间保帝王，保得他国无灾庶民无恙，因此上感威灵岁岁烧香。", "我将那五岳欺，五气掌，五瘟神遣之于霄壤，五音中徵为偏长。", "五星中让我在南天上坐，五方内将咱离位藏，谁不知五显高强。"]'),
('yuanqu-10122','呆古朵','杨景贤','元','元曲','yuanqu','','[]','观音佛作保书名字，会诸天一处商量。',63,'元曲/yuanqu.json','["观音佛作保书名字，会诸天一处商量。", "则为宝藏在灵山，着这真僧离大唐。", "山水广多妖怪，途路远多魔障。", "因此上着众仙离阆苑，诸神往下方。"]'),
('yuanqu-10123','笑和尚','杨景贤','元','元曲','yuanqu','','[]','二郎神神通广，五显圣驱兵将。',48,'元曲/yuanqu.json','["二郎神神通广，五显圣驱兵将。", "顿剑摇环显出那英雄相，一路上保护唐三藏。", "轰雷掣电从天降，压伏定魔王。"]'),
('yuanqu-10124','伴读书','杨景贤','元','元曲','yuanqu','','[]','我、我、我，使金枪法力强，恁、恁、恁，持宝杵威风壮。',63,'元曲/yuanqu.json','["我、我、我，使金枪法力强，恁、恁、恁，持宝杵威风壮。", "众神祗齐保护他无恙，恁、恁离了上方。", "他、他，往了西方，俺程程保护他消灾障。"]'),
('yuanqu-10125','尾','杨景贤','元','元曲','yuanqu','','[]','诸佛众神多谦让，全在吾师做主张。',32,'元曲/yuanqu.json','["诸佛众神多谦让，全在吾师做主张。", "保金经福无量，向花果山中再相访。"]'),
('yuanqu-10126','赵盼儿风月救风尘・仙吕/点绛唇','关汉卿','元','元曲','yuanqu','','[]','妓女追陪，觅钱一世，临收计，怎做的百纵千随，知重咱风流媚。',29,'元曲/yuanqu.json','["妓女追陪，觅钱一世，临收计，怎做的百纵千随，知重咱风流媚。"]'),
('yuanqu-10127','赵盼儿风月救风尘・混江龙','关汉卿','元','元曲','yuanqu','','[]','我想这姻缘匹配，少一时一刻强难为。',83,'元曲/yuanqu.json','["我想这姻缘匹配，少一时一刻强难为。", "如何可意？怎的相知？怕不便脚搭着脑杓成事早，怎知他手拍着胸脯悔后迟！寻前程，觅下梢，恰便是黑海也似难寻觅，料的来人心不问，天理难欺。"]'),
('yuanqu-10128','赵盼儿风月救风尘・油葫芦','关汉卿','元','元曲','yuanqu','','[]','姻缘簿全凭我共你？谁不待拣个称意的？他每都拣来拣去百千回。',101,'元曲/yuanqu.json','["姻缘簿全凭我共你？谁不待拣个称意的？他每都拣来拣去百千回。", "待嫁一个老实的，又怕尽世儿难成对；待嫁一个聪俊的，又怕半路里轻抛弃。", "遮莫向狗溺处藏，遮莫向牛屎里堆，忽地便吃了一个合扑地，那时节睁着眼怨他谁！。"]'),
('yuanqu-10129','赵盼儿风月救风尘・天下乐','关汉卿','元','元曲','yuanqu','','[]','我想这先嫁的还不曾过几日，早折的容也波仪瘦似鬼，只教你难分说，难告诉，空泪垂。',74,'元曲/yuanqu.json','["我想这先嫁的还不曾过几日，早折的容也波仪瘦似鬼，只教你难分说，难告诉，空泪垂。", "我看了些觅前程俏女娘，见了些铁心肠男子辈，便一生里孤眠，我也直甚颓！。"]'),
('yuanqu-10130','赵盼儿风月救风尘・那吒令','关汉卿','元','元曲','yuanqu','','[]','待妆个老实，学三从四德；争奈是匪妓，都三心二意。',56,'元曲/yuanqu.json','["待妆个老实，学三从四德；争奈是匪妓，都三心二意。", "端的是那里是三梢末尾？俺虽居在柳陌中、花街内，可是那件儿便宜？。"]'),
('yuanqu-10131','赵盼儿风月救风尘・鹊踏枝','关汉卿','元','元曲','yuanqu','','[]','俺不是卖查梨，他可也逞刀锥；一个个败坏人伦，乔做胡为。',81,'元曲/yuanqu.json','["俺不是卖查梨，他可也逞刀锥；一个个败坏人伦，乔做胡为。", "（云）但来两三遭，问那厮要钱，他便道：\"这弟子敲馒儿哩！\"（唱）但见俺有些儿不伶俐，便说是女娘家要哄骗东西。"]'),
('yuanqu-10132','赵盼儿风月救风尘・寄生草','关汉卿','元','元曲','yuanqu','','[]','他每有人爱为娼妓，有人爱作次妻。',67,'元曲/yuanqu.json','["他每有人爱为娼妓，有人爱作次妻。", "干家的干落得淘闲气，买虚的看取些羊羔利，嫁人的早中了拖刀计。", "他正是\"南头做了北头开，东行不见西行例\"。"]'),
('yuanqu-10133','赵盼儿风月救风尘・村里迓鼓','关汉卿','元','元曲','yuanqu','','[]','你也合三思而行，再思可矣。',74,'元曲/yuanqu.json','["你也合三思而行，再思可矣。", "你如今年纪小哩，我与你慢慢的别寻个姻配。", "你可便宜，只守着铜斗儿家缘家计。", "也是你歹姐姐把衷肠话劝妹妹，我怕你受不过男儿气息。"]'),
('yuanqu-10134','赵盼儿风月救风尘・元和令','关汉卿','元','元曲','yuanqu','','[]','做丈夫的便做不的子弟，他终不解其意；那做子弟的，他影儿里会虚脾。',89,'元曲/yuanqu.json','["做丈夫的便做不的子弟，他终不解其意；那做子弟的，他影儿里会虚脾。", "那做丈夫的，忒老实。", "（外旦云）那周舍穿着一架子衣服，可也堪爱哩。", "（正旦唱）那厮虽穿着几件虼螂皮，人伦事晓得甚的！。"]'),
('yuanqu-10135','赵盼儿风月救风尘・上马娇','关汉卿','元','元曲','yuanqu','','[]','我听的说就里，你原来为这的，倒引的我忍不住笑微微。',52,'元曲/yuanqu.json','["我听的说就里，你原来为这的，倒引的我忍不住笑微微。", "你道是暑月间扇子扇着你睡，冬月间着炭火煨，烘炙着绵衣。"]'),
('yuanqu-10136','赵盼儿风月救风尘・胜葫芦','关汉卿','元','元曲','yuanqu','','[]','你道这子弟情肠甜似蜜，但娶到他家里，多无半载周年相弃掷，早努牙突嘴，拳椎脚踢，打的你哭啼啼。',46,'元曲/yuanqu.json','["你道这子弟情肠甜似蜜，但娶到他家里，多无半载周年相弃掷，早努牙突嘴，拳椎脚踢，打的你哭啼啼。"]'),
('yuanqu-10137','赵盼儿风月救风尘・幺篇','关汉卿','元','元曲','yuanqu','','[]','恁时节"船到江心补漏迟"，烦恼怨他准？事要前思免后悔。',50,'元曲/yuanqu.json','["恁时节\"船到江心补漏迟\"，烦恼怨他准？事要前思免后悔。", "我也劝你不得，有朝一日，准备着搭救你块望夫石。"]'),
('yuanqu-10138','赵盼儿风月救风尘・赚煞','关汉卿','元','元曲','yuanqu','','[]','这妮子是狐魅人女妖精，缠郎君天魔祟。',141,'元曲/yuanqu.json','["这妮子是狐魅人女妖精，缠郎君天魔祟。", "则他那裤儿里休猜做有腿，吐下鲜红血则当做苏木水。", "耳边休采那等闲食，那的是最容易、剜眼睛嫌的，则除是亲近着他便欢喜。", "(带云)着他疾省呵！(唱)哎，你个双郎子弟，安排下金冠霞帔。", "（带云）一个夫人来到手儿里了。", "（唱）却则为三千张茶引，嫁了冯魁。", "（下）。"]'),
('yuanqu-10139','赵盼儿风月救风尘・商调/集贤宾','关汉卿','元','元曲','yuanqu','','[]','咱这几年来待嫁人心事有，听的道谁揭债、谁买休。',112,'元曲/yuanqu.json','["咱这几年来待嫁人心事有，听的道谁揭债、谁买休。", "他每待强巴结深宅大院，怎知道摧折了舞榭歌楼？一个个眼张狂。", "似漏了网的游鱼，一个个嘴卢都似跌了弹的斑鸠。", "御园中可不道是栽路柳，好人家怎容这等娼优？他每初时间有些实意，临老也没回头。"]'),
('yuanqu-10140','赵盼儿风月救风尘・逍遥乐','关汉卿','元','元曲','yuanqu','','[]','那一个不因循成就，那一个不顷刻前程，那一个不等闲间罢手。',91,'元曲/yuanqu.json','["那一个不因循成就，那一个不顷刻前程，那一个不等闲间罢手。", "他每一做一个水上浮沤。", "和爷娘结下不厮见的冤仇，恰便似日月参辰和卯酉，正中那男儿机彀。", "他使那千般贞烈，万种恩情，到如今一笔都勾。"]'),
('yuanqu-10141','赵盼儿风月救风尘・金菊香','关汉卿','元','元曲','yuanqu','','[]','想当日他暗成公事，只怕不相投。',63,'元曲/yuanqu.json','["想当日他暗成公事，只怕不相投。", "我当初作念你的言词，今日都应口。", "则你那去时，恰便似去秋。", "他本是薄幸的班头，还说道有恩爱、结绸缪。"]'),
('yuanqu-10142','赵盼儿风月救风尘・醋葫芦','关汉卿','元','元曲','yuanqu','','[]','你铺排着鸳衾和凤帱，指望效天长共地久。',120,'元曲/yuanqu.json','["你铺排着鸳衾和凤帱，指望效天长共地久。", "蓦入门，知滋味，便合体。", "几番家眼睁睁打干净，待离了我这手。", "（带云）赵盼儿，（唱）你做的个见死不救，可不羞杀这桃园中杀白马、宰乌牛。", "（云）既然是这般呵，谁着你嫁他来？（卜儿云）大姐，周舍说誓来。", "（正唱）。"]'),
('yuanqu-10143','赵盼儿风月救风尘・幺篇','关汉卿','元','元曲','yuanqu','','[]','想当初有忧呵同共忧，有愁呵一处愁。',159,'元曲/yuanqu.json','["想当初有忧呵同共忧，有愁呵一处愁。", "他道是残生早晚丧荒丘，做了个游街野巷村务酒。", "你道是百年之后，（云）妹子也，你不道来：\"这个也大姐，那个也大姐，出了一包脓！不如嫁个张郎妇、李郎妻，（唱）立一个妇名儿，做鬼也风流！\"（云）奶奶，那寄书的人去了不曾？（卜儿云）还不曾去哩。", "（正旦云）我写一封书，寄与引章去。", "(做写科，唱）。"]'),
('yuanqu-10144','赵盼儿风月救风尘・后庭花','关汉卿','元','元曲','yuanqu','','[]','我将这知心书亲自修，教他把天机休泄漏。',118,'元曲/yuanqu.json','["我将这知心书亲自修，教他把天机休泄漏。", "传示与休莽戆收心的女，拜上你浑身疼的歹事头。", "（带云）引章，我怎的劝你来。", "（唱）你好没来由，遭他毒手，无情的棍棒抽，赤津津鲜血流。", "逐朝家如暴囚，怕不将性命丢！况家乡隔郑州，有谁人相睬瞅，空这般出尽丑。"]'),
('yuanqu-10145','赵盼儿风月救风尘・柳叶儿','关汉卿','元','元曲','yuanqu','','[]','则教你怎生消受，我索合再做个机谋。',63,'元曲/yuanqu.json','["则教你怎生消受，我索合再做个机谋。", "把这云鬟蝉鬓妆梳就，（带云）还再穿上些锦绣衣服。", "（唱）珊瑚钩、芙蓉扣，扭捏的身子儿别样娇柔。"]'),
('yuanqu-10146','赵盼儿风月救风尘・双雁儿','关汉卿','元','元曲','yuanqu','','[]','我着这粉脸儿搭救你女骷髅。',50,'元曲/yuanqu.json','["我着这粉脸儿搭救你女骷髅。", "割舍的一不做二不休，拚了个由他咒也波咒。", "不是我说大口，怎出得我这烟月手！。"]'),
('yuanqu-10147','赵盼儿风月救风尘・浪里来煞','关汉卿','元','元曲','yuanqu','','[]','你收拾了心上忧，你展放了眉间皱，我直着"花叶不损觅归秋"。',194,'元曲/yuanqu.json','["你收拾了心上忧，你展放了眉间皱，我直着\"花叶不损觅归秋\"。", "那厮爱女娘的心，见的便似驴共狗，卖弄他玲珑剔透。", "（云）我到那里，三言两句，肯写休书，万事俱休；若是不肯写休书，我将他掐一掐，拈一拈，搂一搂，抱一抱，着那厮通身酥，遍体麻。", "将他鼻凹儿抹上一块砂糖，着那厮舔又舔不着，吃又吃不着，赚得那厮写了休书。", "引章将的休书来，淹的撤了。", "我这里出了门儿，（唱）可不是一场风月，我着那汉一时休。", "（下）。"]'),
('yuanqu-10148','赵盼儿风月救风尘・正宫/端正好','关汉卿','元','元曲','yuanqu','','[]','则为他满怀愁，心间闷，做的个进退无门。',41,'元曲/yuanqu.json','["则为他满怀愁，心间闷，做的个进退无门。", "那婆娘家一涌性，无思忖，我可也强打入迷魂阵。"]'),
('yuanqu-10149','赵盼儿风月救风尘・滚绣球','关汉卿','元','元曲','yuanqu','','[]','我这里微微的把气喷，输个姓因，怎不教那厮背槽抛粪！更做道普天下无他这等郎君。',113,'元曲/yuanqu.json','["我这里微微的把气喷，输个姓因，怎不教那厮背槽抛粪！更做道普天下无他这等郎君。", "想着容易情，忒献勤，几番家待要不问；第一来我则是可怜见无主娘亲，第二来是我\"惯曾为旅偏怜客，\"第三来也是我\"自己贪杯惜醉人\"。", "到那里呵，也索费些精神。"]'),
('yuanqu-10150','赵盼儿风月救风尘・倘秀才','关汉卿','元','元曲','yuanqu','','[]','县君的则是县君，妓人的则是妓人。',44,'元曲/yuanqu.json','["县君的则是县君，妓人的则是妓人。", "怕不扭捏着身子蓦入他门；怎禁他使数的到支分，背地里暗忍。"]'),
('yuanqu-10151','赵盼儿风月救风尘・幺篇','关汉卿','元','元曲','yuanqu','','[]','俺那妹子儿有见闻，可有福分，抬举的个丈夫俊上添俊，年纪儿恰正青春。',428,'元曲/yuanqu.json','["俺那妹子儿有见闻，可有福分，抬举的个丈夫俊上添俊，年纪儿恰正青春。", "（周舍云）我那里曾见你来？我在客伙里，你弹着一架筝，我不与了你个褐色绸缎儿？（正旦云）小的，你可见来？（小闲云）不曾见他有甚么褐色绸缎儿。", "（周舍云）哦，早起杭州客伙散了，赶到陕西客伙里吃酒，我不与了大姐一分饭来？（正旦云）小的每，你可见来？（小闲云）我不曾见。", "（正旦唱）你则是忒现新，忒忘昏，更做道你眼钝。", "那唱词话的有两句留文：咱也曾\"武陵溪畔曾相识，今日佯推不认人。", "\"我为你断梦劳魂。", "（周舍云）我想起来了，你敢是赵盼儿么？（正旦云）然也。", "（周舍云）你是赵盼儿，好，好！当初破亲也是你来！小二，关了店门，则打这小闲。", "（小闲云）你休要打我。", "俺姐姐将着锦绣衣服，一房一卧来嫁你，你倒打我？（正旦云）周舍，你坐下，你听我说。", "你在南京时，人说你周舍名字，说的我耳满鼻满的，则是不曾见你。", "后得见你呵，害的我不茶不饭，只是思想着你。", "听的你娶了宋引章，教我如何不恼？周舍，我待嫁你，你却着我保亲！（唱）。"]'),
('yuanqu-10152','赵盼儿风月救风尘・倘秀才','关汉卿','元','元曲','yuanqu','','[]','我当初倚大呵妆儇主婚？怎知我嫉妒呵特故里破亲？你这厮外相儿通疏就里村！你今日结婚姻，咱就肯罢论。',48,'元曲/yuanqu.json','["我当初倚大呵妆儇主婚？怎知我嫉妒呵特故里破亲？你这厮外相儿通疏就里村！你今日结婚姻，咱就肯罢论。"]'),
('yuanqu-10153','赵盼儿风月救风尘・脱布衫','关汉卿','元','元曲','yuanqu','','[]','我更是的不待饶人，我为甚不敢明闻；肋底下插柴自忍，怎见你便打他一顿？。',35,'元曲/yuanqu.json','["我更是的不待饶人，我为甚不敢明闻；肋底下插柴自忍，怎见你便打他一顿？。"]'),
('yuanqu-10154','赵盼儿风月救风尘・小梁州','关汉卿','元','元曲','yuanqu','','[]','可不道一夜夫妻百夜恩！你可便息怒停嗔。',50,'元曲/yuanqu.json','["可不道一夜夫妻百夜恩！你可便息怒停嗔。", "你村时节背地里使些村，对着我合思忖：那一个双同叔打杀俏红裙？。"]'),
('yuanqu-10155','赵盼儿风月救风尘・幺篇','关汉卿','元','元曲','yuanqu','','[]','则见他恶哏哏，摸按着无情棍，便有火性的不似你个郎君。',117,'元曲/yuanqu.json','["则见他恶哏哏，摸按着无情棍，便有火性的不似你个郎君。", "（云）你拿着偌粗的棍棒，倘或打杀他呵，可怎了？（周舍云）丈夫打杀老婆，不该偿命。", "（正旦云）这等说，谁敢嫁你？（背唱）我假意儿瞒，虚科儿喷，着这厮有家难奔。", "妹子也。", "你试看咱风月救风尘。"]'),
('yuanqu-10156','赵盼儿风月救风尘・二煞','关汉卿','元','元曲','yuanqu','','[]','则这紧的到头终是紧，亲的原来只是亲。',91,'元曲/yuanqu.json','["则这紧的到头终是紧，亲的原来只是亲。", "凭着我花朵儿身躯、笋条几年纪，为这锦片儿前程，倒赔了几锭儿花银。", "拚着个十米九糠，问甚么两妇三妻，受了些万苦千辛。", "我着人头上气忍，不枉了一世做郎君。"]'),
('yuanqu-10157','赵盼儿风月救风尘・黄钟尾','关汉卿','元','元曲','yuanqu','','[]','你穷杀呵，甘心守分捱贫困；你富呵，休笑我饱暖生淫惹议论。',155,'元曲/yuanqu.json','["你穷杀呵，甘心守分捱贫困；你富呵，休笑我饱暖生淫惹议论。", "您心中觑个意顺。", "但休了你这门内人，不要你钱财使半文。", "早是我走将来自上门。", "家业家私待你六亲，肥马轻裘待你一身，倒贴了奁房和你为眷姻。", "（云）我若还嫁了你，我不比那宋引章，针指油面，刺绣铺房，大裁小剪，都不晓得一些儿的。", "（唱）我将你写了的休书正了本。", "（同下）。"]'),
('yuanqu-10158','赵盼儿风月救风尘・双调/新水令','关汉卿','元','元曲','yuanqu','','[]','笑吟吟案板似写着休书，则俺这脱空的故人何处？卖弄他能爱女、有权术，怎禁那得胜葫芦说到有九千句。',47,'元曲/yuanqu.json','["笑吟吟案板似写着休书，则俺这脱空的故人何处？卖弄他能爱女、有权术，怎禁那得胜葫芦说到有九千句。"]'),
('yuanqu-10159','赵盼儿风月救风尘・乔牌儿','关汉卿','元','元曲','yuanqu','','[]','酒和羊，车上物；大红罗，自将去。',32,'元曲/yuanqu.json','["酒和羊，车上物；大红罗，自将去。", "你一心淫滥无是处，要将人白赖取。"]'),
('yuanqu-10160','赵盼儿风月救风尘・庆东原','关汉卿','元','元曲','yuanqu','','[]','俺须是卖空虚，凭着那说来的言咒誓为活路。',90,'元曲/yuanqu.json','["俺须是卖空虚，凭着那说来的言咒誓为活路。", "（带云）怕你不信呵，（唱）遍花街请到娼家女，那一个不对着明香宝烛，那一个不指着皇天后土，那一个不赌着鬼戮神诛？若信这咒盟言，早死的绝门户！。"]'),
('yuanqu-10161','赵盼儿风月救风尘・落梅风','关汉卿','元','元曲','yuanqu','','[]','则为你思虑，忒模糊。',69,'元曲/yuanqu.json','["则为你思虑，忒模糊。", "（周舍云）休书已毁了，你不跟我去待怎么？（外旦怕科）（正旦云）妹子休慌莫伯！咬碎的是假休书。", "（唱）我特故抄与你个休书。"]'),
('yuanqu-10162','赵盼儿风月救风尘・得胜令','关汉卿','元','元曲','yuanqu','','[]','宋引章有亲夫，他强占作家属。',49,'元曲/yuanqu.json','["宋引章有亲夫，他强占作家属。", "淫乱心情歹，凶顽胆气粗，无徒！到处里胡为做。", "现放着体书，望恩官明鉴取。"]'),
('yuanqu-10163','赵盼儿风月救风尘・沽美酒','关汉卿','元','元曲','yuanqu','','[]','他幼年间便习儒，腹隐着九经书；又是俺共里同村一处居，接受了钗环财物，明是个良人妇。',41,'元曲/yuanqu.json','["他幼年间便习儒，腹隐着九经书；又是俺共里同村一处居，接受了钗环财物，明是个良人妇。"]'),
('yuanqu-10164','赵盼儿风月救风尘・太平令','关汉卿','元','元曲','yuanqu','','[]','现放着保亲的堪为凭据，怎当他抢亲的百计亏图？那里是明婚正娶，公然的伤风败俗！今日个诉与太府做主，可怜见断他夫妻完聚。',196,'元曲/yuanqu.json','["现放着保亲的堪为凭据，怎当他抢亲的百计亏图？那里是明婚正娶，公然的伤风败俗！今日个诉与太府做主，可怜见断他夫妻完聚。", "（孤云）周舍，那宋引章明明有丈夫的，你怎生还赖是你的妻子？若不看你父亲面上，送你有司问罪！您一行人，听我下断：周舍杖六十，与民一体当差。", "宋引章仍归安秀才为妻;赵盼儿等宁家住坐。", "（词云）只为老虔婆爱贿贪钱，赵盼儿细说根源。", "呆周舍不安本业，安秀才夫妇团圆。", "（众叩谢科）（正旦唱）。"]'),
('yuanqu-10165','赵盼儿风月救风尘・收尾','关汉卿','元','元曲','yuanqu','','[]','对恩官一一说缘故，分剖开贪夫怨女。',36,'元曲/yuanqu.json','["对恩官一一说缘故，分剖开贪夫怨女。", "面糊盆再休说死生交，风月所重谐燕莺侣。"]'),
('yuanqu-10166','仙吕・点绛唇','于伯渊','元','元曲','yuanqu','','[]','漏尽铜龙，香消金凤，花梢弄，斜月帘栊，唤醒相思梦。',25,'元曲/yuanqu.json','["漏尽铜龙，香消金凤，花梢弄，斜月帘栊，唤醒相思梦。"]'),
('yuanqu-10167','混江龙・绣帏春重，趁东风培养出牡丹丛。流苏斗帐，龟甲屏风。七宝妆','于伯渊','元','元曲','yuanqu','','[]','奁明彩钿，一帘香雾袅薰笼；慢卷起金花孔雀，锦屏开绿水芙蓉。',127,'元曲/yuanqu.json','["奁明彩钿，一帘香雾袅薰笼；慢卷起金花孔雀，锦屏开绿水芙蓉。", "鸦翅袒金蝉半妥，翠云偏朱凤斜松，眉儿扫杨柳双弯浅碧，口儿点樱桃一颗娇红；眼如珠光摇秋水，脸如连花笑春风。", "鸾钗插花枝蹀躞，凤翘悬珠翠玲珑；胭脂蜡红腻锦犀盒，蔷薇露滴注玻璃瓮。", "端详了艳质，出落着春工。"]'),
('yuanqu-10168','油葫芦・鸾镜光函百炼铜，端详了这玉容。似嫦娥出现广寒宫，衬桃腮巧','于伯渊','元','元曲','yuanqu','','[]','注铅华莹，启朱唇呵暖兰膏冻。',46,'元曲/yuanqu.json','["注铅华莹，启朱唇呵暖兰膏冻。", "着粉呵则太白，施朱呵则太红。", "鬓蝉低娇怯香云重，端的是占断绮罗丛。"]'),
('yuanqu-10169','天下乐・半点儿花钿笑靥中，娇红，酒晕浓，天生下没褒弹的可意种。翰','于伯渊','元','元曲','yuanqu','','[]','林才咏不成，丹青笔画不同，可知道汉宫画爱宠。',22,'元曲/yuanqu.json','["林才咏不成，丹青笔画不同，可知道汉宫画爱宠。"]'),
('yuanqu-10170','那吒令・露春纤玉葱，扫眉尖翠峰，清香含玉容。整花枝翠丛，插金钗玉','于伯渊','元','元曲','yuanqu','','[]','褪罗衣翠绒，缕金妆七宝环，玉簪挑双珠凤，比西施宜淡宜浓。',28,'元曲/yuanqu.json','["褪罗衣翠绒，缕金妆七宝环，玉簪挑双珠凤，比西施宜淡宜浓。"]'),
('yuanqu-10171','寄生草・他生的倾城貌，绝代容。弄春情漏泄的秋波送，秋波送搬斗的春','于伯渊','元','元曲','yuanqu','','[]','山纵，春山纵勾引的芳心动。',29,'元曲/yuanqu.json','["山纵，春山纵勾引的芳心动。", "鬓花腮粉可人怜，翠衾鸳枕和谁共。"]'),
('yuanqu-10172','幺・情尤重，意转浓，恰相逢似晋刘晨误入桃源洞，乍相逢似楚巫娥暂赴','于伯渊','元','元曲','yuanqu','','[]','阳台梦，害相思似庾兰成愁赋香奁咏。',49,'元曲/yuanqu.json','["阳台梦，害相思似庾兰成愁赋香奁咏。", "你这般玉精神花模样赛过玉天仙，我待要锦缠头珠络索盖下一座花胡同。"]'),
('yuanqu-10173','金盏儿・脸霞红，眼波横。见人羞推整双头凤。柳情花意媚东风。钿窝儿','于伯渊','元','元曲','yuanqu','','[]','里粘晓翠，腮斗儿上晕春红。',27,'元曲/yuanqu.json','["里粘晓翠，腮斗儿上晕春红。", "包藏着风月约，出落着雨云踪。"]'),
('yuanqu-10174','后庭花・绣床铺绿剪绒，花房深红守宫。豆蔻蕊梢头嫩，绛纱香臂上封。','于伯渊','元','元曲','yuanqu','','[]','恨匆匆，寻些儿闲空，美甘甘两意通，喜孜孜一笑中。',24,'元曲/yuanqu.json','["恨匆匆，寻些儿闲空，美甘甘两意通，喜孜孜一笑中。"]'),
('yuanqu-10175','幺篇・云鬓松，星眼朦胧，锦被重重，罗袜弓弓，粉汗溶溶。那些儿风流','于伯渊','元','元曲','yuanqu','','[]','受用，兀的不两意浓。',64,'元曲/yuanqu.json','["受用，兀的不两意浓。", "言行功容，四德三从，孟光合配梁鸿，怎教他齐眉举案劳尊重，俏书生别有家风。", "金荷烧尽良宵永，怜香惜玉，倚翠偎红。"]'),
('yuanqu-10176','赚煞・花月巧梳妆，脂粉娇调弄，没乱杀看花的眼睛，更那堪心有灵犀一','于伯渊','元','元曲','yuanqu','','[]','点通，恼春光烂熳娇慵，莫不是蕊珠宫天上飞琼。',56,'元曲/yuanqu.json','["点通，恼春光烂熳娇慵，莫不是蕊珠宫天上飞琼。", "走向瑶台月下逢。", "比及他彩灯照梦，且看咱隔墙儿窥宋，俊宠儿娇怯海棠风。"]'),
('yuanqu-10177','刘夫人庆赏五侯宴・正宫/端正好','关汉卿','元','元曲','yuanqu','','[]','则我这腹中愁、心间闷，俺穷滴滴举眼无亲，则俺这孤寒子母每谁瞅问？俺男儿半世苦受勤，但能勾得钱物，宁可着典咱身！（赵太公云）则今日埋殡你丈夫，便跟我家中去来。',99,'元曲/yuanqu.json','["则我这腹中愁、心间闷，俺穷滴滴举眼无亲，则俺这孤寒子母每谁瞅问？俺男儿半世苦受勤，但能勾得钱物，宁可着典咱身！（赵太公云）则今日埋殡你丈夫，便跟我家中去来。", "（正旦唱）则今日将俺夫主亲埋殡。", "（同下）。"]'),
('yuanqu-10178','刘夫人庆赏五侯宴・仙吕/点绛唇','关汉卿','元','元曲','yuanqu','','[]','我如今短叹长吁，满怀冤屈，难分诉。',35,'元曲/yuanqu.json','["我如今短叹长吁，满怀冤屈，难分诉。", "则我这衣袂粗疏，都是些草络布无绵絮。"]'),
('yuanqu-10179','刘夫人庆赏五侯宴・混江龙','关汉卿','元','元曲','yuanqu','','[]','我堪那无端的豪户，瞒心昧己使心毒。',88,'元曲/yuanqu.json','["我堪那无端的豪户，瞒心昧己使心毒。", "他可便心侥幸，倒换过文书，当日个约定觅自家做乳母，今日个强赖做他家里的买身躯。", "我可也受禁持、吃打骂敢无重数。", "则我这孤孀子母，更和这瘦弱身躯！。"]'),
('yuanqu-10180','刘夫人庆赏五侯宴・油葫芦','关汉卿','元','元曲','yuanqu','','[]','打拷杀咱家谁做主？有百十般曾对付：我从那上灯时直看到二更初，我若是少乳些则管里吖吖的哭，我若是多乳些灌的他啊啊的吐；这孩儿能夜啼不犯触，则从那摇车儿上挂着爷单裤',91,'元曲/yuanqu.json','["打拷杀咱家谁做主？有百十般曾对付：我从那上灯时直看到二更初，我若是少乳些则管里吖吖的哭，我若是多乳些灌的他啊啊的吐；这孩儿能夜啼不犯触，则从那摇车儿上挂着爷单裤，挂到有三十遍倒蹄驴。"]'),
('yuanqu-10181','刘夫人庆赏五侯宴・天下乐','关汉卿','元','元曲','yuanqu','','[]','不似您这孩儿不犯触，可是他声也波声，声声的则待要哭。',66,'元曲/yuanqu.json','["不似您这孩儿不犯触，可是他声也波声，声声的则待要哭。", "则从那摇车儿上魇禳无是处。", "谁敢道是荡他一荡？谁敢是触他一触？可是他叫吖吖无是处。"]'),
('yuanqu-10182','刘夫人庆赏五侯宴・金盏儿','关汉卿','元','元曲','yuanqu','','[]','你富的每有金珠，俺穷的每受孤独，都一般牵挂着他这个亲肠肚。',77,'元曲/yuanqu.json','["你富的每有金珠，俺穷的每受孤独，都一般牵挂着他这个亲肠肚。", "我这里两步为一蓦，急急下街衢。", "我战钦钦身刚举，笃速速手难舒。", "我哭啼啼扳住臂膊，泪漫漫的扯住衣服。"]'),
('yuanqu-10183','刘夫人庆赏五侯宴・尾声','关汉卿','元','元曲','yuanqu','','[]','儿也！则要你久已后报冤仇，托赖着伊家福，好共歹一处受苦。',146,'元曲/yuanqu.json','["儿也！则要你久已后报冤仇，托赖着伊家福，好共歹一处受苦。", "我指望待将傍的孩儿十四五，与人家作婢为奴。", "自踌蹰，堪恨这个无徒！（带云）儿也，你不成人便罢，倘或成了人呵，（唱）你穿着些布背子，排门儿告些故疏。", "恁时节老人家暮古，与人家重生活难做。", "哎，儿也！你寻些个口衔钱，赎买您娘那一纸放良书。", "（下）。"]'),
('yuanqu-10184','刘夫人庆赏五侯宴・南吕/一枝花','关汉卿','元','元曲','yuanqu','','[]','恰才得性命逃，速速的离宅舍。',94,'元曲/yuanqu.json','["恰才得性命逃，速速的离宅舍。", "我可便一心空硬咽，则我这两只脚可兀的走忙迭。", "我把这衣袂来忙遮，俺孩儿浑身上绵茧儿无一叶。", "我与你往前行，无气歇，眼见的无人把我来拦遮，我可便将孩儿直送到荒郊旷野。"]'),
('yuanqu-10185','刘夫人庆赏五侯宴・梁州','关汉卿','元','元曲','yuanqu','','[]','我如今官差可便弃舍。',186,'元曲/yuanqu.json','["我如今官差可便弃舍。", "哎，儿也！咱两个须索今日离别，这冤家必定是前生业。", "这孩儿仪容儿清秀，模样儿英杰。", "我熬煎了无限，受苦了偌些。", "我和他是吃了人多少唇舌，不由我感叹伤嗟！我、我、我，今日个母弃了儿，非是我心毒，是、是、是，更和这儿离了母如何的弃舍！哎！天也，天也！俺可便眼睁睁子母每各自分别，直恁般运拙。", "这冤家苦楚何时彻？谁能够暂时歇？若是我无你个孩儿伶俐些，那其间方得宁贴。"]'),
('yuanqu-10186','刘夫人庆赏五侯宴・隔尾','关汉卿','元','元曲','yuanqu','','[]','我这里牵肠割肚把你个孩儿舍，跌脚捶胸自叹嗟。',69,'元曲/yuanqu.json','["我这里牵肠割肚把你个孩儿舍，跌脚捶胸自叹嗟。", "望得无人，拾将这草料儿遮，将乳食来喂些，我与你且住者。", "儿也！就在这官道旁边，敢将你来冻煞也！。"]'),
('yuanqu-10187','刘夫人庆赏五侯宴・贺新郎','关汉卿','元','元曲','yuanqu','','[]','富豪家安稳把孩儿好抬迭，这孩儿脱命逃生，媳妇儿感承多谢！（李嗣源云）我和你做个亲眷可不好？（正里唱）官人上怎敢为枝叶？教孩儿执帽擎鞭抱靴。',163,'元曲/yuanqu.json','["富豪家安稳把孩儿好抬迭，这孩儿脱命逃生，媳妇儿感承多谢！（李嗣源云）我和你做个亲眷可不好？（正里唱）官人上怎敢为枝叶？教孩儿执帽擎鞭抱靴。", "（李嗣源云）你放心，这孩儿便是我亲生嫡养的一般。", "（正旦唱）听说罢我心内欢悦，便是你李富贵合是遇英杰。", "哎！你个赵太公弄巧翻成拙。", "儿也！你今日弃了你这个穷奶奶，哎，儿也！谁承望你认这富爹爹！。"]'),
('yuanqu-10188','刘夫人庆赏五侯宴・正宫/端正好','关汉卿','元','元曲','yuanqu','','[]','风飕飕遍身麻，则我这笃籁籁连身战，冻钦钦手脚难拳。',45,'元曲/yuanqu.json','["风飕飕遍身麻，则我这笃籁籁连身战，冻钦钦手脚难拳。", "走的紧来到荒坡佃，觉我这可扑扑的心头战。"]'),
('yuanqu-10189','刘夫人庆赏五侯宴・滚绣球','关汉卿','元','元曲','yuanqu','','[]','我这里立不定虚气喘，无筋力手腕软，瘦身躯急难动转。',93,'元曲/yuanqu.json','["我这里立不定虚气喘，无筋力手腕软，瘦身躯急难动转。", "恰来到井口旁边，雪打的我眼怎开，风吹的我身倒偃，冻碌碌自嗟自怨，也是咱前世前缘。", "冻的我拿不的绳索拳挛着手，立不定身躯耸定肩，苦痛难言！。"]'),
('yuanqu-10190','刘夫人庆赏五侯宴・倘秀才','关汉卿','元','元曲','yuanqu','','[]','我这里立不定吁吁的气喘，我将这绳头儿呵的来觉软。',48,'元曲/yuanqu.json','["我这里立不定吁吁的气喘，我将这绳头儿呵的来觉软。", "一桶水提离井口边，寒参参手难拳，我可便应难动转。"]'),
('yuanqu-10191','刘夫人庆赏五侯宴・倘秀才','关汉卿','元','元曲','yuanqu','','[]','那官人系着条玉兔鹘连珠儿石碾，戴着顶白毡笠前檐儿漫卷。',79,'元曲/yuanqu.json','["那官人系着条玉兔鹘连珠儿石碾，戴着顶白毡笠前檐儿漫卷。", "（李从珂云）他来你这里有甚么勾当？（正里唱）可是他赶玉兔因来到俺这地面，他兜玉辔，勒征马宛，斜挑着镫偏。"]'),
('yuanqu-10192','刘夫人庆赏五侯宴・呆骨朵','关汉卿','元','元曲','yuanqu','','[]','那官人笑吟吟，手捻着一枝雕翎箭，我可便把孩儿来与了那个官员。',451,'元曲/yuanqu.json','["那官人笑吟吟，手捻着一枝雕翎箭，我可便把孩儿来与了那个官员。", "（李从珂云）曾有甚么信息来？（正旦唱）知他是富贵也那安然，知他是荣华也那稳便。", "（李从珂云）你这许多时不曾望你那孩儿一望？（正旦唱）要去呵应难去。", "（李从珂云）你曾见你那孩儿来么？（正旦唱）要见阿应难见。", "（李从珂云）你那孩儿小名唤做甚么？（正旦唱）知他是安在也那王阿三。", "（李从珂云）要了你那孩儿去的官人姓甚名谁？（正旦唱）你早则得福也李嗣源。", "（李从珂云）奇怪也！这婆婆叫着我阿妈的名字。", "左右，这世上，有几个李嗣源？（卒子云）止有阿妈一个是李嗣源。", "（李从珂云）兀那婆婆，我和李嗣源一张纸上画字，我到家中说了，若有你那孩儿时，我教他看你来。", "你那孩儿如今多大年纪？几月几日甚么时生？你说与我。", "（正旦云）俺孩儿是八月十五日半夜子时生，年十八岁也，小名唤做王阿三。", "（李从珂云）奇怪也！这婆婆说的那生时年纪，和我同年同月同日同时一般般的，则争一个名字差着，其中必有暗昧。", "我到家中呵，好歹着你孩儿来望你，你意下如何？（正旦云）官人是必着孩儿来看我一看。", "（唱）。"]'),
('yuanqu-10193','刘夫人庆赏五侯宴・啄木儿尾声','关汉卿','元','元曲','yuanqu','','[]','你是必传示与那李嗣源，道与俺那闵子骞，有时节教俺这子母每重相见。',53,'元曲/yuanqu.json','["你是必传示与那李嗣源，道与俺那闵子骞，有时节教俺这子母每重相见。", "要相逢一面，则除是南柯梦里得团圆。", "（下）。"]'),
('yuanqu-10194','刘夫人庆赏五侯宴・逍遥乐','关汉卿','元','元曲','yuanqu','','[]','俺直吃的尽醉方归；转筹箸不得逃席。',92,'元曲/yuanqu.json','["俺直吃的尽醉方归；转筹箸不得逃席。", "（李亚子做递酒科，云）将酒来，阿者满饮一杯！（正旦做接酒科，唱）住者，此盏罢；孩儿每你着他稳坐的，序长幼则论年纪。", "觥筹交错，李嗣源为头，各分您那坐位。"]'),
('yuanqu-10195','刘夫人庆赏五侯宴・醋葫芦','关汉卿','元','元曲','yuanqu','','[]','那时节曾记得你有个弟弟，你阿妈乞将来不曾与些好衣食。',53,'元曲/yuanqu.json','["那时节曾记得你有个弟弟，你阿妈乞将来不曾与些好衣食。", "你阿妈后来生下你，教那厮放牛羊过日，到如今多管一身亏。"]'),
('yuanqu-10196','刘夫人庆赏五侯宴・醋葫芦','关汉卿','元','元曲','yuanqu','','[]','我这里低声便唤你，你可便则管里、你那里干支剌的陪笑卖楂梨，不须咱道破他早知；那孩儿举头会意，咱不说他心下也猜疑。',56,'元曲/yuanqu.json','["我这里低声便唤你，你可便则管里、你那里干支剌的陪笑卖楂梨，不须咱道破他早知；那孩儿举头会意，咱不说他心下也猜疑。"]'),
('yuanqu-10197','刘夫人庆赏五侯宴・后庭花','关汉卿','元','元曲','yuanqu','','[]','则俺这李嗣源别有谁？（李嗣源做悲科）（李从珂云）老阿者，如今王阿三在那里？（正旦云）孩儿也，十八年前你阿妈大雪里在那潞州长子县抱将你来。',461,'元曲/yuanqu.json','["则俺这李嗣源别有谁？（李嗣源做悲科）（李从珂云）老阿者，如今王阿三在那里？（正旦云）孩儿也，十八年前你阿妈大雪里在那潞州长子县抱将你来。", "（李从珂云）老阿者，您孩儿可是谁？（正旦唱）哎，儿也！则这个王阿三可则便是你！（李从珂云）原来我便是王阿三，兀的不气杀我也！（做昏倒科）（众做救科）（李嗣源云）从珂儿也，精细着！（正旦云）从珂儿也，苏醒者！（李从珂做醒、悲科，云）哎哟，痛杀我也！（正旦云）孩儿，省烦恼！（李从珂云）老阿者，我的亲母见受着千般苦楚，我怎生不烦恼？（李嗣源云）阿者，恰才休和他说也罢，不争孩儿知道了，如今便要去认他那亲娘去，如之奈何？（正旦唱）不争咱这养育父将他相瞒昧，（正旦云）咱是他养育父母，他见了他亲娘受无限苦楚，不争你不要他去认呵，（唱）哎，儿也！则他那嫡亲娘可是图一个甚的？他如今受驱驰，他如今六十余岁，他身单寒腹内饥，他哭啼啼担着水；你将来瞒昧者。", "（李嗣源云）阿者，则是生分了孩儿也。", "（正旦云）孩儿，他这里怕不骑鞍压马，受用快活；他那亲娘与人家担水运浆，在那里吃打吃骂。", "孩儿，你寻思波，（唱）。"]'),
('yuanqu-10198','刘夫人庆赏五侯宴・双雁儿','关汉卿','元','元曲','yuanqu','','[]','他怎肯坐而不觉立而饥？母恩临怎忘的？你着他报了冤仇雪了冤气，你着他去认义，那其间来见你。',44,'元曲/yuanqu.json','["他怎肯坐而不觉立而饥？母恩临怎忘的？你着他报了冤仇雪了冤气，你着他去认义，那其间来见你。"]'),
('yuanqu-10199','刘夫人庆赏五侯宴・尾声','关汉卿','元','元曲','yuanqu','','[]','快疾忙摆剑戟，众番官领兵器，将孩儿紧紧的厮追随。',69,'元曲/yuanqu.json','["快疾忙摆剑戟，众番官领兵器，将孩儿紧紧的厮追随。", "我则是可怜见他母亲无主依，你与我疾行动一会。", "他认了他嫡亲娘，你与我疾便的早些儿回。", "（下）。"]'),
('yuanqu-10200','刘夫人庆赏五侯宴・双调/新水令','关汉卿','元','元曲','yuanqu','','[]','则听的叫一声"拿过那贱人来"，我见叫吖吖大惊小怪。',60,'元曲/yuanqu.json','["则听的叫一声\"拿过那贱人来\"，我见叫吖吖大惊小怪。", "狠心肠的歹大哥，欺侮俺无主意的老形骸！也是我运拙时乖，舍死的尽心儿奈。"]'),
('yuanqu-10201','刘夫人庆赏五侯宴・川拔棹','关汉卿','元','元曲','yuanqu','','[]','我则见闹垓垓、闹垓垓的军到来，一个个志气胸怀，马上胎孩；雄赳赳名扬四海，喜孜孜美满腮。',43,'元曲/yuanqu.json','["我则见闹垓垓、闹垓垓的军到来，一个个志气胸怀，马上胎孩；雄赳赳名扬四海，喜孜孜美满腮。"]'),
('yuanqu-10202','刘夫人庆赏五侯宴・七弟兄','关汉卿','元','元曲','yuanqu','','[]','我这里见来、料来，这个英才，入门来两步为一蓦，大踏步一伙上前来，低着头展脚舒腰拜。',41,'元曲/yuanqu.json','["我这里见来、料来，这个英才，入门来两步为一蓦，大踏步一伙上前来，低着头展脚舒腰拜。"]'),
('yuanqu-10203','刘夫人庆赏五侯宴・梅花酒','关汉卿','元','元曲','yuanqu','','[]','他不住的唤奶奶，把泪眼揉开，走向前来，急慌忙扶策。',122,'元曲/yuanqu.json','["他不住的唤奶奶，把泪眼揉开，走向前来，急慌忙扶策。", "众军卒一字摆，众官员两边排。", "俺孩儿是壮哉！可扑的跪在尘埃，可扑的跪在尘埃。", "（李从珂云）母亲，认的您孩儿王阿三么？（正旦云）谁是王阿三？（李从珂云）则我便是王阿三。", "（正旦与从珂做悲科）（正旦唱）。"]'),
('yuanqu-10204','刘夫人庆赏五侯宴・喜江南','关汉卿','元','元曲','yuanqu','','[]','儿也！今日个"月明千里故人来"，这一场好事奔人来。',56,'元曲/yuanqu.json','["儿也！今日个\"月明千里故人来\"，这一场好事奔人来。", "俺孩儿堂堂状貌有人材，畅好是气概！恰便似九重天飞下一纸赦书来。"]'),
('yuanqu-10205','刘夫人庆赏五侯宴・太平令','关汉卿','元','元曲','yuanqu','','[]','稳情取香车麾盖，子母每终是英才。',54,'元曲/yuanqu.json','["稳情取香车麾盖，子母每终是英才。", "怡乐着升平景界，端的是雍熙无赛。", "呀！今日个喜哉、美哉、快哉！谢皇恩躬身礼拜。"]'),
('yuanqu-10206','苏子瞻醉写赤壁赋・仙吕/点绛唇','无名氏','元','元曲','yuanqu','','[]','想伊每十载寒窗，平生指望，登春榜。',34,'元曲/yuanqu.json','["想伊每十载寒窗，平生指望，登春榜。", "今日便怀宝迷邦，谁肯待举直错诸枉。"]'),
('yuanqu-10207','苏子瞻醉写赤壁赋・混江龙','无名氏','元','元曲','yuanqu','','[]','赤紧的斯文天丧，空将这美玉韫匮藏。',125,'元曲/yuanqu.json','["赤紧的斯文天丧，空将这美玉韫匮藏。", "你便能勾片言折狱，一语兴邦，不肯去兰省一朝登北阙，便想这茅庐三顾到南阳。", "毛锥乏尽，铁砚磨穿，高歌鼓腹，长笑掀髯。", "我则待慢登临感慨悦他这个仲宣楼，我则怕有才无命的在颜回巷，我则待养浩然袁门积雪，久以后空嗟叹得潘鬓成霜。"]'),
('yuanqu-10208','苏子瞻醉写赤壁赋・油葫芦','无名氏','元','元曲','yuanqu','','[]','且则说我远志轻离父母乡，投京师应举场，将群儒战退气昂昂，夺这翰林两字标金榜，便是那禹门三级桃花浪。',82,'元曲/yuanqu.json','["且则说我远志轻离父母乡，投京师应举场，将群儒战退气昂昂，夺这翰林两字标金榜，便是那禹门三级桃花浪。", "那时节进表章，才能勾见帝正。", "将白衣脱在金阶上，便能勾披紫绶换金章。"]'),
('yuanqu-10209','苏子瞻醉写赤壁赋・天下乐','无名氏','元','元曲','yuanqu','','[]','恁时节宣赐蒙恩出建章，朱也波裳，列在两厢，起蛰龙一声雷震响。',52,'元曲/yuanqu.json','["恁时节宣赐蒙恩出建章，朱也波裳，列在两厢，起蛰龙一声雷震响。", "会风云志四方，遂功名纸半张，也是男儿当自强。"]'),
('yuanqu-10210','苏子瞻醉写赤壁赋・那吒令','无名氏','元','元曲','yuanqu','','[]','我这里自想，东坡的伎俩，怎比那东山气象，怎做的东床伴当。',53,'元曲/yuanqu.json','["我这里自想，东坡的伎俩，怎比那东山气象，怎做的东床伴当。", "主人宽东阁开，直吃的曙色晓东方亮，论甚么日照东窗。"]'),
('yuanqu-10211','苏子瞻醉写赤壁赋・鹊踏枝','无名氏','元','元曲','yuanqu','','[]','且休说翰林忙，暂入他绮罗乡。',69,'元曲/yuanqu.json','["且休说翰林忙，暂入他绮罗乡。", "我则见烛摇红影，月色昏黄。", "(王)学士，拚了今朝沉醉，有何不可。", "(正末唱)拚了今宵痛赏，我却甚么检书幌剔尽银缸。"]'),
('yuanqu-10212','苏子瞻醉写赤壁赋・寄生草','无名氏','元','元曲','yuanqu','','[]','今日在编修院，往常住冰雪堂。',96,'元曲/yuanqu.json','["今日在编修院，往常住冰雪堂。", "诗魂高压山河壮，琴弹神鬼魂飘荡，剑挥星斗昏无象。", "我将这九经苦志二十年，养就这五陵豪气三千丈。", "(秦云)想布衣之中，苦志攻习经史，今日博得金章紫绶，千钟之禄也。", "(唱)。"]'),
('yuanqu-10213','苏子瞻醉写赤壁赋・幺篇','无名氏','元','元曲','yuanqu','','[]','今日有千钟禄，往常无半日粮。',361,'元曲/yuanqu.json','["今日有千钟禄，往常无半日粮。", "十年礼义勤习讲，半生盐菜贫修养，才落得金章紫绶高名望。", "我将这五车黄卷隐胸中，才博得一轮皂盖飞头上。", "(王云)左右将酒来，与学士满饮一杯。", "(与众把酒科，云)便好道筵前无乐，不成欢笑。", "小官有家乐数人，着筵前吹弹歌舞为乐。", "下次小的每，与我唤出那侍妾来者。", "(外扮旦引众旦上，云)妾身乃王安石夫人也。", "今有苏子瞻官拜端明殿大学士，俺相公今夜排设筵宴，请众官并子瞻学士。", "为何夜间排宴？因妾身闻知子瞻有贯世之才，妾身要见一面。", "筵间出家乐侍妾数人，妾身隐于侍女之中，必然见之。", "可早来到虚檐之下也。", "(见科，王云)你这十数个家乐侍女，则在于帘外，吹的吹，弹的弹，歌的歌。", "左右一壁厢将酒来，与学士、众位相公递一杯。", "(递酒，乐声响科，众看科，正末背云)此侍女中决有安石夫人。", "我着一个小伎俩，要赚出来。", "是好受用也呵。", "(唱)。"]'),
('yuanqu-10214','苏子瞻醉写赤壁赋・村里迓鼓','无名氏','元','元曲','yuanqu','','[]','玉钩高挂，绣帘低放。',70,'元曲/yuanqu.json','["玉钩高挂，绣帘低放。", "我则见银台的这画烛，开华宴乐声嘹亮。", "靠着这翠矮屏，芙蓉幔，绣帏锦帐。", "一个个人如玉，花如锦，酒满觞，俺这里别是个风光画堂。"]'),
('yuanqu-10215','苏子瞻醉写赤壁赋・元和令','无名氏','元','元曲','yuanqu','','[]','雕盘中霭篆香，金盏内泛琼浆。',50,'元曲/yuanqu.json','["雕盘中霭篆香，金盏内泛琼浆。", "这的是主人开宴出红妆，列金钗十二行。", "一个个藕丝新嫩织仙裳，玉圆搓粉颈香。"]'),
('yuanqu-10216','苏子瞻醉写赤壁赋・上马娇','无名氏','元','元曲','yuanqu','','[]','他每都宫样妆，列在两厢。',45,'元曲/yuanqu.json','["他每都宫样妆，列在两厢。", "知他那个是宫主共梅香，将阳春白雪齐歌唱。", "夜正凉，直吃的明月转回廊。"]'),
('yuanqu-10217','苏子瞻醉写赤壁赋・游四门','无名氏','元','元曲','yuanqu','','[]','尚兀自绕梁音韵尚悠扬，犴客恼愁肠。',86,'元曲/yuanqu.json','["尚兀自绕梁音韵尚悠扬，犴客恼愁肠。", "(旦将罗帕藏手科，正末云)小娘子金钗坠也。", "(旦用手抹头上，将帕藏手科，众笑科，正末唱)报一声金钗斜坠乌云上，举手意张狂。", "忙，将罗帕紧遮藏。"]'),
('yuanqu-10218','苏子瞻醉写赤壁赋・胜葫芦','无名氏','元','元曲','yuanqu','','[]','呀，早露出十指纤纤春笋长，他生的颜色果非常，恰便似困倚东风睡海棠。',51,'元曲/yuanqu.json','["呀，早露出十指纤纤春笋长，他生的颜色果非常，恰便似困倚东风睡海棠。", "司空见惯，全胜宋玉，想象赋《高唐》。"]'),
('yuanqu-10219','苏子瞻醉写赤壁赋・后庭花','无名氏','元','元曲','yuanqu','','[]','他生的脸银盘腻粉妆，口微喷兰麝香。',71,'元曲/yuanqu.json','["他生的脸银盘腻粉妆，口微喷兰麝香。", "云鬓堆鸦翅。", "金钗插凤凰。", "细端详，他生的娇容模样，料人间无处长，想蓬莱是故乡。", "宴蟠桃惹下罪非殃，犯天条奏玉皇。"]'),
('yuanqu-10220','苏子瞻醉写赤壁赋・柳叶儿','无名氏','元','元曲','yuanqu','','[]','呀，他生在九重天上，下彩云误落在朝阳，他生的千娇百媚人中样。',50,'元曲/yuanqu.json','["呀，他生在九重天上，下彩云误落在朝阳，他生的千娇百媚人中样。", "比花花无语，比玉玉无香，堪移在兰舍椒房。"]'),
('yuanqu-10221','苏子瞻醉写赤壁赋・尾声','无名氏','元','元曲','yuanqu','','[]','可惜玉山颓，尽教恁金波漾，拚了个前合后仰。',195,'元曲/yuanqu.json','["可惜玉山颓，尽教恁金波漾，拚了个前合后仰。", "终夜劳神将足下央，莫怪我酒席间言语疏狂。", "出雕墙，月下西厢，消洒西风将醉魂爽。", "恁把绛纱笼近掌，我紫丝缰款放，趁天风吹下五云乡。", "(下)(王云)苏轼去了。", "叵耐此人无礼。", "某请你家宴，小官侍妾，淫词戏却，更待干罢。", "我到来日见了圣人说过。", "一者此人不知黄州菊花谢，二者趁此机会，将他贬上黄州，趁了小官之愿。", "天色晚了也，左右收拾果桌。", "我无甚事，回后堂去也。", "(下)。"]'),
('yuanqu-10222','苏子瞻醉写赤壁赋・南昌/一枝花','无名氏','元','元曲','yuanqu','','[]','则为我数杯狂酒终，今日个三唱阳关后。',66,'元曲/yuanqu.json','["则为我数杯狂酒终，今日个三唱阳关后。", "一鞭催行色，满马载离愁。", "羊角风飕飕，时遇冬天候，漫漫雪不休。", "我如今才出皇州，可又早渐入冰壶宇宙。"]'),
('yuanqu-10223','苏子瞻醉写赤壁赋・梁州','无名氏','元','元曲','yuanqu','','[]','我则见银海冻花生的这眼底，玉楼寒耸起肩头。',268,'元曲/yuanqu.json','["我则见银海冻花生的这眼底，玉楼寒耸起肩头。", "摇鞭袖袅深藏手。", "风掀毡帽，雪压寒裘。", "雕鞍懒坐，玉辔慵兜。", "银妆成山岳林丘，粉填合溪涧坑沟。", "这雪恰便似无影月淡朦朦光照人间，这雪有如那冻流水响叮叮冰生他这岸口，这雪浑似那不香花舞翩风落枝头。", "自思，故友，这其间销金帐底羊羔酒，燃宝篆焚香兽。", "簌地毡帘下玉钩，煞强如独钓在江头。", "(童云)那骑马的是俺相公，我在这里等一等咱。", "(解云)也说的是。", "(见末科，云)老相公，俺在前头走，你骑着马又在后头，俺在后头，你又往前头去了。", "似这般大风大雪，寻一个村房草店，买两钟酒吃了呵，可也好。", "(正末云)你也说的是。", "(唱)。"]'),
('yuanqu-10224','苏子瞻醉写赤壁赋・牧羊关','无名氏','元','元曲','yuanqu','','[]','你看那瑞雪迷了前路，彤云蔽了日头，冒风寒满腹离愁。',92,'元曲/yuanqu.json','["你看那瑞雪迷了前路，彤云蔽了日头，冒风寒满腹离愁。", "冷冻皮肤，寒侵肌肉。", "雪拥难行马，风紧懒抬头。", "我这里战兢兢把不住浑身冷，(解云)我说道若雪住了，明日行也罢。", "(正末唱)也是我官差不自由。"]'),
('yuanqu-10225','苏子瞻醉写赤壁赋・贺新郎','无名氏','元','元曲','yuanqu','','[]','我这里停骖举首猛凝眸，恁在这十里长亭，众兄等候。',190,'元曲/yuanqu.json','["我这里停骖举首猛凝眸，恁在这十里长亭，众兄等候。", "(贺云)将酒来，与学士饮一杯荡寒咱。", "(正末唱)你道是劝君更尽一杯酒，则怕酒入愁肠转更愁，(邵云)学士可愁甚么？(正末唱)这愁烦才了又在眉头。", "(贺云)学士，你看风雪如花飞万片，正好饮几杯。", "(正末唱)你道是雪花飞千万片，且饮酒两三瓯，我则为花浓酒酿，送的我无人救。", "(秦云)学士，异日必有相会之期。", "(正末唱)再谁想有花方饮酒，无月不登楼。"]'),
('yuanqu-10226','苏子瞻醉写赤壁赋・牧羊关','无名氏','元','元曲','yuanqu','','[]','俺两个十年旧，到今日一旦休，才得志便与我话不相投。',124,'元曲/yuanqu.json','["俺两个十年旧，到今日一旦休，才得志便与我话不相投。", "则为他家有贤妻，送了俺交绝故友。", "我如今苦痛分妻子，他今日谈笑可便觅封侯。", "(贺云)学士，那一夜忒酒后疏狂也。", "(正末唱)都则为一醉三更酒，(贺云)因此一事，贬学士上黄州歇马。", "(正未唱)送的我孤身万里游。"]'),
('yuanqu-10227','苏子瞻醉写赤壁赋・哭皇天','无名氏','元','元曲','yuanqu','','[]','论今日非吾犯，想前朝先早有。',105,'元曲/yuanqu.json','["论今日非吾犯，想前朝先早有。", "(贺云)学士，可是何人？(正末唱)韩吏部李翰林他今日立下傍州，他每是遭流的罪罪首。", "他两个文施翰墨，笔扫千军，临危世乱，势尽时休。", "传与俺这坏风俗歹事头，一个在潮阳路上，一个在采石渡口。"]'),
('yuanqu-10228','苏子瞻醉写赤壁赋・乌夜啼','无名氏','元','元曲','yuanqu','','[]','他每都摇鞭举棹无人救，送的我眼睁睁有地难投。',90,'元曲/yuanqu.json','["他每都摇鞭举棹无人救，送的我眼睁睁有地难投。", "向山林水馆捱昏昼，一个鞭袅骅骝，一个棹拨轻舟。", "一个他风涛雪浪五更头，一个漫烟雾障三春后。", "一个漾了骸骨，一个没了尸首，二人身死，万古名留。"]'),
('yuanqu-10229','苏子瞻醉写赤壁赋・耍孩儿','无名氏','元','元曲','yuanqu','','[]','咱本是翰林风月三知友，做了个犯省部条章一罪囚。',79,'元曲/yuanqu.json','["咱本是翰林风月三知友，做了个犯省部条章一罪囚。", "再不去东华待漏五更头，再不向国史编修。", "都为那靠妻偎妇的禽兽，背地里厮谗奏。", "送的我伏侍君王不到头，不能勾故国神游。"]'),
('yuanqu-10230','苏子瞻醉写赤壁赋・尾声','无名氏','元','元曲','yuanqu','','[]','我则见樵夫荷担来山口，钓叟鸣榔返渡头。',69,'元曲/yuanqu.json','["我则见樵夫荷担来山口，钓叟鸣榔返渡头。", "冻云垂，朔风透，送行人，酒数瓯，别离情，诗一首，气长吁，泪暗流。", "我向那山掩映野人家茅店上宿。", "(下)。"]'),
('yuanqu-10231','苏子瞻醉写赤壁赋・仙吕/赏花时','无名氏','元','元曲','yuanqu','','[]','我待将百姓民疾件件举，番做了秋草人情日日疏。',45,'元曲/yuanqu.json','["我待将百姓民疾件件举，番做了秋草人情日日疏。", "老夫寒儒，哎！你个无端宰予，每日家醉卧碧纱橱。"]'),
('yuanqu-10232','苏子瞻醉写赤壁赋・越调/半鹌鹑','无名氏','元','元曲','yuanqu','','[]','我则见赤壁千寻，清江万顷。',57,'元曲/yuanqu.json','["我则见赤壁千寻，清江万顷。", "水若僧眸，山如佛顶。", "雨收云霁，风清月明。", "你看这玉露冷，银汉耿。", "趁着这短棹轻舟，风恬浪静。"]'),
('yuanqu-10233','苏子瞻醉写赤壁赋・紫花儿序','无名氏','元','元曲','yuanqu','','[]','山明水秀，夜静更阑，会酒友诗朋。',62,'元曲/yuanqu.json','["山明水秀，夜静更阑，会酒友诗朋。", "千岩风定，万籁无声。", "舒情，抵多少眼底风光展画屏。", "四野如悬镜，不是我趁浪逐波，我待要洗耳独清。"]'),
('yuanqu-10234','苏子瞻醉写赤壁赋・小桃红','无名氏','元','元曲','yuanqu','','[]','你看这鱼龙吹浪水云腥，月照江心静。',64,'元曲/yuanqu.json','["你看这鱼龙吹浪水云腥，月照江心静。", "船过冲开水中镜，橹声鸣，呀呀才过了芦花径。", "恰便似惊飞凤鸣，猛惊起白鹭双双并，因此上点破乱山青。"]'),
('yuanqu-10235','苏子瞻醉写赤壁赋・金蕉叶','无名氏','元','元曲','yuanqu','','[]','人言语山鸣谷应，靠江边把扁舟缆定。',33,'元曲/yuanqu.json','["人言语山鸣谷应，靠江边把扁舟缆定。", "山高处有仙则名，水深处有龙则灵。"]'),
('yuanqu-10236','苏子瞻醉写赤壁赋・调笑令','无名氏','元','元曲','yuanqu','','[]','你道是水声，响冷泠，呀，抵多少流尽年光是此声。',108,'元曲/yuanqu.json','["你道是水声，响冷泠，呀，抵多少流尽年光是此声。", "翠巍巍一带高山静，看人间国祚丰盈。", "则愿的吾皇万岁社稷兴，有江山依旧青青。", "(禅云)将酒来与学士再把一杯，将箫来我试品一曲咱。", "(黄云)学士满饮一杯。", "(禅做品箫科)(正末唱)。"]'),
('yuanqu-10237','苏子瞻醉写赤壁赋・耍三台','无名氏','元','元曲','yuanqu','','[]','将品竹才拈定，宁心听，似《箫韶》九成。',96,'元曲/yuanqu.json','["将品竹才拈定，宁心听，似《箫韶》九成。", "(禅云)品起洞箫声。", "(正末云)休品。", "(禅云)学士为何？(正末唱)怕水底老龙惊，正风寒露冷。", "似引新雏紫燕花外声，怨离凰彩凤月下鸣。", "恰便似雁落平沙，猿啼峻岭。"]'),
('yuanqu-10238','苏子瞻醉写赤壁赋・圣药王','无名氏','元','元曲','yuanqu','','[]','一枝的曲未终，韵更清，便似子规枝上月三更。',47,'元曲/yuanqu.json','["一枝的曲未终，韵更清，便似子规枝上月三更。", "低一声，高一声，似东风花外锦鸠鸣，恰便似斜月睡闻莺。"]'),
('yuanqu-10239','苏子瞻醉写赤壁赋・煞','无名氏','元','元曲','yuanqu','','[]','举目看山青，侧耳听江声。',48,'元曲/yuanqu.json','["举目看山青，侧耳听江声。", "隐遁养姓名，不恋恁世情。", "无利无名，耳根清净。", "一心定，不受恁是非忧宠辱惊。"]'),
('yuanqu-10240','苏子瞻醉写赤壁赋・尾声','无名氏','元','元曲','yuanqu','','[]','愿忘忧乐矣乘诗兴，玩赤壁千寻浪鸣。',35,'元曲/yuanqu.json','["愿忘忧乐矣乘诗兴，玩赤壁千寻浪鸣。", "脱离子眼前愁，思量起梦中境。", "(下)。"]'),
('yuanqu-10241','苏子瞻醉写赤壁赋・双调/新水令','无名氏','元','元曲','yuanqu','','[]','贬黄州一载受驱驰，过一日胜如一岁。',41,'元曲/yuanqu.json','["贬黄州一载受驱驰，过一日胜如一岁。", "魂飞梁地远，肠断楚天低。", "芳草烟迷，夕阳外乱山翠。"]'),
('yuanqu-10242','苏子瞻醉写赤壁赋・驻马听','无名氏','元','元曲','yuanqu','','[]','春事狼藉，桃李东风蝶梦回，离愁索系，关山夜月杜鹃啼。',55,'元曲/yuanqu.json','["春事狼藉，桃李东风蝶梦回，离愁索系，关山夜月杜鹃啼。", "催促江水自奔驰，翰林风月教谁替。", "谩伤悲，滴不尽多少哭雄泪。"]'),
('yuanqu-10243','苏子瞻醉写赤壁赋・搅筝琶','无名氏','元','元曲','yuanqu','','[]','则见他便慌忙跪，举手捧金杯。',117,'元曲/yuanqu.json','["则见他便慌忙跪，举手捧金杯。", "(云)往日小官临门，数次拜谒，则推睡着，并不放参。", "(刺云)旧话休题。", "(正末唱)今日见奉使重宣，他才个克己复礼。", "(刺云)大人旧话休题。", "(正末唱)你算的个人面逐高低，降尊临卑。", "往常时得相逢是梦里，今日百事休题。"]'),
('yuanqu-10244','苏子瞻醉写赤壁赋・雁儿落','无名氏','元','元曲','yuanqu','','[]','也不是徒流感圣德，他每才知我缧绁非其罪。',38,'元曲/yuanqu.json','["也不是徒流感圣德，他每才知我缧绁非其罪。", "我则想人无再少年，元来这花有重开日。"]'),
('yuanqu-10245','苏子瞻醉写赤壁赋・挂玉钩','无名氏','元','元曲','yuanqu','','[]','今日个袖得春风可便马上归，(云)天使，我自到黄州，投了个师父，他道朝野里甚事都不管。',138,'元曲/yuanqu.json','["今日个袖得春风可便马上归，(云)天使，我自到黄州，投了个师父，他道朝野里甚事都不管。", "(使云)可是那个师父？(正末指刺史科，唱)学的这刺史每傍州例，除睡人间着总不知，(刺云)大人可怜见，是我的不是了。", "(正末唱)得与俺妻子每团圆会。", "夸甚么自己醒，说甚么他人醉。", "胡卢今后，大家休题。"]'),
('yuanqu-10246','郑月莲秋夜云窗梦・仙吕/点绛唇','无名氏','元','元曲','yuanqu','','[]','骄马吟鞭，舞裙歌扇，迟些儿见。',27,'元曲/yuanqu.json','["骄马吟鞭，舞裙歌扇，迟些儿见。", "席上尊前，抵多少阳关怨。"]'),
('yuanqu-10247','郑月莲秋夜云窗梦・混江龙','无名氏','元','元曲','yuanqu','','[]','则为俺歌喉宛转，觑着这陷人坑似误入武陵源。',192,'元曲/yuanqu.json','["则为俺歌喉宛转，觑着这陷人坑似误入武陵源。", "但和俺恩情一遍，不弱如流递二年。", "这不义门怎栽连理树，火坑中难长并头莲。", "眉尖传恨，眼角留情，枕边盟誓，袖里香罗，尊前心事，席上恩情，传书寄简，剪发燃香。", "都是俺鼻凹里蜜，待咽如何咽。", "郎君每买了些虚脾风月，卖了些实拍庄田。", "(旦见科)(净做口眼歪斜科，云)请大姐陪张秀才，也满饮一杯。", "(旦云)不会饮酒。", "(净云)小子这般人物，大姐如何不接酒？(旦唱)。"]'),
('yuanqu-10248','郑月莲秋夜云窗梦・油葫芦','无名氏','元','元曲','yuanqu','','[]','有这等夜月春风美少年，他每恶恋缠，每日价长安市上酒家眠。',113,'元曲/yuanqu.json','["有这等夜月春风美少年，他每恶恋缠，每日价长安市上酒家眠。", "(净云)大姐。", "我多有金银钱钞哩。", "(旦云)你道你有钱物。", "(唱)有一日业风吹入悲田院，那其间行云不赴凌波殿。", "丽春园十遍妆，曲江池三坠鞭。", "恰相逢初识桃花面，都是些刀剑上恶姻缘。"]'),
('yuanqu-10249','郑月莲秋夜云窗梦・天下乐','无名氏','元','元曲','yuanqu','','[]','你早卖了城南金谷园，干也波虔，怎过遣？每日价宴西楼醉归明月天。',87,'元曲/yuanqu.json','["你早卖了城南金谷园，干也波虔，怎过遣？每日价宴西楼醉归明月天。", "这壁厢间绮罗，那壁厢列管弦，我怕你有一日饥寒也守自然。", "(净云)大姐，似俺这等做子弟的，有村的，有俏的。", "(旦唱)。"]'),
('yuanqu-10250','郑月莲秋夜云窗梦・那吒令','无名氏','元','元曲','yuanqu','','[]','那等村的，肚皮里无一联半联；那等村的，酒席上不言语强言；那等村的，俺跟前无钱说有钱。',64,'元曲/yuanqu.json','["那等村的，肚皮里无一联半联；那等村的，酒席上不言语强言；那等村的，俺跟前无钱说有钱。", "村的是彻胆村，动不动村筋现，甚的是品竹调弦。"]'),
('yuanqu-10251','郑月莲秋夜云窗梦・鹊踏枝','无名氏','元','元曲','yuanqu','','[]','你觑似这等俏生员，伴着这女婵娟。',48,'元曲/yuanqu.json','["你觑似这等俏生员，伴着这女婵娟。", "吟几首嘲咏情诗，写数幅锦字花笺。", "惯播弄香矫玉软，温存出痛惜轻怜。"]'),
('yuanqu-10252','郑月莲秋夜云窗梦・寄生草','无名氏','元','元曲','yuanqu','','[]','你问我两件事，听俺取一句言。',71,'元曲/yuanqu.json','["你问我两件事，听俺取一句言。", "俏的教柳腰舞困东风软，俏的教蛾眉画出春山浅，俏的教莺喉歌送行云远。", "俏的教半橛土筑就楚阳台，村的教一把火烧了韩王殿。"]'),
('yuanqu-10253','郑月莲秋夜云窗梦・村里迓鼓','无名氏','元','元曲','yuanqu','','[]','恰才俺二人评论，评论这百年姻眷。',145,'元曲/yuanqu.json','["恰才俺二人评论，评论这百年姻眷。", "则这母亲到来，天呵不与人行方便。", "(卜云)你且请退张秀才，留下李官，觅些钱养家，可不好。", "(日唱)待敢要蝶避了蜂，莺离了燕，着镜破了铜，簪折了玉，瓶坠了泉。", "张郎呵俺直恁的缘薄分浅。", "(卜云)李官钱多，你只守着他罢。", "(旦云)他虽有钱，我不爱，我则守着那秀才。", "(唱)。"]'),
('yuanqu-10254','郑月莲秋夜云窗梦・元和令','无名氏','元','元曲','yuanqu','','[]','洞房春口内言，阳关路眼前现。',51,'元曲/yuanqu.json','["洞房春口内言，阳关路眼前现。", "赛潘安容貌可人怜，俺秀才腹中诗欺谪仙。", "一春常费买花钱，我怎肯不辨个愚共贤。"]'),
('yuanqu-10255','郑月莲秋夜云窗梦・上马娇','无名氏','元','元曲','yuanqu','','[]','教那厮空拽拳，干遇仙。',45,'元曲/yuanqu.json','["教那厮空拽拳，干遇仙。", "休想花压帽檐偏，推的个沉点点磨杆儿滴溜溜的转。", "畅好是颠，眼晕又头旋。"]'),
('yuanqu-10256','郑月莲秋夜云窗梦・游四门','无名氏','元','元曲','yuanqu','','[]','待教我片帆云影挂秋天，两岸听啼猿。',41,'元曲/yuanqu.json','["待教我片帆云影挂秋天，两岸听啼猿。", "吴江枫落胭脂浅，看渔火对愁眠。", "旋，你与我紧张筵。"]'),
('yuanqu-10257','郑月莲秋夜云窗梦・胜葫芦','无名氏','元','元曲','yuanqu','','[]','便有那天子呼来不上船，休把女熬煎。',55,'元曲/yuanqu.json','["便有那天子呼来不上船，休把女熬煎。", "待教我冷气虚心将他顾恋，觑一觑要饭吃，搂一搂要衣穿。", "我与你，积攒下些口含钱。"]'),
('yuanqu-10258','郑月莲秋夜云窗梦・幺篇','无名氏','元','元曲','yuanqu','','[]','可知，可知，你可甚只愿儿孙个个贤。',55,'元曲/yuanqu.json','["可知，可知，你可甚只愿儿孙个个贤。", "月缺又重圆，人老何曾再少年！舌尖无甜唾，口内有顽涎。", "虔婆，我委实难使燕莺怜。"]'),
('yuanqu-10259','郑月莲秋夜云窗梦・后庭花','无名氏','元','元曲','yuanqu','','[]','你爱的是贩江淮茶数船，我爱的是撼乾坤诗百联，你爱的是茶引三千道，我爱的是文章数百篇。',75,'元曲/yuanqu.json','["你爱的是贩江淮茶数船，我爱的是撼乾坤诗百联，你爱的是茶引三千道，我爱的是文章数百篇。", "这件事便休言，咱心不愿。", "请点汤晏叔原，告回避白乐天，告回避白乐天。"]'),
('yuanqu-10260','郑月莲秋夜云窗梦・柳叶儿','无名氏','元','元曲','yuanqu','','[]','他便穷如范丹、原宪，甘心守断简残编，他萤窗雪牖咱情愿。',49,'元曲/yuanqu.json','["他便穷如范丹、原宪，甘心守断简残编，他萤窗雪牖咱情愿。", "随机变，你使尽那不疼钱，也买不转我意马心猿。"]'),
('yuanqu-10261','郑月莲秋夜云窗梦・赚煞','无名氏','元','元曲','yuanqu','','[]','赢得腹中愁，不趁心头愿，大刚来时乖命蹇。',110,'元曲/yuanqu.json','["赢得腹中愁，不趁心头愿，大刚来时乖命蹇。", "山海恩情方欲坚，被俺爱钱娘扑地掀天，坏了这好姻缘。", "我则索祷告青天，若到江心早挂帆，向金山那边，豫章城前面，一帆风剪碎了贩茶船。", "(下)(卜云)李官放心。", "我好歹完备了这场事。", "(同下)。"]'),
('yuanqu-10262','郑月莲秋夜云窗梦・正宫/端正好','无名氏','元','元曲','yuanqu','','[]','诗酒翠红乡，风月莺花阵，酝酿出无边岸断梦劳魂。',41,'元曲/yuanqu.json','["诗酒翠红乡，风月莺花阵，酝酿出无边岸断梦劳魂。", "近新来添了眉尖恨，闪的我人远天涯近。"]'),
('yuanqu-10263','郑月莲秋夜云窗梦・滚绣球','无名氏','元','元曲','yuanqu','','[]','据着他满腹文，那堪一品人，酒席上那些谈论，怎不教我似倩女离魂？我官身处投至得起使臣，散了客宾，早教我急煎煎心困，我则怕辜负了人约黄昏。',94,'元曲/yuanqu.json','["据着他满腹文，那堪一品人，酒席上那些谈论，怎不教我似倩女离魂？我官身处投至得起使臣，散了客宾，早教我急煎煎心困，我则怕辜负了人约黄昏。", "不争我半披夜月才归院，多管是独立西风正倚门，盼杀郎君。"]'),
('yuanqu-10264','郑月莲秋夜云窗梦・倘秀才','无名氏','元','元曲','yuanqu','','[]','我为他心忙意紧，他为我行眠立盹，一样相思两断魂。',41,'元曲/yuanqu.json','["我为他心忙意紧，他为我行眠立盹，一样相思两断魂。", "间别一二日，胜似两三春，各自病损。"]'),
('yuanqu-10265','郑月莲秋夜云窗梦・呆骨朵','无名氏','元','元曲','yuanqu','','[]','俺两个眉尖眼角传芳信，等盘儿上暮雨朝云。',63,'元曲/yuanqu.json','["俺两个眉尖眼角传芳信，等盘儿上暮雨朝云。", "你将那铁磨杆争推，锦套头竞伸。", "舍了命风车转，咬着牙皮鞭趁。", "你有钱虽是有，俺亲的则是亲。"]'),
('yuanqu-10266','郑月莲秋夜云窗梦・脱布衫','无名氏','元','元曲','yuanqu','','[]','我如今鬓刁骚强整乌云，年纪大倦点朱唇。',35,'元曲/yuanqu.json','["我如今鬓刁骚强整乌云，年纪大倦点朱唇。", "面皮黄羞施朱粉，腰肢瘦湘裙不称。"]'),
('yuanqu-10267','郑月莲秋夜云窗梦・醉太平','无名氏','元','元曲','yuanqu','','[]','见如今惜花人病损，俺娘和茶客钱亲，却教我嫩橙初破酒微温，那的是眷姻。',139,'元曲/yuanqu.json','["见如今惜花人病损，俺娘和茶客钱亲，却教我嫩橙初破酒微温，那的是眷姻。", "(卜云)孩儿，你命在烟花中，是这样干。", "你守着那秀才，你待要做夫人哩。", "(旦唱)如今春花已落烟花阵，夫人自有夫人分，百年谁是百年人，难寻这白头的对门。", "(净云)大姐，我钱多着哩。", "茶也有几船，你要时，都搬来。", "(旦唱)。"]'),
('yuanqu-10268','郑月莲秋夜云窗梦・醉太平','无名氏','元','元曲','yuanqu','','[]','冯魁是村，倒有金银；俏双生他是读书人，天教他受窘。',76,'元曲/yuanqu.json','["冯魁是村，倒有金银；俏双生他是读书人，天教他受窘。", "书生曾与高人论，钱财也有无时分。", "书生有一日跳龙门，咱便是夫人县君。", "(卜云)李官人，咱吃酒来。", "(旦唱)。"]'),
('yuanqu-10269','郑月莲秋夜云窗梦・倘秀才','无名氏','元','元曲','yuanqu','','[]','俺娘有钱的和他佯亲乍亲，无钱的顶了前门后门，张郎也眼睁睁西出阳关无故人。',52,'元曲/yuanqu.json','["俺娘有钱的和他佯亲乍亲，无钱的顶了前门后门，张郎也眼睁睁西出阳关无故人。", "也待花满眼，酒盈尊，奈时间受窘。"]'),
('yuanqu-10270','郑月莲秋夜云窗梦・滚绣球','无名氏','元','元曲','yuanqu','','[]','倚仗蒙山顶上春，俺只爱菱花镜里人，敢教你有钱难奔，觑这贩茶船似风卷残云。',130,'元曲/yuanqu.json','["倚仗蒙山顶上春，俺只爱菱花镜里人，敢教你有钱难奔，觑这贩茶船似风卷残云。", "留取那买笑的银。", "换取些贩茶的引。", "这其间又下江风顺，休恋我虚飘飘皓齿朱唇。", "如今这丽春园使不的冯魁俊，赤紧的平康巷时行有钞的亲，断送了多少郎君。", "(云)我待寄书与俺那秀才，又不知在那里。", "(唱)。"]'),
('yuanqu-10271','郑月莲秋夜云窗梦・叨叨令','无名氏','元','元曲','yuanqu','','[]','两行诗写不尽丹枫恨，一封书空盼杀青鸾信。',68,'元曲/yuanqu.json','["两行诗写不尽丹枫恨，一封书空盼杀青鸾信。", "三停刀砍不断黄桑棍，九稍炮打不破迷魂阵。", "则是为他来也么哥，为他来也么哥，空教我立斜阳盼的双眸困。"]'),
('yuanqu-10272','郑月莲秋夜云窗梦・二煞','无名氏','元','元曲','yuanqu','','[]','你个谢安把我携出东山隐，我怎肯教宋玉空闲了楚岫云。',97,'元曲/yuanqu.json','["你个谢安把我携出东山隐，我怎肯教宋玉空闲了楚岫云。", "你则待酒酽花浓，月圆人静。", "便休想瓶坠簪折，镜破钗分。", "玉箫对品，彩鸾同乘，鸳枕相亲。", "一锅水正滚，怎教灶底去了柴薪。", "(净云)大姐，我醉了。", "(旦唱)。"]'),
('yuanqu-10273','郑月莲秋夜云窗梦・中吕/粉蝶儿','无名氏','元','元曲','yuanqu','','[]','皓月澄澄，快袁宏泛舟乘兴，便宫鸦啼尽残更。',52,'元曲/yuanqu.json','["皓月澄澄，快袁宏泛舟乘兴，便宫鸦啼尽残更。", "九霄中，千里外，无片云遮映。", "是谁家妆罢娉婷，挂长空不收冰镜？。"]'),
('yuanqu-10274','郑月莲秋夜云窗梦・醉春风','无名氏','元','元曲','yuanqu','','[]','按不住情脉脉喟然声，又添个骨岩岩清瘦影。',73,'元曲/yuanqu.json','["按不住情脉脉喟然声，又添个骨岩岩清瘦影。", "(云)好月色也！闲庭中步月散心咱。", "(唱)步苍苔冰透绣罗鞋，畅好是冷、冷、冷。", "一点离情，半年别恨，满怀愁病。"]'),
('yuanqu-10275','郑月莲秋夜云窗梦・迎仙客','无名氏','元','元曲','yuanqu','','[]','我这里忙接待，紧相迎，量妹妹有甚德能，教姐姐好看承。',51,'元曲/yuanqu.json','["我这里忙接待，紧相迎，量妹妹有甚德能，教姐姐好看承。", "姐姐索厮敬重，真然是意重人情，把月莲真个的人钦敬。"]'),
('yuanqu-10276','郑月莲秋夜云窗梦・红绣鞋','无名氏','元','元曲','yuanqu','','[]','我害的是闲愁闲闷，害的是多绪多情，害的是眉淡远山青。',50,'元曲/yuanqu.json','["我害的是闲愁闲闷，害的是多绪多情，害的是眉淡远山青。", "害的是伤心症，害的是断肠声，害的是绣衾中一半冷。"]'),
('yuanqu-10277','郑月莲秋夜云窗梦・石榴花','无名氏','元','元曲','yuanqu','','[]','我恨不的把家门改换做短长亭，恨不的拆毁了豫章城。',82,'元曲/yuanqu.json','["我恨不的把家门改换做短长亭，恨不的拆毁了豫章城。", "听的唱阳关歌曲脑门疼，委实的倦听，惨然凄声。", "往常时茶里饭里相随定，影儿般随坐随行。", "月窗并枕歌新令，每日价同品玉箫声。"]'),
('yuanqu-10278','郑月莲秋夜云窗梦・斗鹌鹑','无名氏','元','元曲','yuanqu','','[]','则为我暗约私期，致令得离乡背井。',81,'元曲/yuanqu.json','["则为我暗约私期，致令得离乡背井。", "(外旦云)你那秀才那里去了？(旦唱)这其间戴月披星，禁寒受冷。", "恨则恨冯魁那个丑生，买转俺劣柳青。", "一壁厢稳住双生，一壁厢流递了小卿。"]'),
('yuanqu-10279','郑月莲秋夜云窗梦・普天乐','无名氏','元','元曲','yuanqu','','[]','不是我酒中言，心头病，临风对月，见景生情。',66,'元曲/yuanqu.json','["不是我酒中言，心头病，临风对月，见景生情。", "想起我旧日情，当时行。", "谁承望地北天南人孤另，两下里冷冷清清。", "缑山月明，蓝桥水淹，楚岫云平。"]'),
('yuanqu-10280','郑月莲秋夜云窗梦・上小楼','无名氏','元','元曲','yuanqu','','[]','鸳衾半拥，银屏斜凭。',46,'元曲/yuanqu.json','["鸳衾半拥，银屏斜凭。", "半窗凉月，四壁蛩声，一点寒灯。", "布摆下，断人肠，凄凉光景，怎生熬画堂人静。"]'),
('yuanqu-10281','郑月莲秋夜云窗梦・幺篇','无名氏','元','元曲','yuanqu','','[]','想起那心上人，月下情。',50,'元曲/yuanqu.json','["想起那心上人，月下情。", "空教我兜的鼻酸，哄的脸晕，札的心疼，欲解愁，可忘忧，无过酒兴，谁承望酒淘真性。"]'),
('yuanqu-10282','郑月莲秋夜云窗梦・快活三','无名氏','元','元曲','yuanqu','','[]','是谁人唤一声？觑绝时笑相迎。',30,'元曲/yuanqu.json','["是谁人唤一声？觑绝时笑相迎。", "武陵溪畔俏书生，安乐否临川令？。"]'),
('yuanqu-10283','郑月莲秋夜云窗梦・鲍老儿','无名氏','元','元曲','yuanqu','','[]','这搭儿再能见俺可憎，便医可了天样般相思病。',59,'元曲/yuanqu.json','["这搭儿再能见俺可憎，便医可了天样般相思病。", "我则道送人在长沙过了一生，今日个复对上临川令。", "鸾交凤友，莺期燕约，海誓山盟。"]'),
('yuanqu-10284','郑月莲秋夜云窗梦・十二月','无名氏','元','元曲','yuanqu','','[]','金钗倦整，檀口低声。',37,'元曲/yuanqu.json','["金钗倦整，檀口低声。", "云鬟半偏，星眼微睁。", "可搂抱在怀儿里，觑定着这短命牢成。"]'),
('yuanqu-10285','郑月莲秋夜云窗梦・尧民歌','无名氏','元','元曲','yuanqu','','[]','早忘了急煎煎情脉脉冷清清，早忘了扑簌簌泪零零，早忘了意悬悬愁戚戚闷腾腾，早忘了骨岩岩心穰穰病萦萦。',67,'元曲/yuanqu.json','["早忘了急煎煎情脉脉冷清清，早忘了扑簌簌泪零零，早忘了意悬悬愁戚戚闷腾腾，早忘了骨岩岩心穰穰病萦萦。", "多情，多情，逢志减，休学李免王魁幸。"]'),
('yuanqu-10286','郑月莲秋夜云窗梦・俏遍','无名氏','元','元曲','yuanqu','','[]','这搭儿才添欢庆，扑个空半晌痴呆诤。',133,'元曲/yuanqu.json','["这搭儿才添欢庆，扑个空半晌痴呆诤。", "忽剌八梦断碧天涯，空没乱无绪无情。", "夜几更，画屏影里，玉漏声中，依旧的人孤另。", "薄设设衾寒枕冷，愁易感好梦难成。", "千愁万恨断肠人，怎当那半夜三更莫秋景。", "比及日出扶桑，月落西厢，敢折倒了人性命。", "(旦哭科，云)张秀才也，你好下的也呵！(唱)。"]'),
('yuanqu-10287','郑月莲秋夜云窗梦・耍孩儿','无名氏','元','元曲','yuanqu','','[]','愁烦迭万簇，凄凉有四星。',83,'元曲/yuanqu.json','["愁烦迭万簇，凄凉有四星。", "别离人更做到心肠硬，怎禁苍梧落叶凋金井，银烛秋光冷画屏。", "碧澄澄如悬磬，佳人有意，银汉无声。", "(云)我这般烦恼，怎禁耳边几件儿聒噪人也呵！(唱)。"]'),
('yuanqu-10288','郑月莲秋夜云窗梦・四煞','无名氏','元','元曲','yuanqu','','[]','孤鸿枕畔哀，乱蛩砌下鸣，西风鹤唳秋天静。',52,'元曲/yuanqu.json','["孤鸿枕畔哀，乱蛩砌下鸣，西风鹤唳秋天静。", "霜寒鸳帐愁无寐，云冷纱窗月半明。", "添愁病，惊回一堂春色，万籁秋声。"]'),
('yuanqu-10289','郑月莲秋夜云窗梦・三煞','无名氏','元','元曲','yuanqu','','[]','战西风竹叶呜，捣秋霜砧杵清，一弄儿会把愁人并。',59,'元曲/yuanqu.json','["战西风竹叶呜，捣秋霜砧杵清，一弄儿会把愁人并。", "恼人心半窗袅袅疏梅影，聒人耳万种萧萧落叶声。", "那堪听，檐间铁马，雨内梧声。"]'),
('yuanqu-10290','郑月莲秋夜云窗梦・二煞','无名氏','元','元曲','yuanqu','','[]','这一双眼才闭合，争奈万般事不暂停，都是谋儿误倒临川令。',62,'元曲/yuanqu.json','["这一双眼才闭合，争奈万般事不暂停，都是谋儿误倒临川令。", "你莫不笙歌谢馆来金斗，风雪长安访灞陵。", "自古多薄命，天涯流落，海角飘零。"]'),
('yuanqu-10291','郑月莲秋夜云窗梦・尾煞','无名氏','元','元曲','yuanqu','','[]','泪漫漫不暂停，哭啼啼不住声。',151,'元曲/yuanqu.json','["泪漫漫不暂停，哭啼啼不住声。", "不争这惊回一枕云窗梦，这烦恼直哭的西楼月儿冷。", "(下)(净上，云)小子李多是也。", "如今郑月莲被他母亲卖的洛阳张行首家中去了，我如今寻到那里，问亲去来。", "(卜儿上，云)李官，你须计较停当去，那妮子不肯便嫁你。", "(净云)洛阳府判是我叔父，到那里好歹娶了他。", "(卜云)好计，好计。", "(同下)。"]'),
('yuanqu-10292','郑月莲秋夜云窗梦・双调/新水令','无名氏','元','元曲','yuanqu','','[]','凭栏人空望的碧云低，隐天涯远山憔悴。',42,'元曲/yuanqu.json','["凭栏人空望的碧云低，隐天涯远山憔悴。", "江深鱼信杳，天阔雁书迟。", "染病耽疾，别离中过一世。"]'),
('yuanqu-10293','郑月莲秋夜云窗梦・驻马听','无名氏','元','元曲','yuanqu','','[]','幽梦初回，待教我一纸音书传信息。',65,'元曲/yuanqu.json','["幽梦初回，待教我一纸音书传信息。", "闲愁萦系，想当初一尊白酒话别离。", "不争秦台弄玉彩云低，都做了江州司马青衫湿。", "两下里，一般阻隔人千里。"]'),
('yuanqu-10294','郑月莲秋夜云窗梦・夜行船','无名氏','元','元曲','yuanqu','','[]','我却待翠袖殷勤捧玉杯，觑绝时半晌痴迷。',136,'元曲/yuanqu.json','["我却待翠袖殷勤捧玉杯，觑绝时半晌痴迷。", "我认的是实，觑得仔细，掐皮肉犹疑是梦里。", "(云)张秀才，你好下的也！(末云)原来是俺大姐。", "你怎生到的这里来？教我怎生是好！(孤怒云)那妮子教你把盏，因何不把盏？(夫人云)这妮子觑看状元，眼去眉来，不知为甚？(旦云)相公听妾身说。", "(唱)。"]'),
('yuanqu-10295','郑月莲秋夜云窗梦・川拨棹','无名氏','元','元曲','yuanqu','','[]','俺在那曲江池，坠鞭时曾认的。',41,'元曲/yuanqu.json','["俺在那曲江池，坠鞭时曾认的。", "他带减腰围，我玉削香肌。", "做得来掀天扑地，寨儿中鼎沸起。"]'),
('yuanqu-10296','郑月莲秋夜云窗梦・七弟兄','无名氏','元','元曲','yuanqu','','[]','俺娘若听知，俺恁的，他便医治，眼前面便待把阳关闭。',43,'元曲/yuanqu.json','["俺娘若听知，俺恁的，他便医治，眼前面便待把阳关闭。", "片时间云暗武陵溪，半霎儿水淹蓝桥驿。"]'),
('yuanqu-10297','郑月莲秋夜云窗梦・收江南','无名氏','元','元曲','yuanqu','','[]','趁着这下江风顺片帆归，俺好姻缘生纽做恶离。',44,'元曲/yuanqu.json','["趁着这下江风顺片帆归，俺好姻缘生纽做恶离。", "玉箫闲杀共谁吹。", "从来到这里，绿窗前学画远山眉。"]'),
('yuanqu-10298','郑月莲秋夜云窗梦・甜水令','无名氏','元','元曲','yuanqu','','[]','由你铁锁沉枷，一年四季，不离身体，你可甚花压帽檐低。',52,'元曲/yuanqu.json','["由你铁锁沉枷，一年四季，不离身体，你可甚花压帽檐低。", "我则道地北天南，锦营花阵，偎红倚翠，今日个水净鹅飞。"]'),
('yuanqu-10299','郑月莲秋夜云窗梦・折桂令','无名氏','元','元曲','yuanqu','','[]','再休题孟母三移，你狗行狼心，短命相识。',103,'元曲/yuanqu.json','["再休题孟母三移，你狗行狼心，短命相识。", "恨惹情牵，魂劳梦断，雨约云期。", "今日个成就了鸾欢凤喜，何消你爱钱娘唱叫扬疾。", "今日个共守鸳帏，半掩朱扉，我待学村里夫妻，步步相随。", "(孤云)天下喜事，无过夫妇团圆。", "(下阕)。"]'),
('yuanqu-10300','仙吕/八声甘州','杨景贤','元','元曲','yuanqu','','[]','云山缥缈，下隐黄泉，上接青霄。',54,'元曲/yuanqu.json','["云山缥缈，下隐黄泉，上接青霄。", "晓来登眺，眼前景物周遭。", "石洞起云清露冷，金缕生寒秋气高。", "故国路迢遥，恨压眉梢。"]'),
('yuanqu-10301','混江龙','杨景贤','元','元曲','yuanqu','','[]','也是我为人不肖，和这等朝三暮四的便成交。',146,'元曲/yuanqu.json','["也是我为人不肖，和这等朝三暮四的便成交。", "安排着山果，准备着香醪。", "一派笙歌尝御酒，抵多少九重春色醉仙桃。", "山光明媚，柳色妖娆，莺歌巧韵，燕舞纤腰。", "狐变成美丽，虎变作多娇，着我忍不住一场好笑。", "执壶的是木客，把酒的是山魈。", "(孙行者上，云)我天宫内盗得仙衣、仙帽、仙桃、仙酒，夫人快活受用。", "(金女唱)。"]'),
('yuanqu-10302','油葫芦','杨景贤','元','元曲','yuanqu','','[]','王母仙衣无分着，金灿烂光闪烁，多管是天孙巧织紫霞绡。',143,'元曲/yuanqu.json','["王母仙衣无分着，金灿烂光闪烁，多管是天孙巧织紫霞绡。", "(行者云)银丝帽子，丑的带了便可喜。", "(金女云)大圣，你且先戴一戴。", "你去玉皇宫偷得银丝帽，抵多少琼林宴颁赐金花诰。", "(行者云)左右的，与我照管前后洞门，休放闲神上来。", "(金女唱)他耍性儿乖，劣性儿乔，则恐怕筵间引得天兵到，因此上摆布一周遭。"]'),
('yuanqu-10303','天下乐','杨景贤','元','元曲','yuanqu','','[]','抵多少日夜思量计万条，每日个逍遥在山曳脚，受用些春花夏果梨杏枣。',56,'元曲/yuanqu.json','["抵多少日夜思量计万条，每日个逍遥在山曳脚，受用些春花夏果梨杏枣。", "看了他眼中火，觑了他脸上毛，抱着个绣球儿懒去抛。"]'),
('yuanqu-10304','元和令','杨景贤','元','元曲','yuanqu','','[]','恶山林天火烧，深潭洞黑云罩。',55,'元曲/yuanqu.json','["恶山林天火烧，深潭洞黑云罩。", "李天王托着塔皱着眉梢，显他那挟泰山的恶燥暴。", "我便是玉天仙骋不得妖娆，众妖魔四散逃。"]'),
('yuanqu-10305','上马娇','杨景贤','元','元曲','yuanqu','','[]','小的每是金鼎国人，被妖怪扰。',50,'元曲/yuanqu.json','["小的每是金鼎国人，被妖怪扰。", "当日个秋夜月轮高，酒阑人静三更到。", "园内恣游遨，小径里抄风过处，遇着山魈。"]'),
('yuanqu-10306','胜葫芦','杨景贤','元','元曲','yuanqu','','[]','俺甚么女貌郎才厮撞着，将父母远乡相抛，雁杳鱼沉没下落。',43,'元曲/yuanqu.json','["俺甚么女貌郎才厮撞着，将父母远乡相抛，雁杳鱼沉没下落。", "翠蛾浅淡，玉肌消瘦，终日倚楼高。"]'),
('yuanqu-10307','幺','杨景贤','元','元曲','yuanqu','','[]','空着我望断云山恨不消，愁随着江水夜滔滔，一日错番为一世错。',49,'元曲/yuanqu.json','["空着我望断云山恨不消，愁随着江水夜滔滔，一日错番为一世错。", "今日得圣贤接引，天王相救，恩义比太山高。"]'),
('yuanqu-10308','青哥儿','杨景贤','元','元曲','yuanqu','','[]','若如此呵，然后那家乡、家乡得到，到家呵，细说根苗。',74,'元曲/yuanqu.json','["若如此呵，然后那家乡、家乡得到，到家呵，细说根苗。", "将天正众多神将来雕，摆列着香案，供养着容貌。", "每日逐朝，记在心苗。", "办着一片虔心把香烧，将恁那恩来报。"]'),
('yuanqu-10309','尾','杨景贤','元','元曲','yuanqu','','[]','一念霎时生，万里须臾到。',129,'元曲/yuanqu.json','["一念霎时生，万里须臾到。", "四员将神通不小，抵多少万里西风鹤背高，离深山自上云霄。", "自量度，则听得鬼哭神号，休猜做三唱阳关出霸桥。", "(天王云)你离了通天大圣，怎不烦恼，倒欢喜为何？(金女唱)上圣道为甚不蹙青山懊恼，颠倒破朱颜含笑？大古里舍得这碧桃花下凤鸾交。", "(下)。"]'),
('yuanqu-10310','得胜令','杨景贤','元','元曲','yuanqu','','[]','金鼎国女娇姿，放还乡到家时。',83,'元曲/yuanqu.json','["金鼎国女娇姿，放还乡到家时。", "他想我须臾害，我因他厮勾死。", "他寄得言词，抵多少草草三行字。", "我害相思，好重山呵，扭不起沉沉一担儿。", "(观音云)道与山神，看得这厮紧者。", "(下)。"]'),
('yuanqu-10311','南吕/一枝花','杨景贤','元','元曲','yuanqu','','[]','包藏造化灵，禀受阴阳气。',57,'元曲/yuanqu.json','["包藏造化灵，禀受阴阳气。", "采将河汉秀，算尽晦明期。", "兔走鸟飞，看古今兴废。", "茫茫辟两仪，有轩辕制造衣裳，有苍颉流传书史。"]'),
('yuanqu-10312','梁州第七','杨景贤','元','元曲','yuanqu','','[]','唐虞禅天垂雍穆，汤武圣民脱灾危。',109,'元曲/yuanqu.json','["唐虞禅天垂雍穆，汤武圣民脱灾危。", "周公制作非容易。", "春秋无道，振起宣尼，获麟绝笔，轲也闻知。", "笑六王竞角雌雄，叹吕政任了高斯，困重瞳马上英风。", "更有那三分鼎峙，卧龙把炎精扶起。", "晋移魏，如儿戏，纷纷五代自诛夷，怎胜得俺山水幽微。"]'),
('yuanqu-10313','隔尾','杨景贤','元','元曲','yuanqu','','[]','汉明帝佛始来中国，唐太宗僧初入外夷。',175,'元曲/yuanqu.json','["汉明帝佛始来中国，唐太宗僧初入外夷。", "全仗着观音大慈力。", "则为他将蟠桃会闹起，今日将花果山镇伊！(行者云)山神救我咱。", "(山神云)我如何救得？你师父今日必到也。", "专等他来，他便救得你。", "(唐僧引龙马上，云)龙君，我和你行经数月。", "前面一座大山，一个金甲将军在彼，我去问他。", "将军，此是何处？小僧大唐三藏法师是也。", "(山神云)小圣非凡人，乃花果山之神。", "是好一个僧也呵。"]'),
('yuanqu-10314','牧羊关','杨景贤','元','元曲','yuanqu','','[]','圆顶金花灿，方袍紫焰飞，塑来的罗汉容仪。',66,'元曲/yuanqu.json','["圆顶金花灿，方袍紫焰飞，塑来的罗汉容仪。", "此一行半为于民，半为报国。", "十万里程难到，百千样苦难及。", "则怕你闹市里多辛苦，来俺深山中躲是非。"]'),
('yuanqu-10315','骂玉郎','杨景贤','元','元曲','yuanqu','','[]','俺这里山高险阻无存济，云惨淡雨霏微，毒蛇异兽难回避。',65,'元曲/yuanqu.json','["俺这里山高险阻无存济，云惨淡雨霏微，毒蛇异兽难回避。", "(唐僧云)有斋僧的？(山神唱)俺这里难为卓锡居，怎做得香积厨？不是你那祗园地。"]'),
('yuanqu-10316','感皇恩','杨景贤','元','元曲','yuanqu','','[]','呀！遮莫你竹杖龙飞，华表鹤归。',64,'元曲/yuanqu.json','["呀！遮莫你竹杖龙飞，华表鹤归。", "恋荣辱有灾危，远是非无挂念，叹生死有迟疾。", "你若要西天取经，先去这东土忘机，参菩萨，拜圣贤，礼摩尼。"]'),
('yuanqu-10317','采茶歌','杨景贤','元','元曲','yuanqu','','[]','花果山有山祗，云罗洞有幽微，则听得春风桃李杜鹃啼。',68,'元曲/yuanqu.json','["花果山有山祗，云罗洞有幽微，则听得春风桃李杜鹃啼。", "(唐僧云)俺辞了尊神，趁早行，怕晚了。", "(山神唱)师父眼慧休愁红日晚，心明何怕黑云迷？。"]'),
('yuanqu-10318','哭皇天','杨景贤','元','元曲','yuanqu','','[]','师父听得叫罢询详细，弟子见言绝说个就里。',230,'元曲/yuanqu.json','["师父听得叫罢询详细，弟子见言绝说个就里。", "师父，你不知，这座山是花果山。", "山下有一洞，是紫云罗洞。", "洞中有一魔君，号曰\"通天大圣\"，恼得三界圣贤，不得安宁。", "李天王、那叱太子、眉山大圣收得，待杀坏他来。", "观音佛抄化他，压在山下，等师父宋，着与师父护法。", "他凡心不退，不可用他。", "(唐僧云)小僧弘誓如深海，如何不救他？(山神唱)你道你弘誓如海深，那胡孙气力与天齐。", "这厮瞒神唬鬼，铜筋铁骨，火眼金睛。", "偷玉皇仙酒，盗老子金丹。", "他去那众魔君中占第一，他是骊山老母兄弟，巫支祗是姊妹。"]'),
('yuanqu-10319','幺','杨景贤','元','元曲','yuanqu','','[]','休言道仗你释迦威，则寻思念彼观音力。',411,'元曲/yuanqu.json','["休言道仗你释迦威，则寻思念彼观音力。", "他有浑世的愆，迷天罪，取经回后，正果圆寂。", "(唐僧云)小僧救他。", "(做上山科)(行者云)爱弟子么？(唐僧云)爱者乃仁之根本，如何不爱物命？(行者云)爱我是沉香亭上的纤腰。", "(唐僧云)我如何救你？(行者云)师父则揭了这花字，弟子自出来。", "(唐僧做揭字科)(行者做筋斗下来，拜谢科)(背云)好个胖和尚，到前面吃得我一顿饱，依旧回花果山，那里来寻我！(观音上，云)玄奘，见老僧么？我特地寻这个徒弟，与你沿途护法去。", "(看行者科)通天大圣，你本是毁形灭性的，老僧救了你，今次休起凡心。", "我与你一个法名，是孙悟空。", "与你个铁戒箍、皂直裰、戒刀。", "铁戒箍戒你凡性，皂直裰遮你兽身，戒刀豁你之恩爱，好生跟师父去，便唤作孙行者。", "疾便取经，着你也求正果。", "玄奘，你近前来。", "这畜生凡心不退，但欲伤你，你念紧箍儿咒，他头上便紧。", "若不告饶，须臾之间，便刺死这厮。", "你记者。", "(做耳边教咒科)(唐僧拜谢科，云)谢我佛慈悲。", "(山神唱)。"]'),
('yuanqu-10320','红芍药','杨景贤','元','元曲','yuanqu','','[]','观音救苦大慈悲，赐与你戒箍僧衣。',73,'元曲/yuanqu.json','["观音救苦大慈悲，赐与你戒箍僧衣。", "花果山险压损你脊梁皮，得师父放你相随。", "休更出你那锁空房腌见识，振着矢不得伶俐。", "琉璃脑盖戒箍围，比着你那小帽敢牢实。"]'),
('yuanqu-10321','菩萨梁州','杨景贤','元','元曲','yuanqu','','[]','恰便似钉钉入头皮，胶粘在鬏髻。',131,'元曲/yuanqu.json','["恰便似钉钉入头皮，胶粘在鬏髻。", "你那凡心若再起，敢着你魄散魂飞。", "为足下常有杀人机，因此上与师父留下这防身计，劣心肠再不可生奸意。", "如梦幻出尘世，至诚心谨护持，早去疾回。", "小圣对师父说；前面有一河，名曰流沙河。", "河内有怪，能伤人。", "行者，你小心护持师父者。", "师父，好生加持者。"]'),
('yuanqu-10322','尾','杨景贤','元','元曲','yuanqu','','[]','着胡孙将心猿紧紧牢拴系，龙君跟着师父呵把意马频频急控驰。',153,'元曲/yuanqu.json','["着胡孙将心猿紧紧牢拴系，龙君跟着师父呵把意马频频急控驰。", "一个走如风疾，一个脚似云飞。", "到西天取经回来，到大唐方是你。", "(下)(行者云)山神所言，流沙河妖怪能伤人。", "龙君，你和师父慢来，我先去流沙河，寻那妖怪去。", "说道他要吃人，我着他先吃我一吃。", "弟子先去也，你随后便来者。", "(下)(唐僧云)龙君，我和你也去来。", "(下)。"]'),
('yuanqu-10323','大石调/六国朝','杨景贤','元','元曲','yuanqu','','[]','白头蹀足世，似红日西斜。',81,'元曲/yuanqu.json','["白头蹀足世，似红日西斜。", "烦恼甚时休，离愁何日彻？抬举偌来大，出退得全别。", "俺孩儿现世的观音样，羞花也闭月。", "晓日夭桃雾锁，东风弱柳云遮。", "着我何处苦哀求，谁行闲沂说？。"]'),
('yuanqu-10324','喜秋风','杨景贤','元','元曲','yuanqu','','[]','珠泪垂，柔肠结，两眉攒，寸心裂。',30,'元曲/yuanqu.json','["珠泪垂，柔肠结，两眉攒，寸心裂。", "好儿女似花开谢，早相离半月。"]'),
('yuanqu-10325','雁过南楼','杨景贤','元','元曲','yuanqu','','[]','老汉鳏寡孤独运拙，俺孩儿风流美丽奇绝。',78,'元曲/yuanqu.json','["老汉鳏寡孤独运拙，俺孩儿风流美丽奇绝。", "他生得杨柳腰桃花脸，是一块生香玉卞和也欢悦。", "(行者云)你引我去寻来。", "(刘唱)老汉腿脚酸腰肢屈，恰便似投天明的晓灯明灭。"]'),
('yuanqu-10326','擂鼓休','杨景贤','元','元曲','yuanqu','','[]','哥哥三位用心的别，老夫宰一个耕牛儿亲自接。',73,'元曲/yuanqu.json','["哥哥三位用心的别，老夫宰一个耕牛儿亲自接。", "师父跟前都休说，苦告你个孙行者，(行者云)你女孩儿唤做甚么？我去寻他。", "(刘唱)你记着，俺孩儿唤做刘大姐。"]'),
('yuanqu-10327','好观音','杨景贤','元','元曲','yuanqu','','[]','一去迢迢经半月，要相见水远山叠。',79,'元曲/yuanqu.json','["一去迢迢经半月，要相见水远山叠。", "今日相逢莫怨嗟，是吾师的功业，恰浑似枯树生花叶。", "谢三位师父之恩，将何以报师父？今日早行，沿路上小心在意。", "待师父回来，再得相见。"]'),
('yuanqu-10328','观音煞','杨景贤','元','元曲','yuanqu','','[]','感谢吾师收了妖孽，着老汉死有坟穴。',49,'元曲/yuanqu.json','["感谢吾师收了妖孽，着老汉死有坟穴。", "你若西行仔细者，无限的艰难未断绝，我这里专望回来重酬谢。", "(下)。"]'),
('yuanqu-10329','越调/斗鹌鹑','杨景贤','元','元曲','yuanqu','','[]','驾一片妖云，引半垓厉鬼。',77,'元曲/yuanqu.json','["驾一片妖云，引半垓厉鬼。", "则为子母情肠，恶了那神佛面皮。", "则着你钵盂中抄化檀那，谁教你法座下伤人家小的？我和你，是谁非？拿住呵恰便似二鬼争环，休想有九龙喷水。"]'),
('yuanqu-10330','紫花儿序','杨景贤','元','元曲','yuanqu','','[]','出家儿却不慈悲为本，方便为门，使不着仁者无敌。',76,'元曲/yuanqu.json','["出家儿却不慈悲为本，方便为门，使不着仁者无敌。", "黄颜老子，秃发沙弥，直恁跷蹊，你是孔夫子遭逢着柳盗跖，我今日做着不避。", "你认得鬼子母娘娘，休猜做善知识姨姨。"]'),
('yuanqu-10331','小桃红','杨景贤','元','元曲','yuanqu','','[]','咚咚地小鬼擂征鼙，不怕你会使拖刀计。',137,'元曲/yuanqu.json','["咚咚地小鬼擂征鼙，不怕你会使拖刀计。", "待俺将不强不弱的铁胎弓，一拈千转的狼牙箭，去射这厮。", "饶他有千般变幻身躯，怎当我百步穿杨手段？(做射科)(佛做莲花遮科)(鬼母唱)蹬弩开弓那威势，一箭箭往前射，则见他金莲朵朵遮胸臆。", "早难道射不主皮，他元来温而不厉，险恼杀这个搽胭粉的养由基。"]'),
('yuanqu-10332','调笑令','杨景贤','元','元曲','yuanqu','','[]','觑了我这艳质，一捻儿瘦腰围，可甚阃外将军八面威？文殊普贤擎拳立，诸菩萨见贤思齐。',64,'元曲/yuanqu.json','["觑了我这艳质，一捻儿瘦腰围，可甚阃外将军八面威？文殊普贤擎拳立，诸菩萨见贤思齐。", "将我那爱奴儿盖在法座底，恁却甚好生心广大慈悲？。"]'),
('yuanqu-10333','秃厮儿','杨景贤','元','元曲','yuanqu','','[]','将铁枪持，宝剑携，(鬼兵做砍科)掘不开砍不破甚东西？里面人，外面鬼，影光芒一块碧琉璃，崤硬似太湖石。',50,'元曲/yuanqu.json','["将铁枪持，宝剑携，(鬼兵做砍科)掘不开砍不破甚东西？里面人，外面鬼，影光芒一块碧琉璃，崤硬似太湖石。"]'),
('yuanqu-10334','麻郎儿','杨景贤','元','元曲','yuanqu','','[]','惊得阿难皱眉，唬得伽叶伤悲。',30,'元曲/yuanqu.json','["惊得阿难皱眉，唬得伽叶伤悲。", "四天王擎拳顶礼，八菩萨用心支持。"]'),
('yuanqu-10335','幺','杨景贤','元','元曲','yuanqu','','[]','我的手里措底，霜锋剑巨阙神威。',31,'元曲/yuanqu.json','["我的手里措底，霜锋剑巨阙神威。", "二十位诸天听启，但迎着脑门着地。"]'),
('yuanqu-10336','络丝娘','杨景贤','元','元曲','yuanqu','','[]','小哥哥休夸强嘴，则恁这老娘娘当间立地。',42,'元曲/yuanqu.json','["小哥哥休夸强嘴，则恁这老娘娘当间立地。", "怕不怕须当斗神力，手掐定五方真气。", "(做斗科)。"]'),
('yuanqu-10337','尾','杨景贤','元','元曲','yuanqu','','[]','告世尊肯发慈悲力，我着唐三藏西游便回。',45,'元曲/yuanqu.json','["告世尊肯发慈悲力，我着唐三藏西游便回。", "那唐僧，火孩儿妖怪放生了他，到前面须得二圣郎救了你。"]'),
('yuanqu-10338','相国寺公孙合汗衫・仙吕/点绛唇','张国宾','元','元曲','yuanqu','','[]','密布彤云，乱飘琼粉。',61,'元曲/yuanqu.json','["密布彤云，乱飘琼粉。", "朔风紧，一色如银，便有那孟浩然可便骑驴的稳。", "(张孝友云)似这般应时的瑞雪，是好一个冬景也。", "(正末唱)。"]'),
('yuanqu-10339','相国寺公孙合汗衫・油葫芦','张国宾','元','元曲','yuanqu','','[]','我见他百结衣衫不挂身，直恁般家道窘。',200,'元曲/yuanqu.json','["我见他百结衣衫不挂身，直恁般家道窘。", "我为甚连珠儿热酒教他饮了三巡？(云)汉子，自古以来，则不你受贫。", "(孝友云)父亲，可是那几个古人受贫来？(正末唱)想当初苏秦未遇遭贫困，有一日他那时来，也可便腰挂黄金印。", "咱人翻手是雨，合手是云。", "那尘埃中埋没杀多才俊，(带云)你看那人也，则是时运未至。", "(唱)他可敢一世里不如人。", "(云)小大哥，将一领绵团袄来。", "(张孝友做拿衣服科，云)绵团袄在此。", "(正末云)汉子。", "(唱)。"]'),
('yuanqu-10340','相国寺公孙合汗衫・天下乐','张国宾','元','元曲','yuanqu','','[]','我与你这一件衣服旧换做新，(云)再将五两银子来。',189,'元曲/yuanqu.json','["我与你这一件衣服旧换做新，(云)再将五两银子来。", "(张孝友取银科，云)五两银子在此。", "(正末云)这银子呵，(唱)我与你做盘也波缠，速离子俺门。", "(邦老云)救活了小人的性命，又与小人许多银子：此恩将何以报？(正末云)汉子，这衣服和银子。", "(唱)也则是一时间周急，添你气分。", "(邦老云)多谢你老人家。", "(正末云)汉子，你着志者，(唱)有一日马颏下缨似火，头直上伞盖似云，愿哥哥你可便为官早立身。"]'),
('yuanqu-10341','相国寺公孙合汗衫・后庭花','张国宾','元','元曲','yuanqu','','[]','你道他眉下无眼筋，你道他兀那口边厢有饿纹。',201,'元曲/yuanqu.json','["你道他眉下无眼筋，你道他兀那口边厢有饿纹。", "可不道马向那群中觑，陈虎口床我则理会得人居在贫内亲。", "(邦老云)可惜偌多钱与了这厮，他那里是个掌财的？(正末唱)你将他来恶抢问，他如今身遭危困。", "你将他恶语喷，他将你来死记恨。", "恩共仇您两个人，是和非俺三处分，怎劈手里便夺了他银？(云)嗨！陈虎，我恰才与了他些钱钞，你劈手里夺将来。", "知道的便是你夺了，有那不知道的，只说那张员外与了人些钱钞，又着劈手的夺将去。", "(唱)。"]'),
('yuanqu-10342','相国寺公孙合汗衫・青哥儿','张国宾','元','元曲','yuanqu','','[]','陈虎口床，显的我言而、言而无信，(带云)张孝友，(唱)你也忒眼内、眼内无珍。',148,'元曲/yuanqu.json','["陈虎口床，显的我言而、言而无信，(带云)张孝友，(唱)你也忒眼内、眼内无珍。", "(带云)恰才两个人呵，(唱)他如今迭配遭囚锁缠着身，不得风云，困在埃尘。", "你道他一世儿为人，半世儿孤贫，气忍声吞，何日酬恩？则你也曾举目无亲，失魄亡魂，绕户踅门，鼓舌扬唇，唱一年家春尽一年家春。", "陈虎口床，你也曾这般穷时分。"]'),
('yuanqu-10343','相国寺公孙合汗衫・赚煞尾','张国宾','元','元曲','yuanqu','','[]','岂不闻一饭莫忘怀，睚眦休成忿。',208,'元曲/yuanqu.json','["岂不闻一饭莫忘怀，睚眦休成忿。", "这厮他记小过忘人大恩，这厮他胁底下插柴不自稳，那里也敬老怜贫。", "他怒嗔嗔，劈手里夺了他银。", "(带云)不争你夺将来了呵。", "(唱)显的我也惨，他也羞，陈虎口床，你也狠。", "(云)陈虎孩儿。", "自古以来，有两个贤人，你学一个，休学一个。", "(邦老云)父亲，您孩儿学那一个？(正末唱)你则学那灵辄般报恩。", "(邦老云)不学那一个？(正末唱)休学那庞涓般雪恨。", "休！休！休！我劝您这得时人，可便休笑恰才那失时人。", "(下)。"]'),
('yuanqu-10344','相国寺公孙合汗衫・越调/斗鹌鹑','张国宾','元','元曲','yuanqu','','[]','气的来有眼如盲、有口似哑。',85,'元曲/yuanqu.json','["气的来有眼如盲、有口似哑。", "您两个绿鬓朱颜，也合问您这苍髯皓发。", "不争你背母抛爹，直闪的我形孤也那景寡。", "婆婆，他可便那里怕人笑，怕人骂，只待要急煎煎挟橐携囊，稳拍拍乘舟骗马。"]'),
('yuanqu-10345','相国寺公孙合汗衫・紫花序儿','张国宾','元','元曲','yuanqu','','[]','生刺刺弄的来人离财散，眼睁睁看着这水远山长，痛煞煞间隔了海角天涯。',195,'元曲/yuanqu.json','["生刺刺弄的来人离财散，眼睁睁看着这水远山长，痛煞煞间隔了海角天涯。", "(哭科，云)天那，怎么有这一场诧事？儿也，则被你忧愁杀我也。", "(卜儿云)张孝友孩儿挈了媳妇儿，带了许多本钱，敢出去做买卖么？(正末唱)元来他，将着些价高的行货，(带云)钱钞可打甚么不紧？(唱)天那，怎引着那个年小的浑家。", "倘或间有些儿争差，儿也，将您这一双老爹娘，可便看个甚么。", "畅好是心粗胆大，不争你背井离乡，谁替俺送酒供茶？。"]'),
('yuanqu-10346','相国寺公孙合汗衫・鬼三台','张国宾','元','元曲','yuanqu','','[]','我这里听言罢，这的是则好唬庄家。',108,'元曲/yuanqu.json','["我这里听言罢，这的是则好唬庄家。", "哎！儿也，你个聪明人怎便听他谎诈？那一个无子嗣缺根芽，妆了些高驮细马，和着金纸银钱将火化。", "更有那孝子贤孙儿女每打，早难道神不容奸，天能鉴察？(张孝友云)父亲，阴阳不可不信。", "(正末唱)。"]'),
('yuanqu-10347','相国寺公孙合汗衫・调笑令','张国宾','元','元曲','yuanqu','','[]','将衫儿拆下，就着这血糊刷，哎！儿也，可不道世上则有莲子花。',155,'元曲/yuanqu.json','["将衫儿拆下，就着这血糊刷，哎！儿也，可不道世上则有莲子花。", "我如今别无甚么弟兄并房下，倘或间俺命掩黄沙。", "则将这衫儿半壁匣盖上搭，哎！儿也，便当的你哭啼啼拽布拖麻。", "(邦老云)你觑着，兀的不火起了也。", "早些开船去。", "(张孝友云)俺趁着船快走，快走。", "(同旦儿，邦老下)(正末云)孩儿去了也。", "哎哟！兀的不苦痛杀我也。", "(唱)。"]'),
('yuanqu-10348','相国寺公孙合汗衫・幺篇','张国宾','元','元曲','yuanqu','','[]','我则听的张员外家遗漏火发，哎哟！天那，唬得我立挣痴呆了这半霎。',94,'元曲/yuanqu.json','["我则听的张员外家遗漏火发，哎哟！天那，唬得我立挣痴呆了这半霎。", "待去来呵，长街上列着兵马，哎！婆婆也，我可是怕也那不怕。", "(卜儿云)老的，眼见一家儿烧的光光儿了也，教俺怎生过活咱？(正末唱)。"]'),
('yuanqu-10349','相国寺公孙合汗衫・收尾','张国宾','元','元曲','yuanqu','','[]','我直从那水扑花儿抬举的偌来大，您将俺这两口儿生各支的撇下，空指着卧牛城内富人家。',168,'元曲/yuanqu.json','["我直从那水扑花儿抬举的偌来大，您将俺这两口儿生各支的撇下，空指着卧牛城内富人家。", "(卜儿云)咱如今往那里去好？(正末云)哎！婆婆也。", "我和你如今往那里去？只有个沿街儿叫化，学着那一声儿哩。", "(卜儿云)老的，是那一声？(正末云)婆婆也，你岂不曾听见那叫化的叫？我学与你听：那一个舍财的爹爹妈妈哦。", "(唱)少不的悲田院里，学那一声叫爹妈。", "(同下)。"]'),
('yuanqu-10350','相国寺公孙合汗衫・中吕/粉蝶儿','张国宾','元','元曲','yuanqu','','[]','我绕着他后巷的街，叫化些剩汤和这残菜，我受尽了些雪压波风节。',67,'元曲/yuanqu.json','["我绕着他后巷的街，叫化些剩汤和这残菜，我受尽了些雪压波风节。", "猛想起，十年前，兀那鸦飞不过的田宅。", "甚么是月值年灾？可便的眼睁睁一时消坏。"]'),
('yuanqu-10351','相国寺公孙合汗衫・快活三','张国宾','元','元曲','yuanqu','','[]','哎哟！则那风吹的我这头怎抬？雪打的我这眼难开。',45,'元曲/yuanqu.json','["哎哟！则那风吹的我这头怎抬？雪打的我这眼难开。", "则被这一场家天火破了家财，俺少年儿今何在？。"]'),
('yuanqu-10352','相国寺公孙合汗衫・朝天子','张国宾','元','元曲','yuanqu','','[]','哎哟！可则俺两口儿都老迈，肯分的便上该，天哪！天哪！也是俺注定的合受这饥寒债。',118,'元曲/yuanqu.json','["哎哟！可则俺两口儿都老迈，肯分的便上该，天哪！天哪！也是俺注定的合受这饥寒债。", "我如今无铺无盖，教我冷难挨。", "肯分的雪又紧风偏大，到晚来可便不敢番身，拳成做一块。", "天哪！天哪！则俺两口儿受冰雪堂地狱灾，我这里跪在，大街，望着那发心的爷娘每拜。"]'),
('yuanqu-10353','相国寺公孙合汗衫・四边静','张国宾','元','元曲','yuanqu','','[]','哎哟！正值着这冬寒天色，破瓦窑中又无些米柴。',155,'元曲/yuanqu.json','["哎哟！正值着这冬寒天色，破瓦窑中又无些米柴。", "眼见的冻死尸骸，料没个人瞅睬。", "谁肯着半掀儿家土埋，老业人眼见的便撇在这荒郊外。", "(杂当上，云)兀的那老两口儿，比及你在这里叫化，相国寺里散斋哩。", "你那里求一斋去不好那？(正末云)多谢哥哥。", "元来相国寺里散斋。", "婆婆，去来，去来。", "(卜儿云)老的也。", "俺往那里叫化去？(正末唱)。"]'),
('yuanqu-10354','相国寺公孙合汗衫・上小楼','张国宾','元','元曲','yuanqu','','[]','甚风儿便吹他到来？也有日重还乡界。',422,'元曲/yuanqu.json','["甚风儿便吹他到来？也有日重还乡界。", "则俺这烦烦恼恼，哭哭啼啼，想杀我儿也怨怨哀哀。", "到如今可也便欢欢爱爱，潇潇洒洒，无妨无碍。", "(小末云)兀那老的，你说甚么那？(正末云)生忿忤逆的贼也。", "(唱)哎！怎把这双老爹娘做外人看待？(卜儿云)老的，他正是我的儿。", "(小末云)兀那老的，你说甚么我的儿？我且问你，你那儿可姓甚么那？(正末云)我的儿姓张，叫做张孝友。", "(小末云)兀的你孩儿姓张，是张孝友。", "我姓陈，是陈豹。", "你怎生说我是你的儿？(卜儿云)呀！他改了姓也。", "(小末云)你的孩儿去时，多大年纪？(正末云)他去时三十岁也，去了十八年，如今该四十八岁。", "(小末云)你的孩儿去时三十岁，去了十八年，如今该四十八岁，这等说将起来，你那孩儿去时节我还不曾出世哩。", "(正末云)婆婆，不是了也。", "(卜儿云)我道不是了么。", "(正末云)可不道你这眼是琉璃葫芦儿？(卜儿云)则才寺门前挤破了也。", "(小末云)兀那老的，你那孩儿怎生与下官面貌相似？你试说与我听咱。", "(正末云)官人听我说波。", "(唱)。"]'),
('yuanqu-10355','相国寺公孙合汗衫・幺篇','张国宾','元','元曲','yuanqu','','[]','您两个恰便似一个印盒、印盒里脱将下来。',90,'元曲/yuanqu.json','["您两个恰便似一个印盒、印盒里脱将下来。", "您两个都一般容颜，一般模样，一般个身材。", "哎！我好呆，也合该，十分宁奈。", "(云)相公，恕老汉生纪老了。", "(唱)我老汉可便眼昏花，错认了你个相公休怪。"]'),
('yuanqu-10356','相国寺公孙合汗衫・脱布衫','张国宾','元','元曲','yuanqu','','[]','我这里便觑绝时雨泪盈腮，不由我不感叹伤怀。',57,'元曲/yuanqu.json','["我这里便觑绝时雨泪盈腮，不由我不感叹伤怀。", "则被你抛闪杀您这爹爹和您奶奶，婆婆也，去来波，问俺那少年儿是在也不在？。"]'),
('yuanqu-10357','相国寺公孙合汗衫・幺篇','张国宾','元','元曲','yuanqu','','[]','只为那当年认了个不良贼，送的俺一家儿横祸非灾。',104,'元曲/yuanqu.json','["只为那当年认了个不良贼，送的俺一家儿横祸非灾。", "(小末云)你那孩儿那里去了？(正末唱)俺孩儿听了他胡言乱道巧差排，便待离家乡做些买卖，(小末云)他曾有书信来么？(正末云)俺孩儿去了十八年也。", "(唱)只一去不回来。"]'),
('yuanqu-10358','相国寺公孙合汗衫・耍孩儿','张国宾','元','元曲','yuanqu','','[]','你将这衫儿半壁亲稍带，只说是马行街公婆每都老惫。',112,'元曲/yuanqu.json','["你将这衫儿半壁亲稍带，只说是马行街公婆每都老惫。", "官人呵。", "这言语休着您爷知，(小末云)怎生休着他知道？(正末唱)则去那娘亲上分付明白。", "则要你一言说透千年事，俺也不怕十谒朱门九不开。", "那贼汉当天败，婆婆，这也是灾消福长，苦尽甘来。"]'),
('yuanqu-10359','相国寺公孙合汗衫・双调/新水令','张国宾','元','元曲','yuanqu','','[]','您夺下的是轻裘肥马他这不公钱，俺如今受贫穷有如那范丹、原宪。',115,'元曲/yuanqu.json','["您夺下的是轻裘肥马他这不公钱，俺如今受贫穷有如那范丹、原宪。", "(赵兴孙云)你两个老的那里去也？(正末唱)俺只问金沙院在那里？不想道窝弓峪经着您山前。", "(弓兵云)有甚么人事送些与老爷，就放了你去。", "(正末唱)可怜俺赤手空拳，望将军觑方便。"]'),
('yuanqu-10360','相国寺公孙合汗衫・小将军','张国宾','元','元曲','yuanqu','','[]','休提起俺那小业冤，他剔腾了我些好家缘。',122,'元曲/yuanqu.json','["休提起俺那小业冤，他剔腾了我些好家缘。", "(赵兴孙云)员外，偌大庄宅，可还在么？(正末唱)典卖了庄田火烧了俺宅院，(赵兴孙云)嗨！好可怜人也。", "(正末唱)直闪的俺这两口儿可也难过遣。", "(赵兴孙云)员外，你如今怎地做个营生，养赡你那两口儿来？(正末唱)。"]'),
('yuanqu-10361','相国寺公孙合汗衫・清江引','张国宾','元','元曲','yuanqu','','[]','到晚来枕着的是多半个砖，每日在长街上转。',119,'元曲/yuanqu.json','["到晚来枕着的是多半个砖，每日在长街上转。", "口叫爷娘佛，(赵兴孙云)也有肯舍贫的么？(正末唱)无人可怜见，(赵兴孙云)陈虎那厮好狠也。", "(正末唱)陈虎口来我和你便有甚么那个杀父母的冤？(赵兴孙云)看那厮也好模好样的，可怎生这等歹心？(正末唱)。"]'),
('yuanqu-10362','相国寺公孙合汗衫・碧玉箫','张国宾','元','元曲','yuanqu','','[]','那厮模样儿慈善，贼汉软如绵，心肠儿机变，贼胆大如天。',146,'元曲/yuanqu.json','["那厮模样儿慈善，贼汉软如绵，心肠儿机变，贼胆大如天。", "(赵兴孙云)这元是小大哥认义他来。", "(正末唱)俺孩儿信他言、信他言搬上船。", "(赵兴孙云)大小哥去了多时也，曾有书信寄回么？(正末唱)他去了十八年，不能勾见，(赵兴孙云)员外，你这几年可在那里过活？(正末唱)哎哟！天哪！只俺两口儿叫化在这悲田院。"]'),
('yuanqu-10363','相国寺公孙合汗衫・沽美酒','张国宾','元','元曲','yuanqu','','[]','若说着俺祖先，好家私似泼天，(张孝友云)老的，你敢说大话盖着我哩？(正末唱)俺正是披着蒲席说大言。',95,'元曲/yuanqu.json','["若说着俺祖先，好家私似泼天，(张孝友云)老的，你敢说大话盖着我哩？(正末唱)俺正是披着蒲席说大言。", "(张孝友云)老的，你那家乡何处？本贯何方？(正末唱)若说着俺家乡，可便不远，祖居是住在梁园。"]'),
('yuanqu-10364','相国寺公孙合汗衫・太平令','张国宾','元','元曲','yuanqu','','[]','则我在那马行街里开着座门面，师父也与你这花银权当做些经钱。',138,'元曲/yuanqu.json','["则我在那马行街里开着座门面，师父也与你这花银权当做些经钱。", "(张孝友云)哦？他也在马行街住哩。", "老的，你可要看诵甚么经卷？(正末唱)梁武忏多看几卷，(张孝友云)再呢？(正末唱)消灾咒胜读几遍。", "告师父也可怜，可怜，我那命蹇，(张孝友云)你追荐甚么人？(正末唱)与俺个张孝友孩儿追荐。"]'),
('yuanqu-10365','相国寺公孙合汗衫・雁儿落','张国宾','元','元曲','yuanqu','','[]','则你这恶芒神休厮缠，我待超度你在这金沙院。',43,'元曲/yuanqu.json','["则你这恶芒神休厮缠，我待超度你在这金沙院。", "可怜我每日家思念你千万遭，口店题道有十余遍。"]'),
('yuanqu-10366','相国寺公孙合汗衫・得胜令','张国宾','元','元曲','yuanqu','','[]','呀！原来这和尚每都会通仙，我活了七十岁不曾见。',251,'元曲/yuanqu.json','["呀！原来这和尚每都会通仙，我活了七十岁不曾见。", "则你尸首归何处？儿也，你今日个阴魂在眼前。", "(云)你若是人呵，我叫你三声，你一声高一声。", "你若是鬼呵，我叫你三声，你一声低似一声。", "(张孝友云)你叫，我答应。", "(正末云)张孝友儿也。", "(张孝友云)哎！(正末云)是人，是人。", "张孝友儿也！(张孝友云)哎！(正末云)是人，是人。", "张孝友儿也！(张孝友云)偏生的堵了一口气儿。", "(做低应科，云)哎！(正末云)有鬼也。", "(张孝友云)父亲母亲，我不是鬼，是人。", "(正末唱)也是我心专，作念的一灵儿须活现，留得你生全，免的我两口儿长挂牵。"]'),
('yuanqu-10367','相国寺公孙合汗衫・殿前喜','张国宾','元','元曲','yuanqu','','[]','您道一家骨肉再团圆，这快心儿不是浅，便待要杀羊造酒大开筵。',70,'元曲/yuanqu.json','["您道一家骨肉再团圆，这快心儿不是浅，便待要杀羊造酒大开筵。", "多只是天见怜，道我个张员外人家善，也曾济贫救苦舍了偌多钱。", "今日个着他后人儿还贵显。"]'),
('yuanqu-10368','感天动地窦娥冤・仙吕/赏花时','关汉卿','元','元曲','yuanqu','','[]','我也只为尤计营生四壁贫，因此上割舍得亲儿在两处分。',166,'元曲/yuanqu.json','["我也只为尤计营生四壁贫，因此上割舍得亲儿在两处分。", "从今日远践洛阳尘，又不知归期定准，则落的无语暗消魂。", "（下）（卜儿云）窦秀才留下他这女孩儿与我做媳妇儿，他一径上朝应举去了。", "（正旦做悲科，云）爹爹，你直下的撇了我孩儿去也！（卜儿云）媳妇儿，你在我家，我是亲婆，你是亲媳妇，只当自家骨肉一般。", "你不要啼哭，跟着老身前后执料去来。", "（同下）。"]'),
('yuanqu-10369','感天动地窦娥冤・仙吕/点绛唇','关汉卿','元','元曲','yuanqu','','[]','满腹闲愁，数年禁受，天知否？天若是知我情由，怕不待和天瘦。',29,'元曲/yuanqu.json','["满腹闲愁，数年禁受，天知否？天若是知我情由，怕不待和天瘦。"]'),
('yuanqu-10370','感天动地窦娥冤・油葫芦','关汉卿','元','元曲','yuanqu','','[]','莫不是八字儿该载着一世忧？谁似我无尽头！须知道人心不似水长流。',89,'元曲/yuanqu.json','["莫不是八字儿该载着一世忧？谁似我无尽头！须知道人心不似水长流。", "我从三岁母亲身亡后，到七岁与父分离久。", "嫁的个同住人，他可又拔着短筹；撇的俺婆妇每都把空房守，端的个有谁问，有谁瞅？。"]'),
('yuanqu-10371','感天动地窦娥冤・天下乐','关汉卿','元','元曲','yuanqu','','[]','莫不是前世里烧香不到头，今也波生招祸尤？劝今人早将来世修。',50,'元曲/yuanqu.json','["莫不是前世里烧香不到头，今也波生招祸尤？劝今人早将来世修。", "我将这婆侍养，我将这服孝守，我言词须应口。"]'),
('yuanqu-10372','感天动地窦娥冤・一半儿','关汉卿','元','元曲','yuanqu','','[]','为甚么泪漫漫不住点儿流？莫不是为索债与人家惹争斗？我这里连忙迎接慌问候，他那里要说缘由。',80,'元曲/yuanqu.json','["为甚么泪漫漫不住点儿流？莫不是为索债与人家惹争斗？我这里连忙迎接慌问候，他那里要说缘由。", "（卜儿云）羞人答答的，教我怎生说波！（正旦唱）则见他一半儿徘徊一半儿丑。"]'),
('yuanqu-10373','感天动地窦娥冤・后庭花','关汉卿','元','元曲','yuanqu','','[]','避凶神要择好日头，拜家堂要将香火修。',89,'元曲/yuanqu.json','["避凶神要择好日头，拜家堂要将香火修。", "梳着个霜雪般白鬏髻，怎将这云霞般锦帕兜？怪不的\"女大不中留\"。", "你如今六旬左右，可不道到中年万事休！旧恩爱一笔勾，新夫妻两意投，枉教人笑破口！。"]'),
('yuanqu-10374','感天动地窦娥冤・寄生草','关汉卿','元','元曲','yuanqu','','[]','你道他匆匆喜，我替你倒细细愁：愁则愁兴阑珊咽不下交欢酒，愁则愁眼昏腾扭不上同心扣，愁则愁意朦胧睡不稳芙蓉褥。',77,'元曲/yuanqu.json','["你道他匆匆喜，我替你倒细细愁：愁则愁兴阑珊咽不下交欢酒，愁则愁眼昏腾扭不上同心扣，愁则愁意朦胧睡不稳芙蓉褥。", "你待要笙歌引至画堂前，我道这姻缘敢落在他人后。"]'),
('yuanqu-10375','感天动地窦娥冤・赚煞','关汉卿','元','元曲','yuanqu','','[]','我想这妇人每休信那男儿口。',442,'元曲/yuanqu.json','["我想这妇人每休信那男儿口。", "婆婆也，怕没的贞心儿自守，到今日招着个村老子，领着个半死囚。", "（张驴儿做嘴脸料，云）你看我爷儿两个这等身段，尽也选得女婿过，你不要错过了好时辰，我和你早些儿拜堂罢。", "（正旦不礼科，唱）则被你坑杀人燕侣莺俦。", "婆婆也，你岂不知羞！俺公公撞府冲州，挣扎的铜斗儿家缘百事有。", "想着俺公公置就，怎忍教张驴儿情受？（张驴儿做扯正旦拜科，正旦推跌科，唱）兀的不是俺没丈夫的妇女下场头！（下）（卜儿云）你老人家不要恼躁。", "难道你有活命之恩，我岂不思量报你？只是我那媳妇儿气性最不好惹的，既是他不肯招你儿子，教我怎好招你老人家？我如今拚的好酒好饭，养你爷儿两个在家，待我慢慢的劝化俺媳妇儿。", "待他有个回心转意，再作区处。", "（张驴儿云）这歪剌骨！便是黄花女儿，刚刚扯的一把，也不消这等使性，平空的推了我一交，我肯干罢！就当面赌个誓与你：我今生今世不要他做老婆，我也不算好男子！（词云）美妇人我见过万千向外，不似这小妮子生得十分惫赖。", "我救了你老性命死里重生，怎割舍得不肯把肉身陪待？（同下）。"]'),
('yuanqu-10376','感天动地窦娥冤・南吕/一枝花','关汉卿','元','元曲','yuanqu','','[]','他则待一生鸳帐眠，那里肯半夜空房睡；他本是张郎妇，又做了李郎妻。',80,'元曲/yuanqu.json','["他则待一生鸳帐眠，那里肯半夜空房睡；他本是张郎妇，又做了李郎妻。", "有一等妇女每相随，并不说家克计，则打听些闲是非；说一会不明白打风的机关，使了些调虚嚣捞龙的见识。"]'),
('yuanqu-10377','感天动地窦娥冤・梁州第七','关汉卿','元','元曲','yuanqu','','[]','这一个似卓氏般当垆涤器，这一个似孟光般举案齐眉，说的来藏头盖脚多伶俐！道着难晓，做出才知。',144,'元曲/yuanqu.json','["这一个似卓氏般当垆涤器，这一个似孟光般举案齐眉，说的来藏头盖脚多伶俐！道着难晓，做出才知。", "旧恩忘却，新爱偏宜；坟头上土脉犹湿，架儿上又换新衣。", "那里有奔丧处哭倒长城？那里有浣纱时甘投大水？那里有上山来便化顽石？可悲，可耻！妇人家直恁的无仁义。", "多淫奔，少志气，亏杀前人在那里，更休说百步相随。"]'),
('yuanqu-10378','感天动地窦娥冤・隔尾','关汉卿','元','元曲','yuanqu','','[]','你说道少盐欠醋无滋味，加料添椒才脆美。',51,'元曲/yuanqu.json','["你说道少盐欠醋无滋味，加料添椒才脆美。", "但愿娘亲早痊济，饮羹汤一杯，胜甘露灌体，得一个身子平安倒大来喜。"]'),
('yuanqu-10379','感天动地窦娥冤・贺新郎','关汉卿','元','元曲','yuanqu','','[]','一个道你请吃，一个道婆先吃，这言语听也难听，我可是气也不气！想他家与咱家有甚的亲和戚？怎不记旧日夫妻情意，也曾有百纵千随？婆婆也，你莫不为"黄金浮世宝，白发故人',117,'元曲/yuanqu.json','["一个道你请吃，一个道婆先吃，这言语听也难听，我可是气也不气！想他家与咱家有甚的亲和戚？怎不记旧日夫妻情意，也曾有百纵千随？婆婆也，你莫不为\"黄金浮世宝，白发故人稀\"，因此上把旧恩情，全不比新知契？则待要百年同墓穴，那里肯千里送寒衣？。"]'),
('yuanqu-10380','感天动地窦娥冤・斗虾蟆','关汉卿','元','元曲','yuanqu','','[]','空悲戚，没理会，人生死，是轮回。',228,'元曲/yuanqu.json','["空悲戚，没理会，人生死，是轮回。", "感着这般病疾，值着这般时势，可是风寒暑湿，或是饥饱劳役，各人症候自知。", "人命关天关地，别人怎生替得？寿数非干今世。", "相守三朝五夕，说甚一家一计？又无羊酒缎匹，又无花红财礼；把手为活过日，撒手如同休弃。", "不是窦娥忤逆，生怕旁人论议。", "不如听咱劝你，认个自家晦气，割舍的一具棺材停置，几件布帛收拾，出了咱家门里，送入他家坟地。", "这不是你那从小儿年纪指脚的夫妻。", "我其实不关亲，无半点忄西惶泪。", "休得要心如醉，意似痴，便这等嗟嗟怨怨，哭哭啼啼。"]'),
('yuanqu-10381','感天动地窦娥冤・隔尾','关汉卿','元','元曲','yuanqu','','[]','这厮搬调咱老母收留你，自药死亲爷待要唬吓谁？（张驴儿云）我家的老子，倒说是我做儿子的药死了，人也不信。',242,'元曲/yuanqu.json','["这厮搬调咱老母收留你，自药死亲爷待要唬吓谁？（张驴儿云）我家的老子，倒说是我做儿子的药死了，人也不信。", "（做叫科，云）四邻八舍听着：窦娥药杀我家老子哩！（卜儿云）罢么，你不要大惊小怪的，吓杀我也！（张驴儿云）你可怕么？（卜儿云）可知怕哩。", "（张驴儿云）你要饶么？（卜儿云）可知要饶哩。", "（张驴儿云）你教窦娥随顺了我，叫我三声嫡嫡亲亲的丈夫，我便饶了他。", "（卜儿云）孩儿也，你随顺了他罢。", "（正旦云）婆婆，你怎说这般言语！（唱）我一马难将两鞍鞴，想男儿在日曾两年匹配，却教我改嫁别人，其实做不得。"]'),
('yuanqu-10382','感天动地窦娥冤・牧羊关','关汉卿','元','元曲','yuanqu','','[]','大人你明如镜，清似水，照妾身肝胆虚实。',74,'元曲/yuanqu.json','["大人你明如镜，清似水，照妾身肝胆虚实。", "那羹本五味俱全，除了外百事不知。", "他推道尝滋味，吃下去便昏迷。", "不是妾讼庭上胡支对，大人也，却教我平白地说甚的？。"]'),
('yuanqu-10383','感天动地窦娥冤・骂玉郎','关汉卿','元','元曲','yuanqu','','[]','这无情棍棒教我捱不的。',48,'元曲/yuanqu.json','["这无情棍棒教我捱不的。", "婆婆也，须是你自做下，怨他谁？劝普天下前婚后嫁婆娘每，都看取我这般傍州例。"]'),
('yuanqu-10384','感天动地窦娥冤・感皇恩','关汉卿','元','元曲','yuanqu','','[]','呀！是谁人唱叫扬疾，不由我不魄散魂飞。',54,'元曲/yuanqu.json','["呀！是谁人唱叫扬疾，不由我不魄散魂飞。", "恰消停，才苏醒，又昏迷。", "捱千般打拷，万种凌逼，一杖下，一道血，一层皮。"]'),
('yuanqu-10385','感天动地窦娥冤・采茶歌','关汉卿','元','元曲','yuanqu','','[]','打的我肉都飞，血淋漓，腹中冤枉有谁知！则我这小妇人毒药来从何处也？天那，怎么的覆盆不照太阳晖！。',48,'元曲/yuanqu.json','["打的我肉都飞，血淋漓，腹中冤枉有谁知！则我这小妇人毒药来从何处也？天那，怎么的覆盆不照太阳晖！。"]'),
('yuanqu-10386','感天动地窦娥冤・黄锺尾','关汉卿','元','元曲','yuanqu','','[]','我做了个衔冤负屈没头鬼，怎肯便放了你好包荒淫漏面贼！想人心不可欺，冤枉事天地知，争到头，竞到底，到如今待怎的？情愿认药杀公公，与了招罪。',93,'元曲/yuanqu.json','["我做了个衔冤负屈没头鬼，怎肯便放了你好包荒淫漏面贼！想人心不可欺，冤枉事天地知，争到头，竞到底，到如今待怎的？情愿认药杀公公，与了招罪。", "婆婆也，我若是不死呵，如何救得你？（随祗候押下）。"]'),
('yuanqu-10387','感天动地窦娥冤・正宫/端正好','关汉卿','元','元曲','yuanqu','','[]','没来由犯王法，不堤防遭刑宪，叫声屈动地惊天！顷刻间游魂先赴森罗殿，怎不将天地也生埋怨？。',44,'元曲/yuanqu.json','["没来由犯王法，不堤防遭刑宪，叫声屈动地惊天！顷刻间游魂先赴森罗殿，怎不将天地也生埋怨？。"]'),
('yuanqu-10388','感天动地窦娥冤・滚绣球','关汉卿','元','元曲','yuanqu','','[]','有日月朝暮悬，有鬼神掌著生死权，天地也，只合把清浊分辨，可怎生糊突了盗跖、颜渊？为善的受贫穷更命短，造恶的享富贵又寿延。',117,'元曲/yuanqu.json','["有日月朝暮悬，有鬼神掌著生死权，天地也，只合把清浊分辨，可怎生糊突了盗跖、颜渊？为善的受贫穷更命短，造恶的享富贵又寿延。", "天地也，做得个怕硬欺软，却元来也这般顺水推船。", "地也，你不分好歹何为地？天也，你错勘贤愚枉做天！哎，只落得两泪涟涟。"]'),
('yuanqu-10389','感天动地窦娥冤・倘秀才','关汉卿','元','元曲','yuanqu','','[]','则被这枷扭的我左侧右偏，人拥的我前合后偃，我窦娥向哥哥行有句言。',71,'元曲/yuanqu.json','["则被这枷扭的我左侧右偏，人拥的我前合后偃，我窦娥向哥哥行有句言。", "（刽子云）你有甚么话说？（正旦唱）前街里去心怀恨，后街里去死无冤，休推辞路远。"]'),
('yuanqu-10390','感天动地窦娥冤・快活三','关汉卿','元','元曲','yuanqu','','[]','念窦娥葫芦提当罪愆，念窦娥身首不完全，念窦娥从前已往干家缘。',45,'元曲/yuanqu.json','["念窦娥葫芦提当罪愆，念窦娥身首不完全，念窦娥从前已往干家缘。", "婆婆也，你只看窦娥少爷无娘面。"]'),
('yuanqu-10391','感天动地窦娥冤・鲍老儿','关汉卿','元','元曲','yuanqu','','[]','念窦娥伏侍婆婆这几年，遇时节将碗凉浆奠；你去那受刑法尸骸上烈些纸钱，只当把你亡化的孩儿荐。',315,'元曲/yuanqu.json','["念窦娥伏侍婆婆这几年，遇时节将碗凉浆奠；你去那受刑法尸骸上烈些纸钱，只当把你亡化的孩儿荐。", "（卜儿哭科，云）孩儿放心，这个老身都记得。", "天那，兀的不痛杀我也！（正旦唱）婆婆也，再也不要啼啼哭哭，烦烦恼恼，怨气冲天。", "这都是我做窦娥的没时没运，不明不暗，负屈衔冤。", "（刽子做喝科，云）兀那婆子靠后，时辰到了也。", "（正旦跪科）（刽子开枷科）（正旦云）窦娥告监斩大人，有一事肯依窦娥，便死而无怨。", "（监斩官云）你有甚么事？你说。", "（正旦云）要一领净席，等我窦娥站立；又要丈二白练，挂在旗枪上：若是我窦娥委实冤枉，刀过处头落，一腔热血休半点儿沾在地下，都飞在白练上者。", "（监斩官云）这个就依你，打甚么不紧。", "（刽子做取席站科，又取白练挂旗上科）（正旦唱）。"]'),
('yuanqu-10392','感天动地窦娥冤・耍孩儿','关汉卿','元','元曲','yuanqu','','[]','不是我窦娥罚下这等无头愿，委实的冤情不浅；若没些儿灵圣与世人传，也不见得湛湛青天。',86,'元曲/yuanqu.json','["不是我窦娥罚下这等无头愿，委实的冤情不浅；若没些儿灵圣与世人传，也不见得湛湛青天。", "我不要半星热血红尘洒，都只在八尺旗枪素练悬。", "等他四下里皆瞧见，这就是咱苌弘化碧，望帝啼鹃。"]'),
('yuanqu-10393','感天动地窦娥冤・二煞','关汉卿','元','元曲','yuanqu','','[]','你道是暑气暄，不是那下雪天；岂不闻飞霜六月因邹衍？若果有一腔怨气喷如火，定要感的六出冰花滚似绵，免着我尸骸现；要什么素车白马，断送出古陌荒阡！。',72,'元曲/yuanqu.json','["你道是暑气暄，不是那下雪天；岂不闻飞霜六月因邹衍？若果有一腔怨气喷如火，定要感的六出冰花滚似绵，免着我尸骸现；要什么素车白马，断送出古陌荒阡！。"]'),
('yuanqu-10394','感天动地窦娥冤・一煞','关汉卿','元','元曲','yuanqu','','[]','你道是天公不可期，人心不可怜，不知皇天也肯从人愿。',76,'元曲/yuanqu.json','["你道是天公不可期，人心不可怜，不知皇天也肯从人愿。", "做甚么三年不见甘霖降？也只为东海曾经孝妇冤，如今轮到你山阳县。", "这都是官吏每无心正法，使百姓有口难言！。"]'),
('yuanqu-10395','感天动地窦娥冤・煞尾','关汉卿','元','元曲','yuanqu','','[]','浮云为我阴，悲风为我旋，三桩儿誓愿明题遍。',67,'元曲/yuanqu.json','["浮云为我阴，悲风为我旋，三桩儿誓愿明题遍。", "（做哭科，云）婆婆也，直等待雪飞六月，亢旱三年呵，（唱）那其间才把你个屈死的冤魂这窦娥显！。"]'),
('yuanqu-10396','感天动地窦娥冤・双调/新水令','关汉卿','元','元曲','yuanqu','','[]','我每日哭啼啼守住望乡台，急煎煎把仇人等待，慢腾腾昏地里走，足律律旋风中来。',52,'元曲/yuanqu.json','["我每日哭啼啼守住望乡台，急煎煎把仇人等待，慢腾腾昏地里走，足律律旋风中来。", "则被这雾锁云埋，撺掇的鬼魂快。"]'),
('yuanqu-10397','感天动地窦娥冤・沉醉东风','关汉卿','元','元曲','yuanqu','','[]','我是那提刑的女孩，须不比现世的妖怪。',629,'元曲/yuanqu.json','["我是那提刑的女孩，须不比现世的妖怪。", "怎不容我到灯影前，却拦截在门木呈外？（做叫科，云）我那爷爷呵，（唱）枉自有势剑金牌，把俺这屈死三年的腐骨骸，怎脱离无边苦海？（做入见哭科，窦天章亦哭科，云）端云孩儿，你在那里来？（魂旦虚下）（窦天章做醒科，云）好是奇怪也！老夫才合眼去，梦见端云孩儿，恰便似来我跟前一般；如今在那里？我且再看这文卷咱。", "（魂旦上，做弄灯科）（窦天章云）奇怪，我正要看文卷，怎生这灯忽明忽灭的？张千也睡着了，我自己剔灯咱。", "（做剔灯，魂旦翻文卷科）（窦天章云）我剔的这灯明了也，再看几宗文卷。", "\"一起犯人窦娥，药死公公。", "……\"（做疑怪科，云）这一宗文卷，我为头看过，压在文卷底下，怎生又在这上头？这几时问结了的，还压在底下，我别看一宗文卷波。", "（魂旦再弄灯科）（窦天章云）怎么这灯又是半明半暗的？我再剔这灯咱。", "（做剔灯，魂旦再翻文卷科。", "窦天章云）我剔的这灯明了，我另拿一宗文卷看咱。", "\"一起犯人窦娥，药死公公。", "……\"呸！好是奇怪！我才将这文书分明压在底下，刚剔了这灯，怎生又翻在面上？莫不是楚州后厅里有鬼么？便无鬼呵，这桩事必有冤枉。", "将这文卷再压在底上，待我另看一宗如何？（魂旦又弄灯科）（窦天章云）怎么这灯又不明了，敢有鬼弄这灯？我再剔一剔去。", "（做剔灯科，魂旦上，做撞见科，窦天章举剑击桌科，云）呸！我说有鬼！兀那鬼魂：老夫是朝廷钦差，带牌走马肃政廉访使。", "你向前来，一剑挥之两段。", "张千，亏你也睡的着！快起来，有鬼，有鬼。", "兀的不吓杀老夫也！（魂旦唱）。"]'),
('yuanqu-10398','感天动地窦娥冤・乔牌儿','关汉卿','元','元曲','yuanqu','','[]','则见他疑心儿胡乱猜，听了我这哭声儿转惊骇。',46,'元曲/yuanqu.json','["则见他疑心儿胡乱猜，听了我这哭声儿转惊骇。", "哎，你个窦天章直恁的威风大，且受你孩儿窦娥这一拜。"]'),
('yuanqu-10399','感天动地窦娥冤・雁儿落','关汉卿','元','元曲','yuanqu','','[]','你看这文卷曾道来不道来，则我这冤枉要忍耐如何耐？我不肯顺他人，倒着我赴法场；我不肯辱祖上，倒把我残生坏。',52,'元曲/yuanqu.json','["你看这文卷曾道来不道来，则我这冤枉要忍耐如何耐？我不肯顺他人，倒着我赴法场；我不肯辱祖上，倒把我残生坏。"]'),
('yuanqu-10400','感天动地窦娥冤・得胜令','关汉卿','元','元曲','yuanqu','','[]','呀，今日个搭伏定摄魂台，一灵儿怨哀哀。',70,'元曲/yuanqu.json','["呀，今日个搭伏定摄魂台，一灵儿怨哀哀。", "父亲也，你现拿着刑名事，亲蒙圣主差。", "端详这文册，那厮乱纲常，合当败。", "便万剐了乔才，还道报冤仇不畅怀！。"]'),
('yuanqu-10401','感天动地窦娥冤・川拨掉','关汉卿','元','元曲','yuanqu','','[]','猛见了你这吃敲材，我只问你这毒药从何处来？你本意待暗里栽排，要逼勒我和谐，倒把你亲爷毒害，怎教咱替你耽罪责！。',55,'元曲/yuanqu.json','["猛见了你这吃敲材，我只问你这毒药从何处来？你本意待暗里栽排，要逼勒我和谐，倒把你亲爷毒害，怎教咱替你耽罪责！。"]'),
('yuanqu-10402','感天动地窦娥冤・七弟兄','关汉卿','元','元曲','yuanqu','','[]','你只为赖财，放乖，要当灾。',237,'元曲/yuanqu.json','["你只为赖财，放乖，要当灾。", "（带云）这毒药呵，（唱）原来是你赛卢医出卖，张驴儿买，没来由填做我犯由牌，到今日官去衙门在。", "（窦天章云）带那蔡婆婆上来！我看你也六十外人了，家中又是有钱钞的，如何又嫁了老张，做出这等事来？（蔡婆婆云）老妇人因为他爷儿两个救了我的性命，收留他在家养膳过世。", "那张驴儿常说要将他老子接脚进来，老妇人并不曾许他。", "（窦天章云）这等说，你那媳妇就不该认做药死公公了。", "（魂旦云）当日问官要打俺婆婆，我怕他年老，受刑不起，因此咱认做药死公公，委实是屈招个！（唱）。"]'),
('yuanqu-10403','感天动地窦娥冤・梅花酒','关汉卿','元','元曲','yuanqu','','[]','你道是咱不该，这招状供写的明白。',92,'元曲/yuanqu.json','["你道是咱不该，这招状供写的明白。", "本一点孝顺的心怀，倒做了惹祸的胚胎。", "我只道官吏每还覆勘，怎将咱屈斩首在长街！第一要素旗枪鲜血洒，第二要三尺雪将死尸埋，第三要三年旱示天灾：咱誓愿委实大。"]'),
('yuanqu-10404','感天动地窦娥冤・收江南','关汉卿','元','元曲','yuanqu','','[]','呀，这的是"衙门从古向南开，就中无个不冤哉"！痛杀我娇姿弱体闭泉台，早三年以外，则落的悠悠流恨似长淮。',51,'元曲/yuanqu.json','["呀，这的是\"衙门从古向南开，就中无个不冤哉\"！痛杀我娇姿弱体闭泉台，早三年以外，则落的悠悠流恨似长淮。"]'),
('yuanqu-10405','感天动地窦娥冤・鸳鸯煞尾','关汉卿','元','元曲','yuanqu','','[]','从今后把金牌势剑从头摆，将滥官污吏都杀坏，与天子分忧，万民除害。',467,'元曲/yuanqu.json','["从今后把金牌势剑从头摆，将滥官污吏都杀坏，与天子分忧，万民除害。", "（云）我可忘了一件：爹爹，俺婆婆年纪高大，无人侍养，你可收恤家中，替你孩儿尽养生送死之礼，我便九泉之下，可也瞑目。", "（窦天章云）好孝顺的儿也！（魂旦唱）嘱付你爹爹，收养我奶奶。", "要怜他无妇无儿，谁管顾年衰迈！再将那文卷舒开，（带云）爹爹，也把我窦娥名下，（唱）屈死的招伏罪名儿改。", "（下）（窦天章云）唤那蔡婆婆上来。", "你可认的我么？（蔡婆婆云）老妇人眼花了，不认的。", "（窦天章云）我便是窦天章。", "这才的鬼魂，便是我屈死的女孩儿端云。", "你这一行人，听我下断：张驴儿毒杀亲爷，谋占寡妇，合拟凌迟，押付市曹中，钉上木驴，剐一百二十刀处死。", "升任州守桃杌并该房吏典，刑名违错，各杖一百，永不叙用。", "赛卢医不合赖钱，勒死平民；又不合修合毒药，致伤人命，发烟瘴地面，永远充军。", "蔡婆婆我家收养。", "窦娥罪改正明白。", "（词云）莫道我念亡女与他又罪消愆，也只可怜见楚州郡大旱三年。", "昔于公曾表白东海孝妇，果然是感召得灵雨如泉。", "岂可便推诿道天灾代有，竟不想人之意感应通天。", "今日个将文卷重行改正，方显的王家法不使民冤。"]'),
('yuanqu-10406','冻苏秦衣锦还乡・仙吕/赏花时','无名氏','元','元曲','yuanqu','','[]','凭着我七尺身驱八斗才，那怕他十谒朱门九不开。',98,'元曲/yuanqu.json','["凭着我七尺身驱八斗才，那怕他十谒朱门九不开。", "休想我白首闲尘埃，凭着这兵书也那战策。", "(孛老云)孩儿，我则记着金榜无名誓不归。", "(正末云)父亲、母亲，您放心也。", "(唱)我直着夺得一个可兀的锦标来。", "(下)。"]'),
('yuanqu-10407','冻苏秦衣锦还乡・仙吕/点绛唇','无名氏','元','元曲','yuanqu','','[]','我又不会下贱营生，特的来上朝取应，离乡井。',36,'元曲/yuanqu.json','["我又不会下贱营生，特的来上朝取应，离乡井。", "感的这时气天行，早是我身耽病。"]'),
('yuanqu-10408','冻苏秦衣锦还乡・混江龙','无名氏','元','元曲','yuanqu','','[]','俺把那指尖儿掐定，整整的二十年窗下学穷经。',94,'元曲/yuanqu.json','["俺把那指尖儿掐定，整整的二十年窗下学穷经。", "苦了我也青灯黄卷，误了我也白马红缨。", "本待做人鹏乌高抟九万里，却被这恶西风先摧折了六稍翎。", "端的是云霄有路难侥幸，把我在红尘中埋没，几能勾青史上标名。"]'),
('yuanqu-10409','冻苏秦衣锦还乡・油葫芦','无名氏','元','元曲','yuanqu','','[]','难道我不想功名只这等？(王长者云)先生莫非是盘缠缺少么？(正末唱)但得个有盘缠便进程。',183,'元曲/yuanqu.json','["难道我不想功名只这等？(王长者云)先生莫非是盘缠缺少么？(正末唱)但得个有盘缠便进程。", "(王长者云)先生若肯屈节于人，必有进步之日。", "(正末唱)我可也心高气傲惹人憎，因此上空囊那讨一文剩，只落的孤身干受十分冷。", "(王长者云)时值严冬天道，雪花初霁，风力犹严，先生，你身上敢单寒么？(正末唱)昨日个风又起，今日个雪乍晴。", "则我这领破蓝衫刚有那一条囫囵领，那夜里不长叹到二三更。"]'),
('yuanqu-10410','冻苏秦衣锦还乡・天下乐','无名氏','元','元曲','yuanqu','','[]','可正是酒冷灯昏梦不成，则我那通也波厅，通厅土坑冷，兀的不着我翻来覆去直到明。',391,'元曲/yuanqu.json','["可正是酒冷灯昏梦不成，则我那通也波厅，通厅土坑冷，兀的不着我翻来覆去直到明。", "且休说冰断我肚肠，争些儿冻出我眼睛。", "(王长者云)如此般寂寞，先生你怎捱的这等寒苦也？(正末云)着长者便道恁的八苏秦，(唱)哎。", "我可甚么画堂春自生！(王长者云)在下聊备一杯淡酒，与先生荡寒。", "家童抬上果桌来者。", "(家童云)理会的。", "(抬果桌上，云)老员外，果桌在此。", "(王长者云)将酒来。", "(家童云)酒到。", "(王长者把盏科，云)斟的满者，先生请饮一杯。", "(正末云)长者先请。", "(王长者云)先生请。", "(正末饮科)(王长者云)久闻先生胸藏盖世文章，腹隐安邦妙策。", "我想太公未遇。", "持钓于渭水之滨；伍相含冤，吹箫在丹阳之县。", "后来兴师伐纣。", "万万载书史留名；报恨强吴，千千古丹青画像。", "据先生甘贫守困，待势乘时，所谓蛟龙得云雨，终非池中之物。", "且请开怀饮酒者。", "(诗云)文章锦绣满胸怀，知是天生冠世才。", "任使无心求富贵，终须富贵逼人来。", "(正末唱)。"]'),
('yuanqu-10411','冻苏秦衣锦还乡・元和令','无名氏','元','元曲','yuanqu','','[]','你道我满胸中文学精，又道我有才华会施逞。',56,'元曲/yuanqu.json','["你道我满胸中文学精，又道我有才华会施逞。", "可不道黄河有日也澄清，偏则是我五星。", "直恁般时乖运蹇不通亨，觑功名如画饼。"]'),
('yuanqu-10412','冻苏秦衣锦还乡・上马娇','无名氏','元','元曲','yuanqu','','[]','那一个不把我欺，不把我凌，这都是冷暖世人情。',42,'元曲/yuanqu.json','["那一个不把我欺，不把我凌，这都是冷暖世人情。", "直待将牙爪安排定，惊，方知道画虎恁时成。"]'),
('yuanqu-10413','冻苏秦衣锦还乡・后庭花','无名氏','元','元曲','yuanqu','','[]','他、他、他，沧海将升斗倾，泰山将等秤称，鳌鱼向池中养，凤凰在笼内盛。',101,'元曲/yuanqu.json','["他、他、他，沧海将升斗倾，泰山将等秤称，鳌鱼向池中养，凤凰在笼内盛。", "我如今眼睁睁，捱尽了十分蹭蹬。", "待要去做庄农，又怕误了九经；做经商，又没个本领。", "往前去赚入坑，往后来褪入井，两下里怎据凭，折磨俺过一生。"]'),
('yuanqu-10414','冻苏秦衣锦还乡・青哥儿','无名氏','元','元曲','yuanqu','','[]','也是我那前程、前程不定，百忙里揣摩、揣摩踪影，还说甚有志的从来事竞成。',219,'元曲/yuanqu.json','["也是我那前程、前程不定，百忙里揣摩、揣摩踪影，还说甚有志的从来事竞成。", "(王长者云)先生，我想这先贫后富的古人，有伊尹躬耕，傅说版筑，冯罐弹铗，宁戚饭牛，孙膑刖足，百里奚卖身。", "古人尚然如此，先生必遂其愿也。", "(正末唱)想当初伊尹在莘野躬耕，傅说版筑劳形，冯獾弹铗知名，宁戚扣角歌声，孙膑是趾遭刑，百里奚陪嫁秦庭。", "这都白古豪英，个个白衣公卿。", "苏秦也是书生。", "偏我半生飘零，一世不得峥嵘。", "都则为命儿里注定在前生。", "(带云)长者，(唱)我待和谁争竞？。"]'),
('yuanqu-10415','冻苏秦衣锦还乡・赚煞尾','无名氏','元','元曲','yuanqu','','[]','打灭了腹中饥，挣坐了身边冷。',150,'元曲/yuanqu.json','["打灭了腹中饥，挣坐了身边冷。", "谢长者将咱厚赠，免的我流落穷途涕泪零。", "只今日便索长行，看鲰生，黄榜高登。", "博一个千万人中第一名。", "(王长者云)先生，此一去则要你着志者。", "(正末唱)我将这星辰再整，乾坤来扶定。", "(王长者云)先生，此一去投于何处？(正末云)小生往那里去的是，(唱)我只索占那虎狼丛卫觅前程。", "(下)。"]'),
('yuanqu-10416','冻苏秦衣锦还乡・正宫/端正好','无名氏','元','元曲','yuanqu','','[]','叹书生，我这里便叹书生可兀的身无济，那里也荫子封妻。',50,'元曲/yuanqu.json','["叹书生，我这里便叹书生可兀的身无济，那里也荫子封妻。", "则俺那一般儿求仕的诸相识，他每都闪赚的我难回避。"]'),
('yuanqu-10417','冻苏秦衣锦还乡・滚绣球','无名氏','元','元曲','yuanqu','','[]','想着我去家来望发迹，定道是上青云可指日。',116,'元曲/yuanqu.json','["想着我去家来望发迹，定道是上青云可指日。", "又谁知遇天行染了这场儿病疾，险些儿连性命也不得回归。", "我苏秦也年纪呵近三十岁，文学呵又不是没得，可怎生不能图个荣贵？却教我满头家风雪凄凄。", "看别人峥嵘黄阁三公位，偏则我依旧红尘一布衣，怎不伤悲？。"]'),
('yuanqu-10418','冻苏秦衣锦还乡・伴读书','无名氏','元','元曲','yuanqu','','[]','我待上来，终久则是他苗裔；待不去来，便怎肯务了恩义？想着我那父母情肠别不得，可知俺三从四德妻贤慧。',76,'元曲/yuanqu.json','["我待上来，终久则是他苗裔；待不去来，便怎肯务了恩义？想着我那父母情肠别不得，可知俺三从四德妻贤慧。", "却不道相随百步有这徘徊意，俺爷娘便怎肯出丑的这场疾？。"]'),
('yuanqu-10419','冻苏秦衣锦还乡・笑歌赏','无名氏','元','元曲','yuanqu','','[]','我待去来，你觑我这衣衫褴褴缕缕不整齐；待不去来。',260,'元曲/yuanqu.json','["我待去来，你觑我这衣衫褴褴缕缕不整齐；待不去来。", "则这里勿、勿、勿，风共雪相摧逼；去不去三两次白猜疑。", "我、我、我，突磨到多半晌走到他跟底，呀、呀、呀，可怎生无一个睬我的？来、来、来，我将这羞睑儿且揣在怀儿内。", "(云)事已到此，无如之奈，且自过去咱。", "(见科，云)父亲，您孩儿回来了也。", "(拜科)(孛老转身科)(正末云)母亲，您孩儿回来了也。", "(做拜科)(卜儿转身科)(正末云)父亲、母亲都不理我，则望着中间里拜咱。", "(做拜科)(孛老与卜儿同转身撞脸科)(正末云)二嫂，我来家了也。", "(二旦做织机科)(正末云)可怎生都不言语那？(唱)。"]'),
('yuanqu-10420','冻苏秦衣锦还乡・滚绣球','无名氏','元','元曲','yuanqu','','[]','这壁厢拜了一会，那壁厢问了一日，可怎生无一个将咱支对？则您这一家儿端的是嫌淮？(孛老云)嫌你，嫌你。',268,'元曲/yuanqu.json','["这壁厢拜了一会，那壁厢问了一日，可怎生无一个将咱支对？则您这一家儿端的是嫌淮？(孛老云)嫌你，嫌你。", "你可怎么不做官来？(正末唱)俺爹娘他须是老背悔，(二旦云)苏秦，你得了官来，那个嫌你？(正未唱)妻也，你也好忒下的。", "(大旦云)苏秦，你选场中及第也不曾？(正夫唱)你问我选场中及第来不曾及第，你不看见我马头前列山行家朱衣。", "(孛老云)苏秦，我问你，你当日不做庄农生活，则去读书，要做官。", "你跟的张仪去了许多时光景，你如今得了个甚么官来？(正末唱)我恰才入门来休问荣枯事，可不道观着容颜兀的使得知？(带云)我这官职呵，(唱)大古里是箱儿里盛只。"]'),
('yuanqu-10421','冻苏秦衣锦还乡・四边静','无名氏','元','元曲','yuanqu','','[]','我想着那当初一日，(二旦云)可不道金榜无名誓不归？(正末云)苏秦也，你料着不得官呵，休说那般大言波。',152,'元曲/yuanqu.json','["我想着那当初一日，(二旦云)可不道金榜无名誓不归？(正末云)苏秦也，你料着不得官呵，休说那般大言波。", "(唱)你再休说道是金榜无名誓不归。", "(二旦云)你这些时在那里那？(正末唱)我在那弘农县里。", "(二旦云)在那里做些甚么？(正末唱)无靠无依，任受尽多狼狈。", "罢、罢、罢！我男子汉身长七尺，宁死也做一个不着家乡的鬼。"]'),
('yuanqu-10422','冻苏秦衣锦还乡・南吕/一枝花','无名氏','元','元曲','yuanqu','','[]','如今那有才学的受困穷，几时得居要路为卿相？我想那耕牛无宿料，仓鼠可兀的有余粮。',83,'元曲/yuanqu.json','["如今那有才学的受困穷，几时得居要路为卿相？我想那耕牛无宿料，仓鼠可兀的有余粮。", "十载寒窗，捱不出齑盐况。", "怎生那风共雪缠的我慌？则他好茶饭不济饥肠，这破衣衫偏歇着我脊梁。"]'),
('yuanqu-10423','冻苏秦衣锦还乡・隔尾','无名氏','元','元曲','yuanqu','','[]','我喜则喜一盏琼花酿，恨则恨十分他这个冰雪般凉。',117,'元曲/yuanqu.json','["我喜则喜一盏琼花酿，恨则恨十分他这个冰雪般凉。", "(张仪云)这一杯酒，与兄弟荡寒咱。", "(正末唱)你待与我荡寒呵，你着那祗候人荡一荡。", "(张仪云)兄弟吃了者。", "(正末唱)小生咽下去怎当，冰断我这肚肠，(带云)哥哥先饮。", "(唱)这一盏酒推辞了多半晌。"]'),
('yuanqu-10424','冻苏秦衣锦还乡・絮虾蟆','无名氏','元','元曲','yuanqu','','[]','只为你个同窗友做头厅相，因此上我心中自酌量。',272,'元曲/yuanqu.json','["只为你个同窗友做头厅相，因此上我心中自酌量。", "这交情非比泛常，好做十分倚仗。", "撇下父母在堂，远远特来相访。", "吟就新诗一章，诉说飘零异方。", "必然见我感伤，不惜于金治装。", "岂知你故人名望，也不问别来无恙。", "放下一张饭床，上面都没摆当，冷酒冷粉冷汤，着咱如何近傍；厅般装模作样，汕笑寒酸魍魉。", "甚勾当，来来往往，张张狂狂，村村棒棒。", "(张千喝科，云)点汤！(正末唱)哎，又要你走将来，走将来便雪仁加霜，忒颓慌。", "(正末云)张仪！(张仪云)苏秦！(正末唱)这都是剥民脂膏养的能豪旺，腌情况，甚纪纲。", "只我在你行，待将些寒温活讲，(带云)抬了去者！(唱)须不是告甚么从良！。"]'),
('yuanqu-10425','冻苏秦衣锦还乡・牧羊关','无名氏','元','元曲','yuanqu','','[]','你比我文学浅，(张千云)点汤！(正末唱)我比你只命运囊，(张千云)点汤！(正末唱)你苟图些紫绶金章。',230,'元曲/yuanqu.json','["你比我文学浅，(张千云)点汤！(正末唱)我比你只命运囊，(张千云)点汤！(正末唱)你苟图些紫绶金章。", "(张千云)点汤！(张仪云)我则理会的见世生苗。", "(正末唱)赤紧的见世生苗，(张千云)点汤！(正末唱)我则理会的埋根千丈。", "(张千云)点汤！(张仪云)你骂大官的，得甚么罪过？(正末唱)止不过恶大官吃八十棒。", "(张千云)点汤！(正末唱)须不是我见小利闹一千场。", "(张千云)点汤！(正末唱)俺两个才厮挺、才厮挺，(张千云)点汤！(正末唱)口足！你敢也走将来喝点汤、喝点汤！。"]'),
('yuanqu-10426','冻苏秦衣锦还乡・幺篇','无名氏','元','元曲','yuanqu','','[]','他赍发了我银两锭，我恰便似梦一场，着苏秦死生难忘。',294,'元曲/yuanqu.json','["他赍发了我银两锭，我恰便似梦一场，着苏秦死生难忘。", "他是个祗候人的所为，可有那孟尝君的这度量。", "张仪也。", "你便头顶养军司库，脚踹着万年仓。", "说不尽宰相多荣贵，找苏秦也男儿当白强！(正末云)哥，我拿着你这两锭白银，再过去羞那厮一场。", "(陈用云)好、好、好，贤上，你过去。", "(正末做见张仪科，云)张仪，你看。", "(张仪云)你不是苏秦？两个手呈拿着许多东西。", "莫不是那里偷将来的？(正末云)我偷了你的末？你听者，我久后得官呵，必不在你之下！(张仪云)你怎生能勾为宫！我量着你一世儿不能发迹！你若能勾发迹呵，(诗云)则除是驴生笄角瓮生根，大教穷断脊梁筋。", "小物不堪成大用，苏秦则是旧苏秦！快出去！快出去！(正末唱)。"]'),
('yuanqu-10427','冻苏秦衣锦还乡・黄钟尾','无名氏','元','元曲','yuanqu','','[]','罢、罢、罢！凭着我胸中豪气三千丈，笔下文才七步章。',153,'元曲/yuanqu.json','["罢、罢、罢！凭着我胸中豪气三千丈，笔下文才七步章。", "亲不亲是乡党；若今番，到举场；将万言书，见帝王；插官花，饮御觞；伞盖下，马儿上；请哥哥，再相访；我言语，个虚诳；这赍发，这觑当；两锭银，重百两，遮莫便十年呵，休想我贵人多忘。", "将你一个山海也似人恩人，(云)哥。", "你叫做陈用。", "(唱)我苏秦长则个今门般想。", "(下)。"]'),
('yuanqu-10428','冻苏秦衣锦还乡・双调/新水令','无名氏','元','元曲','yuanqu','','[]','谢当今圣主重贤臣，我争些儿有家难奔。',346,'元曲/yuanqu.json','["谢当今圣主重贤臣，我争些儿有家难奔。", "恰便似旱苗才得雨。", "枯树恰逢春。", "受尽了万革苦千辛，苏秦也常汜得求官去那时分。", "(孛老同卜儿领苏大、大旦、二旦上)(孛老云)老汉苏大公的便是。", "领着俺一家儿，直至驿亭中认孩儿去来。", "可早来到门首也。", "令人，报复去，道有元帅的老相公同母亲、哥哥、嫂嫂、夫人都在于门首。", "(张千云)喏。", "报的元帅得知，有老相公同家眷来了也。", "(正末云)甚么老相公？着他过来。", "(张千云)理会的。", "着过去。", "(孛老同众做见科。", "云)孩儿也，我道你不是个受贫的。", "(正末云)谁是你的孩儿？(孛老云)你是我的孩儿。", "你得了官，你怎生不回家里去？(正末云)兀那老儿，你是甚么人？(孛老云)我是你父亲。", "你如今得了甚么官来？(正末云)我做了六国都元帅。", "(孛老云)似你这等峥嵘，与我父母增多少光彩，好儿也呵！(正末唱)。"]'),
('yuanqu-10429','冻苏秦衣锦还乡・步步娇','无名氏','元','元曲','yuanqu','','[]','怎消的父亲、母亲将孩儿认。',660,'元曲/yuanqu.json','["怎消的父亲、母亲将孩儿认。", "(孛老云)孩儿家去来，在驿亭中做甚么？(正末唱)我为甚馆驿里权安顿，当日个父亲行得处分，恰便似经板儿由然在心印。", "(孛老云)孩儿，旧话休题。", "(正末云)父亲你不道来？(孛老云)我道甚么来？(正末唱)我若是踏着你正堂门，我其实怕打那二百黄桑棍！(孛老云)是老汉的不是了。", "(正末云)张千，都与我抢出去！(张千云)理会的。", "(做抢科，云)出去！(孛老云)婆婆，孩儿不肯认我父母，可怎生是了也？(张仪领陈用上，云)小官张仪是也。", "听知的苏秦兄弟做了六国都元帅。", "差人持千金来，谢弘农县主人王真。", "又打一封战书，要来伐我秦国。", "这个是明明记着冰雪堂的仇恨。", "若待他兵马到来，那时晚矣。", "如今趁他衣锦还乡，在洛阳驿亭中安下，我特地探望他一遭去。", "说开此事，多少是好。", "迤逦而来，可早到了也。", "令人，接了马者。", "(做见孛老、卜儿科，云)兀的不是父亲、母亲、哥哥、嫂嫂都在这里？(孛老云)原来是张仪孩儿那。", "(张仪云)父亲曾过去认你孩儿来么？(孛老云)恰才俺都过去认孩儿来，他坚意不肯认俺，把俺一家儿都赶将出来了。", "(张仪云)父亲、母亲、哥哥、嫂嫂且放心者，待您孩儿过去，他必然认了也。", "(孛老云)为甚么你过去便认你？(张仪云)想着我冰雪堂那场好管待，他怎么不认？令人。", "报复去，道有秦丞相张仪，来见元帅。", "(张千云)喏。", "报的元帅得知，有秦丞相张仪来了也。", "(正末云)你说去：他不自过来，等我接待他怎的？(张千云)奉俺元帅将令说，你不自过去，等俺元帅接待你怎的？(张仪云)他早还了我一句儿也。", "(见科，云)元帅，我说你不是受贫的人，多时不见，有一拜。"]'),
('yuanqu-10430','冻苏秦衣锦还乡・川拨棹','无名氏','元','元曲','yuanqu','','[]','便待要献殷勤，笑吟吟叙弟昆。',56,'元曲/yuanqu.json','["便待要献殷勤，笑吟吟叙弟昆。", "我那时衣不遮身，今日个驷马雕轮。", "公吏每忙跟，兀良胁底下插柴内忍，全不想冰雪堂无事哏。"]'),
('yuanqu-10431','冻苏秦衣锦还乡・七弟兄','无名氏','元','元曲','yuanqu','','[]','我这里动问，你是甚人？(张仪云)我是你哥哥张仪。',79,'元曲/yuanqu.json','["我这里动问，你是甚人？(张仪云)我是你哥哥张仪。", "(正末云)我道你是谁那，(唱)元来你是那孟尝君。", "想蛟龙未得风雷信，定是泥蟠无日上青云，也似俺书生怎脱凄凉运！。"]'),
('yuanqu-10432','冻苏秦衣锦还乡・梅花酒','无名氏','元','元曲','yuanqu','','[]','呀，我直捱到这地分，在野店荒村，被疾病缠身，举日也无亲。',116,'元曲/yuanqu.json','["呀，我直捱到这地分，在野店荒村，被疾病缠身，举日也无亲。", "只有你、你、你，张仪是故人，因此上我、我、我，千里远投奔。", "怕不的有黄金济我贫？岂知你倚恃着做官尊，觑朋友若遗尘，没半点话温存，讪笑的我不成人。", "定饿死做异乡魂，到今日也跳龙门！。"]'),
('yuanqu-10433','冻苏秦衣锦还乡・喜江南','无名氏','元','元曲','yuanqu','','[]','呀，莫不我驴生笄角瓮生根，你觑波莫不我穷断脊梁筋，苏秦只是旧苏秦。',50,'元曲/yuanqu.json','["呀，莫不我驴生笄角瓮生根，你觑波莫不我穷断脊梁筋，苏秦只是旧苏秦。", "今日个证本，想皇天也不负读书人！。"]'),
('yuanqu-10434','冻苏秦衣锦还乡・沽美酒','无名氏','元','元曲','yuanqu','','[]','我须是钱亲人不亲，(陈用云)元帅，折杀小人也。',63,'元曲/yuanqu.json','["我须是钱亲人不亲，(陈用云)元帅，折杀小人也。", "(正末唱)追富来不追贫。", "他是一个紫衫银带的祗候人，他倒肯怜咱困窘，赍发与雪花银。"]'),
('yuanqu-10435','冻苏秦衣锦还乡・鸳鸯煞','无名氏','元','元曲','yuanqu','','[]','想当初风尘落落谁怜悯，到今日衣冠楚楚争亲近。',75,'元曲/yuanqu.json','["想当初风尘落落谁怜悯，到今日衣冠楚楚争亲近。", "畅道威震诸侯，腰悬六印，也索把世态炎凉，心中暗忖：假使一朝马死黄金尽，可不的依旧苏秦，做陌路看承被人晒！。"]'),
('yuanqu-10436','仙吕・点绛唇','无名氏','元','元曲','yuanqu','','[]','道妙玄微，先须要悟明心地，非容易。',32,'元曲/yuanqu.json','["道妙玄微，先须要悟明心地，非容易。", "见放着古圣文书，内隐着真消息。"]'),
('yuanqu-10437','混江龙・若说着胎元根蒂，只除是含光默默守虚极。去动中求静，静定是','无名氏','元','元曲','yuanqu','','[]','幽微。',64,'元曲/yuanqu.json','["幽微。", "默坐忘言方是道，群居缄口是道根基。", "有一等明师，自高自大，狂言诈语，道听涂说，自把他元神昧。", "全不怕上天照察，也不怕六道轮回。"]'),
('yuanqu-10438','油葫芦・道本无言行妙理，夺天地髓，就中只许自家知。无中生有人还会，','无名氏','元','元曲','yuanqu','','[]','玉炉内常把阴阳来配。',33,'元曲/yuanqu.json','["玉炉内常把阴阳来配。", "要进火功，莫得迟。", "双关透入泥丸内，自然显光辉。"]'),
('yuanqu-10439','天下乐・金液还丹下玉梯。烹煎，白雪飞，黄芽渐长生天地。质体内真，','无名氏','元','元曲','yuanqu','','[]','路不迷，化琼浆满玉池。',11,'元曲/yuanqu.json','["路不迷，化琼浆满玉池。"]'),
('yuanqu-10440','后庭花・饥中饱饱后饥，饮醍醐滋肾水。将地户牢关闭，化真精吞玉蕊。','无名氏','元','元曲','yuanqu','','[]','吐虹霓，黄庭内相会。',32,'元曲/yuanqu.json','["吐虹霓，黄庭内相会。", "见金公红了面皮，将婴儿和戊己，共元神相护持。"]'),
